window.poetryCorpus = [{"title":"在嶽詠蟬","author":"駱賓王","dynasty":"唐","form":"诗","lines":["西陸蟬聲唱，南冠客思侵。","那堪玄鬢影，來對白頭吟。","露重飛難進，風多響易沈。","無人信高潔，誰爲表予心。"],"source":"《唐诗三百首》"},{"title":"登幽州臺歌","author":"陳子昂","dynasty":"唐","form":"诗","lines":["前不見古人，後不見來者。","念天地之悠悠，獨愴然而涕下。"],"source":"《唐诗三百首》"},{"title":"經鄒魯祭孔子而歎之","author":"明皇帝","dynasty":"唐","form":"诗","lines":["夫子何爲者？栖栖一代中。","地猶鄹氏邑，宅即魯王宮。","歎鳳嗟身否，傷麟怨道窮。","今看兩楹奠，當與夢時同。"],"source":"《唐诗三百首》"},{"title":"鼓吹曲辭 將進酒","author":"李白","dynasty":"唐","form":"诗","lines":["君不見黃河之水天上來，奔流到海不復回。","君不見高堂明鏡悲白髮，朝如青絲暮成雪。","人生得意須盡歡，莫使金尊空對月。","天生我材必有用，千金散盡還復來。","烹羊宰牛且爲樂，會須一飲三百杯。","岑夫子，丹丘生，將進酒，杯莫停。","與君歌一曲，請君爲我側耳聽。","鐘鼓饌玉不足貴，但願長醉不復醒。","古來聖賢皆寂寞，惟有飲者留其名。","陳王昔時宴平樂，斗酒十千恣歡謔。","主人何爲言少錢，徑須酤取對君酌。","五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"],"source":"《唐诗三百首》"},{"title":"橫吹曲辭 出塞 一","author":"王昌齡","dynasty":"唐","form":"诗","lines":["秦時明月漢時關，萬里長征人未還。","但使龍城飛將在，不教胡馬度陰山。"],"source":"《唐诗三百首》"},{"title":"橫吹曲辭 出塞","author":"王之渙","dynasty":"唐","form":"诗","lines":["黃砂直上白雲間，一片孤城萬仞山。","羌笛何須怨楊柳，春風不度玉門關。"],"source":"《唐诗三百首》"},{"title":"橫吹曲辭 關山月","author":"李白","dynasty":"唐","form":"诗","lines":["明月出天山，蒼茫雲海間。","長風幾萬里，吹度玉門關。","漢下白登道，胡窺青海灣。","由來征戰地，不見有人還。","戍客望邊色，思歸多苦顏。","高樓當此夜，歎息未應閑。"],"source":"《唐诗三百首》"},{"title":"新嫁娘詞三首 三","author":"王建","dynasty":"唐","form":"诗","lines":["三日入廚下，洗手作羹湯。","未諳姑食性，先遣小姑嘗。"],"source":"《唐诗三百首》"},{"title":"故行宮","author":"王建","dynasty":"唐","form":"诗","lines":["寥落古行宮，宮花寂寞紅。","白頭宮女在，閑坐說玄宗。"],"source":"《唐诗三百首》"},{"title":"錦瑟","author":"李商隱","dynasty":"唐","form":"诗","lines":["錦瑟無端五十絃，一絃一柱思華年。","莊生曉夢迷蝴蝶，望帝春心託杜鵑。","滄海月明珠有淚，藍田日暖玉生煙。","此情可待成追憶，只是當時已惘然。"],"source":"《唐诗三百首》"},{"title":"蟬","author":"李商隱","dynasty":"唐","form":"诗","lines":["本以高難飽，徒勞恨費聲。","五更疎欲斷，一樹碧無情。","薄宦梗猶汎，故園蕪已平。","煩君最相警，我亦舉家清。"],"source":"《唐诗三百首》"},{"title":"樂遊原","author":"李商隱","dynasty":"唐","form":"诗","lines":["向晚意不適，驅車登古原。","夕陽無限好，只是近黃昏。"],"source":"《唐诗三百首》"},{"title":"夜雨寄北","author":"李商隱","dynasty":"唐","form":"诗","lines":["君問歸期未有期，巴山夜雨漲秋池。","何當共剪西窗燭，却話巴山夜雨時。"],"source":"《唐诗三百首》"},{"title":"韓碑","author":"李商隱","dynasty":"唐","form":"诗","lines":["元和天子神武姿，彼何人哉軒與羲。","誓將上雪列聖恥，坐法宮中朝四夷。","淮西有賊五十載，封狼生貙貙生羆。","不據山河據平地，長戈利矛日可麾。","帝得聖相相曰度，賊斫不死神扶持。","腰懸相印作都統，陰風慘澹天王旗。","愬武古通作牙爪，儀曹外郎載筆隨。","行軍司馬智且勇，十四萬衆猶虎貔。","入蔡縛賊獻太廟，功無與讓恩不訾。","帝曰汝度功第一，汝從事愈宜爲辭。","愈拜稽首蹈且舞，金石刻畫臣能爲。","古者世稱大手筆，此事不繫于職司。","當仁自古有不讓，言訖屢頷天子頤。","公退齋戒坐小閣，濡染大筆何淋漓。","點竄堯典舜典字，塗改清廟生民詩。","文成破體書在紙，清晨再拜鋪丹墀。","表曰臣愈昧死上，詠神聖功書之碑。","碑高三丈字如斗，負以靈鼇蟠以螭。","句奇語重喻者少，讒之天子言其私。","長繩百尺拽碑倒，麤砂大石相磨治。","公之斯文若元氣，先時已入人肝脾。","湯盤孔鼎有述作，今無其器存其辭。","嗚呼聖皇及聖相，相與烜赫流淳熙。","公之斯文不示後，曷與三五相攀追。","願書萬本誦萬過，口角流沫右手胝。","傳之七十有二代，以爲封禪玉檢明堂基。"],"source":"《唐诗三百首》"},{"title":"風雨","author":"李商隱","dynasty":"唐","form":"诗","lines":["淒涼寶劍篇，羈泊欲窮年。","黃葉仍風雨，青樓自管絃。","新知遭薄俗，舊好隔良緣。","心斷新豐酒，銷愁斗幾千。"],"source":"《唐诗三百首》"},{"title":"寄令狐郎中","author":"李商隱","dynasty":"唐","form":"诗","lines":["嵩雲秦樹久離居，雙鯉迢迢一紙書。","休問梁園舊賓客，茂陵秋雨病相如。"],"source":"《唐诗三百首》"},{"title":"隋宮","author":"李商隱","dynasty":"唐","form":"诗","lines":["紫泉宮殿鎖煙霞，欲取蕪城作帝家。","玉璽不緣歸日角，錦帆應是到天涯。","于今腐草無螢火，終古垂楊有暮鴉。","地下若逢陳後主，豈宜重問後庭花。"],"source":"《唐诗三百首》"},{"title":"籌筆驛","author":"李商隱","dynasty":"唐","form":"诗","lines":["猿鳥猶疑畏簡書，風雲常爲護儲胥。","徒令上將揮神筆，終見降王走傳車。","管樂有才終不忝，關張無命欲何如。","他年錦里經祠廟，梁父吟成恨有餘。"],"source":"《唐诗三百首》"},{"title":"無題二首 一","author":"李商隱","dynasty":"唐","form":"诗","lines":["昨夜星辰昨夜風，畫樓西畔桂堂東。","身無綵鳳雙飛翼，心有靈犀一點通。","隔座送鉤春酒暖，分曹射覆蠟燈紅。","嗟余聽鼓應官去，走馬蘭臺類斷蓬。"],"source":"《唐诗三百首》"},{"title":"無題四首 一","author":"李商隱","dynasty":"唐","form":"诗","lines":["來是空言去絕踪，月斜樓上五更鐘。","夢爲遠別啼難喚，書被催成墨未濃。","蠟照半籠金翡翠，麝熏微度繡芙蓉。","劉郎已恨蓬山遠，更隔蓬山一萬重。"],"source":"《唐诗三百首》"},{"title":"無題四首 二","author":"李商隱","dynasty":"唐","form":"诗","lines":["颯颯東風細雨來，芙蓉塘外有輕雷。","金蟾齧鏁燒香入，玉虎牽絲汲井迴。","賈氏窺簾韓掾少，宓妃留枕魏王才。","春心莫共花爭發，一寸相思一寸灰。"],"source":"《唐诗三百首》"},{"title":"隋宮","author":"李商隱","dynasty":"唐","form":"诗","lines":["乘興南遊不戒嚴，九重誰省諫書函。","春風舉國裁宮錦，半作障泥半作帆。"],"source":"《唐诗三百首》"},{"title":"落花","author":"李商隱","dynasty":"唐","form":"诗","lines":["高閣客竟去，小園花亂飛。","參差連曲陌，迢遰送斜暉。","腸斷未忍掃，眼穿仍欲歸。","芳心向春盡，所得是沾衣。"],"source":"《唐诗三百首》"},{"title":"爲有","author":"李商隱","dynasty":"唐","form":"诗","lines":["爲有雲屏無限嬌，鳳城寒盡怕春宵。","無端嫁得金龜壻，辜負香衾事早朝。"],"source":"《唐诗三百首》"},{"title":"無題","author":"李商隱","dynasty":"唐","form":"诗","lines":["相見時難別亦難，東風無力百花殘。","春蠶到死絲方盡，蠟炬成灰淚始乾。","曉鏡但愁雲鬢改，夜吟應覺月光寒。","蓬山此去無多路，青鳥殷勤爲探看。"],"source":"《唐诗三百首》"},{"title":"瑤池","author":"李商隱","dynasty":"唐","form":"诗","lines":["瑤池阿母綺窗開，黃竹歌聲動地哀。","八駿日行三萬里，穆王何事不重來。"],"source":"《唐诗三百首》"},{"title":"春雨","author":"李商隱","dynasty":"唐","form":"诗","lines":["悵臥新春白袷衣，白門寥落意多違。","紅樓隔雨相望冷，珠箔飄燈獨自歸。","遠路應悲春晼晚，殘宵猶得夢依稀。","玉璫緘札何由達，萬里雲羅一雁飛。"],"source":"《唐诗三百首》"},{"title":"常娥","author":"李商隱","dynasty":"唐","form":"诗","lines":["雲母屏風燭影深，長河漸落曉星沈。","常娥應悔偷靈藥，碧海青天夜夜心。"],"source":"《唐诗三百首》"},{"title":"無題二首 一","author":"李商隱","dynasty":"唐","form":"诗","lines":["鳳尾香羅薄幾重，碧文圓頂夜深縫。","扇裁月魄羞難掩，車走雷聲語未通。","曾是寂寥金燼暗，斷無消息石榴紅。"],"source":"《唐诗三百首》"},{"title":"無題二首 二","author":"李商隱","dynasty":"唐","form":"诗","lines":["重帷深下莫愁堂，臥後清宵細細長。","神女生涯原是夢，小姑居處本無郎。","風波不信菱枝弱，月露誰教桂葉香。","直道相思了無益，未妨惆悵是清狂。"],"source":"《唐诗三百首》"},{"title":"賈生","author":"李商隱","dynasty":"唐","form":"诗","lines":["宣室求賢訪逐臣，賈生才調更無倫。","可憐夜半虛前席，不問蒼生問鬼神。"],"source":"《唐诗三百首》"},{"title":"涼思","author":"李商隱","dynasty":"唐","form":"诗","lines":["客去波平檻，蟬休露滿枝。","永懷當此節，倚立自移時。","北斗兼春遠，南陵寓使遲。","天涯占夢數，疑誤有新知。"],"source":"《唐诗三百首》"},{"title":"北青蘿","author":"李商隱","dynasty":"唐","form":"诗","lines":["殘陽西入崦，茅屋訪孤僧。","落葉人何在，寒雲路幾層。","獨敲初夜磬，閑倚一枝藤。","世界微塵裏，吾寧愛與憎。"],"source":"《唐诗三百首》"},{"title":"赤壁","author":"李商隱","dynasty":"唐","form":"诗","lines":["折戟沈沙鐵未銷，自將磨洗認前朝。","東風不與周郎便，銅雀春深鎖二喬。"],"source":"《唐诗三百首》"},{"title":"章臺夜思","author":"韋莊","dynasty":"唐","form":"诗","lines":["清瑟怨遙夜，遶弦風雨哀。","孤燈聞楚角，殘月下章臺。","芳草已云暮，故人殊未來。","鄉書不可寄，秋雁又南迴。"],"source":"《唐诗三百首》"},{"title":"金陵圖","author":"韋莊","dynasty":"唐","form":"诗","lines":["誰謂傷心畫不成，畫人心逐世人情。","君看六幅南朝事，老木寒雲滿故城。"],"source":"《唐诗三百首》"},{"title":"臺城","author":"韋莊","dynasty":"唐","form":"诗","lines":["江雨霏霏江草齊，六朝如夢鳥空啼。","無情最是臺城柳，依舊煙籠十里堤。"],"source":"《唐诗三百首》"},{"title":"宮詞","author":"薛逢","dynasty":"唐","form":"诗","lines":["十二樓中盡曉妝，望仙樓上望君王。","鎖銜金獸連環冷，水滴銅龍晝漏長。","雲髻罷梳還對鏡，羅衣欲換更添香。","遙窺正殿簾開處，袍袴宮人掃御牀。"],"source":"《唐诗三百首》"},{"title":"楚江懷古三首 一","author":"馬戴","dynasty":"唐","form":"诗","lines":["露氣寒光集，微陽下楚丘。","猨啼洞庭樹，人在木蘭舟。","廣澤生明月，蒼山夾亂流。","雲中君不降，竟夕自悲秋。"],"source":"《唐诗三百首》"},{"title":"灞上秋居","author":"馬戴","dynasty":"唐","form":"诗","lines":["灞原風雨定，晚見鴈行頻。","落葉他鄉樹，寒燈獨夜人。","空園白露滴，孤壁野僧隣。","寄臥郊扉久，何門致此身。"],"source":"《唐诗三百首》"},{"title":"馬嵬坡","author":"鄭畋","dynasty":"唐","form":"诗","lines":["[玄]宗回馬楊妃死，雲雨雖亡日月新。","終是聖明天子事，景陽宮井又何人。"],"source":"《唐诗三百首》"},{"title":"沒蕃故人","author":"張籍","dynasty":"唐","form":"诗","lines":["前年伐月支，城上沒全師。","蕃漢斷消息，死生長別離。","無人收廢帳，歸馬識殘旗。","欲祭疑君在，天涯哭此時。"],"source":"《唐诗三百首》"},{"title":"春怨","author":"金昌緒","dynasty":"唐","form":"诗","lines":["打起黃鶯兒，莫教枝上啼。","啼時驚妾夢，不得到遼西。"],"source":"《唐诗三百首》"},{"title":"遣悲懷三首 一","author":"元稹","dynasty":"唐","form":"诗","lines":["謝公最小偏憐女，嫁與黔婁百事乖。","顧我無衣搜畫篋，泥他沽酒拔金釵。","野蔬充膳甘長藿，落葉添薪仰古槐。","今日俸錢過十萬，與君營奠復營齋。"],"source":"《唐诗三百首》"},{"title":"遣悲懷三首 二","author":"元稹","dynasty":"唐","form":"诗","lines":["昔日戲言身後意，今朝皆到眼前來。","衣裳已施行看盡，針線猶存未忍開。","尚想舊情憐婢僕，也曾因夢送錢財。","誠知此恨人人有，貧賤夫妻百事哀。"],"source":"《唐诗三百首》"},{"title":"遣悲懷三首 三","author":"元稹","dynasty":"唐","form":"诗","lines":["閑坐悲君亦自悲，百年都是幾多時。","鄧攸無子尋知命，潘岳悼亡猶費詞。","同穴窅冥何所望，他生緣會更難期。","唯將終夜長開眼，報荅平生未展眉。"],"source":"《唐诗三百首》"},{"title":"行宮","author":"元稹","dynasty":"唐","form":"诗","lines":["寥落古行宮，宮花寂寞紅。","白頭宮女在，閑坐說玄宗。"],"source":"《唐诗三百首》"},{"title":"哥舒歌","author":"西鄙人","dynasty":"唐","form":"诗","lines":["北斗七星高，哥舒夜帶刀。","至今窺牧馬，不敢過臨洮。"],"source":"《唐诗三百首》"},{"title":"雜詩 十三","author":"無名氏","dynasty":"唐","form":"诗","lines":["近寒食雨草萋萋，著麥苗風柳映堤。","早是有家歸未得，杜鵑休向耳邊啼。"],"source":"《唐诗三百首》"},{"title":"雜詩三首 三","author":"沈佺期","dynasty":"唐","form":"诗","lines":["聞道黃龍戍，頻年不解兵。","可憐閨裏月，長在漢家營。","少婦今春意，良人昨夜情。","誰能將旗鼓，一爲取龍城。"],"source":"《唐诗三百首》"},{"title":"古意呈補闕喬知之","author":"沈佺期","dynasty":"唐","form":"诗","lines":["盧家少婦鬱金堂，海燕雙棲玳瑁梁。","九月寒砧催木葉，十年征戍憶遼陽。","白狼河北音書斷，丹鳳城南秋夜長。","誰謂含愁獨不見，更教明月照流黃。"],"source":"《唐诗三百首》"},{"title":"次北固山下","author":"王灣","dynasty":"唐","form":"诗","lines":["客路青山外，行舟綠水前。","潮平兩岸闊，風正一帆懸。","海日生殘夜，江春入舊年。","鄉書何處達，歸雁洛陽邊。"],"source":"《唐诗三百首》"},{"title":"桃花谿","author":"張旭","dynasty":"唐","form":"诗","lines":["隱隱飛橋隔野煙，石磯西畔問漁船。","桃花盡日隨流水，洞在清谿何處邊。"],"source":"《唐诗三百首》"},{"title":"送別","author":"王維","dynasty":"唐","form":"诗","lines":["下馬飲君酒，問君何所之。","君言不得意，歸臥南山陲。","但去莫復問，白雲無盡時。"],"source":"《唐诗三百首》"},{"title":"送綦毋潛落第還鄉","author":"王維","dynasty":"唐","form":"诗","lines":["聖代無隱者，英靈盡來歸。","遂令東山客，不得顧采薇。","既至君門遠，孰云吾道非。","江淮度寒食，京洛縫春衣。","置酒臨長道，同心與我違。","行當浮桂櫂，未幾拂荆扉。","遠樹帶行客，孤村當落暉。","吾謀適不用，勿謂知音稀。"],"source":"《唐诗三百首》"},{"title":"青谿","author":"王維","dynasty":"唐","form":"诗","lines":["言入黃花川，每逐青谿水。","隨山將萬轉，趣途無百里。","聲喧亂石中，色靜深松裏。","漾漾汎菱荇，澄澄映葭葦。","我心素已閑，清川澹如此。","請留盤石上，垂釣將已矣。"],"source":"《唐诗三百首》"},{"title":"渭川田家","author":"王維","dynasty":"唐","form":"诗","lines":["斜陽照墟落，窮巷牛羊歸。","野老念牧童，倚杖候荆扉。","雉雊麥苗秀，蠶眠桑葉稀。","田夫荷鋤至，相見語依依。","即此羨閑逸，悵然吟式微。"],"source":"《唐诗三百首》"},{"title":"西施詠","author":"王維","dynasty":"唐","form":"诗","lines":["豔色天下重，西施寧久微。","朝仍越溪女，暮作吳宮妃。","賤日豈殊衆，貴來方悟稀。","邀人傅香粉，不自著羅衣。","君寵益嬌態，君憐無是非。","當時浣紗伴，莫得同車歸。","持謝鄰家子，效顰安可希。"],"source":"《唐诗三百首》"},{"title":"老將行","author":"王維","dynasty":"唐","form":"诗","lines":["少年十五二十時，步行奪得胡馬射。","射殺中山白額虎，肯數鄴下黃鬚兒。","一身轉戰三千里，一劒曾當百萬師。","漢兵奮迅如霹靂，虜騎崩騰畏蒺藜。","衞青不敗由天幸，李廣無功緣數奇。","自從棄置便衰朽，世事磋跎成白首。","昔時飛箭無全目，今日垂楊生左肘。","路傍時賣故侯瓜，門前學種先生柳。","蒼茫古木連窮巷，寥落寒山對虛牖。","誓令疏勒出飛泉，不似潁川空使酒。","賀蘭山下陣如雲，羽檄交馳日夕聞。","節使三河募年少，詔書五道出將軍。","試拂鐵衣如雪色，聊持寶劒動星文。","願得燕弓射天將，恥令越甲鳴吳軍。","莫嫌舊日雲中守，猶堪一戰取功勳。"],"source":"《唐诗三百首》"},{"title":"桃源行","author":"王維","dynasty":"唐","form":"诗","lines":["漁舟逐水愛山春，兩岸桃花夾去津。","坐看紅樹不知遠，行盡青溪不見人。","山口潛行始隈隩，山開曠望旋平陸。","遙看一處攢雲樹，近入千家散花竹。","樵客初傳漢姓名，居人未改秦衣服。","居人共住武陵源，還從物外起田園。","月明松下房櫳靜，日出雲中雞犬喧。","驚聞俗客爭來集，競引還家問都邑。","平明閭巷埽花開，薄暮漁樵乘水入。","初因避地去人間，及至成仙遂不還。","峽裏誰知有人事，世中遙望空雲山。","不疑靈境難聞見，塵心未盡思鄉縣。","出洞無論隔山水，辭家終擬長游衍。","自謂經過舊不迷，安知峰壑今來變。","當時只記入山深，青溪幾曲到雲林。","春來遍是桃花水，不辨仙源何處尋。"],"source":"《唐诗三百首》"},{"title":"洛陽女兒行","author":"王維","dynasty":"唐","form":"诗","lines":["洛陽女兒對門居，纔可容顏十五餘。","良人玉勒乘驄馬，侍女金盤鱠鯉魚。","畫閣朱樓盡相望，紅桃綠柳垂簷向。","羅幃送上七香車，寶扇迎歸九華帳。","狂夫富貴在青春，意氣驕奢劇季倫。","自憐碧玉親教舞，不惜珊瑚持與人。","春窗曙滅九微火，九微片片飛花璅。","戲罷曾無理曲時，妝成秪是薰香坐。","城中相識盡繁華，日夜經過趙李家。","誰憐越女顏如玉，貧賤江頭自浣紗。"],"source":"《唐诗三百首》"},{"title":"輞川閑居贈裴秀才迪","author":"王維","dynasty":"唐","form":"诗","lines":["寒山轉蒼翠，秋水日潺湲。","倚杖柴門外，臨風聽暮蟬。","渡頭餘落日，墟里上孤煙。","復值接輿醉，狂歌五柳前。"],"source":"《唐诗三百首》"},{"title":"酬張少府","author":"王維","dynasty":"唐","form":"诗","lines":["晚年唯好靜，萬事不關心。","自顧無長策，空知返舊林。","松風吹解帶，山月照彈琴。","君問窮通理，漁歌入浦深。"],"source":"《唐诗三百首》"},{"title":"送梓州李使君","author":"王維","dynasty":"唐","form":"诗","lines":["萬壑樹參天，千山響杜鵑。","山中一夜雨，樹杪百重泉。","漢女輸橦布，巴人訟芋田。","文翁翻教授，不敢倚先賢。"],"source":"《唐诗三百首》"},{"title":"玉臺體十二首 十一","author":"權德輿","dynasty":"唐","form":"诗","lines":["昨夜裙帶解，今朝蟢子飛。","鉛華不可棄，莫是藁砧歸。"],"source":"《唐诗三百首》"},{"title":"山石","author":"韓愈","dynasty":"唐","form":"诗","lines":["山石犖確行徑微，黃昏到寺蝙蝠飛。","升堂坐階新雨足，芭蕉葉大支子肥。","僧言古壁佛畫好，以火來照所見稀。","鋪牀拂席置羹飯，疎糲亦足飽我飢。","夜深靜臥百蟲絕，清月出嶺光入扉。","天明獨去無道路，出入高下窮煙霏。","山紅澗碧紛爛漫，時見松櫪皆十圍。","當流赤足蹋澗石，水聲激激風吹衣。","人生如此自可樂，豈必局束爲人鞿。","嗟哉吾黨二三子，安得至老不更歸。"],"source":"《唐诗三百首》"},{"title":"八月十五夜贈張功曹","author":"韓愈","dynasty":"唐","form":"诗","lines":["纖雲四卷天無河，清風吹空月舒波。","沙平水息聲影絕，一桮相屬君當歌。","君歌聲酸辭且苦，不能聽終淚如雨。","洞庭連天九疑高，蛟龍出沒猩鼯號。","十生九死到官所，幽居默默如藏逃。","下牀畏蛇食畏藥，海氣濕蟄熏腥臊。","昨者州前搥大鼓，嗣皇繼聖登夔臯。","赦書一日行萬里，罪從大辟皆除死。","遷者追廻流者還，滌瑕蕩垢清朝班。","州家申名使家抑，坎軻祗得移荆蠻。","判司卑官不堪說，未免捶楚塵埃間。","同時輩流多上道，天路幽險難追攀。","君歌且休聽我歌，我歌今與君殊科。"],"source":"《唐诗三百首》"},{"title":"謁衡嶽廟遂宿嶽寺題門樓","author":"韓愈","dynasty":"唐","form":"诗","lines":["五嶽祭秩皆三公，四方環鎮嵩當中。","火維地荒足妖怪，天假神柄專其雄。","噴雲泄霧藏半腹，雖有絕頂誰能窮。","我來正逢秋雨節，陰氣晦昧無清風。","潛心默禱若有應，豈非正直能感通。","須臾靜掃衆峰出，仰見突兀撐青空。","紫蓋連延接天柱，石廩騰擲堆祝融。","森然魄動下馬拜，松柏一逕趨靈宮。","粉牆丹柱動光彩，鬼物圖畫填青紅。","升階傴僂薦脯酒，欲以菲薄明其衷。","廟令老人識神意，睢盱偵伺能鞠躬。","手持桮珓導我擲，云此最吉餘難同。","竄逐蠻荒幸不死，衣食纔足甘長終。","侯王將相望久絕，神縱欲福難爲功。","夜投佛寺上高閣，星月掩暎雲朣朧。","猿鳴鐘動不知曙，杲杲寒日生於東。"],"source":"《唐诗三百首》"},{"title":"已涼","author":"韓偓","dynasty":"唐","form":"诗","lines":["碧闌干外繡簾垂，猩血屏風畫折枝。","八尺龍鬚方錦褥，已涼天氣未寒時。"],"source":"《唐诗三百首》"},{"title":"春宮怨","author":"杜荀鶴","dynasty":"唐","form":"诗","lines":["早被嬋娟誤，欲妝臨鏡慵。","承恩不在貌，教妾若爲容。","風暖鳥聲碎，日高花影重。","年年越溪女，相憶採芙蓉。"],"source":"《唐诗三百首》"},{"title":"近試上張籍水部","author":"朱慶餘","dynasty":"唐","form":"诗","lines":["洞房昨夜停紅燭，待曉堂前拜舅姑。","[妝]罷低聲問夫壻，畫眉深淺入時無。"],"source":"《唐诗三百首》"},{"title":"將赴吳興登樂遊原一絕","author":"杜牧","dynasty":"唐","form":"诗","lines":["清時有味是無能，閑愛孤雲靜愛僧。","欲把一麾江海去，樂遊原上望昭陵。"],"source":"《唐诗三百首》"},{"title":"赤壁","author":"杜牧","dynasty":"唐","form":"诗","lines":["折戟沈沙鐵未銷，自將磨洗認前朝。","東風不與周郎便，銅雀春深鏁二喬。"],"source":"《唐诗三百首》"},{"title":"泊秦淮","author":"杜牧","dynasty":"唐","form":"诗","lines":["煙籠寒水月籠沙，夜泊秦淮近酒家。","商女不知亡國恨，隔江猶唱後庭花。"],"source":"《唐诗三百首》"},{"title":"贈別二首 一","author":"杜牧","dynasty":"唐","form":"诗","lines":["娉娉褭褭十三餘，豆蔻梢頭二月初。","春風十里揚州路，卷上珠簾總不如。"],"source":"《唐诗三百首》"},{"title":"贈別二首 二","author":"杜牧","dynasty":"唐","form":"诗","lines":["多情却似總無情，唯覺尊前笑不成。","蠟燭有心還惜別，替人垂淚到天明。"],"source":"《唐诗三百首》"},{"title":"遣懷","author":"杜牧","dynasty":"唐","form":"诗","lines":["落魄江南載酒行，楚腰腸斷掌中輕。","十年一覺揚州夢，贏得青樓薄倖名。"],"source":"《唐诗三百首》"},{"title":"秋夕","author":"杜牧","dynasty":"唐","form":"诗","lines":["紅燭秋光冷畫屏，輕羅小扇撲流螢。","天階夜色涼如水，坐看牽牛織女星。"],"source":"《唐诗三百首》"},{"title":"金谷園","author":"杜牧","dynasty":"唐","form":"诗","lines":["繁華事散逐香塵，流水無情草自春。","日暮東風怨啼鳥，落花猶似墮樓人。"],"source":"《唐诗三百首》"},{"title":"旅宿","author":"杜牧","dynasty":"唐","form":"诗","lines":["旅館無良伴，凝情自悄然。","寒燈思舊事，斷鴈警愁眠。","遠夢歸侵曉，家書到隔年。","湘江好煙月，門繫釣魚船。"],"source":"《唐诗三百首》"},{"title":"早秋三首 一","author":"許渾","dynasty":"唐","form":"诗","lines":["遙夜泛清瑟，西風生翠蘿。","殘螢委玉露，早鴈拂銀河。","高樹曉還密，遠山晴更多。","淮南一葉下，自覺老煙波。"],"source":"《唐诗三百首》"},{"title":"秋日赴闕題潼關驛樓","author":"許渾","dynasty":"唐","form":"诗","lines":["紅葉晚蕭蕭，長亭酒一瓢。","殘雲歸太華，疎雨過中條。","樹色隨山迥，河聲入海遙。","帝鄉明日到，猶自夢漁樵。"],"source":"《唐诗三百首》"},{"title":"寄人 一","author":"張泌","dynasty":"唐","form":"诗","lines":["別夢依依到謝家，小廊迴合曲闌斜。","多情只有春庭月，猶爲離人照落花。"],"source":"《唐诗三百首》"},{"title":"隴西行四首 二","author":"陳陶","dynasty":"唐","form":"诗","lines":["誓掃匈奴不顧身，五千貂錦喪胡塵。","可憐無定河邊骨，猶是春閨夢裏人。"],"source":"《唐诗三百首》"},{"title":"頌古三十二首  其二三","author":"釋明辯","dynasty":"唐","form":"诗","lines":["打起黄鶯兒，莫教枝上啼。","幾回驚妾夢，不得到遼西。"],"source":"《唐诗三百首》"},{"title":"後宮詞","author":"白居易","dynasty":"唐","form":"诗","lines":["淚濕羅巾夢不成，夜深前殿按歌聲。","紅顏未老恩先斷，斜倚薰籠坐到明。"],"source":"《唐诗三百首》"},{"title":"喜見外弟又言別","author":"李益","dynasty":"唐","form":"诗","lines":["十年離亂後，長大一相逢。","問姓驚初見，稱名憶舊容。","別來滄海事，語罷暮天鐘。","明日巴陵道，秋山又幾重。"],"source":"《唐诗三百首》"},{"title":"江南詞","author":"李益","dynasty":"唐","form":"诗","lines":["嫁得瞿塘賈，朝朝悞妾期。","早知潮有信，嫁與弄潮兒。"],"source":"《唐诗三百首》"},{"title":"夜上受降城聞笛","author":"李益","dynasty":"唐","form":"诗","lines":["回樂峰前沙似雪，受降城下月如霜。","不知何處吹蘆管，一夜征人盡望鄉。"],"source":"《唐诗三百首》"},{"title":"聽箏","author":"李端","dynasty":"唐","form":"诗","lines":["鳴箏金粟柱，素手玉房前。","欲得周郎顧，時時誤拂弦。"],"source":"《唐诗三百首》"},{"title":"賊平後送人北歸","author":"司空曙","dynasty":"唐","form":"诗","lines":["世亂同南去，時清獨北還。","他鄉生白髮，舊國見青山。","曉月過殘壘，繁星宿故關。","寒禽與衰草，處處伴愁顏。"],"source":"《唐诗三百首》"},{"title":"雲陽館與韓紳宿別","author":"司空曙","dynasty":"唐","form":"诗","lines":["故人江海別，幾度隔山川。","乍見翻疑夢，相悲各問年。","孤燈寒照雨，溼竹暗浮煙。","更有明朝恨，離杯惜共傳。"],"source":"《唐诗三百首》"},{"title":"喜外弟盧綸見宿","author":"司空曙","dynasty":"唐","form":"诗","lines":["靜夜四無鄰，荒居舊業貧。","雨中黃葉樹，燈下白頭人。","以我獨沈久，愧君相見頻。","平生自有分，況是蔡家親。"],"source":"《唐诗三百首》"},{"title":"聽彈琴","author":"劉長卿","dynasty":"唐","form":"诗","lines":["泠泠七絲上，靜聽松風寒。","古調雖自愛，今人多不彈。"],"source":"《唐诗三百首》"},{"title":"送方外上人","author":"劉長卿","dynasty":"唐","form":"诗","lines":["孤雲將野鶴，豈向人間住。","莫買沃洲山，時人已知處。"],"source":"《唐诗三百首》"},{"title":"送靈澈上人","author":"劉長卿","dynasty":"唐","form":"诗","lines":["蒼蒼竹林寺，杳杳鐘聲晚。","荷笠帶夕陽，青山獨歸遠。"],"source":"《唐诗三百首》"},{"title":"新年作","author":"劉長卿","dynasty":"唐","form":"诗","lines":["鄉心新歲切，天畔獨潸然。","老至居人下，春歸在客先。","嶺猨同旦暮，江柳共風煙。","已是長沙傅，從今又幾年。"],"source":"《唐诗三百首》"},{"title":"秋日登吳公臺上寺遠眺寺即陳將吳明徹戰場","author":"劉長卿","dynasty":"唐","form":"诗","lines":["古臺搖落後，秋日望鄉心。","野寺人來少，雲峰水隔深。","夕陽依舊壘，寒磬滿空林。","惆悵南朝事，長江獨至今。"],"source":"《唐诗三百首》"},{"title":"尋南溪常山道人隱居","author":"劉長卿","dynasty":"唐","form":"诗","lines":["一路經行處，莓苔見履痕。","白雲依靜渚，春草閉閑門。","過雨看松色，隨山到水源。","溪花與禪意，相對亦忘言。"],"source":"《唐诗三百首》"},{"title":"餞別王十一南遊","author":"劉長卿","dynasty":"唐","form":"诗","lines":["望君煙水闊，揮手淚霑巾。","飛鳥沒何處，青山空向人。","長江一帆遠，落日五湖春。","誰見汀洲上，相思愁白蘋。"],"source":"《唐诗三百首》"},{"title":"江州重別薛六柳八二員外","author":"劉長卿","dynasty":"唐","form":"诗","lines":["生涯豈料承優詔，世事空知學醉歌。","江上月明胡鴈過，淮南木落楚山多。","寄身且喜滄洲近，顧影無如白髮何。","今日龍鍾人共棄，媿君猶遣慎風波。"],"source":"《唐诗三百首》"},{"title":"長沙過賈誼宅","author":"劉長卿","dynasty":"唐","form":"诗","lines":["三年謫宦此棲遲，萬古惟留楚客悲。","秋草獨尋人去後，寒林空見日斜時。","漢文有道恩猶薄，湘水無情弔豈知。","寂寂江山搖落處，憐君何事到天涯。"],"source":"《唐诗三百首》"},{"title":"自夏口至鸚鵡洲夕望岳陽寄源中丞","author":"劉長卿","dynasty":"唐","form":"诗","lines":["[汀]洲無浪復無煙，楚客相思益渺然。","漢口夕陽斜渡鳥，洞庭秋水遠連天。","孤城背嶺寒吹角，獨戍臨江夜泊船。","賈誼上書憂漢室，長沙謫去古今憐。"],"source":"《唐诗三百首》"},{"title":"賦得","author":"劉長卿","dynasty":"唐","form":"诗","lines":["鶯啼燕語報新年，馬邑龍堆路幾千。","家住層城臨漢苑，[心]隨明月到胡天。","機中錦字論長恨，樓上花枝笑獨眠。","爲問元戎竇車騎，何時返斾勒燕然。"],"source":"《唐诗三百首》"},{"title":"九日登望仙臺呈劉明府容","author":"崔曙","dynasty":"唐","form":"诗","lines":["漢文皇帝有高臺，此日登臨曙色開。","三晉雲山皆北向，二陵風雨自東來。","關門令尹誰能識，河上仙翁去不回。","且欲近尋彭澤宰，陶然共醉菊花杯。"],"source":"《唐诗三百首》"},{"title":"涼州詞二首 一","author":"王翰","dynasty":"唐","form":"诗","lines":["葡萄美酒夜光杯，欲飲琵琶馬上催。","醉臥沙場君莫笑，古來征戰幾人回。"],"source":"《唐诗三百首》"},{"title":"秋登蘭山寄張五","author":"孟浩然","dynasty":"唐","form":"诗","lines":["北山白雲裏，隱者自怡悅。","相望試登高，心飛逐鳥滅。","愁因薄暮起，興是清秋發。","時見歸村人，沙行渡頭歇。","天邊樹若薺，江畔舟如月。","何當載酒來，共醉重陽節。"],"source":"《唐诗三百首》"},{"title":"夏日南亭懷辛大","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山光忽西落，池月漸東上。","散髮乘夕涼，開軒臥閑敞。","荷風送香氣，竹露滴清響。","欲取鳴琴彈，恨無知音賞。","感此懷故人，中宵勞夢想。"],"source":"《唐诗三百首》"},{"title":"宿業師山房期丁大不至","author":"孟浩然","dynasty":"唐","form":"诗","lines":["夕陽度西嶺，羣壑倏已暝。","松月生夜涼，風泉滿清聽。","樵人歸欲盡，煙鳥棲初定。","之子期宿來，孤琴候蘿逕。"],"source":"《唐诗三百首》"},{"title":"夜歸鹿門山歌","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山寺鐘鳴晝已昏，漁梁渡頭爭渡喧。","人隨沙路向江村，余亦乘舟歸鹿門。","鹿門月照開煙樹，忽到龐公棲隱處。","巖扉松徑長寂寥，惟有幽人夜來去。"],"source":"《唐诗三百首》"},{"title":"望洞庭湖贈張丞相","author":"孟浩然","dynasty":"唐","form":"诗","lines":["八月湖水平，涵虛混太清。","氣蒸雲夢澤，波撼岳陽城。","欲濟無舟楫，端居恥聖明。","坐觀垂釣者，空有羨魚情。"],"source":"《唐诗三百首》"},{"title":"秦中感秋寄遠上人","author":"孟浩然","dynasty":"唐","form":"诗","lines":["一丘常欲臥，三徑苦無資。","北土非吾願，東林懷我師。","黃金然桂盡，壯志逐年衰。","日夕涼風至，聞蟬但益悲。"],"source":"《唐诗三百首》"},{"title":"宿桐廬江寄廣陵舊遊","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山暝聞猿愁，滄江急夜流。","風鳴兩岸葉，月照一孤舟。","建德非吾土，維揚憶舊遊。","還將兩行淚，遙寄海西頭。"],"source":"《唐诗三百首》"},{"title":"早寒江上有懷","author":"孟浩然","dynasty":"唐","form":"诗","lines":["木落雁南度，北風江上寒。","我家襄水上，遙隔楚雲端。","鄉淚客中盡，孤帆天際看。","迷津欲有問，平海夕漫漫。"],"source":"《唐诗三百首》"},{"title":"留別王侍御維","author":"孟浩然","dynasty":"唐","form":"诗","lines":["寂寂竟何待，朝朝空自歸。","欲尋芳草去，惜與故人違。","當路誰相假，知音世所稀。","秪應守索寞，還掩故園扉。"],"source":"《唐诗三百首》"},{"title":"清明日宴梅道士房","author":"孟浩然","dynasty":"唐","form":"诗","lines":["林臥愁春盡，開軒覽物華。","忽逢青鳥使，邀入赤松家。","丹竈初開火，仙桃正落花。","童顏若可駐，何惜醉流霞。"],"source":"《唐诗三百首》"},{"title":"與諸子登峴山","author":"孟浩然","dynasty":"唐","form":"诗","lines":["人事有代謝，往來成古今。","江山留勝跡，我輩復登臨。","水落魚梁淺，天寒夢澤深。","羊公碑字在，讀罷淚沾襟。"],"source":"《唐诗三百首》"},{"title":"過故人莊","author":"孟浩然","dynasty":"唐","form":"诗","lines":["故人具雞黍，邀我至田家。","綠樹村邊合，青山郭外斜。","開筵面場圃，把酒話桑麻。","待到重陽日，還來就菊花。"],"source":"《唐诗三百首》"},{"title":"歲暮歸南山","author":"孟浩然","dynasty":"唐","form":"诗","lines":["北闕休上書，南山歸敝廬。","不才明主棄，多病故人疎。","白髮催年老，青陽逼歲除。","永懷愁不寐，松月夜窗虛。"],"source":"《唐诗三百首》"},{"title":"歲除夜有懷","author":"孟浩然","dynasty":"唐","form":"诗","lines":["迢遞三巴路，羈危萬里身。","亂山殘雪夜，孤燈異鄉人。","漸與骨肉遠，轉於奴僕親。","那堪正飄泊，來日歲華新。"],"source":"《唐诗三百首》"},{"title":"春曉","author":"孟浩然","dynasty":"唐","form":"诗","lines":["春眠不覺曉，處處聞啼鳥。","夜來風雨聲，花落知多少。"],"source":"《唐诗三百首》"},{"title":"宿建德江","author":"孟浩然","dynasty":"唐","form":"诗","lines":["移舟泊煙渚，日暮客愁新。","野曠天低樹，江清月近人。"],"source":"《唐诗三百首》"},{"title":"蜀道難","author":"李白","dynasty":"唐","form":"诗","lines":["噫吁戲！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。","爾來四萬八千歲，不與秦塞通人煙。","西當太白有鳥道，可以橫絕峨眉巔。","地崩山摧壯士死，然後天梯石棧相鉤連。","上有六龍回日之高標，下有衝波逆折之回川。","黃鶴之飛尚不得過，猨猱欲度愁攀援。","青泥何盤盤，百步九折縈巖巒。","捫參歷井仰脅息，以手撫膺坐長歎。","問君西遊何時還？畏途巉巖不可攀。","但見悲鳥號古木，雄飛雌從繞林間。","又聞子規啼夜月，愁空山，蜀道之難難於上青天，使人聽此凋朱顏。","連峯去天不盈尺，枯松倒挂倚絕壁。","飛湍瀑流爭喧豗，砅厓轉石萬壑雷。","其險也如此，嗟爾遠道之人胡爲乎來哉！劒閣崢嶸而崔嵬，一夫當關，萬夫莫開。","所守或匪親，化爲狼與豺。","朝避猛虎，夕避長蛇。","磨牙吮血，殺人如麻。","錦城雖云樂，不如早還家。","蜀道之難難於上青天，側身西望長咨嗟。"],"source":"《唐诗三百首》"},{"title":"將進酒","author":"李白","dynasty":"唐","form":"诗","lines":["君不見黃河之水天上來，奔流到海不復迴。","君不見高堂明鏡悲白髮，朝如青絲暮成雪。","人生得意須盡歡，莫使金樽空對月。","天生我材必有用，千金散盡還復來。","烹羊宰牛且爲樂，會須一飲三百盃。","岑夫子，丹丘生，將進酒，君莫停。","與君歌一曲，請君爲我側耳聽。","鐘鼓饌玉不足貴，但願長醉不願醒。","古來聖賢皆寂寞，惟有飲者留其名。","陳王昔時宴平樂，斗酒十千恣讙謔。","主人何爲言少錢，徑須沽取對君酌。","五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"],"source":"《唐诗三百首》"},{"title":"客夜與故人偶集","author":"戴叔倫","dynasty":"唐","form":"诗","lines":["天秋月又滿，城闕夜千重。","還作江南會，翻疑夢裏逢。","風枝驚暗鵲，露草覆寒蛩。","羈旅長堪醉，相留畏曉鐘。"],"source":"《唐诗三百首》"},{"title":"和張僕射塞下曲 一","author":"盧綸","dynasty":"唐","form":"诗","lines":["鷲翎金僕姑，燕尾繡蝥弧。","獨立揚新令，千營共一呼。"],"source":"《唐诗三百首》"},{"title":"和張僕射塞下曲 二","author":"盧綸","dynasty":"唐","form":"诗","lines":["林暗草驚風，將軍夜引弓。","平明尋白羽，沒在石稜中。"],"source":"《唐诗三百首》"},{"title":"和張僕射塞下曲 三","author":"盧綸","dynasty":"唐","form":"诗","lines":["月黑鴈飛高，單于夜遁逃。","欲將輕騎逐，大雪滿弓刀。"],"source":"《唐诗三百首》"},{"title":"和張僕射塞下曲 四","author":"盧綸","dynasty":"唐","form":"诗","lines":["野幕敞瓊筵，羌戎賀勞旋。","醉和金甲舞，雷鼓動山川。"],"source":"《唐诗三百首》"},{"title":"晚次鄂州","author":"盧綸","dynasty":"唐","form":"诗","lines":["雲開遠見漢陽城，猶是孤帆一日程。","估客晝眠知浪靜，舟人夜語覺潮生。","三湘衰鬢逢秋色，萬里歸心對月明。","舊業已隨征戰盡，更堪江上鼓鼙聲。"],"source":"《唐诗三百首》"},{"title":"李端公","author":"盧綸","dynasty":"唐","form":"诗","lines":["故關衰草遍，離別自堪悲。","路出寒雲外，人歸暮雪時。","少孤爲客早，多難識君遲。","掩淚空相向，風塵何處期。"],"source":"《唐诗三百首》"},{"title":"過香積寺","author":"王維","dynasty":"唐","form":"诗","lines":["不知香積寺，數里入雲峰。","古木無人逕，深山何處鐘。","泉聲咽危石，日色冷青松。","薄暮空潭曲，安禪制毒龍。"],"source":"《唐诗三百首》"},{"title":"山居秋暝","author":"王維","dynasty":"唐","form":"诗","lines":["空山新雨後，天氣晚來秋。","明月松間照，清泉石上流。","竹喧歸浣女，蓮動下漁舟。","隨意春芳歇，王孫自可留。"],"source":"《唐诗三百首》"},{"title":"終南別業","author":"王維","dynasty":"唐","form":"诗","lines":["中歲頗好道，晚家南山陲。","興來每獨往，勝事空自知。","行到水窮處，坐看雲起時。","偶然值林叟，談笑無還期。"],"source":"《唐诗三百首》"},{"title":"歸嵩山作","author":"王維","dynasty":"唐","form":"诗","lines":["清川帶長薄，車馬去閑閑。","流水如有意，暮禽相與還。","荒城臨古渡，落日滿秋山。","迢遞嵩高下，歸來且閉關。"],"source":"《唐诗三百首》"},{"title":"終南山","author":"王維","dynasty":"唐","form":"诗","lines":["太乙近天都，連山接海隅。","白雲迴望合，青靄入看無。","分野中峰變，陰晴衆壑殊。","欲投人處宿，隔水問樵夫。"],"source":"《唐诗三百首》"},{"title":"漢江臨汎","author":"王維","dynasty":"唐","form":"诗","lines":["楚塞三湘接，荆門九派通。","江流天地外，山色有無中。","郡邑浮前浦，波瀾動遠空。","襄陽好風日，留醉與山翁。"],"source":"《唐诗三百首》"},{"title":"奉和聖製從蓬萊向興慶閣道中留春雨中春望之作應制","author":"王維","dynasty":"唐","form":"诗","lines":["渭水自縈秦塞曲，黃山舊遶漢宮斜。","鑾輿迥出千門柳，閣道廻看上苑花。","雲裏帝城雙鳳闕，雨中春樹萬人家。","爲乘陽氣行時令，不是宸遊玩物華。"],"source":"《唐诗三百首》"},{"title":"和賈舍人早朝大明宮之作","author":"王維","dynasty":"唐","form":"诗","lines":["絳幘雞人送曉籌，尚衣方進翠雲裘。","九天閶闔開宮殿，萬國衣冠拜冕旒。","日色纔臨仙掌動，香煙欲傍衮龍浮。","朝罷須裁五色詔，佩聲歸向鳳池頭。"],"source":"《唐诗三百首》"},{"title":"酬郭給事","author":"王維","dynasty":"唐","form":"诗","lines":["洞門高閣靄餘輝，桃李陰陰柳絮飛。","禁裏疎鐘官舍晚，省中啼鳥吏人稀。","晨搖玉佩趨金殿，夕奉天書拜瑣闈。","強欲從君無那老，將因臥病解朝衣。"],"source":"《唐诗三百首》"},{"title":"積雨輞川莊作","author":"王維","dynasty":"唐","form":"诗","lines":["積雨空林煙火遲，蒸藜炊黍餉東菑。","漠漠水田飛白鷺，陰陰夏木囀黃鸝。","山中習靜觀朝槿，松下清齋折露葵。","野老與人爭席罷，海鷗何事更相疑。"],"source":"《唐诗三百首》"},{"title":"輞川集 鹿柴","author":"王維","dynasty":"唐","form":"诗","lines":["空山不見人，但聞人語響。","返景入深林，復照青苔上。"],"source":"《唐诗三百首》"},{"title":"輞川集 竹里館","author":"王維","dynasty":"唐","form":"诗","lines":["獨坐幽篁裏，彈琴復長嘯。","深林人不知，明月來相照。"],"source":"《唐诗三百首》"},{"title":"送別","author":"王維","dynasty":"唐","form":"诗","lines":["山中相送罷，日暮掩柴扉。","春草明年綠，王孫歸不歸。"],"source":"《唐诗三百首》"},{"title":"雜詩三首 二","author":"王維","dynasty":"唐","form":"诗","lines":["君自故鄉來，應知故鄉事。","來日綺窗前，寒梅着花未。"],"source":"《唐诗三百首》"},{"title":"相思","author":"王維","dynasty":"唐","form":"诗","lines":["紅豆生南國，秋來發故枝。","願君多采擷，此物最相思。"],"source":"《唐诗三百首》"},{"title":"九月九日憶山東兄弟","author":"王維","dynasty":"唐","form":"诗","lines":["獨在異鄉爲異客，每逢佳節倍思親。","遙知兄弟登高處，遍插茱萸少一人。"],"source":"《唐诗三百首》"},{"title":"渭城曲","author":"王維","dynasty":"唐","form":"诗","lines":["渭城朝雨浥輕塵，客舍青青楊柳春。","勸君更盡一杯酒，西出陽關無故人。"],"source":"《唐诗三百首》"},{"title":"崔九欲往南山馬上口號與別","author":"裴迪","dynasty":"唐","form":"诗","lines":["歸山深淺去，須盡丘壑美。","莫學武陵人，暫游桃源裏。"],"source":"《唐诗三百首》"},{"title":"尋西山隱者不遇","author":"丘爲","dynasty":"唐","form":"诗","lines":["絕頂一茅茨，直[上]三十里。","扣關無僮僕，窺室唯案几。","若非巾柴車，應是釣秋水。","差池不相見，黽勉空仰止。","草色新雨中，松聲晚牕裏。","及茲契幽絕，自足蕩心耳。","雖無賓主意，頗得清淨理。","興盡方下山，何必待之子。"],"source":"《唐诗三百首》"},{"title":"黃鶴樓","author":"崔顥","dynasty":"唐","form":"诗","lines":["昔人已乘白雲去，此地空餘黃鶴樓。","黃鶴一去不復返，白雲千載空悠悠。","晴川歷歷漢陽樹，春草萋萋鸚鵡洲。","日暮鄉關何處是，煙波江上使人愁。"],"source":"《唐诗三百首》"},{"title":"行經華陰","author":"崔顥","dynasty":"唐","form":"诗","lines":["岧嶤太華俯咸京，天外三峰削不成。","武帝祠前雲欲散，仙人掌上雨初晴。","河山北枕秦關險，驛樹西連漢畤平。","借問路傍名利客，無如此處學長生。"],"source":"《唐诗三百首》"},{"title":"長干曲四首 一","author":"崔顥","dynasty":"唐","form":"诗","lines":["君家何處住？妾住在橫塘。","停船暫借問，或恐是同鄉。"],"source":"《唐诗三百首》"},{"title":"長干曲四首 二","author":"崔顥","dynasty":"唐","form":"诗","lines":["家臨九江水，來去九江側。","同是長干人，自小不相識。"],"source":"《唐诗三百首》"},{"title":"望薊門","author":"祖詠","dynasty":"唐","form":"诗","lines":["燕臺一望客心驚，簫鼓喧喧漢將營。","萬里寒光生積雪，三邊曙色動危旌。","沙場烽火連胡月，海畔雲山擁薊城。","少小雖非投筆吏，論功還欲請長纓。"],"source":"《唐诗三百首》"},{"title":"終南望餘雪","author":"祖詠","dynasty":"唐","form":"诗","lines":["終南陰嶺秀，積雪浮雲端。","林表明霽色，城中增暮寒。"],"source":"《唐诗三百首》"},{"title":"古從軍行","author":"李頎","dynasty":"唐","form":"诗","lines":["白日登山望烽火，黃昏飲馬傍交河。","行人刁斗風沙暗，公主琵琶幽怨多。","野雲萬里無城郭，雨雪紛紛連大漠。","胡鴈哀鳴夜夜飛，胡兒眼淚雙雙落。","聞道玉門猶被遮，應將性命逐輕車。","年年戰骨埋荒外，空見蒲桃入漢家。"],"source":"《唐诗三百首》"},{"title":"琴歌","author":"李頎","dynasty":"唐","form":"诗","lines":["主人有酒歡今夕，請奏鳴琴廣陵客。","月照城頭烏半飛，霜淒萬樹風入衣。","銅鑪華燭燭增輝，初彈淥水後楚妃。","一聲已動物皆靜，四座無言星欲稀。","清淮奉使千餘里，敢告雲山從此始。"],"source":"《唐诗三百首》"},{"title":"送陳章甫","author":"李頎","dynasty":"唐","form":"诗","lines":["四月南風大麥黃，棗花未落桐陰長。","青山朝別暮還見，嘶馬出門思舊鄉。","陳侯立身何坦蕩，虬鬚虎眉仍大顙。","腹中貯書一萬卷，不肯低頭在草莽。","東門酤酒飲我曹，心輕萬事皆鴻毛。","醉臥不知白日暮，有時空望孤雲高。","長河浪頭連天黑，津口停舟渡不得。","鄭國遊人未及家，洛陽行子空歎息。","聞道故林相識多，罷官昨日今如何。"],"source":"《唐诗三百首》"},{"title":"聽安萬善吹觱篥歌","author":"李頎","dynasty":"唐","form":"诗","lines":["南山截竹爲觱篥，此樂本自龜茲出。","流傳漢地曲轉奇，涼州胡人爲我吹。","傍鄰聞者多歎息，遠客思鄉皆淚垂。","世人解聽不解賞，長飆風中自來往。","枯桑老柏寒颼飀，九雛鳴鳳亂啾啾。","龍吟虎嘯一時發，萬籟百泉相與秋。","忽然更作漁陽摻，黃雲蕭條白日暗。","變調如聞楊柳春，上林繁花照眼新。","歲夜高堂列明燭，美酒一杯聲一曲。"],"source":"《唐诗三百首》"},{"title":"古意","author":"李頎","dynasty":"唐","form":"诗","lines":["男兒事長征，少小幽燕客。","賭勝馬蹄下，由來輕七尺。","殺人莫敢前，鬚如蝟毛磔。","黃雲隴底白雪飛，未得報恩不能歸。","遼東小婦年十五，慣彈琵琶解歌舞。","今爲羗笛出塞聲，使我三軍淚如雨。"],"source":"《唐诗三百首》"},{"title":"聽董大彈胡笳聲兼寄語弄房給事","author":"李頎","dynasty":"唐","form":"诗","lines":["蔡女昔造胡笳聲，一彈一十有八拍。","胡人落淚沾邊草，漢使斷腸對歸客。","古戍蒼蒼烽火寒，大荒沈沈飛雪白。","先拂商弦後角羽，四郊秋葉驚摵摵。","董夫子，通神明，深山竊聽來妖精。","言遲更速皆應手，將往復旋如有情。","空山百鳥散還合，萬里浮雲陰且晴。","嘶酸雛鴈失羣夜，斷絕胡兒戀母聲。","川爲淨其波，鳥亦罷其鳴。","烏孫部落家鄉遠，邏娑沙塵哀怨生。","幽音變調忽飄灑，長風吹林雨墮瓦。","迸泉颯颯飛木末，野鹿呦呦走堂下。","長安城連東掖垣，鳳凰池對青瑣門。","高才脫略名與利，日夕望君抱琴至。"],"source":"《唐诗三百首》"},{"title":"送魏萬之京","author":"李頎","dynasty":"唐","form":"诗","lines":["朝聞遊子唱離歌，昨夜微霜初渡河。","鴻鴈不堪愁裏聽，雲山況是客中過。","關城樹色催寒近，御苑砧聲向晚多。","莫見長安行樂處，空令歲月易蹉跎。"],"source":"《唐诗三百首》"},{"title":"春泛若耶溪","author":"綦毋潛","dynasty":"唐","form":"诗","lines":["幽意無斷絕，此去隨所偶。","晚風吹行舟，花路入溪口。","際夜轉西壑，隔山望南斗。","潭煙飛溶溶，林月低向後。","生事且彌漫，願爲持竿叟。"],"source":"《唐诗三百首》"},{"title":"塞下曲四首 一","author":"王昌齡","dynasty":"唐","form":"诗","lines":["蟬鳴空桑林，八月蕭關道。","出塞入塞寒，處處黃蘆草。","從來幽幷客，皆共塵沙老。","莫學遊俠兒，矜夸紫騮好。"],"source":"《唐诗三百首》"},{"title":"塞下曲四首 二","author":"王昌齡","dynasty":"唐","form":"诗","lines":["飲馬渡秋水，水寒風似刀。","平沙日未沒，黯黯見臨洮。","昔日長城戰，咸言意氣高。","黃塵足今古，白骨亂蓬蒿。"],"source":"《唐诗三百首》"},{"title":"同從弟銷南齋玩月憶山陰崔少府","author":"王昌齡","dynasty":"唐","form":"诗","lines":["高臥南齋時，開帷月初吐。","清輝淡水木，演漾在窗戶。","苒苒幾盈虛，澄澄變今古。","美人清江畔，是夜越吟苦。","千里其如何，微風吹蘭杜。"],"source":"《唐诗三百首》"},{"title":"出塞二首 一","author":"王昌齡","dynasty":"唐","form":"诗","lines":["秦時明月漢時關，萬里長征人未還。","但使龍城飛將在，不教胡馬度陰山。"],"source":"《唐诗三百首》"},{"title":"春宮曲","author":"王昌齡","dynasty":"唐","form":"诗","lines":["昨夜風開露井桃，未央前殿月輪高。","平陽歌舞新承寵，簾外春寒賜錦袍。"],"source":"《唐诗三百首》"},{"title":"閨怨","author":"王昌齡","dynasty":"唐","form":"诗","lines":["閨中少婦不曾愁，春日凝妝上翠樓。","忽見陌頭楊柳色，悔教夫壻覓封侯。"],"source":"《唐诗三百首》"},{"title":"芙蓉樓送辛漸二首 一","author":"王昌齡","dynasty":"唐","form":"诗","lines":["寒雨連天夜入湖，平明送客楚山孤。","洛陽親友如相問，一片冰心在玉壺。"],"source":"《唐诗三百首》"},{"title":"宿王昌齡隱居","author":"常建","dynasty":"唐","form":"诗","lines":["清溪深不測，隱處唯孤雲。","松際露微月，清光猶爲君。","茅亭宿花影，藥院滋苔紋。","余亦謝時去，西山鸞鶴羣。"],"source":"《唐诗三百首》"},{"title":"清平調 一","author":"李白","dynasty":"唐","form":"诗","lines":["雲想衣裳花想容，春風拂檻露華濃。","若非羣玉山頭見，會向瑤臺月下逢。"],"source":"《唐诗三百首》"},{"title":"清平調 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝紅豔露凝香，雲雨巫山枉斷腸。","借問漢宮誰得似，可憐飛燕倚新妝。"],"source":"《唐诗三百首》"},{"title":"清平調 三","author":"李白","dynasty":"唐","form":"诗","lines":["名花傾國兩相歡，常得君王帶笑看。","解得春風無限恨，沈香亭北倚闌干。"],"source":"《唐诗三百首》"},{"title":"還鄉偶書  其二","author":"黄拱","dynasty":"唐","form":"诗","lines":["少小離家老大回，鄉音難改鬢毛衰。","兒童相見不相識，借問客從何處來。"],"source":"《唐诗三百首》"},{"title":"長恨歌","author":"白居易","dynasty":"唐","form":"诗","lines":["漢皇重色思傾國，御宇多年求不得。","楊家有女初長成，養在深閨人未識。","天生麗質難自棄，一朝選在君王側。","回眸一笑百媚生，六宮粉黛無顏色。","春寒賜浴華清池，溫泉水滑洗凝脂。","侍兒扶起嬌無力，始是新承恩澤時。","雲鬢花顏金步搖，芙蓉帳暖度春宵。","春宵苦短日高起，從此君王不早朝。","承歡侍宴無閑暇，春從春遊夜專夜。","後宮佳麗三千人，三千寵愛在一身。","金屋妝成嬌侍夜，玉樓宴罷醉和春。","姊妹弟兄皆列土，可憐光彩生門戶。","遂令天下父母心，不重生男重生女。","驪宮高處入青雲，仙樂風飄處處聞。","緩歌慢舞凝絲竹，盡日君王看不足。","漁陽鞞鼓動地來，驚破霓裳羽衣曲。","九重城闕煙塵生，千乘萬騎西南行。","翠華搖搖行復止，西出都門百餘里。","六軍不發無奈何，宛轉蛾眉馬前死。","花鈿委地無人收，翠翹金雀玉搔頭。","君王掩面救不得，回看血淚相和流。","黃埃散漫風蕭索，雲棧縈紆登劒閣。","峨嵋山下少人行，旌旗無光日色薄。","蜀江水碧蜀山青，聖主朝朝暮暮情。","行宮見月傷心色，夜雨聞鈴腸斷聲。","天旋日轉迴龍馭，到此躊躇不能去。","馬嵬坡下泥土中，不見玉顏空死處。","君臣相顧盡霑衣，東望都門信馬歸。","歸來池苑皆依舊，太液芙蓉未央柳。","芙蓉如面柳如眉，對此如何不淚垂？","春風桃李花開夜，秋雨梧桐葉落時。","西宮南苑多秋草，宮葉滿階紅不埽。","棃園弟子白髮新，椒房阿監青娥老。","夕殿螢飛思悄然，孤燈挑盡未成眠。","遲遲鐘鼓初長夜，耿耿星河欲曙天。","鴛鴦瓦冷霜華重，翡翠衾寒誰與共。","悠悠生死別經年，魂魄不曾來入夢。","臨邛道士鴻都客，能以精誠致魂魄。","爲感君王展轉思，遂教方士殷勤覓。","排空馭氣奔如電，升天入地求之徧。","上窮碧落下黃泉，兩處茫茫皆不見。","忽聞海上有仙山，山在虛無縹緲間。","樓閣玲瓏五雲起，其中綽約多仙子。","中有一人字太真，雪膚花貌參差是。","金闕西廂叩玉扃，轉教小玉報雙成。","聞道漢家天子使，九華帳裏夢魂驚。","攬衣推枕起裴回，珠箔銀屏邐迤開。","雲鬢半偏新睡覺，花冠不整下堂來。","風吹仙袂飄颻舉，猶似霓裳羽衣舞。","玉容寂莫淚闌干，棃花一枝春帶雨。","含情凝睇謝君王，一別音容兩渺茫。","昭陽殿裏恩愛絕，蓬萊宮中日月長。","回頭下望人寰處，不見長安見塵霧。","唯將舊物表深情，鈿合金釵寄將去。","釵留一股合一扇，釵擘黃金合分鈿。","但教心似金鈿堅，天上人間會相見。","臨別殷勤重寄詞，詞中有誓兩心知。","七月七日長生殿，夜半無人私語時。","在天願作比翼鳥，在地願爲連理枝。","天長地久有時盡，此恨緜緜無絕期。"],"source":"《唐诗三百首》"},{"title":"琵琶引","author":"白居易","dynasty":"唐","form":"诗","lines":["潯陽江頭夜送客，楓葉荻花秋索索。","主人下馬客在船，舉酒欲飲無管弦。","醉不成歡慘將別，別時茫茫江浸月。","忽聞水上琵琶聲，主人忘歸客不發。","尋聲暗問彈者誰，琵琶聲停欲語遲。","移船相近邀相見，添酒迴燈重開宴。","千呼萬喚始出來，猶抱琵琶半遮面。","轉軸撥弦三兩聲，未成曲調先有情。","弦弦掩抑聲聲思，似訴平生不得意。","低眉信手續續彈，說盡心中無限事。","輕攏慢撚抹復挑，初爲霓裳後六幺。","大弦嘈嘈如急雨，小弦切切如私語。","嘈嘈切切錯雜彈，大珠小珠落玉盤。","間關鶯語花底滑，幽咽泉流水下灘。","水泉冷澀弦疑絕，疑絕不通聲暫歇。","別有幽愁暗恨生，此時無聲勝有聲。","銀缾乍破水漿迸，鐵騎突出刀槍鳴。","曲終收撥當心畫，四弦一聲如裂帛。","東舟西舫悄無言，唯見江心秋月白。","沈吟放撥插弦中，整頓衣裳起斂容。","自言本是京城女，家在蝦蟇陵下住。","十三學得琵琶成，名蜀教坊第一部。","曲罷曾教善才伏，妝成每被秋娘妬。","五陵年少爭纏頭，一曲紅綃不知數。","鈿頭雲箆擊節碎，血色羅帬飜酒汙。","今年歡笑復明年，秋月春風等閑度。","弟走從軍阿姨死，暮去朝來顏色故。","門前冷落鞍馬稀，老大嫁作商人婦。","商人重利輕別離，前月浮梁買茶去。","去來江口守空船，繞船月明江水寒。","夜深忽夢少年事，夢啼妝淚紅闌干。","我聞琵琶已歎息，又聞此語重唧唧。","同是天涯淪落人，相逢何必曾相識。","我從去年辭帝京，謫居臥病潯陽城。","潯陽小處無音樂，終歲不聞絲竹聲。","住近湓江地低濕，黃蘆苦竹繞宅生。","其間旦暮聞何物，杜鵑啼血猨哀鳴。","春江花朝秋月夜，往往取酒還獨傾。","豈無山歌與村笛，嘔啞嘲哳難爲聽。","今夜聞君琵琶語，如聽仙樂耳暫明。","莫辭更坐彈一曲，爲君飜作琵琶行。","感我此言良久立，却坐促弦弦轉急。","淒淒不似向前聲，滿座重聞皆掩泣。","座中泣下誰最多，江州司馬青衫濕。"],"source":"《唐诗三百首》"},{"title":"賦得古原草送別","author":"白居易","dynasty":"唐","form":"诗","lines":["離離原上草，一歲一枯榮。","野火燒不盡，春風吹又生。","遠芳侵古道，晴翠接荒城。","又送王孫去，萋萋滿別情。"],"source":"《唐诗三百首》"},{"title":"自河南經亂關內阻饑兄弟離散各在一處因望月有感聊書所懷寄上浮梁大兄於潛七兄烏江十五兄兼示符離及下邽弟妹","author":"白居易","dynasty":"唐","form":"诗","lines":["時難年饑世業空，弟兄羇旅各西東。","田園寥落干戈後，骨肉流離道路中。","弔影分爲千里鴈，辭根散作九秋蓬。","共看明月應垂淚，一夜鄉心五處同。"],"source":"《唐诗三百首》"},{"title":"問劉十九","author":"白居易","dynasty":"唐","form":"诗","lines":["綠螘新醅酒，紅泥小火壚。","晚來天欲雪，能飲一杯無。"],"source":"《唐诗三百首》"},{"title":"尋隱者不遇","author":"賈島","dynasty":"唐","form":"诗","lines":["松下問童子，言師採藥去。","只在此山中，雲深不知處。"],"source":"《唐诗三百首》"},{"title":"利州南渡","author":"溫庭筠","dynasty":"唐","form":"诗","lines":["澹然空水對斜暉，曲島蒼茫接翠微。","波上馬嘶看櫂去，柳邊人歇待船歸。","數叢沙草羣鷗散，萬頃江田一鷺飛。","誰解乘舟尋范蠡，五湖煙水獨忘機。"],"source":"《唐诗三百首》"},{"title":"瑤瑟怨","author":"溫庭筠","dynasty":"唐","form":"诗","lines":["冰簟銀牀夢不成，碧天如水夜雲輕。","雁聲遠過瀟湘去，十二樓中月自明。"],"source":"《唐诗三百首》"},{"title":"送人東遊","author":"溫庭筠","dynasty":"唐","form":"诗","lines":["荒戍落黃葉，浩然離故關。","高風漢陽渡，初日郢門山。","江上幾人在，天涯孤櫂還。","何當重相見，尊酒慰離顏。"],"source":"《唐诗三百首》"},{"title":"蘇武廟","author":"溫庭筠","dynasty":"唐","form":"诗","lines":["蘇武魂銷漢使前，古祠高樹兩茫然。","雲邊雁斷胡天月，隴上羊歸塞草煙。","廻日樓臺非甲帳，去時冠劒是丁年。","茂陵不見封侯印，空向秋波哭逝川。"],"source":"《唐诗三百首》"},{"title":"渡漢江","author":"李頻","dynasty":"唐","form":"诗","lines":["嶺外音書絕，經年復歷春。","近鄉情更怯，不敢問來人。"],"source":"《唐诗三百首》"},{"title":"貧女","author":"秦韜玉","dynasty":"唐","form":"诗","lines":["蓬門未識綺羅香，擬託良媒益自傷。","誰愛風流高格調，共憐時世儉梳妝。","敢將十指誇偏巧，不把雙眉鬬畫長。","苦恨年年壓金線，爲他人作嫁衣裳。"],"source":"《唐诗三百首》"},{"title":"春宮怨","author":"周朴","dynasty":"唐","form":"诗","lines":["早被嬋娟誤，欲妝臨鏡慵。","承恩不在貌，教妾若爲容。","風暖鳥聲碎，日高花影重。","年年越溪女，相憶采芙蓉。"],"source":"《唐诗三百首》"},{"title":"孤鴈 二","author":"崔塗","dynasty":"唐","form":"诗","lines":["幾行歸去盡，片影獨何之。","暮雨相呼失，寒塘獨下遲。","渚雲低暗度，關月冷遙隨。","未必逢矰繳，孤飛自可疑。"],"source":"《唐诗三百首》"},{"title":"巴山道中除夜書懷","author":"崔塗","dynasty":"唐","form":"诗","lines":["迢遰三巴路，羇危萬里身。","亂山殘雪夜，孤燭異鄉春。","漸與骨肉遠，轉於僮僕親。","那堪正漂泊，明日歲華新。"],"source":"《唐诗三百首》"},{"title":"宮詞二首 一","author":"張祜","dynasty":"唐","form":"诗","lines":["故國三千里，深宮二十年。","一聲河滿子，雙淚落君前。"],"source":"《唐诗三百首》"},{"title":"贈內人","author":"張祜","dynasty":"唐","form":"诗","lines":["禁門宮樹月痕過，媚眼唯看宿燕窠。","斜拔玉釵燈影畔，剔開紅焰救飛蛾。"],"source":"《唐诗三百首》"},{"title":"集靈臺二首 一","author":"張祜","dynasty":"唐","form":"诗","lines":["日光斜照集靈臺，紅樹花迎曉露開。","昨夜上皇新授籙，太真含笑入簾來。"],"source":"《唐诗三百首》"},{"title":"集靈臺二首 二","author":"張祜","dynasty":"唐","form":"诗","lines":["虢國夫人承主恩，平明騎馬入宮門。","却嫌脂粉汚顏色，淡掃蛾眉朝至尊。"],"source":"《唐诗三百首》"},{"title":"題金陵渡","author":"張祜","dynasty":"唐","form":"诗","lines":["金陵津渡小山樓，一宿行人自可愁。","潮落夜江斜月裏，兩三星火是瓜州。"],"source":"《唐诗三百首》"},{"title":"宮詞","author":"朱慶餘","dynasty":"唐","form":"诗","lines":["寂寂花時閉院門，美人相並立瓊軒。","含情欲說宮中事，鸚鵡前頭不敢言。"],"source":"《唐诗三百首》"},{"title":"石鼓歌","author":"韓愈","dynasty":"唐","form":"诗","lines":["張生手持石鼓文，勸我試作石鼓歌。","少陵無人謫仙死，才薄將奈石鼓何。","周綱陵遲四海沸，宣王憤起揮天戈。","大開明堂受朝賀，諸侯劒佩鳴相磨。","蒐于岐陽騁雄俊，萬里禽獸皆遮羅。","鐫功勒成告萬世，鑿石作鼓隳嵯峨。","從臣才藝咸第一，揀選撰刻留山阿。","雨淋日炙野火燎，鬼物守護煩撝呵。","公從何處得紙本，毫髮盡備無差訛。","辭嚴義密讀難曉，字體不類隸與科。","年深豈免有缺畫，快劒斫斷生蛟鼉。","鸞翔鳳翥衆僊下，珊瑚碧樹交枝柯。","金繩鐵索鎖紐壯，古鼎躍水龍騰梭。","陋儒編詩不收入，二雅褊迫無委蛇。","孔子西行不到秦，掎摭星宿遺羲娥。","嗟予好古生苦晚，對此涕淚雙滂沱。","憶昔初蒙博士徴，其年始改稱元和。","故人從軍在右輔，爲我度量掘臼科。","濯冠沐浴告祭酒，如此至寶存豈多。","氊包席裹可立致，十鼓祗載數駱駝。","薦諸太廟比郜鼎，光價豈止百倍過。","聖恩若許留太學，諸生講解得切磋。","觀經鴻都尚填咽，坐見舉國來奔波。","剜苔剔蘚露節角，安置妥帖平不頗。","大廈深簷與蓋覆，經歷久遠期無佗。","中朝大官老於事，詎肯感激徒媕婀。","牧童敲火牛礪角，誰復著手爲摩挲。","日銷月鑠就埋沒，六年西顧空吟哦。","羲之俗書趁姿媚，數紙尚可博白鵝。","繼周八代爭戰罷，無人收拾理則那。","方今太平日無事，柄任儒術崇丘軻。","安能以此上論列，願借辨口如懸河。","石鼓之歌止於此，嗚呼吾意其蹉跎。"],"source":"《唐诗三百首》"},{"title":"秋夜曲","author":"王涯","dynasty":"唐","form":"诗","lines":["桂魄初生秋露微，輕羅已薄未更衣。","銀箏夜久殷勤弄，心怯空房不忍歸。"],"source":"《唐诗三百首》"},{"title":"晨詣超師院讀禪經","author":"柳宗元","dynasty":"唐","form":"诗","lines":["汲井漱寒齒，清心拂塵服。","閒持貝葉書，步出東齋讀。","真源了無取，妄跡世所逐。","遺言冀可冥，繕性何由熟。","道人庭宇靜，苔色連深竹。","日出霧露餘，青松如膏沐。","澹然離言說，悟悅心自足。"],"source":"《唐诗三百首》"},{"title":"登柳州城樓寄漳汀封連四州","author":"柳宗元","dynasty":"唐","form":"诗","lines":["城上高樓接大荒，海天愁思正茫茫。","驚風亂颭芙蓉水，密雨斜侵薜荔牆。","嶺樹重遮千里目，江流曲似九廻腸。","共來百越文身地，猶自音書滯一鄉。"],"source":"《唐诗三百首》"},{"title":"溪居","author":"柳宗元","dynasty":"唐","form":"诗","lines":["久爲簪組累，幸此南夷謫。","閑依農圃鄰，偶似山林客。","曉耕翻露草，夜榜響溪石。","來往不逢人，長歌楚天碧。"],"source":"《唐诗三百首》"},{"title":"江雪","author":"柳宗元","dynasty":"唐","form":"诗","lines":["千山鳥飛絕，萬逕人蹤滅。","孤舟蓑笠翁，獨釣寒江雪。"],"source":"《唐诗三百首》"},{"title":"漁翁","author":"柳宗元","dynasty":"唐","form":"诗","lines":["漁翁夜傍西巖宿，曉汲清湘燃楚竹。","煙銷日出不見人，[欸]乃一聲山水綠。","迴看天際下中流，巖上無心雲相逐。"],"source":"《唐诗三百首》"},{"title":"蜀先主廟","author":"劉禹錫","dynasty":"唐","form":"诗","lines":["天地英雄氣，千秋尚凜然。","勢分三足鼎，業復五銖錢。","得相能開國，生兒不象賢。","淒涼蜀故妓，來舞魏宮前。"],"source":"《唐诗三百首》"},{"title":"月夜","author":"杜甫","dynasty":"唐","form":"诗","lines":["今夜鄜州月，閨中只獨看。","遙憐小兒女，未解憶長安。","香霧雲鬟濕，清輝玉臂寒。","何時倚虛幌，雙照淚痕乾。"],"source":"《唐诗三百首》"},{"title":"春望","author":"杜甫","dynasty":"唐","form":"诗","lines":["國破山河在，城春草木深。","感時花濺淚，恨別鳥驚心。","烽火連三月，家書抵萬金。","白頭搔更短，渾欲不勝簪。"],"source":"《唐诗三百首》"},{"title":"春宿左省","author":"杜甫","dynasty":"唐","form":"诗","lines":["花隱掖垣暮，啾啾棲鳥過。","星臨萬戶動，月傍九霄多。","不寢聽金鑰，因風想玉珂。","明朝有封事，數問夜如何。"],"source":"《唐诗三百首》"},{"title":"至德二載甫自京金光門出問道歸鳳翔乾元初從左拾遺移華州掾與親故別因出此門有悲往事","author":"杜甫","dynasty":"唐","form":"诗","lines":["此道昔歸順，西郊胡正繁。","至今殘破膽，應有未招魂。","近得歸京邑，移官豈至尊。","無才日衰老，駐馬望千門。"],"source":"《唐诗三百首》"},{"title":"月夜憶舍弟","author":"杜甫","dynasty":"唐","form":"诗","lines":["戍鼓斷人行，秋邊一雁聲。","露從今夜白，月是故鄉明。","有弟皆分散，無家問死生。","寄書長不避，況乃未休兵。"],"source":"《唐诗三百首》"},{"title":"天末憶李白","author":"杜甫","dynasty":"唐","form":"诗","lines":["涼風起天末，君子意如何。","鴻雁幾時到，江湖秋水多。","文章憎命達，魑魅喜人過。","應共冤魂語，投詩贈汩羅。"],"source":"《唐诗三百首》"},{"title":"蜀相","author":"杜甫","dynasty":"唐","form":"诗","lines":["丞相祠堂何處尋，錦官城外柏森森。","映堦碧草自春色，隔葉黃鸝空好音。","三顧頻煩天下計，兩朝開濟老臣心。","出師未捷身先死，長使英雄淚滿襟。"],"source":"《唐诗三百首》"},{"title":"客至","author":"杜甫","dynasty":"唐","form":"诗","lines":["舍南舍北皆春水，但見羣鷗日日來。","花徑不曾緣客掃，蓬門今始爲君開。","盤餐市遠無兼味，樽酒家貧只舊醅。","肯與鄰翁相對飲，隔籬呼取盡餘桮。"],"source":"《唐诗三百首》"},{"title":"野望","author":"杜甫","dynasty":"唐","form":"诗","lines":["西山白雪三奇戍，南浦清江萬里橋。","海內風塵諸弟隔，天涯涕淚一身遙。","唯將遲暮供多病，未有涓埃荅聖朝。","跨馬出郊時極目，不堪人事日蕭條。"],"source":"《唐诗三百首》"},{"title":"奉濟驛重送嚴公四韻","author":"杜甫","dynasty":"唐","form":"诗","lines":["遠送從此別，青山空復情。","幾時桮重把，昨夜月同行。","列郡謳歌惜，三朝出入榮。","江村獨歸處，寂寞養殘生。"],"source":"《唐诗三百首》"},{"title":"聞官軍收河南河北","author":"杜甫","dynasty":"唐","form":"诗","lines":["劒外忽傳收薊北，初聞涕淚滿衣裳。","却看妻子愁何在，漫卷詩書喜欲狂。","白日放歌須縱酒，青春作伴好還鄉。","即從巴峽穿巫峽，便下襄陽向洛陽。"],"source":"《唐诗三百首》"},{"title":"登高","author":"杜甫","dynasty":"唐","form":"诗","lines":["風急天高猨嘯哀，渚清沙白鳥飛迴。","無邊落木蕭蕭下，不盡長江衮衮來。","萬里悲秋常作客，百年多病獨登臺。","艱難苦恨繁霜鬢，潦倒新停濁酒桮。"],"source":"《唐诗三百首》"},{"title":"別房太尉墓","author":"杜甫","dynasty":"唐","form":"诗","lines":["他鄉復行役，駐馬別孤墳。","近淚無乾土，低空有斷雲。","對碁陪謝傅，把劒覓徐君。","唯見林花落，鸎啼送客聞。"],"source":"《唐诗三百首》"},{"title":"登樓","author":"杜甫","dynasty":"唐","form":"诗","lines":["花近高樓傷客心，萬方多難此登臨。","錦江春色來天地，玉壘浮雲變古今。","北極朝廷終不改，西山寇盜莫相侵。","可憐後主還祠廟，日暮聊爲梁甫吟。"],"source":"《唐诗三百首》"},{"title":"宿府","author":"杜甫","dynasty":"唐","form":"诗","lines":["清秋幕府井梧寒，獨宿江城蠟炬殘。","永夜角聲悲自語，中天月色好誰看。","風塵荏苒音書絕，關塞蕭條行路難。","已忍伶俜十年事，強移栖息一枝安。"],"source":"《唐诗三百首》"},{"title":"旅夜書懷","author":"杜甫","dynasty":"唐","form":"诗","lines":["細草微風岸，危檣獨夜舟。","星垂平野闊，月湧大江流。","名豈文章著，官因老病休。","飄飄何所似，天地一沙鷗。"],"source":"《唐诗三百首》"},{"title":"閣夜","author":"杜甫","dynasty":"唐","form":"诗","lines":["歲暮陰陽催短景，天涯霜雪霽寒宵。","五更鼓角聲悲壯，三峽星河影動搖。","野哭幾家聞戰伐，夷歌數處起漁樵。","臥龍躍馬終黃土，人事依依漫寂寥。"],"source":"《唐诗三百首》"},{"title":"八陣圖","author":"杜甫","dynasty":"唐","form":"诗","lines":["功蓋三分國，名高八陣圖。","江流石不轉，遺恨失吞吳。"],"source":"《唐诗三百首》"},{"title":"詠懷古跡五首 一","author":"杜甫","dynasty":"唐","form":"诗","lines":["支離東北風塵際，漂泊西南天地間。","三峽樓臺淹日月，五溪衣服共雲山。","羯胡事主終無賴，詞客衰時且未還。","庾信平生最蕭瑟，暮年詩賦動江關。"],"source":"《唐诗三百首》"},{"title":"詠懷古跡五首 二","author":"杜甫","dynasty":"唐","form":"诗","lines":["搖落深知宋玉悲，風流儒雅亦吾師。","悵望千秋一灑淚，蕭條異代不同時。","江山故宅空文藻，雲雨荒臺豈夢思。","最是楚宮俱泯滅，舟人指點到今疑。"],"source":"《唐诗三百首》"},{"title":"詠懷古跡五首 三","author":"杜甫","dynasty":"唐","form":"诗","lines":["羣山萬壑赴荆門，生長明妃尚有村。","一去紫臺連朔漠，獨留青塚向黃昏。","畫圖省識春風面，環佩空歸月夜魂。","千載琵琶作胡語，分明怨恨曲中論。"],"source":"《唐诗三百首》"},{"title":"詠懷古跡五首 四","author":"杜甫","dynasty":"唐","form":"诗","lines":["蜀主窺吳幸三峽，崩年亦在永安宮。","翠華想像空山裏，玉殿虛無野寺中。","古廟杉松巢水鶴，歲時伏臘走村翁。","武侯祠屋常鄰近，一體君臣祭祀同。"],"source":"《唐诗三百首》"},{"title":"詠懷古跡五首 五","author":"杜甫","dynasty":"唐","form":"诗","lines":["諸葛大名垂宇宙，宗臣遺像肅清高。","三分割據紆籌策，萬古雲霄一羽毛。","伯仲之間見伊呂，指揮若定失蕭曹。","福移漢祚難恢復，志決身殲軍務勞。"],"source":"《唐诗三百首》"},{"title":"江南逢李龜年","author":"杜甫","dynasty":"唐","form":"诗","lines":["歧王宅裏尋常見，崔九堂前幾度聞。","正是江南好風景，落花時節又逢君。"],"source":"《唐诗三百首》"},{"title":"登岳陽樓","author":"杜甫","dynasty":"唐","form":"诗","lines":["昔聞洞庭水，今上岳陽樓。","吳楚東南坼，乾坤日夜浮。","親朋無一字，老病有孤舟。","戎馬關山北，憑軒涕泗流。"],"source":"《唐诗三百首》"},{"title":"虢國夫人","author":"杜甫","dynasty":"唐","form":"诗","lines":["虢國夫人承主恩，平明上馬入宮門。","却嫌脂粉涴顏色，澹埽蛾眉朝至尊。"],"source":"《唐诗三百首》"},{"title":"望月懷遠","author":"張九齡","dynasty":"唐","form":"诗","lines":["海上生明月，天涯共此時。","情人怨遙夜，竟夕起相思。","滅燭憐光滿，披衣覺露滋。","不堪盈手贈，還寢夢佳期。"],"source":"《唐诗三百首》"},{"title":"題大庾嶺北驛","author":"宋之問","dynasty":"唐","form":"诗","lines":["陽月南飛雁，傳聞至此回。","我行殊未已，何日復歸來？江靜潮初落，林昏瘴不開。","明朝望鄉處，應見隴頭梅。"],"source":"《唐诗三百首》"},{"title":"渡漢江","author":"宋之問","dynasty":"唐","form":"诗","lines":["嶺外音書斷，經冬復歷春。","近鄉情更怯，不敢問來人。"],"source":"《唐诗三百首》"},{"title":"新年作","author":"宋之問","dynasty":"唐","form":"诗","lines":["鄉心新歲切，天畔獨澘然。","老至居人下，春歸在客先。","嶺猨同旦暮，江柳共風煙。","已似長沙傅，從今又幾年。"],"source":"《唐诗三百首》"},{"title":"杜少府之任蜀州","author":"王勃","dynasty":"唐","form":"诗","lines":["城闕輔三秦，風煙望五津。","與君離別意，同是宦遊人。","海內存知己，天涯若比隣。","無爲在岐路，兒女共霑巾。"],"source":"《唐诗三百首》"},{"title":"和晉陵陸丞早春遊望","author":"杜審言","dynasty":"唐","form":"诗","lines":["獨有宦遊人，偏驚物候新。","雲霞出海曙，梅柳渡江春。","淑氣催黃鳥，晴光轉綠蘋。","忽聞歌古調，歸思欲霑巾。"],"source":"《唐诗三百首》"},{"title":"登樓","author":"朱斌","dynasty":"唐","form":"诗","lines":["白日依山盡，黃河入海流。","欲窮千里目，更上一層樓。"],"source":"《唐诗三百首》"},{"title":"送李少府貶峽中王少府貶長沙","author":"高適","dynasty":"唐","form":"诗","lines":["嗟君此別意何如，駐馬銜桮問謫居。","巫峽啼猿數行淚，衡陽歸雁幾封書。","青楓江上秋天遠，白帝城邊古木疎。","聖代即今多雨露，暫時分手莫躊躇。"],"source":"《唐诗三百首》"},{"title":"望嶽","author":"杜甫","dynasty":"唐","form":"诗","lines":["岱宗夫如何，齊魯青未了。","造化鍾神秀，陰陽割昏曉。","盪胷生曾雲，決眥入歸鳥。","會當凌絕頂，一覽衆山小。"],"source":"《唐诗三百首》"},{"title":"兵車行","author":"杜甫","dynasty":"唐","form":"诗","lines":["車轔轔，馬蕭蕭，行人弓箭各在腰。","耶孃妻子走相送，塵埃不見咸陽橋。","牽衣頓足闌道哭，哭聲直上干雲霄。","道傍過者問行人，行人但云點行頻。","或從十五北防河，便至四十西營田。","去時里正與裹頭，歸來頭白還戍邊。","邊亭流血成海水，武皇開邊意未已。","君不聞漢家山東二百州，千村萬落生荆杞。","縱有健婦把鋤犂，禾生隴畝無東西。","況復秦兵耐苦戰，被驅不異犬與雞。","長者雖有問，役夫敢申恨。","且如今年冬，未休關西卒。","縣官急索租，租稅從何出？信知生男惡，反是生女好。","生女猶是嫁比鄰，生男埋沒隨百草。","君不見青海頭，古來白骨無人收。","新鬼煩冤舊鬼哭，天陰雨濕聲啾啾。"],"source":"《唐诗三百首》"},{"title":"贈衛八處士","author":"杜甫","dynasty":"唐","form":"诗","lines":["人生不相見，動如參與商。","今夕復何夕，共此燈燭光。","少壯能幾時，鬢髮各已蒼。","訪舊半爲鬼，驚呼熱中腸。","焉知二十載，重上君子堂。","昔別君未婚，兒女忽成行。","怡然敬父執，問我來何方。","問荅乃未已，兒女羅酒漿。","夜雨剪春韭，新炊間黃粱。","主稱會面難，一舉累十觴。","十觴亦不醉，感子故意長。","明日隔山岳，世事兩茫茫。"],"source":"《唐诗三百首》"},{"title":"麗人行","author":"杜甫","dynasty":"唐","form":"诗","lines":["三月三日天氣新，長安水邊多麗人。","態濃意遠淑且真，肌理細膩骨肉勻。","繡羅衣裳照暮春，蹙金孔雀銀麒麟。","頭上何所有，翠微㔩葉垂鬢脣。","背後何所見，珠壓腰衱穩稱身。","就中雲幕椒房親，賜名大國虢與秦。","紫駝之峰出翠釜，水精之盤行素鱗。","犀箸厭飫久未下，鑾刀縷切空紛綸。","黃門飛鞚不動塵，御廚絡繹送八珍。","簫鼓哀吟感鬼神，賓從雜遝實要津。","後來鞍馬何逡巡，當軒下馬入錦茵。","楊花雪落覆白蘋，青鳥飛去銜紅巾。","炙手可熱勢絕倫，慎莫近前丞相嗔。"],"source":"《唐诗三百首》"},{"title":"哀江頭","author":"杜甫","dynasty":"唐","form":"诗","lines":["少陵野老吞聲哭，春日潛行曲江曲。","江頭宮殿鎖千門，細柳新蒲爲誰綠。","憶昔霓旌下南苑，苑中萬物生顏色。","昭陽殿裏第一人，同輦隨君侍君側。","輦前才人帶弓箭，白馬嚼齧黃金勒。","翻身向天仰射雲，一箭正墜雙飛翼。","明眸皓齒今何在，血污遊魂歸不得。","清渭東流劒閣深，去住彼此無消息。","人生有情淚霑臆，江水江花豈終極。","黃昏胡騎塵滿城，欲往城南忘南北。"],"source":"《唐诗三百首》"},{"title":"哀王孫","author":"杜甫","dynasty":"唐","form":"诗","lines":["長安城頭頭白烏，夜飛延秋門上呼。","又向人家啄大屋，屋底達官走避胡。","金鞭斷折九馬死，骨肉不待同馳驅。","腰下實玦青珊瑚，可憐王孫泣路隅。","問之不肯道姓名，但道困苦乞爲奴。","已經百日竄荆棘，身上無有完肌膚。","高帝子孫盡隆準，龍種自與常人殊。","豺狼在邑龍在野，王孫善保千金軀。","不敢長語臨交衢，且爲王孫立斯須。","昨夜東風吹血腥，東來橐駝滿舊都。","朔方健兒好身手，昔何勇銳今何愚。","竊聞天子已傳位，賢德北服南單于。","花門剺面請雪恥，慎勿出口他人狙。","哀哉王孫慎勿疎，五陵佳氣無時無。"],"source":"《唐诗三百首》"},{"title":"佳人","author":"杜甫","dynasty":"唐","form":"诗","lines":["絕代有佳人，幽居在空谷。","自云良家子，零落依草木。","關中昔喪敗，兄弟遭殺戮。","官高何足論，不得收骨肉。","世情惡衰歇，萬事隨轉燭。","夫壻輕薄兒，新人已如玉。","合昏尚知時，鴛鴦不獨宿。","但見新人笑，那聞舊人哭。","在山泉水清，出山泉水濁。","侍婢賣珠回，牽蘿補茅屋。","摘花不插髮，采柏動盈匊。","天寒翠袖薄，日暮倚修竹。"],"source":"《唐诗三百首》"},{"title":"夢李白二首 一","author":"杜甫","dynasty":"唐","form":"诗","lines":["死別已吞聲，生別常惻惻。","江南瘴癘地，逐客無消息。","故人入我夢，明我長相憶。","恐非平生魂，路遠不可測。","魂來楓葉青，魂返關塞黑。","君今在羅網，何以有羽翼。","落月滿屋梁，猶疑照顏色。","水深波浪闊，無使蛟龍得。"],"source":"《唐诗三百首》"},{"title":"夢李白二首 二","author":"杜甫","dynasty":"唐","form":"诗","lines":["浮雲終日行，遊子久不至。","三夜頻夢君，情親見君意。","告歸常局促，苦道來不易。","江湖多風波，舟楫恐失墜。","出門搔白首，若負平生志。","冠蓋滿京華，斯人獨顦顇。","孰云網恢恢，將老身反累。","千秋萬歲名，寂莫身後事。"],"source":"《唐诗三百首》"},{"title":"韋諷錄事宅觀曹將軍畫馬圖","author":"杜甫","dynasty":"唐","form":"诗","lines":["國初已來畫鞍馬，神妙獨數江都王。","將軍得名三十載，人間又見真乘黃。","曾貌先帝照夜白，龍池十日飛霹靂。","內府殷紅馬腦盌，倢伃傳詔才人索。","盌賜將軍拜舞歸，輕紈細綺相追飛。","貴戚權門得筆跡，始覺屏障生光輝。","昔日太宗拳毛騧，近時郭家師子花。","今之新圖有二馬，復令識者久歎嗟。","此皆騎戰一敵萬，縞素漠漠開風沙。","其餘七匹亦殊絕，迥若寒空動煙雪。","霜蹄蹴踏長楸間，馬官廝養森成列。","可憐九馬爭神駿，顧視清高氣深穩。","借問苦心愛者誰，後有韋諷前支遁。","憶昔巡幸新豐宮，翠華拂天來向東。","騰驤磊落三萬匹，皆與此圖筋骨同。","自從獻寶朝河宗，無復射蛟江水中。","君不見金粟堆前松柏裏，龍媒去盡鳥呼風。"],"source":"《唐诗三百首》"},{"title":"丹青引贈曹將軍霸","author":"杜甫","dynasty":"唐","form":"诗","lines":["將軍魏武之子孫，於今爲庶爲清門。","英雄割據雖已矣，文彩風流猶尚存。","學書初學衛夫人，但恨無過王右軍。","丹青不知老將至，富貴於我如浮雲。","開元之中常引見，承恩數上南熏殿。","凌煙功臣少顏色，將軍下筆開生面。","良相頭上進賢冠，猛將腰間大羽箭。","褒公鄂公毛髮動英姿颯爽來酣戰。","先帝天馬玉花驄，畫工如山貌不同。","是日牽來赤墀下，迥立閶闔生長風。","詔謂將軍拂絹素，意匠慘澹經營中。","斯須九重真龍出，一洗萬古凡馬空。","玉花却在御榻上，榻上庭前屹相向。","至尊含笑催賜金，圉人太僕皆惆悵。","弟子韓幹早入室，亦能畫馬窮殊相。","幹惟畫肉不畫骨，忍使驊騮氣凋喪。","將軍畫善蓋有神，必逢佳士亦寫真。","即今飄泊干戈際，屢貌尋常行路人。","途窮反遭俗眼白，世上未有如公貧。","但看古來盛名下，終日坎壈纏其身。"],"source":"《唐诗三百首》"},{"title":"寄韓諫議","author":"杜甫","dynasty":"唐","form":"诗","lines":["今我不樂思岳陽，身欲奮飛病在牀。","美人娟娟隔秋水，濯足洞庭望八荒。","鴻飛冥冥日月白，青楓葉赤天雨霜。","玉京羣帝集北斗，或騎騏驎翳鳳皇。","芙蓉旌旗煙霧樂，影動倒景搖瀟湘。","星宮之君醉瓊漿，羽人稀少不在旁。","似聞昨者赤松子，恐是漢代韓張良。","昔隨劉氏定長安，帷幄未改神慘傷。","國家成敗吾豈敢，色難腥腐餐風香。","周南留滯古所惜，南極老人應壽昌。","美人胡爲隔秋水，焉得置之貢玉堂。"],"source":"《唐诗三百首》"},{"title":"古柏行","author":"杜甫","dynasty":"唐","form":"诗","lines":["孔明廟前有老柏，柯如青銅根如石。","霜皮溜雨四十圍，黛色參天二千尺。","君臣已與時際會，樹木猶爲人愛惜。","雲來氣接巫峽長，月出寒通雪山白。","憶昨路繞錦亭東，先主武侯同閟宮。","崔嵬枝幹郊原古，窈窕丹青戶牖空。","落落盤踞雖得地，冥冥孤高多烈風。","扶持自是神明力，正直原因造化功。","大廈如傾要梁棟，萬牛回首丘山重。","不露文章世已驚，未辭剪伐誰能送。","苦心豈免容螻蟻，香葉終經宿鸞鳳。","志士幽人莫怨嗟，古來材大難爲用。"],"source":"《唐诗三百首》"},{"title":"觀公孫大娘弟子舞劒器行","author":"杜甫","dynasty":"唐","form":"诗","lines":["昔有佳人公孫氏，一舞劒氣動四方。","觀者如山色沮喪，天地爲之久低昂。","㸌如羿射九日落，矯如羣帝驂龍翔。","來如雷霆收震怒，罷如江海凝清光。","絳脣珠袖兩寂莫，況有弟子傳芬芳。","臨潁美人在白帝，妙舞此曲神揚揚。","與余問答既有以，感時撫事增惋傷。","先帝侍女八千人，公孫劒器初第一。","五十年間似反掌，風塵傾動昏王室。","棃園子弟散如煙，女樂餘姿映寒日。","金粟堆南木已拱，瞿唐石城草蕭瑟。","玳筵急管曲復終，樂極哀來月東出。","老夫不知其所往，足繭荒山轉愁疾。"],"source":"《唐诗三百首》"},{"title":"寄人二首  其一","author":"張佖","dynasty":"唐","form":"诗","lines":["別夢依依到謝家，小廊迴合曲闌斜。","多情只有春庭月，猶爲離人照落花。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 蓋羅縫 一","author":"不詳","dynasty":"唐","form":"诗","lines":["秦時明月漢時關，萬里征人尚未還。","但願龍庭神將在，不教胡馬渡陰山。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 婆羅門","author":"楊敬述進","dynasty":"唐","form":"诗","lines":["迴樂峰前沙似雪，受降城外月如霜。","不知何處吹蘆管？一夜征人盡望鄉。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 清平調 一","author":"李白","dynasty":"唐","form":"诗","lines":["雲想衣裳花想容，春風拂檻露華濃。","若非羣玉山頭見，會向瑤臺月下逢。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 清平調 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝紅豔露凝香，雲雨巫山枉斷腸。","借問漢宮誰得似，可憐飛燕倚新妝。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 清平調 三","author":"李白","dynasty":"唐","form":"诗","lines":["名花傾國兩相歡，長得君王帶笑看。","解釋春風無限恨，沈香亭北倚闌干。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 渭城曲","author":"王維","dynasty":"唐","form":"诗","lines":["謂城朝雨浥輕塵，客舍青青柳色春。","勸君更盡一杯酒，西出陽關無故人。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 金縷衣","author":"不詳","dynasty":"唐","form":"诗","lines":["勸君莫惜金縷衣，勸君惜取少年時。","花開堪折直須折，莫待無花空折枝。"],"source":"《唐诗三百首》"},{"title":"感遇十二首 一","author":"張九齡","dynasty":"唐","form":"诗","lines":["蘭葉春葳蕤，桂華秋皎潔。","欣欣此生意，自爾爲佳節。","誰知林棲者，聞風坐相悅。","草木有本心，何求美人折。"],"source":"《唐诗三百首》"},{"title":"感遇十二首 二","author":"張九齡","dynasty":"唐","form":"诗","lines":["幽林歸獨臥，滯慮洗孤清。","持此謝高鳥，因之傳遠情。","日夕懷空意，人誰感至精。","飛沈理自隔，何所慰吾誠。"],"source":"《唐诗三百首》"},{"title":"感遇十二首 四","author":"張九齡","dynasty":"唐","form":"诗","lines":["孤鴻海上來，池潢不敢顧。","側見雙翠鳥，巢在三珠樹。","矯矯珍木巔，得無金丸懼。","美服患人指，高明逼神惡。","今我遊冥冥，弋者何所慕。"],"source":"《唐诗三百首》"},{"title":"感遇十二首 七","author":"張九齡","dynasty":"唐","form":"诗","lines":["江南有丹橘，經冬猶綠林。","豈伊地氣暖，自有歲寒心。","可以薦嘉客，奈何阻重深。","運命唯所遇，循環不可尋。","徒言樹桃李，此木豈無陰。"],"source":"《唐诗三百首》"},{"title":"尋陸鴻漸不遇","author":"皎然","dynasty":"唐","form":"诗","lines":["移家雖帶郭，野徑入桑麻。","近種籬邊菊，秋來未著花。","扣門無犬吠，欲去問西家。","報道山中去，歸時每日斜。"],"source":"《唐诗三百首》"},{"title":"西塞山懷古","author":"劉禹錫","dynasty":"唐","form":"诗","lines":["西晉樓船下益州，金陵王氣黯然收。","千尋鐵鎖沈江底，一片降旛出石頭。","人世幾回傷往事，山形依舊枕江流。","今逢四海爲家日，故壘蕭蕭蘆荻秋。"],"source":"《唐诗三百首》"},{"title":"金陵五題 烏衣巷","author":"劉禹錫","dynasty":"唐","form":"诗","lines":["朱雀橋邊野草花，烏衣巷口夕陽斜。","舊時王謝堂前燕，飛入尋常百姓家。"],"source":"《唐诗三百首》"},{"title":"和樂天春詞","author":"劉禹錫","dynasty":"唐","form":"诗","lines":["新妝面面下朱樓，深鎖春光一院愁。","行到中庭數花朵，蜻蜓飛上玉搔頭。"],"source":"《唐诗三百首》"},{"title":"列女操","author":"孟郊","dynasty":"唐","form":"诗","lines":["梧桐相待老，鴛鴦會雙死。","貞女貴狥夫，捨生亦如此。","波瀾誓不起，妾心井中水。"],"source":"《唐诗三百首》"},{"title":"遊子吟","author":"孟郊","dynasty":"唐","form":"诗","lines":["慈母手中線，遊子身上衣。","臨行密密縫，意恐遲遲歸。","誰言寸草心，報得三春暉。"],"source":"《唐诗三百首》"},{"title":"度南澗","author":"蔡襄","dynasty":"唐","form":"诗","lines":["隠隠飛橋隔野煙，石磯西畔問漁船。","桃花盡日隨流水，洞在清溪何處邊。"],"source":"《唐诗三百首》"},{"title":"谷口書齋寄楊補闕","author":"錢起","dynasty":"唐","form":"诗","lines":["泉壑帶茅茨，雲霞生薜帷。","竹憐新雨後，山愛夕陽時。","閑鷺棲常早，秋花落更遲。","家童掃蘿逕，昨與故人期。"],"source":"《唐诗三百首》"},{"title":"送僧歸日本","author":"錢起","dynasty":"唐","form":"诗","lines":["上國隨緣住，來途若夢行。","浮天滄海遠，去世法舟輕。","水月通禪觀，魚龍聽梵聲。","惟憐一燈影，萬里眼中明。"],"source":"《唐诗三百首》"},{"title":"贈闕下裴舍人","author":"錢起","dynasty":"唐","form":"诗","lines":["二月黃鶯飛上林，春城紫禁曉陰陰。","長樂鐘聲花外盡，龍池柳色雨中深。","陽和不散窮途恨，霄漢長懷捧日新。","獻賦十年猶未遇，羞將白髮對華簪。"],"source":"《唐诗三百首》"},{"title":"和張僕射塞下曲","author":"錢起","dynasty":"唐","form":"诗","lines":["月黑雁飛高，單于夜遁逃。","欲將輕騎逐，大雪滿弓刀。"],"source":"《唐诗三百首》"},{"title":"賊退示官吏","author":"元結","dynasty":"唐","form":"诗","lines":["昔歲逢太平，山林二十年。","泉源在庭戶，洞壑當門前。","井稅有常期，日[晏]猶得眠。","忽然遭世變，數歲親戎旃。","今來典斯郡，山夷又紛然。","城小賊不屠，人貧傷可憐。","是以陷隣境，此州獨見全。","使臣將王命，豈不如賊焉。","今彼徴斂者，迫之如火煎。","誰能絕人命，以作時世賢。","思欲委符節，引竿自刺船。","將家就魚麥，歸老江湖邊。"],"source":"《唐诗三百首》"},{"title":"石魚湖上醉歌","author":"元結","dynasty":"唐","form":"诗","lines":["石魚湖，似洞庭，夏水欲滿君山青。","山爲樽，水爲沼，酒徒歷歷坐洲島。","長風連日作大浪，不能廢人運酒舫。","我持長瓢坐巴丘，酌飲四坐以散愁。"],"source":"《唐诗三百首》"},{"title":"楓橋夜泊","author":"張繼","dynasty":"唐","form":"诗","lines":["月落烏啼霜滿天，江楓漁父對愁眠。","姑蘇城外寒山寺，夜半鐘聲到客船。"],"source":"《唐诗三百首》"},{"title":"酬程延秋夜即事見贈","author":"韓翃","dynasty":"唐","form":"诗","lines":["長簟迎風早，空城澹月華。","星河秋一雁，砧杵夜千家。","節候看應晚，心期臥亦賒。","向來吟秀句，不覺已鳴鴉。"],"source":"《唐诗三百首》"},{"title":"同題仙游觀","author":"韓翃","dynasty":"唐","form":"诗","lines":["仙臺下見五城樓，風物淒淒宿雨收。","山色遙連秦樹晚，砧聲近報漢宮秋。","疎松影落空壇靜，細草香閑小洞幽。","何用別尋方外去，人間亦自有丹丘。"],"source":"《唐诗三百首》"},{"title":"寒食","author":"韓翃","dynasty":"唐","form":"诗","lines":["春城無處不飛花，寒食東風御柳斜。","日暮漢宮傳蠟燭，輕煙散入五侯家。"],"source":"《唐诗三百首》"},{"title":"寄李儋元錫","author":"韋應物","dynasty":"唐","form":"诗","lines":["去年花裏逢君別，今日花開已一年。","世事茫茫難自料，春愁黯黯獨成眠。","身多疾病思田里，邑有流亡愧俸錢。","聞道欲來相問訊，西樓望月幾廻圓。"],"source":"《唐诗三百首》"},{"title":"寄全椒山中道士","author":"韋應物","dynasty":"唐","form":"诗","lines":["今朝郡齋冷，忽念山中客。","澗底束荆薪，歸來煮白石。","欲持一瓢酒，遠慰風雨夕。","落葉滿空山，何處尋行跡。"],"source":"《唐诗三百首》"},{"title":"秋夜寄丘二十二員外","author":"韋應物","dynasty":"唐","form":"诗","lines":["懷君屬秋夜，散步詠涼天。","山空松子落，幽人應未眠。"],"source":"《唐诗三百首》"},{"title":"賦得暮雨送李胄","author":"韋應物","dynasty":"唐","form":"诗","lines":["楚江微雨裏，建業暮鐘時。","漠漠帆來重，冥冥鳥去遲。","海門深不見，浦樹遠含滋。","相送情無限，沾襟比散絲。"],"source":"《唐诗三百首》"},{"title":"送楊氏女","author":"韋應物","dynasty":"唐","form":"诗","lines":["永日方慼慼，出門復悠悠。","女子今有行，大江泝輕舟。","爾輩況無恃，撫念益慈柔。","幼爲長所育，兩別泣不休。","對此結中腸，義往難復留。","自小闕內訓，事姑貽我憂。","賴茲託令門，仁恤庶無尤。","貧儉誠所尚，資從豈待周。","孝恭遵婦道，容止順其猷。","別離在今晨，見爾當何秋。","居閑始自遣，臨感忽難收。","歸來視幼女，零淚緣纓流。"],"source":"《唐诗三百首》"},{"title":"長安遇馮著","author":"韋應物","dynasty":"唐","form":"诗","lines":["客從東方來，衣上灞陵雨。","問客何爲來，采山因買斧。","冥冥花正開，颺颺燕新乳。","昨別今已春，鬢絲生幾縷。"],"source":"《唐诗三百首》"},{"title":"夕次盱眙縣","author":"韋應物","dynasty":"唐","form":"诗","lines":["落帆逗淮鎮，停舫臨孤驛。","浩浩風起波，冥冥日沈夕。","人歸山郭暗，雁下蘆洲白。","獨夜憶秦關，聽鐘未眠客。"],"source":"《唐诗三百首》"},{"title":"東郊","author":"韋應物","dynasty":"唐","form":"诗","lines":["吏舍跼終年，出郊曠清曙。","楊柳散和風，青山澹吾慮。","依叢適自憩，緣澗還復去。","微雨靄芳原，春鳩鳴何處？樂幽心屢止，遵事跡猶遽。","終罷斯結廬，慕陶真可庶。"],"source":"《唐诗三百首》"},{"title":"滁州西澗","author":"韋應物","dynasty":"唐","form":"诗","lines":["獨憐幽草澗邊生，上有黃鸝深樹鳴。","春潮帶雨晚來急，野渡無人舟自橫。"],"source":"《唐诗三百首》"},{"title":"和晉陵陸丞早春遊望","author":"韋應物","dynasty":"唐","form":"诗","lines":["獨有宦遊人，偏驚物候新。","雲霞出海曙，梅柳渡江春。","淑氣催黃鳥，晴光照綠蘋。","忽聞歌苦調，歸思欲霑巾。"],"source":"《唐诗三百首》"},{"title":"與高適薛據慈恩寺浮圖","author":"岑參","dynasty":"唐","form":"诗","lines":["塔勢如湧出，孤高聳天宮。","登臨出世界，磴道盤虛空。","突兀壓神州，崢嶸如鬼工。","四角礙白日，七層摩蒼穹。","下窺指高鳥，俯聽聞驚風。","連山若波濤，奔湊似朝東。","青槐夾馳道，宮館何玲瓏。","秋色從西來，蒼然滿關中。","五陵北原上，萬古青濛濛。","淨理了可悟，勝因夙所宗。","誓將挂冠去，覺道資無窮。"],"source":"《唐诗三百首》"},{"title":"白雪歌送武判官歸京","author":"岑參","dynasty":"唐","form":"诗","lines":["北風捲地白草折，胡天八月即飛雪。","忽然一夜春風來，千樹萬樹梨花開。","散入珠簾濕羅幕，狐裘不煖錦衾薄。","將軍角弓不得控，都護鐵衣冷難着。","瀚海闌干百丈冰，愁雲黲淡萬里凝。","中軍置酒飲歸客，胡琴琵琶與羌笛。","紛紛暮雪下轅門，風掣紅旗凍不翻。","輪臺東門送君去，去時雪滿天山路。","山迴路轉不見君，雪上空留馬行處。"],"source":"《唐诗三百首》"},{"title":"輪臺歌奉送封大夫出師西征","author":"岑參","dynasty":"唐","form":"诗","lines":["輪臺城頭夜吹角，輪臺城北旄頭落。","羽書昨夜過渠黎，單于已在金山西。","戍樓西望煙塵黑，漢兵屯在輪臺北。","上將擁旄西出征，平明吹笛大軍行。","四邊伐鼓雪海湧，三軍大呼陰山動。","虜塞兵氣連雲屯，戰場白骨纏草根。","劒河風急雪片闊，沙口石凍馬蹄脫。","亞相勤王甘苦辛，誓將報主靜邊塵。","古來青史誰不見，今見功名勝古人。"],"source":"《唐诗三百首》"},{"title":"走馬川行奉送出師西征","author":"岑參","dynasty":"唐","form":"诗","lines":["君不見走馬川行雪海邊，平沙莽莽黃入天。","輪臺九月風夜吼，一川碎石大如斗，隨風滿地石亂走。","匈奴草黃馬正肥，金山西見煙塵飛。","漢家大將西出師，將軍金甲夜不脫。","半夜軍行戈相撥，風頭如刀面如割。","馬毛帶雪汗氣蒸，五花連錢旋作冰。","幕中草檄硯水凝，虜騎聞之應膽懾。","料知短兵不敢接，車師西門佇獻捷。"],"source":"《唐诗三百首》"},{"title":"寄左省杜拾遺","author":"岑參","dynasty":"唐","form":"诗","lines":["聯步趨丹陛，分曹限紫微。","曉隨天仗入，暮惹御香歸。","白髮悲花落，青雲羨鳥飛。","聖朝無闕事，自覺諫書稀。"],"source":"《唐诗三百首》"},{"title":"奉和中書舍人賈至早朝大明宮","author":"岑參","dynasty":"唐","form":"诗","lines":["雞鳴紫陌曙光寒，鶯囀皇州春色闌。","金闕曉鐘開萬戶，玉階仙仗擁千官。","花迎劒珮星初落，柳拂旌旗露未乾。","獨有鳳皇池上客，陽春一曲和皆難。"],"source":"《唐诗三百首》"},{"title":"逢入京使","author":"岑參","dynasty":"唐","form":"诗","lines":["故園東望路漫漫，雙袖龍鍾淚不乾。","馬上相逢無紙筆，憑君傳語報平安。"],"source":"《唐诗三百首》"},{"title":"訪羊尊師","author":"孫革","dynasty":"唐","form":"诗","lines":["松下問童子，言師採藥去。","只在此山中，雲深不知處。"],"source":"《唐诗三百首》"},{"title":"書邊事","author":"張喬","dynasty":"唐","form":"诗","lines":["調角斷清秋，征人倚戍樓。","春風對青塚，白日落梁州。","大漢無兵阻，窮邊有客遊。","蕃情似此水，長願向南流。"],"source":"《唐诗三百首》"},{"title":"行路難三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["金樽清酒斗十千，玉盤珍羞直萬錢。","停杯投筯不能食，拔劒四顧心茫然。","欲渡黃河冰塞川，將登太行雪滿山。","閑來垂釣碧溪上，忽復乘舟夢日邊。","行路難，行路難，多岐路，今安在。","長風破浪會有時，直挂雲帆濟滄海。"],"source":"《唐诗三百首》"},{"title":"行路難三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["大道如青天，我獨不得出。","羞逐長安社中兒，赤雞白狗賭梨栗。","彈劒作歌奏苦聲，曳裾王門不稱情。","淮陰市井笑韓信，漢朝公卿忌賈生。","君不見昔時燕家重郭隗，擁篲折節無嫌猜。","劇辛樂毅感恩分，輸肝剖膽效英才。","昭王白骨縈爛草，誰人更掃黃金臺。","行路難，歸去來。"],"source":"《唐诗三百首》"},{"title":"行路難三首 三","author":"李白","dynasty":"唐","form":"诗","lines":["有耳莫洗潁川水，有口莫食首陽蕨。","含光混世貴無名，何用孤高比雲月。","吾觀自古賢達人，功成不退皆殞身。","子胥既棄吳江上，屈原終投湘水濱。","陸機雄才豈自保，李斯稅駕苦不早。","華亭鶴唳詎可聞，上蔡蒼鷹何足道。","君不見吳中張翰稱達生，秋風忽憶江東行。","且樂生前一杯酒，何須身後千載名。"],"source":"《唐诗三百首》"},{"title":"長相思","author":"李白","dynasty":"唐","form":"诗","lines":["長相思，在長安，絡緯秋啼金井闌。","微霜淒淒簟色寒，孤燈不明思欲絕。","卷帷望月空長歎，美人如花隔雲端。","上有青冥之長天，下有淥水之波瀾。","天長路遠魂飛苦，夢魂不到關山難。","長相思，摧心肝。"],"source":"《唐诗三百首》"},{"title":"關山月","author":"李白","dynasty":"唐","form":"诗","lines":["明月出天山，蒼茫雲海間。","長風幾萬里，吹度玉門關。","漢下白登道，胡窺青海灣。","由來征戰地，不見有人還。","[戍]客望邊色，思歸多苦顏。","高樓當此夜，歎息未應閑。"],"source":"《唐诗三百首》"},{"title":"玉階怨","author":"李白","dynasty":"唐","form":"诗","lines":["玉階生白露，夜久侵羅襪。","却下水晶簾，玲瓏望秋月。"],"source":"《唐诗三百首》"},{"title":"清平調詞三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["雲想衣裳花想容，春風拂檻露華濃。","若非羣玉山頭見，會向瑤臺月下逢。"],"source":"《唐诗三百首》"},{"title":"清平調詞三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝穠豔露凝香，雲雨巫山枉斷腸。","借問漢宮誰得似，可憐飛燕倚新妝。"],"source":"《唐诗三百首》"},{"title":"靜夜思","author":"李白","dynasty":"唐","form":"诗","lines":["牀前看月光，疑是地上霜。","舉頭望山月，低頭思故鄉。"],"source":"《唐诗三百首》"},{"title":"春思","author":"李白","dynasty":"唐","form":"诗","lines":["燕草如碧絲，秦桑低綠枝。","當君懷歸日，是妾斷腸時。","春風不相識，何事入羅幃。"],"source":"《唐诗三百首》"},{"title":"子夜吳歌 春歌","author":"李白","dynasty":"唐","form":"诗","lines":["秦地羅敷女，採桑綠水邊。","素手青條上，紅妝白日鮮。","蠶飢妾欲去，五馬莫留連。"],"source":"《唐诗三百首》"},{"title":"子夜吳歌 夏歌","author":"李白","dynasty":"唐","form":"诗","lines":["鏡湖三百里，菡萏發荷花。","五月西施採，人看隘若耶。","回舟不待月，歸去越王家。"],"source":"《唐诗三百首》"},{"title":"子夜吳歌 秋歌","author":"李白","dynasty":"唐","form":"诗","lines":["長安一片月，萬戶擣衣聲。","秋風吹不盡，總是玉關情。","何日平胡虜，良人罷遠征。"],"source":"《唐诗三百首》"},{"title":"子夜吳歌 冬歌","author":"李白","dynasty":"唐","form":"诗","lines":["明朝驛使發，一夜絮征袍。","素手抽針冷，那堪把剪刀。","裁縫寄遠道，幾日到臨洮。"],"source":"《唐诗三百首》"},{"title":"贈孟浩然","author":"李白","dynasty":"唐","form":"诗","lines":["吾愛孟夫子，風流天下聞。","紅顏棄軒冕，白首臥松雲。","醉月頻中聖，迷花不事君。","高山安可仰，徒此揖清芬。"],"source":"《唐诗三百首》"},{"title":"廬山謠寄盧侍御虛舟","author":"李白","dynasty":"唐","form":"诗","lines":["我本楚狂人，鳳歌笑孔丘。","手持綠玉杖，朝別黃鶴樓。","五嶽尋仙不辭遠，一生好入名山遊。","廬山秀出南斗傍，屏風九疊雲錦張，影落明湖青黛光。","金闕前開二峰長，銀河倒挂三石梁。","香爐瀑布遙相望，迴厓沓嶂凌蒼蒼。","翠影紅霞映朝日，鳥飛不到吳天長。","登高壯觀天地間，大江茫茫去不還。","黃雲萬里動風色，白波九道流雪山。","好爲廬山謠，興因廬山發。","閑窺石鏡清我心，謝公行處蒼苔沒。","早服還丹無世情，琴心三疊道初成。","遙見仙人綵雲裏，手把芙蓉朝玉京。","先期汗漫九垓上，願接盧敖遊太清。"],"source":"《唐诗三百首》"},{"title":"夢遊天姥吟留別","author":"李白","dynasty":"唐","form":"诗","lines":["海客談瀛洲，煙濤微茫信難求。","越人語天姥，雲霓明滅或可覩。","天姥連天向天橫，勢拔五嶽掩赤城。","天台四萬八千丈，對此欲倒東南傾。","我欲因之夢吳越，一夜飛度鏡湖月。","湖月照我影，送我至剡溪。","謝公宿處今尚在，淥水蕩漾清猨啼。","脚著謝公屐，身登青雲梯。","半壁見海日，空中聞天雞。","千巖萬轉路不定，迷花倚石忽已暝。","熊咆龍吟殷巖泉，慄深林兮驚層巔。","雲青青兮欲雨，水澹澹兮生煙。","列缺霹靂，丘巒崩摧。","洞天石扇，訇然中開。","青冥浩蕩不見底，日月照耀金銀臺。","霓爲衣兮風爲馬，雲之君兮紛紛而來下。","虎鼓瑟兮鸞迴車，仙之人兮列如麻。","忽魂悸以魄動，怳驚起而長嗟。","惟覺時之枕席，失向來之煙霞。","世間行樂亦如此，古來萬事東流水。","別君去時何時還，且放白鹿青崖間，須行即騎訪名山。","安能摧眉折腰事權貴？使我不得開心顏。"],"source":"《唐诗三百首》"},{"title":"金陵酒肆留別","author":"李白","dynasty":"唐","form":"诗","lines":["風吹柳花滿店香，吳姬壓酒喚客嘗。","金陵子弟來相送，欲行不行各盡觴。","請君試問東流水，別意與之誰短長。"],"source":"《唐诗三百首》"},{"title":"黃鶴樓送孟浩然之廣陵","author":"李白","dynasty":"唐","form":"诗","lines":["故人西辭黃鶴樓，煙花三月下揚州。","孤帆遠影碧山盡，唯見長江天際流。"],"source":"《唐诗三百首》"},{"title":"渡荆門送別","author":"李白","dynasty":"唐","form":"诗","lines":["渡遠荆門外，來從楚國遊。","山隨平野盡，江入大荒流。","月下飛天鏡，雲生結海樓。","仍連故鄉水，萬里送行舟。"],"source":"《唐诗三百首》"},{"title":"送友人","author":"李白","dynasty":"唐","form":"诗","lines":["青山橫北郭，白水遶東城。","此地一爲別，孤蓬萬里征。","浮雲遊子意，落日故人情。","揮手自茲去，蕭蕭班馬鳴。"],"source":"《唐诗三百首》"},{"title":"宣州謝朓樓餞別校書叔雲","author":"李白","dynasty":"唐","form":"诗","lines":["棄我去者昨日之日不可留，亂我心者今日之日多煩憂。","長風萬里送秋雁，對此可以酣高樓。","蓬萊文章建安骨，中間小謝又清發。","俱懷逸興壯思飛，欲上青天覽日月。","抽刀斷水水更流，舉杯銷愁愁更愁。","人生在世不稱意，明朝散髮弄扁舟。"],"source":"《唐诗三百首》"},{"title":"下終南山過斛斯山人宿置酒","author":"李白","dynasty":"唐","form":"诗","lines":["暮從碧山下，山月隨人歸。","却顧所來徑，蒼蒼橫翠微。","相攜及田家，童稚開荆扉。","綠竹入幽徑，青蘿拂行衣。","歡言得所憩，美酒聊共揮。","長歌吟松風，曲盡河星稀。","我醉君復樂，陶然共忘機。"],"source":"《唐诗三百首》"},{"title":"登金陵鳳凰臺","author":"李白","dynasty":"唐","form":"诗","lines":["鳳凰臺上鳳凰遊，鳳去臺空江自流。","吳宮花草埋幽徑，晉代衣冠成古丘。","三山半落青天外，二水中分白鷺洲。","總爲浮雲能蔽日，長安不見使人愁。"],"source":"《唐诗三百首》"},{"title":"早發白帝城","author":"李白","dynasty":"唐","form":"诗","lines":["朝辭白帝彩雲間，千里江陵一日還。","兩岸猨聲啼不盡，輕舟已過萬重山。"],"source":"《唐诗三百首》"},{"title":"夜泊牛渚懷古","author":"李白","dynasty":"唐","form":"诗","lines":["牛渚西江夜，青天無片雲。","登舟望秋月，空憶謝將軍。","余亦能高詠，斯人不可聞。","明朝挂帆席，楓葉落紛紛。"],"source":"《唐诗三百首》"},{"title":"月下獨酌四首 一","author":"李白","dynasty":"唐","form":"诗","lines":["花間一壺酒，獨酌無相親。","舉杯邀明月，對影成三人。","月既不解飲，影徒隨我身。","暫伴月將影，行樂須及春。","我歌月裴回，我舞影零亂。","醒時同交歡，醉後各分散。","永結無情遊，相期邈雲漢。"],"source":"《唐诗三百首》"},{"title":"聽蜀僧濬彈琴","author":"李白","dynasty":"唐","form":"诗","lines":["蜀僧抱綠綺，西下峨眉峰。","爲我一揮手，如聽萬壑松。","客心洗流水，餘響入霜鐘。","不覺碧山暮，秋雲暗幾重。"],"source":"《唐诗三百首》"},{"title":"怨情","author":"李白","dynasty":"唐","form":"诗","lines":["美人捲珠簾，深坐顰蛾眉。","但見淚痕濕，不知心恨誰。"],"source":"《唐诗三百首》"},{"title":"淮上喜會梁川故人","author":"韋應物","dynasty":"唐","form":"诗","lines":["江漢曾爲客，相逢每醉還。","浮雲一別後，流水十年間。","歡笑情如舊，蕭疎鬢已斑。","何因北歸去，淮上對秋山。"],"source":"《唐诗三百首》"},{"title":"郡齋雨中與諸文士燕集","author":"韋應物","dynasty":"唐","form":"诗","lines":["兵衛森畫戟，宴寢凝清香。","海上風雨至，逍遙池閣涼。","煩疴近消散，嘉賓復滿堂。","自慙居處崇，未覩斯民康。","理會是非遣，性達形迹忘。","鮮肥屬時禁，蔬果幸見嘗。","俯飲一杯酒，仰聆金玉章。","神歡體自輕，意欲凌風翔。","吳中盛文史，羣彥今汪洋。","方知大藩地，豈曰財賦疆。"],"source":"《唐诗三百首》"},{"title":"初發揚子寄元大校書","author":"韋應物","dynasty":"唐","form":"诗","lines":["悽悽去親愛，泛泛入煙霧。","歸棹洛陽人，殘鐘廣陵樹。","今朝此爲別，何處還相遇。","世事波上舟，沿洄安得住。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 江南曲","author":"李益","dynasty":"唐","form":"诗","lines":["嫁得瞿塘賈，朝朝誤妾期。","早知潮有信，嫁與弄潮兒。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 燕歌行","author":"高適","dynasty":"唐","form":"诗","lines":["漢家煙塵在東北，漢將辭家破殘賊。","男兒本自重橫行，天子非常賜顏色。","摐金伐鼓下榆關，旌旗逶迤碣石間。","校尉羽書飛瀚海，單于獵火照狼山。","山川蕭條極邊土，胡騎憑凌雜風雨。","戰士軍前半死生，美人帳下猶歌舞。","大漠窮秋塞草衰，孤城落日鬬兵稀。","身當恩遇常輕敵，力盡關山未解圍。","鐵衣遠戍辛勤久，玉箸應啼別離後。","少婦城南欲斷腸，征人薊北空回首。","邊風飄飄那可度，絕域蒼茫更何有。","殺氣三日作陣雲，寒聲一夜傳刁斗。","相看白刃血紛紛，死節從來豈顧勳。","君不見沙場征戰苦，至今猶憶李將軍。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 從軍行","author":"李頎","dynasty":"唐","form":"诗","lines":["白日登山望烽火，昏黃飲馬傍交河。","行人刁斗風砂暗，公主琵琶幽怨多。","野營萬里無城郭，雨雪紛紛連大漠。","胡雁哀鳴夜夜飛，胡兒眼淚雙雙落。","聞道玉門猶被遮，應將性命逐輕車。","年年戰骨埋荒外，空見蒲萄入漢家。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 蜀道難","author":"李白","dynasty":"唐","form":"诗","lines":["噫吁嚱！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。","爾來四萬八千歲，乃與秦塞通人煙。","西當太白有鳥道，可以橫絕峨眉巔。","地崩山摧壯士死，然後天梯石棧方鉤連。","上有六龍迴日之高標，下有衝波逆折之迴川。","黃鶴之飛尚不得，猨猱欲度愁攀緣。","青泥何盤盤，百步九折縈巖巒。","捫參歷井仰脅息，以手撫膺坐長歎。","問君西遊何時還？畏途巉巖不可攀。","但見悲鳥號枯木，雄飛呼雌繞林間。","又聞子規啼夜月，愁空山，蜀道之難難於上青天！使人聽此彫朱顏。","連峰去天不盈尺，枯松倒挂倚絕壁。","飛湍瀑流相喧豗，砅崖轉石萬壑雷。","其嶮也若此，嗟爾遠道之人胡爲乎來哉？劒閣崢嶸而崔嵬，一夫當關，萬夫莫開。","所守或匪親，化爲狼與豺。","朝避猛虎，夕避長蛇。","磨牙吮血，殺人如麻。","錦城雖云樂，不如早還家。","蜀道之難難於上青天，側身西望長咨嗟。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 長信怨 二","author":"王昌齡","dynasty":"唐","form":"诗","lines":["奉帚平明金殿開，暫將團扇共裴回。","玉顏不及寒鵶色，猶帶昭陽日影來。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 玉階怨","author":"李白","dynasty":"唐","form":"诗","lines":["玉階生白露，夜久侵羅襪。","却下水精簾，玲瓏望秋月。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 子夜四時歌四首 春歌","author":"李白","dynasty":"唐","form":"诗","lines":["秦地羅敷女，采桑綠水邊。","素手青條上，紅妝白日鮮。","蠶飢妾欲去，五馬莫留連。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 子夜四時歌四首 夏歌","author":"李白","dynasty":"唐","form":"诗","lines":["鏡湖三百里，菡萏發荷花。","五月西施采，人看隘若邪。","迴舟不待月，歸去越王家。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 子夜四時歌四首 秋歌","author":"李白","dynasty":"唐","form":"诗","lines":["長安一片月，萬戶擣衣聲。","秋風吹不盡，總是玉關情。","何日平胡虜？良人罷遠征。"],"source":"《唐诗三百首》"},{"title":"相和歌辭 子夜四時歌四首 冬歌","author":"李白","dynasty":"唐","form":"诗","lines":["明朝驛使發，一夜絮征袍。","素手抽針冷，那堪把剪刀。","裁縫寄遠道，幾日到臨洮。"],"source":"《唐诗三百首》"},{"title":"琴曲歌辭 列女操","author":"孟郊","dynasty":"唐","form":"诗","lines":["梧桐相待老，鴛鴦會雙死。","貞婦貴徇夫，舍生亦如此。","波瀾誓不起，妾心井中水。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 遊子吟","author":"孟郊","dynasty":"唐","form":"诗","lines":["慈母手中線，遊子身上衣。","臨行密密縫，意恐遲遲歸。","誰言寸草心，報得三春暉。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 麗人行","author":"杜甫","dynasty":"唐","form":"诗","lines":["三月三日天氣新，長安水邊多麗人。","態濃意遠淑且真，肌理細膩骨肉勻。","繡羅衣裳照暮春，蹙金孔雀銀麒麟。","頭上何所有？翠微㔩葉垂鬢脣。","背後何所見？珠壓腰衱穩稱身。","就中雲幕椒房親，賜名大國虢與秦。","紫駞之峯出翠釜，水晶之盤行素鱗。","犀筯厭飫久未下，鸞刀縷切空紛綸。","黃門飛鞚不動塵，御廚絲絡送八珍。","簫鼓哀吟感鬼神，賓從雜遝實要津。","後來鞍馬何逡巡，當軒下馬入錦茵。","楊花雪落覆白蘋，青鳥飛去銜紅巾。","炙手可熱勢絕倫，慎莫近前丞相嗔。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 長相思三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["長相思，在長安，絡緯秋啼金井欄。","微霜淒淒簟色寒，孤燈不明思欲絕。","卷帷望月空長歎，美人如花隔雲端。","上有青冥之長天，下有綠水之波瀾。","天長路遠魂飛苦，夢魂不到關山難。","長相思，摧心肝。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 長相思三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["日色已盡花含煙，月明欲素愁不眠。","趙瑟初停鳳凰柱，蜀琴欲奏鴛鴦弦。","此曲有意無人傳，願隨春風寄燕然，憶君迢迢隔青天。","昔日橫波目，今成流淚泉。","不信妾腸斷，歸來看取明鏡前。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 行路難三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["金尊清酒斗十千，玉盤珍羞直萬錢。","停杯投筯不能食，拔劒四顧心茫然。","欲渡黃河冰塞川，將登太行雪暗天。","閑來垂釣坐溪上，忽復乘舟夢日邊。","行路難，行路難，多岐路，今安在？長風破浪會有時，直挂雲帆濟滄海。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 行路難三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["大道如青天，我獨不得出。","羞逐長安社中兒，赤雞白狗賭梨栗。","彈劒作歌奏苦聲，曳裾王門不稱情。","淮陰市井笑韓信，漢朝公卿忌賈生。","君不見昔時燕家重郭隗，擁篲折腰無嫌猜。","劇辛樂毅感恩分，輸肝剖膽效英才。","昭王白骨縈蔓草，誰人更掃黃金臺。","行路難，歸去來。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 行路難三首 三","author":"李白","dynasty":"唐","form":"诗","lines":["有耳莫洗潁川水，有口莫食首陽蕨。","含光混世貴無名，何用孤高比雲月。","吾觀自古賢達人，功成不退皆殞身。","子胥既棄吳江上，屈原終投湘水濱。","陸機才多豈自保，李斯稅駕苦不早。","華亭鶴唳詎可聞，上蔡蒼鷹何足道？君不見吳中張翰稱達士，秋風忽憶江東行。","且樂生前一杯酒，何須身後千載名。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 長干曲四首 一","author":"崔顥","dynasty":"唐","form":"诗","lines":["君家定何處？妾住在橫塘。","停舟暫借問，或恐是同鄉。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 長干曲四首 二","author":"崔顥","dynasty":"唐","form":"诗","lines":["家臨九江水，去來九江側。","同是長干人，生小不相識。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 長干行二首 一","author":"李白","dynasty":"唐","form":"诗","lines":["妾髮初覆額，折花門前劇。","郎騎竹馬來，遶牀弄青梅。","同居長干里，兩小無嫌猜。","十四爲君婦，羞顏尚不開。","低頭向暗壁，千喚不一迴。","十五始展眉，願同塵與灰。","常存抱柱信，豈上望夫臺。","十六君遠行，瞿塘灩預堆。","五月不可觸，猨鳴天上哀。","門前遲行跡，一一生綠苔。","苔深不能掃，落葉秋風早。","八月蝴蝶來，雙飛西園草。","感此傷妾心，坐愁紅顏老。","早晚下三巴，預將書報家。","相迎不道遠，直至長風沙。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 獨不見","author":"沈佺期","dynasty":"唐","form":"诗","lines":["盧家小婦鬱金堂，海燕雙栖玳瑁梁。","九月寒砧催下葉，十年征戍憶遼陽。","白狼河北音書斷，丹鳳城南秋夜長。","誰知含愁獨不見，使妾明月照流黃。"],"source":"《唐诗三百首》"},{"title":"雜曲歌辭 秋夜曲","author":"王涯","dynasty":"唐","form":"诗","lines":["桂魄初生秋露微，輕羅已薄未更衣。","銀箏夜久殷勤弄，心怯空房不忍歸。"],"source":"《唐诗三百首》"},{"title":"春思","author":"皇甫冉","dynasty":"唐","form":"诗","lines":["鶯啼燕語報新年，馬邑龍堆路幾千。","家住秦城鄰漢苑，心隨明月到胡天。","機中錦字論長恨，樓上花枝笑獨眠。","爲問元戎竇車騎，何時反斾勒燕然。"],"source":"《唐诗三百首》"},{"title":"夜月","author":"劉方平","dynasty":"唐","form":"诗","lines":["更深月色半人家，北斗闌干南斗斜。","今夜偏知春氣暖，蟲聲新透綠窗紗。"],"source":"《唐诗三百首》"},{"title":"春怨","author":"劉方平","dynasty":"唐","form":"诗","lines":["紗窗日落漸黃昏，金屋無人見淚痕。","寂寞空庭春欲晚，梨花滿地不開門。"],"source":"《唐诗三百首》"},{"title":"登鸛雀樓","author":"王之渙","dynasty":"唐","form":"诗","lines":["白日依山盡，黃河入海流。","欲窮千里目，更上一層樓。"],"source":"《唐诗三百首》"},{"title":"涼州詞二首 一","author":"王之渙","dynasty":"唐","form":"诗","lines":["黃河遠上白雲間，一片孤城萬仞山。","羌笛何須怨楊柳，春光不度玉門關。"],"source":"《唐诗三百首》"},{"title":"闕題","author":"劉眘虛","dynasty":"唐","form":"诗","lines":["道由白雲盡，春與青溪長。","時有落花至，遠隨流水香。","閑門向山路，深柳讀書堂。","幽映每白日，清輝照衣裳。"],"source":"《唐诗三百首》"},{"title":"征怨","author":"柳中庸","dynasty":"唐","form":"诗","lines":["歲歲金河復玉關，朝朝馬策與刀環。","三春白雪歸青冢，萬里黃河遶黑山。"],"source":"《唐诗三百首》"},{"title":"送李端","author":"嚴維","dynasty":"唐","form":"诗","lines":["故關衰草遍，離別正堪悲。","路出寒雲外，人歸暮雪時。","少孤爲客早，多難識君遲。","揜泣空相向，風塵何所期。"],"source":"《唐诗三百首》"},{"title":"宮詞五首 二","author":"顧況","dynasty":"唐","form":"诗","lines":["玉樓天半起笙歌，風送宮嬪笑語和。","月殿影開聞夜漏，水精簾卷近銀河。"],"source":"《唐诗三百首》"},{"title":"赤壁词・念奴娇","author":"陆游","dynasty":"宋","form":"词","lines":["禁门锺晓，忆君来朝路，初翔鸾鹄。","西府中台推独步，行对金莲宫烛。","蹙绣华鞯，仙葩宝带，看即飞腾速。","人生难料，一尊此地相属。","回首紫陌青门，西湖闲院，锁千梢修竹。","素壁栖鸦应好在，残梦不堪重续。","岁月惊心，功名看镜，短鬓无多绿。","一欢休惜，与君同醉浮玉。"],"source":"宋词"},{"title":"浣溪沙","author":"陆游","dynasty":"宋","form":"词","lines":["懒向沙头醉玉瓶。","唤君同赏小窗明。","夕阳吹角最关情。","忙日苦多闲日少，新愁常续旧愁生。","客中无伴怕君行。"],"source":"宋词"},{"title":"浣溪沙","author":"陆游","dynasty":"宋","form":"词","lines":["浴罢华清第二汤。","红绵扑粉玉肌凉。","娉婷初试藕丝裳。","凤尺裁成猩血色，螭奁熏透麝脐香。","水亭幽处捧霞觞。"],"source":"宋词"},{"title":"青玉案","author":"陆游","dynasty":"宋","form":"词","lines":["西风挟雨声翻浪。","恰洗尽、黄茅瘴。","老惯人间齐得丧。","千岩高卧，五湖归棹，替却凌烟像。","故人小驻平戎帐。","白羽腰间气何壮。","我老渔樵君将相。","小槽红酒，晚香丹荔，记取蛮江上。"],"source":"宋词"},{"title":"水调歌头","author":"陆游","dynasty":"宋","form":"词","lines":["江左占形胜，最数古徐州。","连山如画，佳处缥渺著危楼。","鼓角临风悲壮，烽火连空明灭，往事忆孙刘。","千里曜戈甲，万灶宿貔貅。","露沾草，风落木，岁方秋。","使君宏放，谈笑洗尽古今愁。","不见襄阳登览，磨灭游人无数，遗恨黯难收。","叔子独千载，名与汉江流。"],"source":"宋词"},{"title":"浪淘沙","author":"陆游","dynasty":"宋","form":"词","lines":["绿树暗长亭。","几把离尊。","阳关常恨不堪闻。","何况今朝秋色里，身是行人。","清泪浥罗巾。","各自消魂。","一江离恨恰平分。","安得千寻横铁锁，截断烟津。"],"source":"宋词"},{"title":"定风波","author":"陆游","dynasty":"宋","form":"词","lines":["敧帽垂鞭送客回。","小桥流水一枝梅。","衰病逢春都不记。","谁谓。","幽香却解逐人来。","安得身闲频置酒。","携手。","与君看到十分开。","少壮相从今雪鬓。","因甚。","流年羁恨两相催。"],"source":"宋词"},{"title":"南乡子","author":"陆游","dynasty":"宋","form":"词","lines":["归梦寄吴樯。","水驿江程去路长。","想见芳洲初系缆，斜阳。","烟树参差认武昌。","愁鬓点新霜。","曾是朝衣染御香。","重到故乡交旧少，凄凉。","却恐它乡胜故乡。"],"source":"宋词"},{"title":"南乡子","author":"陆游","dynasty":"宋","form":"词","lines":["早岁入皇州。","尊酒相逢尽胜流。","三十年来真一梦，堪愁。","客路萧萧两鬓秋。","蓬峤偶重游。","不待人嘲我自羞。","看镜倚楼俱已矣，扁舟。","月笛烟蓑万事休。"],"source":"宋词"},{"title":"满江红","author":"陆游","dynasty":"宋","form":"词","lines":["危堞朱栏，登览处、一江秋色。","人正似、征鸿社燕，几番轻别。","缱绻难忘当日语，凄凉又作它乡客。","问鬓边、都有几多丝，真堪织。","杨柳院，秋千陌。","无限事，成虚掷。","如今何处也，梦魂难觅。","金鸭微温香缥渺，锦茵初展情萧瑟。","料也应、红泪伴秋霖，灯前滴。"],"source":"宋词"},{"title":"满江红","author":"陆游","dynasty":"宋","form":"词","lines":["疏蕊幽香，禁不过、晚寒愁绝。","那更是、巴东江上，楚山千叠。","敧帽闲寻西瀼路，亸鞭笑向南枝说。","恐使君、归去上銮坡，孤风月。","清镜里，悲华发。","山驿外，溪桥侧。","凄然回首处，凤凰城阙。","憔悴如今谁领略，飘零已是无颜色。","问行厨、何日唤宾僚，犹堪折。"],"source":"宋词"},{"title":"感皇恩","author":"陆游","dynasty":"宋","form":"词","lines":["春色到人间，彩旛初戴。","正好春盘细生菜。","一般日月，只有仙家偏耐。","雪霜从点鬓，朱颜在。","温诏鼎来，延英催对。","凤阁鸾台看除拜。","对衣裁稳，恰称球纹新带。","个时方旋了、功名债。"],"source":"宋词"},{"title":"感皇恩","author":"陆游","dynasty":"宋","form":"词","lines":["小阁倚秋空，下临江渚。","漠漠孤云未成雨。","数声新雁，回首杜陵何处。","壮心空万里，人谁许。","黄阁紫枢，筑坛开府。","莫怕功名欠人做。","如今熟计，只有故乡归路。","石帆山脚下，菱三亩。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["羁雁未成归，肠断宝筝零落。","那更冻醪无力，似故人情薄。","瘴云蛮雨暗孤城，身在楚山角。","烦问剑南消息，怕还成疏索。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["风露九霄寒，侍宴玉华宫阙。","亲向紫皇香案，见金芝千叶。","碧壶仙露酝初成，香味两奇绝。","醉后却骑丹凤，看蓬莱春色。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["客路苦思归，愁似茧丝千绪。","梦里镜湖烟雨，看山无重数。","尊前消尽少年狂，慵著送春语。","花落燕飞庭户，叹年光如许。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["岁晚喜东归，扫尽市朝陈迹。","拣得乱山环处，钓一潭澄碧。","卖鱼沽酒醉还醒，心事付横笛。","家在万重云外，有沙鸥相识。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["华表又千年，谁记驾云孤鹤。","回首旧曾游处，但山川城郭。","纷纷车马满人间，尘土污芒屩。","且访葛仙丹井，看岩花开落。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["挥袖别人间，飞蹑峭崖苍壁。","寻见古仙丹灶，有白云成积。","心如潭水静无风，一坐数千息。","夜半忽惊奇事，看鲸波暾日。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["湓口放船归，薄暮散花洲宿。","两岸白苹红蓼，映一蓑新绿。","有沽酒处便为家，菱芡四时足。","明日又乘风去，任江南江北。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["挥袖上西峰，孤绝去天无尺。","拄杖下临鲸海，数烟帆历历。","贪看云气舞青鸾，归路已将夕。","多谢半山松吹，解殷勤留客。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["小倦带馀酲，澹澹数櫺斜日。","驱退睡魔十万，有双龙苍璧。","少年莫笑老人衰，风味似平昔。","扶杖冻云深处，探溪梅消息。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["觅个有缘人，分付玉壶灵药。","谁向市尘深处，识辽天孤鹤。","月中吹笛下巴陵，条华赴前约。","今古废兴何限，叹山川如昨。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["平旦出秦关，雪色驾车双鹿。","借问此行安往，赏清伊修竹。","汉家宫殿劫灰中，春草几回绿。","君看变迁如许，况纷纷荣辱。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["秋晓上莲峰，高蹑倚天青壁。","谁与放翁为伴，有天坛轻策。","铿然忽变赤龙飞，雷雨四山黑。","谈笑做成丰岁，笑禅龛楖栗。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["家住东吴近帝乡。","平生豪举少年场。","十千沽酒青楼上，百万呼卢锦瑟傍。","身易老，恨难忘。","尊前赢得是凄凉。","君归为报京华旧，一事无成两鬓霜。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["看尽巴山看蜀山。","子规江上过春残。","惯眠古驿常安枕，熟听《阳关》不惨颜。","慵服气，懒烧丹。","不妨青鬓戏人间。","秘传一字神仙诀，说与君知只是顽。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["梳发金盘剩一窝。","画眉鸾镜晕双蛾。","人间何处无春到，只有伊家独占多。","微步处，奈娇何。","春衫初换曲尘罗。","东邻斗草归来晚，忘却新传子夜歌。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["家住苍烟落照间。","丝毫尘事不相关。","斟残玉瀣行穿竹，卷罢《黄庭》卧看山。","贪啸傲，任衰残。","不妨随处一开颜。","元知造物心肠别，老却英雄似等闲。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["插脚红尘已是颠。","更求平地上青天。","新来有个生涯别，买断烟波不用钱。","沽酒市，采菱船。","醉听风雨拥蓑眠。","三山老子真堪笑，见事迟来四十年。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["懒向青门学种瓜。","只将渔钓送年华。","双双新燕飞春岸，片片轻鸥落晚沙。","歌缥渺，舻呕哑。","酒如清露鮓如花。","逢人问道归何处，笑指船儿此是家。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["南浦舟中两玉人。","谁知重见楚江滨。","凭教后苑红牙版，引上西川绿锦茵。","才浅笑，却轻嚬。","淡黄杨柳又催春。","情知言语难传恨，不思琵琶道得真。"],"source":"宋词"},{"title":"蓦山溪","author":"陆游","dynasty":"宋","form":"词","lines":["元戎十乘，出次高唐馆。","归去旧鹓行，更何人、齐飞霄汉。","瞿唐水落，惟是泪波深，催叠鼓，起牙樯，难锁长江断。","春深鳌禁，红日宫瓦暖。","何处望音尘，黯消魂、层城飞观。","人情见惯，不敢恨相忘，梅驿外，蓼滩边，只待除书看。"],"source":"宋词"},{"title":"蓦山溪","author":"陆游","dynasty":"宋","form":"词","lines":["穷山孤垒，腊尽春初破。","寂寞掩空斋，好一个、无聊底我。","啸台龙岫，随分有云山，临浅濑，荫长松，闲据胡床坐。","三杯径醉，不觉纱巾堕。","画角唤人归，落梅村、篮舆夜过。","城门渐近，几点妓衣红，官驿外，酒垆前，也有闲灯火。"],"source":"宋词"},{"title":"木兰花・玉楼春","author":"陆游","dynasty":"宋","form":"词","lines":["三年流落巴山道。","破尽青衫尘满帽。","身如西瀼渡头云，愁抵瞿塘关上草。","春盘春酒年年好。","试戴银旛判醉倒。","今朝一岁大家添，不是人间偏我老。"],"source":"宋词"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["幽姿不入少年场。","无语只凄凉。","一个飘零身世，十分冷淡心肠。","江头月底，新诗旧梦，孤恨清香。","任是春风不管，也曾先识东皇。"],"source":"宋词"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["怕歌愁舞懒逢迎。","妆晚托春酲。","总是向人深处，当时枉道无情。","关心近日，啼红密诉，剪绿深盟。","杏馆花阴恨浅，画堂银烛嫌明。"],"source":"宋词"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["咚咚傩鼓饯流年。","烛焰动金船。","彩燕难寻前梦，酥花空点春妍。","文园谢病，兰成久旅，回首凄然。","明月梅山笛夜，和风禹庙莺天。"],"source":"宋词"},{"title":"临江仙","author":"陆游","dynasty":"宋","form":"词","lines":["鸠雨催成新绿，燕泥收尽残红。","春光还与美人同。","论心空眷眷，分袂却匆匆。","只道真情易写，那知怨句难工。","水流云散各西东。","半廊花院月，一帽柳桥风。"],"source":"宋词"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["陌上箫声寒食近。","雨过园林，花气浮芳润。","千里斜阳锺欲瞑。","凭高望断南楼信。","海角天涯行略尽。","三十年间，无处无遗恨。","天若有情终欲问。","忍教霜点相思鬓。"],"source":"宋词"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["桐叶晨飘蛩夜语。","旅思秋光，黯黯长安路。","忽记横戈盘马处。","散关清渭应如故。","江海轻舟今已具。","一卷兵书，叹息无人付。","早信此生终不遇。","当年悔草《长杨赋》。"],"source":"宋词"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["水漾萍根风卷絮。","倩笑娇颦，忍记逢迎处。","只有梦魂能再遇。","堪嗟梦不由人做。","梦若由人何处去。","短帽轻衫，夜夜眉州路。","不怕银缸深绣户。","只愁风断青衣渡。"],"source":"宋词"},{"title":"钗头凤・撷芳词","author":"陆游","dynasty":"宋","form":"词","lines":["红酥手。","黄縢酒。","满城春色宫墙柳。","东风恶。","欢情薄。","一怀愁绪，几年离索。","错错错。","春如旧。","人空瘦。","泪痕红浥鲛绡透。","桃花落。","闲池阁。","山盟虽在，锦书难托。","莫莫莫。"],"source":"宋词"},{"title":"清商怨","author":"陆游","dynasty":"宋","form":"词","lines":["江头日暮痛饮。","乍雪晴犹凛。","山驿凄凉，灯昏人独寝。","鸳机新寄断锦。","叹往事、不堪重省。","梦破南楼，绿云堆一枕。"],"source":"宋词"},{"title":"水龙吟","author":"陆游","dynasty":"宋","form":"词","lines":["樽前花底寻春处，堪叹心情全减。","一身萍寄，酒徒云散，佳人天远。","那更今年，瘴烟蛮雨，夜郎江畔。","漫倚楼横笛，临窗看镜，时挥涕、惊流转。","花落月明庭院。","悄无言、魂消肠断。","凭肩携手，当时曾效，画梁栖燕。","见说新来，网萦尘暗，舞衫歌扇。","料也羞憔悴，慵行芳径，怕啼莺见。"],"source":"宋词"},{"title":"秋波媚・眼儿媚","author":"陆游","dynasty":"宋","form":"词","lines":["秋到边城角声哀。","烽火照高台。","悲歌击筑，凭高酹酒，此兴悠哉。","多情谁似南山月，特地暮云开。","灞桥烟柳，曲江池馆，应待人来。"],"source":"宋词"},{"title":"秋波媚・眼儿媚","author":"陆游","dynasty":"宋","form":"词","lines":["曾散天花蕊珠宫。","一念堕尘中。","铅华洗尽，珠玑不御，道骨仙风。","东游我醉骑鲸去，君驾素鸾从。","垂虹看月，天台采药，更与谁同。"],"source":"宋词"},{"title":"采桑子","author":"陆游","dynasty":"宋","form":"词","lines":["宝钗楼上妆梳晚，懒上秋千。","闲拨沈烟。","金缕衣宽睡髻偏。","鳞鸿不寄辽东信，又是经年。","弹泪花前。","愁入春风十四弦。"],"source":"宋词"},{"title":"卜算子","author":"陆游","dynasty":"宋","form":"词","lines":["驿外断桥边，寂寞开无主。","已是黄昏独自愁，更著风和雨。","无意苦争春，一任群芳妒。","零落成泥碾作尘，只有香如故。"],"source":"宋词"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["粉破梅梢，绿动萱丛，春意已深。","渐珠帘低卷，筇枝微步，冰开跃鲤，林暖鸣禽。","荔子扶疏，竹枝哀怨，浊酒一尊和泪斟。","凭栏久，叹山川冉冉，岁月骎骎。","当时岂料如今。","漫一事无成霜鬓侵。","看故人强半，沙堤黄阁，鱼悬带玉，貂映蝉金。","许国虽坚，朝天无路，万里凄凉谁寄音。","东风里，有灞桥烟柳，知我归心。"],"source":"宋词"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["一别秦楼，转眼新春，又近放灯。","忆盈盈倩笑，纤纤柔握，玉香花语，雪暖酥凝。","念远愁肠，伤春病思，自怪平生殊未曾。","君知否，渐香消蜀锦，泪渍吴绫。","难求系日长绳。","况倦客飘零少旧朋。","但江郊雁起，渔村笛怨，寒釭委烬，孤砚生冰。","水绕山围，烟昏云惨，纵有高台常怯登。","消魂处，是鱼笺不到，兰梦无凭。"],"source":"宋词"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["孤鹤归飞，再过辽天，换尽旧人。","念累累枯冢，茫茫梦境，王侯蝼蚁，毕竟成尘。","载酒园林，寻花巷陌，当日何曾轻负春。","流年改，叹围腰带剩，点鬓霜新。","交亲。","散落如云。","又岂料如今馀此身。","幸眼明身健，茶甘饭软，非惟我老，更有人贫。","躲尽危机，消残壮志，短艇湖中闲采莼。","吾何恨，有渔翁共醉，溪友为邻。"],"source":"宋词"},{"title":"忆秦娥","author":"陆游","dynasty":"宋","form":"词","lines":["玉花骢。","晚街金辔声璁珑。","声璁珑。","闲敧乌帽，又过城东。","富春巷陌花重重。","千金沽酒酬春风。","酬春风。","笙歌围里，锦绣丛中。"],"source":"宋词"},{"title":"汉宫春","author":"陆游","dynasty":"宋","form":"词","lines":["浪迹人间。","喜闻猿楚峡，学剑秦川。","虚舟泛然不系，万里江天。","朱颜绿鬓，作红尘、无事神仙。","何妨在，莺花海里，行歌闲送流年。","休笑放慵狂眼，看闲坊深院，多少婵娟。","燕宫海棠夜宴，花覆金船。","如椽画烛，酒阑时、百炬吹烟。","凭寄语，京华旧侣，幅巾莫换貂蝉。"],"source":"宋词"},{"title":"汉宫春","author":"陆游","dynasty":"宋","form":"词","lines":["羽箭雕弓，忆呼鹰古垒，截虎平川。","吹笳暮归，野帐雪压青毡。","淋漓醉墨，看龙蛇、飞落蛮笺。","人误许，诗情将略，一时才气超然。","何事又作南来，看重阳药市，元夕灯山。","花时万人乐处，敧帽垂鞭。","闻歌感旧，尚时时、流涕尊前。","君记取，封侯事在，功名不信由天。"],"source":"宋词"},{"title":"月上海棠","author":"陆游","dynasty":"宋","form":"词","lines":["斜阳废苑朱门闭。","吊兴亡、遗恨泪痕里。","淡淡宫梅，也依然、点酥剪水。","凝愁处，似忆宣华旧事。","行人别有凄凉意。","折幽香、谁与寄千里。","伫立江皋，杳难逢、陇头归骑。","音尘远，楚天危楼独倚。"],"source":"宋词"},{"title":"月上海棠","author":"陆游","dynasty":"宋","form":"词","lines":["兰房绣户厌厌病。","叹春酲、和闷甚时醒。","燕子空归，几曾传、玉关边信。","伤心处，独展团窠瑞锦。","熏笼消歇沈烟冷。","泪痕深、展转看花影。","漫拥馀香，怎禁他、峭寒孤枕。","西窗晓，几声银瓶玉井。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["金鸭馀香尚暖，绿窗斜日偏明。","兰膏香染云鬟腻，钗坠滑无声。","冷落秋千伴侣，阑珊打马心情。","绣屏惊断潇湘梦，花外一声莺。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["檐角楠阴转日，楼前荔子吹花。","鹧鸪声里霜天晚，叠鼓已催衙。","乡梦时来枕上，京书不到天涯。","邦人讼少文移省，闲院自煎茶。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["我校丹台玉字，君书蕊殿云篇。","锦官城里重相遇，心事两依然。","携酒何妨处处，寻梅共约年年。","细思上界多官府，且作地行仙。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["世事从来惯见，吾生更欲何之。","镜湖西畔秋千顷，鸥鹭共忘机。","一枕苹风午醉，二升菰米晨炊。","故人莫讶音书绝，钓侣是新知。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["素意幽栖物外，尘缘浪走天涯。","归来犹幸身强健，随分作山家。","已趁馀寒泥酒，还乘小雨移花。","柴门尽日无人到，一径傍溪斜。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["园馆青林翠樾，衣巾细葛轻纨。","好风吹散霏微雨，沙路喜新乾。","小燕双飞水际，流莺百啭林端。","投壶声断弹棋罢，闲展道书看。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["从宦元知漫浪，还家更觉清真。","兰亭道上多修竹，随处岸纶巾。","泉冽偏宜雪茗，粳香雅称丝莼。","け然一饱西窗下，天地有闲人。"],"source":"宋词"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["纨扇婵娟素月，纱巾缥渺轻烟。","高槐叶长阴初合，清润雨馀天。","弄笔斜行小草，钩帘浅醉闲眠。","更无一点尘埃到，枕上听新蝉。"],"source":"宋词"},{"title":"真珠帘","author":"陆游","dynasty":"宋","form":"词","lines":["山村水馆参差路。","感羁游、正似残春风絮。","掠地穿帘，知是竟归何处。","镜里新霜空自悯，问几时、鸾台鳌署。","迟暮。","谩凭高怀远，书空独语。","自古。","儒冠多误。","悔当年、早不扁舟归去。","醉下白苹洲，看夕阳鸥鹭。","菰菜鲈鱼都弃了，只换得、青衫尘土。","休顾。","早收身江上，一蓑烟雨。"],"source":"宋词"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["混迹寄人间，夜夜画楼银烛。","谁见五云丹灶，养黄芽初熟。","春风归从紫皇游，东海宴晹谷。","进罢碧桃花赋，赐玉尘千斛。"],"source":"宋词"},{"title":"柳梢青","author":"陆游","dynasty":"宋","form":"词","lines":["锦里繁华。","环宫故邸，叠萼奇花。","俊客妖姬，争飞金勒，齐驻香车。","何须幕障帏遮。","宝杯浸、红云瑞霞。","银烛光中，清歌声里，休恨天涯。"],"source":"宋词"},{"title":"柳梢青","author":"陆游","dynasty":"宋","form":"词","lines":["十载江湖，行歌沽酒，不到京华。","底事翩然，长亭烟草，衰鬓风沙。","凭高目断天涯。","细雨外、楼台万家。","只恐明朝，一时不见，人共梅花。"],"source":"宋词"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["雪晓清笳乱起。","梦游处、不知何地。","铁骑无声望似水。","想关河，雁门西，青海际。","睡觉寒灯里。","漏声断、月斜窗纸。","自许封侯在万里。","有谁知，鬓虽残，心未死。"],"source":"宋词"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["独夜寒侵翠被。","奈幽梦、不成还起。","欲写新愁泪溅纸。","忆承恩，叹馀生，今至此。","蔌蔌灯花坠。","问此际、报人何事。","咫尺长门过万里。","恨君心，似危栏，难久倚。"],"source":"宋词"},{"title":"安公子","author":"陆游","dynasty":"宋","form":"词","lines":["风雨初经社。","子规声里春光谢。","最是无情，零落尽、蔷薇一架。","况我今年，憔悴幽窗下。","人尽怪、诗酒消声价。","向药炉经卷，忘却莺窗柳榭。","万事收心也。","粉痕犹在香罗帕。","恨月愁花，争信道、如今都罢。","空忆前身，便面章台马。","因自来、禁得心肠怕。","纵遇歌逢酒，但说京都旧话。"],"source":"宋词"},{"title":"玉胡蝶・玉蝴蝶","author":"陆游","dynasty":"宋","form":"词","lines":["倦客平生行处，坠鞭京洛，解佩潇湘。","此夕何年，来赋宋玉高唐。","绣帘开、香尘乍起，莲步稳、银烛分行。","暗端相。","燕羞莺妒，蝶绕蜂忙。","难忘。","芳樽频劝，峭寒新退，玉漏犹长。","几许幽情，只愁歌罢月侵廊。","欲归时、司空笑问，微近处，丞相嗔狂。","断人肠。","假饶相送，上马何妨。"],"source":"宋词"},{"title":"木兰花慢","author":"陆游","dynasty":"宋","form":"词","lines":["阅邯郸梦境，叹绿鬓、早霜侵。","奈华岳烧丹，青溪看鹤，尚负初心。","年来向浊世里，悟真诠秘诀绝幽深。","养就金芝九畹，种成琪树千林。","星坛夜学步虚吟。","露冷透瑶簪。","对翠凤披云，青鸾溯月，宫阙萧森。","琅函一封奏罢，自钧天帝所有知音。","却过蓬壶啸傲，世间岁月骎骎。"],"source":"宋词"},{"title":"苏武慢","author":"陆游","dynasty":"宋","form":"词","lines":["澹霭空濛，轻阴清润，绮陌细尘初静。","平桥系马，画阁移舟，湖水倒空如镜。","掠岸飞花，傍檐新燕，都似学人无定。","叹连年戎帐，经春边垒，暗凋颜鬓。","空记忆、杜曲池台，新丰歌管，怎得故人音信。","羁怀易感，老伴无多，谈麈久闲犀柄。","惟有修然，笔床茶灶，自适笋舆烟艇。","待绿荷遮岸，红蕖浮水，更乘幽兴。"],"source":"宋词"},{"title":"齐天乐","author":"陆游","dynasty":"宋","form":"词","lines":["角残锺晚关山路，行人乍依孤店。","塞月征尘，鞭丝帽影，常把流年虚占。","藏鸦柳暗。","叹轻负莺花，谩劳书剑。","事往关情，悄然频动壮游念。","孤怀谁与强遣。","市垆沽酒，酒薄怎当愁酽。","倚瑟妍词，调铅妙笔，那写柔情芳艳。","征途自厌。","况烟敛芜痕，雨稀萍点。","最是眠时，枕寒门半掩。"],"source":"宋词"},{"title":"齐天乐","author":"陆游","dynasty":"宋","form":"词","lines":["客中随处闲消闷，来寻啸台龙岫。","路敛春泥，山开翠雾，行乐年年依旧。","天工妙手。","放轻绿萱牙，淡黄杨柳。","笑问东君，为人能染鬓丝否。","西州催去近也，帽檐风软，且看市楼沽酒。","宛转巴歌，凄凉塞管，携客何妨频奏。","征尘暗袖。","漫禁得梅花，伴人疏瘦。","几日东归，画船平放溜。"],"source":"宋词"},{"title":"望梅","author":"陆游","dynasty":"宋","form":"词","lines":["寿非金石。","恨天教老向，水程山驿。","似梦里、来到南柯，这些子光阴，更勘轻掷。","戍火边尘，又过了、一年春色。","叹名姬骏马，尽付杜陵，苑路豪客。","长绳漫劳系日。","看人间俯仰，俱是陈迹。","纵自倚、英气凌云，奈回尽鹏程，铩残鸾翮。","终日凭高，诮不见、江东消息。","算沙边、也有断鸿，倩谁问得。"],"source":"宋词"},{"title":"洞庭春色・沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["壮岁文章，暮年勋业，自昔误人。","算英雄成败，轩裳得失，难如人意，空丧天真。","请看邯郸当日梦，待炊罢黄粱徐欠伸。","方知道，许多时富贵，何处关身。","人间定无可意，怎换得、玉鲙丝莼。","且钓竿渔艇，笔床茶灶，闲听荷雨，一洗衣尘。","洛水秦关千古后，尚棘暗铜驼空怆神。","何须更，慕封侯定远，图像麒麟。"],"source":"宋词"},{"title":"渔家傲","author":"陆游","dynasty":"宋","form":"词","lines":["东望山阴何处是。","往来一万三千里。","写得家书空满纸。","流清泪。","书回已是明年事。","寄语红桥桥下水。","扁舟何日寻兄弟。","行遍天涯真老矣。","愁无寐。","鬓丝几缕茶烟里。"],"source":"宋词"},{"title":"绣停针","author":"陆游","dynasty":"宋","form":"词","lines":["叹半纪，跨万里秦吴，顿觉衰谢。","回首鹓行，英俊并游，咫尺玉堂金马。","气凌嵩华。","负壮略、纵横王霸。","梦经洛浦梁园，觉来泪流如泻。","山林定去也。","却自恐说著，少年时话。","静院焚香，闲倚素屏，今古总成虚假。","趁时婚嫁。","幸自有、湖边茅舍。","燕归应笑，客中又还过社。"],"source":"宋词"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["斜阳寂历柴门闭。","一点炊烟时起。","鸡犬往来林外。","俱有萧然意。","衰翁老去疏荣利。","绝爱山城无事。","临去画楼频倚。","何日重来此。"],"source":"宋词"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["栏干几曲高斋路。","正在重云深处。","丹碧未乾人去。","高栋空留句。","离离芳草长亭暮。","无奈征车不住。","惟有断鸿烟渚。","知我频回顾。"],"source":"宋词"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["一弹指顷浮生过。","堕甑元知当破。","去去醉吟高卧。","独唱何须和。","残年还我从来我。","万里江湖烟舸。","脱尽利名缰锁。","世界元来大。"],"source":"宋词"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["城南载酒行歌路。","冶叶倡条无数。","一朵鞓红凝露。","最是关心处。","莺声无赖催春去。","那更兼旬风雨。","试问岁华何许。","芳草连天暮。"],"source":"宋词"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["中原当日三川震。","关辅回头煨烬。","泪尽两河征镇。","日望中兴运。","秋风霜满青青鬓。","老却新丰英俊。","云外华山千仞。","依旧无人问。"],"source":"宋词"},{"title":"极相思","author":"陆游","dynasty":"宋","form":"词","lines":["江头疏雨轻烟。","寒食落花天。","翻红坠素，残霞暗锦，一段凄然。","惆怅东君堪恨处，也不念、冷落尊前。","那堪更看，漫空相趁，柳絮榆钱。"],"source":"宋词"},{"title":"一丛花","author":"陆游","dynasty":"宋","form":"词","lines":["尊前凝伫漫魂迷。","犹恨负幽期。","从来不惯伤春泪，为伊后、滴满罗衣。","那堪更是，吹箫池馆，青子绿阴时。","回廊帘影昼参差。","偏共睡相宜。","朝云梦断知何处，倩双燕、说与相思。","从今判了，十分憔悴，图要个人知。"],"source":"宋词"},{"title":"一丛花","author":"陆游","dynasty":"宋","form":"词","lines":["仙姝天上自无双。","玉面翠蛾长。","黄庭读罢心如水，闭朱户、愁近丝簧。","窗明几净，闲临唐帖，深炷宝奁香。","人间无药驻流光。","风雨又催凉。","相逢共话清都旧，叹尘劫、生死茫茫。","何如伴我，绿蓑青箬，秋晚钓潇湘。"],"source":"宋词"},{"title":"隔浦莲近拍","author":"陆游","dynasty":"宋","form":"词","lines":["飞花如趁燕子。","直度帘栊里。","帐掩香云暖，金笼鹦鹉惊起。","凝恨慵梳洗。","妆台畔，蘸粉纤纤指。","宝钗坠。","才醒又困，厌厌中酒滋味。","墙头柳暗，过尽一年春事。","罨画高楼怕独倚。","千里。","孤舟何处烟水。"],"source":"宋词"},{"title":"隔浦莲近拍","author":"陆游","dynasty":"宋","form":"词","lines":["骑鲸云路倒景。","醉面风吹醒。","笑把浮丘袂，寥然非复尘境。","震泽秋万顷。","烟霏散，水面飞金镜。","露华冷。","湘妃睡起，鬟倾钗坠慵整。","临江舞处，零乱塞鸿清影。","河汉横斜夜漏永。","人静。","吹箫同过缑岭。"],"source":"宋词"},{"title":"昭君怨","author":"陆游","dynasty":"宋","form":"词","lines":["昼永蝉声庭院。","人倦懒摇团扇。","小景写潇湘。","自生凉。","帘外蹴花双燕。","帘下有人同见。","宝篆拆官黄。","炷熏香。"],"source":"宋词"},{"title":"双头莲","author":"陆游","dynasty":"宋","form":"词","lines":["华鬓星星，惊壮志成虚，此身如寄。","萧条病骥。","向暗里。","消尽当年豪气。","梦断故国山川，隔重重烟水。","身万里。","旧社凋零，青门俊游谁记。","尽道锦里繁华，叹官闲昼永，柴荆添睡。","清愁自醉。","念此际。","付与何人心事。","纵有楚柂吴樯，知何时东逝。","空怅望，鲙美菰香，秋风又起。"],"source":"宋词"},{"title":"南歌子","author":"陆游","dynasty":"宋","form":"词","lines":["异县相逢晚，中年作别难。","暮秋风雨客衣寒。","又向朝天门外、话悲欢。","瘦马行霜栈，轻舟下雪滩。","乌奴山下一林丹。","为说三年常寄、梦魂间。"],"source":"宋词"},{"title":"豆叶黄・忆王孙","author":"陆游","dynasty":"宋","form":"词","lines":["春风楼上柳腰肢。","初试花前金缕衣。","袅袅娉娉不自持。","晓妆迟。","画得蛾眉胜旧时。"],"source":"宋词"},{"title":"豆叶黄・忆王孙","author":"陆游","dynasty":"宋","form":"词","lines":["一春常是雨和风。","风雨晴时春已空。","谁惜泥沙万点红。","恨难穷。","恰似衰翁一世中。"],"source":"宋词"},{"title":"醉落魄・一斛珠","author":"陆游","dynasty":"宋","form":"词","lines":["江湖醉客。","投杯起舞遗乌帻。","三更冷翠沾衣湿。","袅袅菱歌，催落半川月。","空花昨梦休寻觅。","云台麟阁俱陈迹。","元来只有闲难得。","青史功名，天却无心惜。"],"source":"宋词"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["华灯纵博，雕鞍驰射，谁记当年豪举。","酒徒一一取封侯，独去作、江边渔父。","轻舟八尺，低篷三扇，占断苹洲烟雨。","镜湖元自属闲人，又何必、君恩赐与。"],"source":"宋词"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["一竿风月，一蓑烟雨，家在钓台西住。","卖鱼生怕近城门，况肯到、红尘深处。","潮生理棹，潮平系缆，潮落浩歌归去。","时人错把比严光，我自是、无名渔父。"],"source":"宋词"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["茅檐人静，蓬窗灯暗，春晚连江风雨。","林莺巢燕总无声，但月夜、常啼杜宇。","催成清泪，惊残孤梦，又拣深枝飞去。","故山犹自不堪听，况半世、飘然羁旅。"],"source":"宋词"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["云千重。","水千重。","身在千重云水中。","月明收钓筒。","头未童。","耳未聋。","得酒犹能双脸红。","一尊谁与同。"],"source":"宋词"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["桥如虹。","水如空。","一叶飘然烟雨中。","天教称放翁。","侧船篷。","使江风。","蟹舍参差渔市东。","到时闻暮锺。"],"source":"宋词"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["面苍然。","鬓皤然。","满腹诗书不直钱。","官闲常昼眠。","画凌烟。","上甘泉。","自古功名属少年。","知心惟杜鹃。"],"source":"宋词"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["暮山青。","暮霞明。","梦笔桥头艇子横。","苹风吹酒醒。","看潮生。","看潮平。","小住西陵莫较程。","莼丝初可烹。"],"source":"宋词"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["悟浮生。","厌浮名。","回视千锺一发轻。","从今心太平。","爱松声。","爱泉声。","写向孤桐谁解听。","空江秋月明。"],"source":"宋词"},{"title":"菩萨蛮","author":"陆游","dynasty":"宋","form":"词","lines":["江天淡碧云如扫。","苹花零落莼丝老。","细细晚波平。","月从波面生。","渔家真个好。","悔不归来早。","经岁洛阳城。","鬓丝添几茎。"],"source":"宋词"},{"title":"菩萨蛮","author":"陆游","dynasty":"宋","form":"词","lines":["小院蚕眠春欲老。","新巢燕乳花如扫。","幽梦锦城西。","海棠如旧时。","当年真草草。","一棹还吴早。","题罢惜春诗。","镜中添鬓丝。"],"source":"宋词"},{"title":"诉衷情","author":"陆游","dynasty":"宋","form":"词","lines":["当年万里觅封侯。","匹马戍梁州。","关河梦断何处，尘暗旧貂裘。","胡未灭，鬓先秋。","泪空流。","此生谁料，心在天山，身老沧洲。"],"source":"宋词"},{"title":"诉衷情","author":"陆游","dynasty":"宋","form":"词","lines":["青衫初入九重城。","结友尽豪英。","蜡封夜半传檄，驰骑谕幽并。","时易失，志难成。","鬓丝生。","平章风月，弹压江山，别是功名。"],"source":"宋词"},{"title":"生查子","author":"陆游","dynasty":"宋","form":"词","lines":["还山荷主恩，聊试扶犁手。","新结小茅茨，恰占清江口。","风尘不化衣，邻曲常持酒。","那似宦游时，折尽长亭柳。"],"source":"宋词"},{"title":"生查子","author":"陆游","dynasty":"宋","form":"词","lines":["梁空燕委巢，院静鸠催雨。","香润上朝衣，客少闲谈麈。","鬓边千缕丝，不是吴蚕吐。","孤梦泛潇湘，月落闻柔橹。"],"source":"宋词"},{"title":"破阵子","author":"陆游","dynasty":"宋","form":"词","lines":["仕至千锺良易，年过七十常稀。","眼底荣华元是梦，身后声名不自知。","营营端为谁。","幸有旗亭沽酒，何妨茧纸题诗。","幽谷云萝朝采药，静院轩窗夕对棋。","不归真个痴。"],"source":"宋词"},{"title":"破阵子","author":"陆游","dynasty":"宋","form":"词","lines":["看破空花尘世，放轻昨梦浮名。","蜡屐登山真率饮，筇杖穿林自在行。","身闲心太平。","料峭馀寒犹力，廉纤细雨初晴。","苔纸闲题溪上句，菱唱遥闻烟外声。","与君同醉醒。"],"source":"宋词"},{"title":"上西楼・相见欢","author":"陆游","dynasty":"宋","form":"词","lines":["江头绿暗红稀。","燕交飞。","忽到当年行处、恨依依。","洒清泪。","叹人事。","与心违。","满酌玉壶花露、送春归。"],"source":"宋词"},{"title":"点绛唇","author":"陆游","dynasty":"宋","form":"词","lines":["采药归来，独寻茅店沽新酿。","暮烟千嶂。","处处闻渔唱。","醉弄扁舟，不怕粘天浪。","江湖上。","遮回疏放。","作个闲人样。"],"source":"宋词"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["壮岁从戎，曾是气吞残虏。","阵云高、狼烽夜举。","朱颜青鬓，拥雕戈西戍。","笑儒冠、自来多误。","功名梦断，却泛扁舟吴楚。","漫悲歌、伤怀吊古。","烟波无际，望秦关何处。","叹流年、又成虚度。"],"source":"宋词"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["贺监湖边，初系放翁归棹。","小园林、时时醉倒。","春眠惊起，听啼莺催晓。","叹功名、误人勘笑。","朱桥翠径，不许京尘飞到。","挂朝衣、东归欠早。","连宵风雨，卷残红如扫。","恨樽前、送春人老。"],"source":"宋词"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["七十衰翁，不减少年豪气。","似天山、凄凉病骥。","铜驼荆棘，洒临风清泪。","甚情怀、伴人儿戏。","如今何幸，作个故溪归计。","鹤飞来、晴岚暖翠。","玉壶春酒，约群仙同醉。","洞天寒、露桃开未。"],"source":"宋词"},{"title":"一落索","author":"陆游","dynasty":"宋","form":"词","lines":["满路游丝飞絮。","韶光将暮。","此时谁与说新愁，有百啭、流莺语。","俯仰人间今古。","神仙何处。","花前须判醉扶归，酒不到、刘伶墓。"],"source":"宋词"},{"title":"一落索","author":"陆游","dynasty":"宋","form":"词","lines":["识破浮生虚妄。","从人讥谤。","此身恰似弄潮儿，曾过了、千重浪。","且喜归来无恙。","一壶春酿。","雨蓑烟笠傍渔矶，应不是、封侯相。"],"source":"宋词"},{"title":"杏花天","author":"陆游","dynasty":"宋","form":"词","lines":["老来驹隙骎骎度。","筭只合、狂歌醉舞。","金杯到手君休诉。","看著春光又暮。","谁为倩、柳条系住。","且莫遣、城笳催去。","残红转眼无寻处。","尽属蜂房燕户。"],"source":"宋词"},{"title":"太平时・添声杨柳枝","author":"陆游","dynasty":"宋","form":"词","lines":["竹里房栊一径深。","静愔愔。","乱红飞尽绿成阴。","有鸣禽。","临罢兰亭无一事，自修琴。","铜炉袅袅海南沉。","洗尘襟。"],"source":"宋词"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["不惜貂裘换钓篷。","嗟时人、谁识放翁。","归棹借、樵风稳，数声闻、林外暮锺。","幽栖莫笑蜗庐小，有云山、烟水万重。","半世向、丹青看，喜如今、身在画中。"],"source":"宋词"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["无方能驻脸上红。","笑浮生、扰扰梦中。","平地是、冲霄路，又何劳、千日用功。","飘然再过莲峰下，乱云深、吹下暮锺。","访旧隐、依然在，但鹤巢、时有堕松。"],"source":"宋词"},{"title":"风入松","author":"陆游","dynasty":"宋","form":"词","lines":["十年裘马锦江滨。","酒隐红尘。","万金选胜莺花海，倚疏狂、驱使青春。","吹笛鱼龙尽出，题诗风月俱新。","自怜华发满纱巾。","犹是官身。","凤楼常记当年语，问浮名、何似身亲。","欲寄吴笺说与，这回真个闲人。"],"source":"宋词"},{"title":"真珠帘","author":"陆游","dynasty":"宋","form":"词","lines":["灯前月下嬉游处。","向笙歌、锦绣丛中相遇。","彼此知名，才见便论心素。","浅黛娇蝉风调别，最动人、时时偷顾。","归去。","想闲窗深院，调弦促柱。","乐府初翻新谱。","漫裁红点翠，闲题金缕。","燕子入帘时，又一番春暮。","侧帽燕脂坡下过，料也记、前年崔护。","休诉。","待从今须与，好花为主。"],"source":"宋词"},{"title":"风流子","author":"陆游","dynasty":"宋","form":"词","lines":["佳人多命薄，初心慕、德耀嫁梁鸿。","记绿窗睡起，静吟闲咏，句翻离合，格变玲珑。","更乘兴，素纨留戏墨，纤玉抚孤桐。","蟾滴夜寒，水浮微冻，凤笺春丽，花砑轻红。","人生谁能料，堪悲处、身落柳陌花丛。","空羡画堂鹦鹉，深闭金笼。","向宝镜鸾钗，临妆常晚，绣茵牙版，催舞还慵。","肠断市桥月笛，灯院霜锺。"],"source":"宋词"},{"title":"双头莲","author":"陆游","dynasty":"宋","form":"词","lines":["风卷征尘，堪叹处、青骢正摇金辔。","客襟贮泪。","漫万点如血，凭谁持寄。","伫想艳态幽情，压江南佳丽。","春正媚。","怎忍长亭，匆匆顿分连理。","目断淡日平芜，望烟浓树远，微茫如荠。","悲欢梦里。","奈倦客、又是关河千里。","最苦唱彻骊歌，重迟留无计。","何限事。","待与丁宁，行时已醉。"],"source":"宋词"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["杖屦寻春苦未迟。","洛城樱笋正当时。","三千界外归初到，五百年前事总知。","吹玉笛，渡清伊。","相逢休问姓名谁。","小车处士深衣叟，曾是天津共赋诗。"],"source":"宋词"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["禹庙兰亭今古路。","一夜清霜，染尽湖边树。","鹦鹉杯深君莫诉。","他时相遇知何处。","冉冉年华留不住。","镜里朱颜，毕竟消磨去。","一句丁宁君记取。","神仙须是闲人做。"],"source":"宋词"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["石帆山下雨空濛。","三扇香新翠箬篷。","苹叶绿，蓼花红。","回首功名一梦中。"],"source":"宋词"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["晴山滴翠水挼蓝。","聚散渔舟两复三。","横埭北，断桥南。","侧起船篷便作帆。"],"source":"宋词"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["镜湖俯仰两青天。","万顷玻璃一叶船。","拈棹舞，拥蓑眠。","不作天仙作水仙。"],"source":"宋词"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["湘湖烟雨长莼丝。","菰米新炊滑上匙。","云散后，月斜时。","潮落舟横醉不知。"],"source":"宋词"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["长安拜免几公卿。","渔父横眠醉未醒。","烟艇小，钓车腥。","遥指梅山一点青。"],"source":"宋词"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["雨断西山晚照明。","悄无人、幽梦自惊。","说道去、多时也，到如今、真个是行。","远山已是无心画，小楼空、斜掩绣屏。","你嚎早、收心呵，趁刘郎、双鬓未星。"],"source":"宋词"},{"title":"采桑子","author":"陆游","dynasty":"宋","form":"词","lines":["三山山下闲居士，巾履萧然。","小醉闲眠。","风引飞花落钓船。"],"source":"宋词"},{"title":"水龙吟","author":"陆游","dynasty":"宋","form":"词","lines":["摩诃池上追游路，红绿参差春晚。","韶光妍媚，海棠如醉，桃花欲暖。","挑菜初闲，禁烟将近，一城丝管。","看金鞍争道，香车飞盖，争先占、新亭馆。","惆怅年华暗换。","黯销魂、雨收云散。","镜奁掩月，钗梁拆凤，秦筝斜雁。","身在天涯，乱山孤垒，危楼飞观。","叹春来只有，杨花和恨、向东风满。"],"source":"宋词"},{"title":"月照梨花・河传","author":"陆游","dynasty":"宋","form":"词","lines":["霁景风软，烟江春涨。","小阁无人，绣帘半上。","花外姊妹相呼。","约樗蒲。","修蛾忘了章台样。","细思一饷。","感事添惆怅。","胸酥臂玉消减，拟觅双鱼。","倩传书。"],"source":"宋词"},{"title":"月照梨花・河传","author":"陆游","dynasty":"宋","form":"词","lines":["闷已萦损。","那堪多病。","几曲屏山，伴人昼静。","梁燕催起犹慵。","换熏龙。","新愁旧恨何时尽。","渐凋绿鬓。","小雨知花信。","芳笺寄与何处，绣阁珠栊。","柳阴中。"],"source":"宋词"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["宴罢珠帘半卷。","画檐外、蜡香人散。","翠雾霏霏漏声断。","倚香肩，看中庭，花影乱。","宛是高唐馆。","宝奁炷、麝烟初暖。","璧月何妨夜夜满。","拥芳柔，恨今年，寒尚浅。"],"source":"宋词"},{"title":"如梦令","author":"陆游","dynasty":"宋","form":"词","lines":["独倚博山峰小。","翠雾满身飞绕。","只恐学行云，去作阳台春晓。","春晓。","春晓。","满院绿阳芳草。"],"source":"宋词"},{"title":"失调名","author":"陆游","dynasty":"宋","form":"词","lines":["飞上锦裀红皱。"],"source":"宋词"},{"title":"解连环","author":"陆游","dynasty":"宋","form":"词","lines":["泪淹妆薄。","背东风伫立，柳绵池阁。","漫细字、书满芳笺，恨钗燕筝鸿，总难凭托。","风雨无情，又颠倒、绿苔红萼。","仗香醪破闷，怎禁夜阑，酒酲萧索。","刘郎已望故约。","奈重门静院，光景如昨。","尽做它、别有留心，便不念当时，雨意初著。","京兆眉残，怎忍为、新人梳掠。","尽今生、拼了为伊，任人道错。"],"source":"宋词"},{"title":"大圣乐","author":"陆游","dynasty":"宋","form":"词","lines":["电转雷惊，自叹浮生，四十二年。","试思量往事，虚无似梦，悲欢万状，合散如烟。","苦海无边，爱河无底，流浪看成百漏船。","何人解，问无常火里，铁打身坚。","须臾便是华颠。","好收拾形体归自然。","又何通，是非荣辱，此事由来都在天。","从今去，任东西南北，作个飞仙。"],"source":"宋词"},{"title":"桂枝香","author":"王安石","dynasty":"宋","form":"词","lines":["登临送目。","正故国晚秋，天气初肃。","千里澄江似练，翠峰如簇。","归帆去棹残阳里，背西风、酒旗斜矗。","彩舟云淡，星河鹭起，画图难足。","念往昔、繁华竞逐。","叹门外楼头，悲恨相续。","千古凭高，对此漫嗟荣辱。","六朝旧事随流水，但寒烟、芳草凝绿。","至今商女，时时犹唱，后庭遗曲。"],"source":"宋词"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["折得一枝香在手。","人间应未有。","疑是经春雪未消。","今日是何朝。"],"source":"宋词"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["尽日含毫难比兴。","都无色可并。","万里晴天何处来。","真是屑琼瑰。"],"source":"宋词"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["天寒日暮山谷里。","的砾愁成水。","池上渐多枝上稀。","唯有故人知。"],"source":"宋词"},{"title":"菩萨蛮","author":"王安石","dynasty":"宋","form":"词","lines":["数家茅屋闲临水。","单衫短帽垂杨里。","今日是何朝。","看予度石桥。","梢梢新月偃。","午醉醒来晚。","何物最关情。","黄鹂三两声。"],"source":"宋词"},{"title":"渔家傲","author":"王安石","dynasty":"宋","form":"词","lines":["灯火已收正月半。","山南山北花撩乱。","闻说洊亭新水漫。","骑款段。","穿云入坞寻游伴。","却拂僧床褰素幔。","千岩万壑春风暖。","一弄松声悲急管。","吹梦断。","西看窗日犹嫌短。"],"source":"宋词"},{"title":"渔家傲","author":"王安石","dynasty":"宋","form":"词","lines":["平岸小桥千嶂抱。","柔蓝一水萦花草。","茅屋数间窗窈窕。","尘不到。","时时自有春风扫。","午枕觉来闻语鸟。","敧眠似听朝鸡早。","忽忆故人今总老。","贪梦好。","茫然忘了邯郸道。"],"source":"宋词"},{"title":"雨霖铃","author":"王安石","dynasty":"宋","form":"词","lines":["孜孜矻矻。","向无明里、强作窠窟。","浮名浮利何济，堪留恋处，轮回仓猝。","幸有明空妙觉，可弹指超出。","缘底事、抛了全潮，认一浮沤作瀛渤。","本源自性天真佛。","祗些些、妄想中埋没。","贪他眼花阳艳，谁信道、本来无物。","一旦茫然，终被阎罗老子相屈。","便纵有、千种机筹，怎免伊唐突。"],"source":"宋词"},{"title":"清平乐","author":"王安石","dynasty":"宋","form":"词","lines":["云垂平野。","掩映竹篱茅舍。","阒寂幽居实潇洒。","是处绿娇红冶。","丈夫运用堂堂。","且莫五角六张。","若有一卮芳酒，逍遥自在无妨。"],"source":"宋词"},{"title":"浣溪沙","author":"王安石","dynasty":"宋","form":"词","lines":["百亩中庭半是苔。","门前白道水萦回。","爱闲能有几人来。","小院回廊春寂寂，山桃溪杏两三栽。","为谁零落为谁开。"],"source":"宋词"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["常时黄色见眉间。","松桂我同攀。","每言天上辛苦，不肯饵金丹。","怜水静，爱云闲。","便忘还。","高歌一曲，岩谷迤逦，宛似商山。"],"source":"宋词"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["练巾藜杖白云间。","有兴即跻攀。","追思往昔如梦，华毂也曾丹。","尘自扰，性长闲。","更无还。","达如周召，穷似丘轲，祗个山山。"],"source":"宋词"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["茫然不肯住林间。","有处即追攀。","将他死语图度，怎得离真丹。","浆水价，匹如闲。","也须还。","何如直截，踢倒军持，赢取沩山。"],"source":"宋词"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["营巢燕子逞翱翔。","微志在雕梁。","碧云举翮千里，其奈有鸾皇。","临济处，德山行。","果承当。","自时降住，一切天魔，扫地焚香。"],"source":"宋词"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["莫言普化祗颠狂。","真解作津梁。","蓦然打个筋斗，直跳过羲皇。","临济处，德山行。","果承当。","将他建立，认作心诚，也是寻香。"],"source":"宋词"},{"title":"诈妮子调风月・仙吕/点绛唇","author":"关汉卿","dynasty":"元","form":"曲","lines":["半世为人，不曾教大人心困。","虽是搽胭粉，只争不裹头巾，将那等不做人的婆娘恨。"],"source":"元曲"},{"title":"诈妮子调风月・混江龙","author":"关汉卿","dynasty":"元","form":"曲","lines":["男儿人若不依本分，一个抢白是非两家分。","壮鼻凹硬如石铁，教满耳根都做了烧云。","普天下汉子尽教都先有意，牢把定自己休不成人。","虽然两家无意，便待一面成亲，不分晓便似包着一肚皮干牛粪。","知人无意，及早抽身。"],"source":"元曲"},{"title":"诈妮子调风月・那吒令","author":"关汉卿","dynasty":"元","form":"曲","lines":["等不得水温，一声要面盆；恰递与面盆，一声要手巾；却执与手巾，一声解纽门。","使的人无淹润、百般支分！。"],"source":"元曲"},{"title":"诈妮子调风月・鹊踏枝","author":"关汉卿","dynasty":"元","form":"曲","lines":["入得房门，怎回身？厅独卧房儿窄窄别别，有甚铺呈？燕燕己身有甚么孝顺？拗不过哥哥行在意殷勤。"],"source":"元曲"},{"title":"诈妮子调风月・寄生草","author":"关汉卿","dynasty":"元","form":"曲","lines":["卧地观经史，坐地对圣人。","你观的国风、雅、颂施诂训，诵的典谟训诰居尧舜，（末云了）（正旦唱）说的温良恭俭行忠信。","燕燕子理会得龙盘虎踞灭燕齐，谁会甚儿婚女聘成秦晋？（末云）这书院好。"],"source":"元曲"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["这书房存得阿马，会得客宾。","翠筠月朗龙蛇印，碧轩夜冷灯香信，绿窗雨细琴书润。","每朝席上宴佳宾，抵多少\"十年窗下无人问\"！（末云住）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・村里迓鼓","author":"关汉卿","dynasty":"元","form":"曲","lines":["更做道一家生女，百家求问。","才说贞烈，那里取一个时辰？见他语言儿栽排得淹润，怕不待言词硬，性格村、他怎比寻常世人？（末云了）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・元和令","author":"关汉卿","dynasty":"元","form":"曲","lines":["无男儿只一身，担寂寞受孤闷；有男儿呓梦入劳魂，心肠百处分。","知得有情人不曾来问肯，便待要成眷姻。"],"source":"元曲"},{"title":"诈妮子调风月・上马娇","author":"关汉卿","dynasty":"元","form":"曲","lines":["自勘婚，自说亲，也是\"贱媳妇责媒人\"。","往常我冰清玉洁难亲近，是他亲，子管教话儿亲。","我煞待嗔，我便恶相闻。"],"source":"元曲"},{"title":"诈妮子调风月・胜葫芦","author":"关汉卿","dynasty":"元","form":"曲","lines":["怕不依随蒙君一夜恩，争奈忒达地、忒知根，兼上亲上成亲好对门。","觑了他兀的模样，这般身分。","若脱过这好郎君。"],"source":"元曲"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["教人道\"眼里无珍一世贫\"；成就了又怕辜恩。","若往常烈焰飞腾情性紧，若一遭儿恩爱，再来不问，枉侵了这百年恩。"],"source":"元曲"},{"title":"诈妮子调风月・柳叶儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["一个个背槽抛粪，一个个负义忘恩，自来鱼雁无音信。","自思忖，不审得话儿真，枉葫芦提了\"燕尔新婚。"],"source":"元曲"},{"title":"诈妮子调风月・尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["忽地却掀帘，兜地回头问，不由我心儿里便亲。","你把那并枕睡的日头儿再定轮，休教我逐宵价握雨携云。","过今春，先教我不系腰裙，便是半簸箕头钱扑个复纯。","教人道\"眼里有珍\"，你可休\"言而无信\"！（云）许下我包髻、团衫、绣手巾。","专等你世袭千户的小夫人。","（下）。"],"source":"元曲"},{"title":"诈妮子调风月・中吕/粉蝶儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["年例寒食，邻姬每斗来邀会，去年时没人将我拘管收拾。","打秋千，闲斗草，直到个昏天黑地；今年个不敢来迟，有一个未拿着性儿女婿。"],"source":"元曲"},{"title":"诈妮子调风月・醉春风","author":"关汉卿","dynasty":"元","form":"曲","lines":["因甚把玉粳米牙儿抵，金莲花攒枕倚？或嗔或喜脸儿多？哎！你、你！教我没想没思，两心两意，早晨古自一家一计！。"],"source":"元曲"},{"title":"诈妮子调风月・朱履曲","author":"关汉卿","dynasty":"元","form":"曲","lines":["莫不是郊外去逢着甚邪祟？又不疯又不呆痴，面没罗、呆答孩、死堆灰。","这烦恼在谁身上？莫不在我根底，打听得些闲是非？。"],"source":"元曲"},{"title":"诈妮子调风月・满庭芳","author":"关汉卿","dynasty":"元","form":"曲","lines":["见我这般微微喘息，语言恍惚，脚步儿查梨。","慢松松胸带儿频那系，裙腰儿空闲里偷提。","见我这般气丝丝偏斜了髟。"],"source":"元曲"},{"title":"诈妮子调风月・十二月","author":"关汉卿","dynasty":"元","form":"曲","lines":["直到个天昏地黑，不肯更换衣袂；把兔鹘解开，纽扣相离，把袄子疏剌剌松开上拆，将手帕撇漾在田地。"],"source":"元曲"},{"title":"诈妮子调风月・尧民歌","author":"关汉卿","dynasty":"元","form":"曲","lines":["见那厮手慌脚乱紧收拾，被我先藏在香罗袖儿里。","是好哥哥和我做头敌，咱两个官司有商议。","休提！体提！哥哥撇下的手帕是阿谁的？（末云了）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・江儿水","author":"关汉卿","dynasty":"元","form":"曲","lines":["老阿者使将来伏侍你，展污了咱身起。","你养着别个的，看我如奴婢，燕燕那些儿亏负你？（旦做住）（末告科）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・上小楼","author":"关汉卿","dynasty":"元","form":"曲","lines":["我敢摔碎这盒子，玳瑁纳子，教石头砸碎。","（带云）这手帕。","（唱）剪了做靴檐，染了做鞋面，持了做铺持。","一万分好待你，好觑你！如今刀子根底，我敢割得来粉零麻碎！。"],"source":"元曲"},{"title":"诈妮子调风月・幺","author":"关汉卿","dynasty":"元","form":"曲","lines":["更做道你好处打唤来的，却怎看得非轻，看得值钱，待得尊贵？这两下里捻捎的，有多少功绩，到重如细搀绒绣来胸背？。"],"source":"元曲"},{"title":"诈妮子调风月・哨遍","author":"关汉卿","dynasty":"元","form":"曲","lines":["并不是婆娘人把你抑勒，招取那肯心儿自说来的神前誓。","天果报，无差移，子争个来早来迟。","限时刻，十王地藏，六道轮回，单劝化人间世。","善恶天心人意，\"人间私语，天闻若雷\"。","但年高都是积善好心人；早寿夭都是辜恩负德贼。","好说话清晨，变了卦今日，冷了心晚夕。"],"source":"元曲"},{"title":"诈妮子调风月・五煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["别人斩眉我早举动眼，道头知道尾。","你这般沙糖般甜话儿多曾吃！你又不是\"残花酝酿蜂儿蜜，细雨调和燕子泥\"。","自笑我狂踪迹。","我往常受那无男儿烦恼，今日知有丈夫滋味。"],"source":"元曲"},{"title":"诈妮子调风月・四煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["待争来怎地争？待悔来怎地悔？怎补得我这有气分全身体？打也阿儿包髻，真加要带与别人成美，况团衫怎能勾披？他若不在俺宅司内，便大家南北，各自东西！。"],"source":"元曲"},{"title":"诈妮子调风月・三煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["明日索一般供与他衣袂穿，一般过与他茶饭吃，到晚送得他被底成双睡。","他\"做成暖帐三更梦\"，我\"拨尽寒炉一夜灰\"。","有句话存心记：则愿得辜恩负德，一个个荫于封妻！。"],"source":"元曲"},{"title":"诈妮子调风月・二煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["出门来一脚高一脚低，自不觉鞋底儿着田地。","痛连心除他外谁根前说，气夯破肚别人行怎又不敢提？独自向银蟾底，则道是孤鸿伴影，几时吃四马攒蹄？。"],"source":"元曲"},{"title":"诈妮子调风月・尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["呆敲才、呆敲才休怨天；死贱人、死贱人自骂你！本待要皂腰裙，刚待要蓝包髻，则这的是折挂攀高落得的！（下）。"],"source":"元曲"},{"title":"诈妮子调风月・越调/斗鹌鹑","author":"关汉卿","dynasty":"元","form":"曲","lines":["短叹长吁，千声万声；捣枕捶床，到三更四更。","便似止渴思梅，充饥画饼，因甚顷刻体？则伤我取次成。","好个个舒心，干支刺没兴。"],"source":"元曲"},{"title":"诈妮子调风月・紫花儿序","author":"关汉卿","dynasty":"元","form":"曲","lines":["好轻乞列薄命，热忽刺姻缘，短古取恩情。","（见灯蛾科，云）哎！蛾儿，俺两个有比喻：见一个耍蛾儿来往向烈焰上飞腾，正撞着银灯，拦头送了性命。","咱两个堪为比并：我为那包譬白身，你为这灯火青荧。"],"source":"元曲"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["我把这银灯来指定，引了咱两个魂灵，都是这一点虚名。","怕不百伶百俐，千战千赢，更做道\"能行怎离得影\"？这一场其身不正，怎当那厮大四至铺排，小夫人名称？。"],"source":"元曲"},{"title":"诈妮子调风月・梨花儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["是教我软地上吃交，我也不共你争。","煞是多劳重，降尊临卑，（云）有劳长者车马，贵脚踏于贱地，小的每多谢承。","本待麻线道上不和你一处行；（云）你依得我一件事，依得我愿随鞭镫。","（云）你要我饶你咱，再对星月赌一个誓。","（云了）（出门了）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・紫花儿序","author":"关汉卿","dynasty":"元","form":"曲","lines":["你把遥天指定，指定那淡月疏星，再说一个海誓山盟；我便收撮了火性，铺撒了人情，忍气吞声，饶过你那亏人不志诚。","赚出门程，（入房科）呼的关上栊门，铺的吹灭残灯。"],"source":"元曲"},{"title":"诈妮子调风月・小桃红","author":"关汉卿","dynasty":"元","form":"曲","lines":["燕燕上复传示煞曾经，谁会甚儿女成婚聘？甚的是许出羞、下红定？问这洛阳城，少甚么能言快语官媒证？燕燕怎敢假名托姓？但教我一权为政，情取\"火上等冬凌\"。"],"source":"元曲"},{"title":"诈妮子调风月・调笑令","author":"关汉卿","dynasty":"元","form":"曲","lines":["这厮短命，没前程，做得个\"轻人还自轻\"，横死口里栽排定。","老夫人随邪水性，道我能言快语说合成，我说波娘七代先灵！，。"],"source":"元曲"},{"title":"诈妮子调风月・圣药王","author":"关汉卿","dynasty":"元","form":"曲","lines":["然道户厮迎，也合再打听，两门亲便走一遭儿成。","我若到那户庭，见那婢婷，若是那女孩儿言语没实诚，俺这厮强风情。","（虚下）（外孤上）（旦上，见孤云）夫人使来问小姐亲事，相公许不许，燕燕回去。","（外孤云了）（闪下）（外旦上）（旦随上，见了，云）特地来问小姐亲事，许不许？回去。","（外旦许了）（正旦唱）。"],"source":"元曲"},{"title":"诈妮子调风月・天净沙","author":"关汉卿","dynasty":"元","form":"曲","lines":["先教人掩扑了我几夜恩情，来这里被他骂得我百节酸疼，我便似□墙贼蝎蜇呼声。","空使心作幸，被小夫人引了我魂灵。"],"source":"元曲"},{"title":"诈妮子调风月・拙鲁速","author":"关汉卿","dynasty":"元","form":"曲","lines":["终身无簸箕星，指云中雁做羹。","时下且口口声声，战战兢兢，袅袅婷婷，坐坐行行；有一日孤孤另另，冷冷清清，咽咽哽哽，觑着你个拖汉精！。"],"source":"元曲"},{"title":"诈妮子调风月・收尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["大刚来\"主人有福牙推胜\"，不似这调风月媒人背厅。","说得他美甘甘枕头儿上双成，闪得我薄设设被窝儿里冷！（下）。"],"source":"元曲"},{"title":"诈妮子调风月・双调/新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["双撒敦是部尚书，女婿是世袭千户。","有二百匹金勒马，五十辆画轮车。","说得他儿女妻夫，似水如鱼；撇得我鳏寡孤独，那的是撮合山养身处？。"],"source":"元曲"},{"title":"诈妮子调风月・驻马听","author":"关汉卿","dynasty":"元","form":"曲","lines":["官人石碾连珠，满腰背无瑕玉免鹘；夫人每是依时按序，细搀绒全套绣衣服。","包髻是缨络大真珠，额花是秋色玲珑玉。","悠悠的品着鹧鸪，雁行般但举手都能舞。"],"source":"元曲"},{"title":"诈妮子调风月・甜水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["姐姐骨甜肉净，堪描堪塑。","生得肌肤似凝酥。","从小里梅香、嬷嬷抬举，问燕燕梳裹何如？。"],"source":"元曲"},{"title":"诈妮子调风月・水仙子","author":"关汉卿","dynasty":"元","form":"曲","lines":["推那领系眼落处，采揪住那系腰行行掐胯骨。","我这般拈拈掐掐有甚难当处？想我那声冤不得苦痛处。","你不合先发头怒；你若无言语，怎敢将你觑付，你则索做使长、郎主。"],"source":"元曲"},{"title":"诈妮子调风月・殿前欢","author":"关汉卿","dynasty":"元","form":"曲","lines":["俺千户跨龙驹，称得上的敢望七香车。","愿结同心结，永挂合欢树。","蛮凤娇雏，连理枝比目鱼。","千载相完聚，花发无风雨。","头白相守，眼黑处全无。"],"source":"元曲"},{"title":"诈妮子调风月・乔牌儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["勘婚处恰岁数，出嫁后有衣禄。","若言招女婿，下财钱将娶过去。"],"source":"元曲"},{"title":"诈妮子调风月・挂玉钩","author":"关汉卿","dynasty":"元","form":"曲","lines":["是个破败家私铁扫帚，没些儿发旺夫家处，可更绝子嗣、妨公婆、克丈夫，脸上承泪靥无重数。","今年见吊客临，丧门聚；反阴覆阴，半载其余。"],"source":"元曲"},{"title":"诈妮子调风月・落梅风","author":"关汉卿","dynasty":"元","form":"曲","lines":["据着生的年月，演的岁数，不是个义夫节妇，休想得五男并二女，死得教灭门绝户！（夫人云了）（旦跪唱）。"],"source":"元曲"},{"title":"诈妮子调风月・雁儿落","author":"关汉卿","dynasty":"元","form":"曲","lines":["燕燕那书房中伏侍处，许第二个夫人做。","他须是人身人面皮，人口人言语！。"],"source":"元曲"},{"title":"诈妮子调风月・得胜令","author":"关汉卿","dynasty":"元","form":"曲","lines":["到如今总是彻梢虚，燕燕不是石头镌、铁头做；教我死临侵身无措，错支刺心受苦。","（夫人云了）（正旦唱）瘫痪着身躯，教我两下里难停住；气夯破胸脯，教燕燕两下里没是处。"],"source":"元曲"},{"title":"诈妮子调风月・阿古令","author":"关汉卿","dynasty":"元","form":"曲","lines":["满盏内盈盈绿醑，子合当作婢为奴。","谢相公、夫人抬举，怎敢做三妻两妇？子得和丈夫一处对舞，便是燕燕花生满路。"],"source":"元曲"},{"title":"正宫・白鹤子（四首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["四时春富贵，万物酒风流。","澄澄水如蓝，灼灼花如绣。","（之一）花边停骏马，柳外缆轻舟。","湖内画船交，湖上骅骝骤。","（之二）鸟啼花影里，人立粉墙头。","春意两丝牵，秋水双波溜。","（之三）香焚金鸭鼎，闲傍小红楼。","月在柳梢头，人约黄昏后。","（之四）。"],"source":"元曲"},{"title":"南吕・四块玉别情","author":"关汉卿","dynasty":"元","form":"曲","lines":["自送别，心难舍，一点相思几时绝？凭阑袖拂杨花雪。","溪又斜，山又遮，人去也！。"],"source":"元曲"},{"title":"南吕・四块玉闲适（四首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["适意行，安心坐，渴时饮饥时餐醉时歌，困来时就向莎茵卧。","日月长，天地阔，闲快活！（之一）旧酒投，新醅泼，老瓦盆边笑呵呵，共山僧野叟闲吟和。","他出一对鸡，我出一个鹅，闲快活！（之二）意马多，心猿锁，跳出红尘恶风波，槐阴午梦谁惊破？离了利名场，钻入安乐窝，闲快活！（之三）南亩耕，东山卧，世态人情经历多，闲将往事思量过。","贤的是他，愚的是我，争甚么！（之四）。"],"source":"元曲"},{"title":"中吕・朝天子书所见","author":"关汉卿","dynasty":"元","form":"曲","lines":["鬓鸦，脸霞，屈杀将陪嫁。","规模全是大人家，不在红娘下。","笑眼偷瞧，文谈回话，真如解语花。","若咱得他，倒了葡萄架。"],"source":"元曲"},{"title":"商调・梧叶儿别情","author":"关汉卿","dynasty":"元","form":"曲","lines":["别离易，相见难，何处锁雕鞍？春将去，人未还。","这其间，殃及杀愁眉泪眼。"],"source":"元曲"},{"title":"双调・大德歌（四首）春","author":"关汉卿","dynasty":"元","form":"曲","lines":["子规啼，不如归，道是春归人未归。","几日添憔悴，虚飘飘柳絮飞。","一春鱼雁无消息，则见双燕斗衔泥。","夏俏冤家，在天涯，偏那里绿杨堪系马？困坐南窗下，数对清风想念他。","蛾眉淡了教谁画？瘦岩岩羞带石榴花。","秋风飘飘，雨潇潇，便做陈抟睡不着。","懊恼伤怀抱，扑簌簌泪点抛。","秋蝉儿噪罢寒蛩儿叫，淅零零细雨打芭蕉。","冬雪纷纷，掩重门，不由人不断魂，瘦损江梅韵。","那里是清江江上村？香闺里冷落谁瞅问？好一个憔悴的凭阑人！。"],"source":"元曲"},{"title":"双调・大德歌（六首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["粉墙低，景凄凄，正是那西厢月上时。","会得琴中意，我是个香闺里钟子期。","好教人暗想张君瑞，敢则是爱月夜眠迟。","（之一）绿杨堤，画船儿，正撞着一帆风赶上水。","冯魁吃的醺醺醉，怎想着金山寺壁上诗。","醒来不见多姝丽，冷清清空载月明归。","（之二）郑元和，受寂寞，道是你无钱怎奈何？哥哥家缘破，谁着你摇铜铃唱换歌。","因打亚仙门前过，恰便是司马泪痕多。","（之三）谢家村，赏芳春，疑怪他桃花冷笑人。","着谁传芳信，强题诗也断魂。","花阴下等待无人问，则听得黄犬吠柴门。","（之四）雪粉华，舞梨花，再不见烟村四五家。","密洒堪图画，看疏林噪晚鸦。","黄芦掩映清江下，斜缆着钓鱼航模。","（之五）吹一个，弹一个，唱新行大德歌。","快活休张罗，想人生能几何？十分淡薄随缘过，得磨陀处且磨陀。","（之六）套数。"],"source":"元曲"},{"title":"黄钟・侍香金童","author":"关汉卿","dynasty":"元","form":"曲","lines":["春闺院宇，柳絮飘香雪。","帘幕轻寒雨乍歇，东风落花迷粉蝶。","芍药初开，海棠才谢。"],"source":"元曲"},{"title":"幺・柔肠脉脉，新愁千万叠。偶记年前人乍别，秦台玉萧声断绝。雁底关","author":"关汉卿","dynasty":"元","form":"曲","lines":["河，马头明月。"],"source":"元曲"},{"title":"降黄龙衮・鳞鸿无个，锦笺慵写。腕松金，肌削玉，罗衣宽彻。泪痕淹破，","author":"关汉卿","dynasty":"元","form":"曲","lines":["胭脂双颊。","宝鉴愁临，翠钿羞贴。"],"source":"元曲"},{"title":"幺・等闲辜负，好天良夜。玉炉中，银台上，香消烛灭。凤帏冷落，鸳衾","author":"关汉卿","dynasty":"元","form":"曲","lines":["虚设，玉笋频搓，绣鞋重扌颠。"],"source":"元曲"},{"title":"幺・铜壶玉漏催凄切，正更阑人静也。金闺潇洒转伤嗟，莲步轻移呼侍妾：","author":"关汉卿","dynasty":"元","form":"曲","lines":["“把香桌儿安排打快些。"],"source":"元曲"},{"title":"仙吕・翠裙腰闺怨","author":"关汉卿","dynasty":"元","form":"曲","lines":["晓来雨过山横秀，野水涨汀洲。","阑干倚遍空回首。","下危楼，一天风物暮伤秋。"],"source":"元曲"},{"title":"六幺遍・乍凉时候，西风透。碧梧脱叶，余暑才收。香生凤口，帘垂玉钩，","author":"关汉卿","dynasty":"元","form":"曲","lines":["小院深闲清昼。","清幽，听声声蝉噪柳梢头。"],"source":"元曲"},{"title":"寄生草・为甚忧，为甚愁？为萧郎一去经今久。玉台宝鉴生尘垢，绿窗冷","author":"关汉卿","dynasty":"元","form":"曲","lines":["落闲针锈。","岂知人玉腕钏儿松，岂知人两叶眉儿皱！。"],"source":"元曲"},{"title":"后庭花煞・掩袖暗含羞，开樽越酿愁。闷把苔墙画，慵将锦字修。最风流，","author":"关汉卿","dynasty":"元","form":"曲","lines":["真真恩爱，等闲分付等闲休。"],"source":"元曲"},{"title":"南吕・一枝花赠朱帘秀","author":"关汉卿","dynasty":"元","form":"曲","lines":["轻裁虾万须，巧织珠千串；金钩光错落，绣带舞蹁跹。","似雾非烟，妆点就深闺院，不许那等闲人取次展。","摇四壁翡翠浓阴，射万瓦琉璃色浅。"],"source":"元曲"},{"title":"梁州・富贵似侯家紫帐，风流如谢府红莲，锁春愁不放双飞燕。绮窗相近，","author":"关汉卿","dynasty":"元","form":"曲","lines":["翠户相连，雕栊相映，绣幕相牵。","拂苔痕满砌榆钱，惹杨花飞点如锦。","愁的是抹回廊暮雨萧萧，恨的是筛曲槛西风剪剪，爱的是透长门夜月娟娟。","凌波殿前，碧玲珑掩映湘妃面，没福怎能够见？十里扬州风物妍，出落着神仙。"],"source":"元曲"},{"title":"南吕・一枝花杭州景","author":"关汉卿","dynasty":"元","form":"曲","lines":["普天下锦绣乡，寰海内风流地。","大元朝新附国，亡宋家旧华夷。","水秀山奇，一到处堪游戏。","这答儿忒富贵，满城中绣幕风帘，一哄地人烟辏集。"],"source":"元曲"},{"title":"梁州・百十里街衢整齐，万余家楼阁参差，并无半答儿闲田地。松轩竹径，","author":"关汉卿","dynasty":"元","form":"曲","lines":["药圃花蹊，茶园稻陌，竹坞梅溪。","一陀儿一句诗题，行一步扇面屏帏。","西盐场便似一带琼瑶，吴山色千叠悲翠。","兀良，望钱塘江万顷玻璃。","更有清溪绿水，画船儿来往闲游戏。","浙江亭紧相对，相对着险岭高峰长怪石，堪羡堪题。"],"source":"元曲"},{"title":"尾・家家掩映渠流水，楼阁峥嵘出翠微。遥望西湖暮山势，看了这壁，觑","author":"关汉卿","dynasty":"元","form":"曲","lines":["了那壁，纵有丹青下不得笔。"],"source":"元曲"},{"title":"南吕・一枝花不伏老","author":"关汉卿","dynasty":"元","form":"曲","lines":["攀出墙朵朵花，折临路枝枝柳。","花攀红蕊嫩，柳折翠条柔，浪子风流。","凭着我折柳攀花手，直煞得花残柳败休。","半生来折柳攀花，一世里眠花卧柳。"],"source":"元曲"},{"title":"梁州・我是个普天下郎君领袖，盖世界浪子班头。愿朱颜不改常依旧，花","author":"关汉卿","dynasty":"元","form":"曲","lines":["中消遣，酒内忘忧。","分茶扌颠竹，打马藏阄；通五音六律滑熟，甚闲愁到我心头！伴的是银筝女银台前理银筝笑倚银屏，伴的是玉天仙携玉手并玉肩同登玉楼，伴的是金钗客歌《金缕》捧金樽满泛金瓯。","你道我老也，暂休。","占排场风月功名首，更玲珑又剔透。","我是个锦阵花营都帅头，曾玩府游州。"],"source":"元曲"},{"title":"隔尾・子弟每是个茅草冈、沙土窝初生的兔羔儿乍向围场上走，我是个经","author":"关汉卿","dynasty":"元","form":"曲","lines":["笼罩、受索网苍翎毛老野鸡踏踏的阵马儿熟。","经了些窝弓冷箭蜡枪头，不曾落人后。","恰不道“人到中年万事休”，我怎肯虚度了春秋。"],"source":"元曲"},{"title":"尾・我是个蒸不烂、煮不熟、捶不匾、炒不爆响当当一粒铜豌豆，恁子弟","author":"关汉卿","dynasty":"元","form":"曲","lines":["每谁教你钻入他锄不断、斫不下、解不开、顿不脱慢腾腾千层锦套头。","我玩的是梁园月，饮的是东京酒，赏的是洛阳花，攀的是章台柳。","我也会围棋、会蹴リ、会打围、会插科、会歌舞、会吹弹、会咽作、会吟诗、会双陆。","你便是落了我牙、歪了我嘴、瘸了我腿、折了我手，天赐与我这几般儿歹症候，尚兀自不肯休。","则除是阎王亲自唤，神鬼自来勾，三魂归地府，七魂丧冥幽，天那，那其间才不向烟花路儿上走！。"],"source":"元曲"},{"title":"中吕・古调石榴花闺思","author":"关汉卿","dynasty":"元","form":"曲","lines":["颠狂柳絮扑帘飞，绿暗红稀。","垂杨影里杜鹃啼，一弄儿断送了春归。","牡丹亭畔人寂静，恼芳心似醉如痴。","恹恹为他成病也，松金钏，褪罗衣。"],"source":"元曲"},{"title":"酥枣儿・一自相逢，将人来萦系。樽前席上，眼约心期。比及道是配合了，","author":"关汉卿","dynasty":"元","form":"曲","lines":["受了些闲是闲非。","咱各办着个坚心，要拨个终缘之计。"],"source":"元曲"},{"title":"鲍老儿・当初指望成家计，谁想琼簪碎；当初指望无抛弃，谁想银瓶坠。","author":"关汉卿","dynasty":"元","form":"曲","lines":["烦烦恼恼，哀哀怨怨，哭哭啼啼，回黄倒皂，长吁短叹，自跌自堆。"],"source":"元曲"},{"title":"墙头花・守香闺，镇日情如醉，闷懊恼离愁空教我诉与谁？愁闻的是紫燕","author":"关汉卿","dynasty":"元","form":"曲","lines":["关关，倦听的是黄莺呖呖。"],"source":"元曲"},{"title":"卖花声煞・愁山闷海不许当敌，好教我无一个百刂划，耐心儿多陪下些凄","author":"关汉卿","dynasty":"元","form":"曲","lines":["惶泪。","呼侍婢将绣帘低放，把重门深闭，怕莺花笑人憔悴。"],"source":"元曲"},{"title":"幺・天付两风流，翻成南北悠悠，落花流水人何处？相思一点，离愁几许，","author":"关汉卿","dynasty":"元","form":"曲","lines":["撮上心头。"],"source":"元曲"},{"title":"荼コ香・记得初相守，偶尔间因循成就，美满效绸缪。花朝月夜同宴赏，","author":"关汉卿","dynasty":"元","form":"曲","lines":["佳节须酬，到今一旦休。","常言道好事天悭，美姻缘他娘间阻，生拆散鸾交凤友。"],"source":"元曲"},{"title":"幺・坐想行思，伤怀感旧，各辜负了星前月下深深咒。愿不损，愁不煞，","author":"关汉卿","dynasty":"元","form":"曲","lines":["神天还佑。","他有日不测相逢，话别离情取一场消瘦。"],"source":"元曲"},{"title":"好观音煞・与怪友狂朋寻花柳，时复间和哄消愁。对着浪蕊浮花懒回首，","author":"关汉卿","dynasty":"元","form":"曲","lines":["怏怏归来，原不饮杯中酒。"],"source":"元曲"},{"title":"大石调・青杏子骋怀","author":"关汉卿","dynasty":"元","form":"曲","lines":["花月酒家楼，可追欢亦可悲秋。","悲欢聚散为常事，明眸皓齿，歌莺舞燕，各逞温柔。"],"source":"元曲"},{"title":"幺・人俊惜风流，欠前生酒病花愁。尚还不彻相思债，携云挈雨，批风切","author":"关汉卿","dynasty":"元","form":"曲","lines":["月，到处绸缪。"],"source":"元曲"},{"title":"催拍子・爱共寝花间锦鸠，恨孤眠水上白鸥。月宵花昼，大筵排回雪韦娘，","author":"关汉卿","dynasty":"元","form":"曲","lines":["小酌会窃香韩寿。","举觞红袖，玉纤横管，银甲调筝，酒令诗筹。","曲成诗就，韵协声律，情动魂消，腹稿冥搜，美恩当受。","水仙山鬼，月妹花妖，如还得遇，不许干休，会埋伏未尝泄漏。"],"source":"元曲"},{"title":"幺・群芳会首，繁英故友，梦回时绿肥红瘦。荣华过可见蔬薄，财物广始","author":"关汉卿","dynasty":"元","form":"曲","lines":["知亲厚。","慕新思旧，簪遗佩解，镜破钗分，蜂妒蝶羞。","恶缘难救，痼疾常发，业贯将盈，努力呈头。","冷餐重馏，口刀舌剑，吻槊唇枪，独攻决胜，混战无忧，不到得落人奸彀。"],"source":"元曲"},{"title":"天净沙・平生肥马轻裘，何须锦带吴钩？百岁光阴转首，休闲生受，叹功","author":"关汉卿","dynasty":"元","form":"曲","lines":["名似水上浮沤。"],"source":"元曲"},{"title":"寨儿冷・得自由，莫刚求。茶余饭饱邀故友，谢馆秦楼，散闷消愁，惟蹴","author":"关汉卿","dynasty":"元","form":"曲","lines":["リ最风流。","演习得踢打温柔，施逞得解数滑熟。","引脚蹑龙斩眼，担枪拐凤摇头。","一左一右，折叠鹘胜游。"],"source":"元曲"},{"title":"尾・锦缠腕、叶底桃、鸳鸯叩，入脚面带黄河逆流。斗白打赛官场，三场","author":"关汉卿","dynasty":"元","form":"曲","lines":["儿尽皆有。"],"source":"元曲"},{"title":"越调・斗鹌鹑又","author":"关汉卿","dynasty":"元","form":"曲","lines":["蹴リ场中，鸣珂巷里，南北驰名，寰中可意。","夹缝堪夸，抛声尽喜。","那换活，煞整齐。","款侧金莲，微那玉体。","唐裙轻荡，绣带斜飘，舞袖低垂。"],"source":"元曲"},{"title":"小桃红・装跷委实用心机，不枉了夸强会，女辈丛中最为贵。煞曾习，沾","author":"关汉卿","dynasty":"元","form":"曲","lines":["身那取着田地。","赶起了白踢，诸余里快收拾。"],"source":"元曲"},{"title":"秃厮儿・粉汗湿珍珠乱滴，宝髻偏鸦玉斜堆。虚蹬落实拾蹑起，侧身动，","author":"关汉卿","dynasty":"元","form":"曲","lines":["柳腰脆，丸惜。"],"source":"元曲"},{"title":"圣药王・甚旖旎，解数儿希，左盘右折煞曾习。甚整齐，省气力，旁行侧","author":"关汉卿","dynasty":"元","form":"曲","lines":["脚步频移，来往似粉蝶儿飞。"],"source":"元曲"},{"title":"尾・不离了花前柳影闲田地，斗白打官场小踢。竿网下世无双，全场儿占","author":"关汉卿","dynasty":"元","form":"曲","lines":["了第一。"],"source":"元曲"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["楚台云雨会巫峡，赴昨宵约来的期话。","楼头栖燕子，庭院已闻鸦，料想他家，收针指晚妆罢。"],"source":"元曲"},{"title":"乔牌儿・款将花径踏，独立在纱窗下，颤钦钦把不定心头怕。不敢将小名","author":"关汉卿","dynasty":"元","form":"曲","lines":["呼，咱则索等候他。"],"source":"元曲"},{"title":"挂搭钩・等候多时不见他，这的是约下佳期话，莫不是贪睡人儿忘了那？","author":"关汉卿","dynasty":"元","form":"曲","lines":["伏冢在蓝桥下。","意懊恼却待将他骂，听得呀的门开，蓦见如花。"],"source":"元曲"},{"title":"豆叶黄・髻挽乌云，蝉鬓堆鸦，粉腻酥胸，脸衬红霞；袅娜腰肢更喜恰，","author":"关汉卿","dynasty":"元","form":"曲","lines":["堪讲堪夸。","比月里嫦娥，媚媚孜孜，那更撑达。"],"source":"元曲"},{"title":"关雎","author":"佚名","dynasty":"先秦","form":"诗","lines":["关关雎鸠，在河之洲。窈窕淑女，君子好逑。","参差荇菜，左右流之。窈窕淑女，寤寐求之。","求之不得，寤寐思服。悠哉悠哉，辗转反侧。","参差荇菜，左右采之。窈窕淑女，琴瑟友之。","参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。"],"source":"《诗经》"},{"title":"葛覃","author":"佚名","dynasty":"先秦","form":"诗","lines":["葛之覃兮，施于中谷，维叶萋萋。黄鸟于飞，集于灌木，其鸣喈喈。","葛之覃兮，施于中谷，维叶莫莫。是刈是濩，为絺为绤，服之无斁。","言告师氏，言告言归。薄污我私，薄浣我衣。害浣害否，归宁父母。"],"source":"《诗经》"},{"title":"卷耳","author":"佚名","dynasty":"先秦","form":"诗","lines":["采采卷耳，不盈顷筐。嗟我怀人，置彼周行。","陟彼崔嵬，我马虺隤。我姑酌彼金罍，维以不永怀。","陟彼高冈，我马玄黄。我姑酌彼兕觥，维以不永伤。","陟彼砠矣，我马瘏矣，我仆痡矣，云何吁矣。"],"source":"《诗经》"},{"title":"樛木","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有樛木，葛藟累之。乐只君子，福履绥之。","南有樛木，葛藟荒之。乐只君子，福履将之。","南有樛木，葛藟萦之。乐只君子，福履成之。"],"source":"《诗经》"},{"title":"螽斯","author":"佚名","dynasty":"先秦","form":"诗","lines":["螽斯羽，诜诜兮。宜尔子孙，振振兮。","螽斯羽，薨薨兮。宜尔子孙。绳绳兮。","螽斯羽，揖揖兮。宜尔子孙，蛰蛰兮。"],"source":"《诗经》"},{"title":"桃夭","author":"佚名","dynasty":"先秦","form":"诗","lines":["桃之夭夭，灼灼其华。之子于归，宜其室家。","桃之夭夭，有蕡其实。之子于归，宜其家室。","桃之夭夭，其叶蓁蓁。之子于归，宜其家人。"],"source":"《诗经》"},{"title":"兔罝","author":"佚名","dynasty":"先秦","form":"诗","lines":["肃肃兔罝，椓之丁丁。赳赳武夫，公侯干城。","肃肃兔罝，施于中逵。赳赳武夫，公侯好仇。","肃肃免罝，施于中林。赳赳武夫，公侯腹心。"],"source":"《诗经》"},{"title":"芣苡","author":"佚名","dynasty":"先秦","form":"诗","lines":["采采芣苡，薄言采之。采采芣苡，薄言有之。","采采芣苡，薄言掇之。采采芣苡，薄言捋之。","采采芣苡，薄言袺之。采采芣苡，薄言襭之。"],"source":"《诗经》"},{"title":"汉广","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有乔木，不可休息。汉有游女，不可求思。汉之广矣，不可泳思。江之永矣，不可方思。","翘翘错薪，言刈其楚。之子于归，言秣其马。汉之广矣，不可泳思。江之永矣，不可方思。","翘翘错薪，言刈其蒌。之子于归。言秣其驹。汉之广矣，不可泳思。江之永矣，不可方思。"],"source":"《诗经》"},{"title":"汝坟","author":"佚名","dynasty":"先秦","form":"诗","lines":["遵彼汝坟，伐其条枚。未见君子，惄如调饥。","遵彼汝坟，伐其条肄。既见君子，不我遐弃。","鲂鱼赪尾，王室如毁。虽则如毁，父母孔迩。"],"source":"《诗经》"},{"title":"麟之趾","author":"佚名","dynasty":"先秦","form":"诗","lines":["麟之趾，振振公子，于嗟麟兮。","麟之定，振振公姓，于嗟麟兮。","麟之角，振振公族，于嗟麟兮。"],"source":"《诗经》"},{"title":"鹊巢","author":"佚名","dynasty":"先秦","form":"诗","lines":["维鹊有巢，维鸠居之。之子于归，百两御之。","维鹊有巢，维鸠方之。之子于归，百两将之。","维鹊有巢，维鸠盈之。之子于归，百两成之。"],"source":"《诗经》"},{"title":"采蘩","author":"佚名","dynasty":"先秦","form":"诗","lines":["于以采蘩？于沼于沚。于以用之？公侯之事。","于以采蘩？于涧之中。于以用之？公侯之宫。","被之僮僮，夙夜在公。被之祁祁，薄言还归。"],"source":"《诗经》"},{"title":"草虫","author":"佚名","dynasty":"先秦","form":"诗","lines":["喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。亦既见止，亦既觏止，我心则降。","陟彼南山，言采其蕨。未见君子，忧心惙惙。亦既见止，亦既觏止，我心则说。","陟彼南山，言采其薇。未见君子，我心伤悲。亦既见止，亦既觏止，我心则夷。"],"source":"《诗经》"},{"title":"采蘋","author":"佚名","dynasty":"先秦","form":"诗","lines":["于以采蘋？南涧之滨。于以采藻？于彼行潦。","于以盛之？维筐及筥。于以湘之？维锜及釜。","于以奠之？宗室牖下。谁其尸之？有齐季女。"],"source":"《诗经》"},{"title":"甘棠","author":"佚名","dynasty":"先秦","form":"诗","lines":["蔽芾甘棠，勿翦勿伐，召伯所茇。","蔽芾甘棠，勿翦勿败，召伯所憩。","蔽芾甘棠，勿翦勿拜，召伯所说。"],"source":"《诗经》"},{"title":"行露","author":"佚名","dynasty":"先秦","form":"诗","lines":["厌浥行露，岂不夙夜，谓行多露。","谁谓雀无角？何以穿我屋？谁谓女无家？何以速我狱？虽速我狱，室家不足！","谁谓鼠无牙？何以穿我墉？谁谓女无家？何以速我讼？虽速我讼，亦不女从！"],"source":"《诗经》"},{"title":"羔羊","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔羊之皮，素丝五紽。退食自公，委蛇委蛇。","羔羊之革，素丝五緎。委蛇委蛇，自公退食。","羔羊之缝，素丝五总。委蛇委蛇，退食自公。"],"source":"《诗经》"},{"title":"殷其雷","author":"佚名","dynasty":"先秦","form":"诗","lines":["殷其雷，在南山之阳。何斯违斯，莫敢或遑？振振君子，归哉归哉！","殷其雷，在南山之侧。何斯违斯，莫敢遑息？振振君子，归哉归哉！","殷其雷，在南山之下。何斯违斯，莫或遑处？振振君子，归哉归哉！"],"source":"《诗经》"},{"title":"摽有梅","author":"佚名","dynasty":"先秦","form":"诗","lines":["摽有梅，其实七兮。求我庶士，迨其吉兮。","摽有梅，其实三兮。求我庶士，迨其今兮。","摽有梅，顷筐塈之。求我庶士，迨其谓之。"],"source":"《诗经》"},{"title":"小星","author":"佚名","dynasty":"先秦","form":"诗","lines":["嘒彼小星，三五在东。肃肃宵征，夙夜在公。寔命不同！","嘒彼小星，维参与昴。肃肃宵征，抱衾与裯。寔命不犹！"],"source":"《诗经》"},{"title":"江有汜","author":"佚名","dynasty":"先秦","form":"诗","lines":["江有汜，之子归，不我以。不我以，其后也悔。","江有渚，之子归，不我与。不我与，其后也处。","江有沱，之子归，不我过。不我过，其啸也歌。"],"source":"《诗经》"},{"title":"野有死麕","author":"佚名","dynasty":"先秦","form":"诗","lines":["野有死麕，白茅包之。有女怀春，吉士诱之。","林有朴樕，野有死鹿。白茅纯束，有女如玉。","舒而脱脱兮，无感我帨兮，无使尨也吠。"],"source":"《诗经》"},{"title":"何彼襛矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["何彼襛矣，唐棣之华？曷不肃雍？王姬之车。","何彼襛矣，华如桃李？平王之孙，齐侯之子。","其钓维何？维丝伊缗。齐侯之子，平王之孙。"],"source":"《诗经》"},{"title":"驺虞","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼茁者葭，壹发五豝，于嗟乎驺虞！","彼茁者蓬，壹发五豵，于嗟乎驺虞！"],"source":"《诗经》"},{"title":"柏舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["泛彼柏舟，亦泛其流。耿耿不寐，如有隐忧。微我无酒，以敖以游。","我心匪鉴，不可以茹。亦有兄弟，不可以据。薄言往诉，逢彼之怒。","我心匪石，不可转也。我心匪席，不可卷也。威仪棣棣，不可选也。","忧心悄悄，愠于群小。觏闵既多，受侮不少。静言思之，寤辟有摽。","日居月诸，胡迭而微？心之忧矣，如匪浣衣。静言思之，不能奋飞。"],"source":"《诗经》"},{"title":"绿衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["绿兮衣兮，绿衣黄裹。心之忧矣，曷维其已！","绿兮衣兮，绿衣黄裳。心之忧矣，曷维其亡！","绿兮丝兮，女所治兮。我思古人，俾无訧兮！","絺兮绤兮，凄其以风。我思古人，实获我心！"],"source":"《诗经》"},{"title":"燕燕","author":"佚名","dynasty":"先秦","form":"诗","lines":["燕燕于飞，差池其羽。之子于归，远送于野。瞻望弗及，泣涕如雨。","燕燕于飞，颉之颃之。之子于归，远于将之。瞻望弗及，伫立以泣。","燕燕于飞，下上其音。之子于归，远送于南。瞻望弗及，实劳我心。","仲氏任只，其心塞渊。终温且惠，淑慎其身。先君之思，以勖寡人。"],"source":"《诗经》"},{"title":"日月","author":"佚名","dynasty":"先秦","form":"诗","lines":["日居月诸，照临下土。乃如之人兮，逝不古处？胡能有定？宁不我顾。","日居月诸，下土是冒。乃如之人兮，逝不相好。胡能有定？宁不我报。","日居月诸，出自东方。乃如之人兮，德音无良。胡能有定？俾也可忘。","日居月诸，东方自出。父兮母兮，畜我不卒。胡能有定？报我不述。"],"source":"《诗经》"},{"title":"终风","author":"佚名","dynasty":"先秦","form":"诗","lines":["终风且暴，顾我则笑，谑浪笑敖，中心是悼。","终风且霾，惠然肯来，莫往莫来，悠悠我思。","终风且曀，不日有曀，寤言不寐，愿言则嚏。","曀曀其阴，虺虺其雷，寤言不寐，愿言则怀。"],"source":"《诗经》"},{"title":"击鼓","author":"佚名","dynasty":"先秦","form":"诗","lines":["击鼓其镗，踊跃用兵。土国城漕，我独南行。","从孙子仲，平陈与宋。不我以归，忧心有忡。","爰居爰处？爰丧其马？于以求之？于林之下。","死生契阔，与子成说。执子之手，与子偕老。","于嗟阔兮，不我活兮。于嗟洵兮，不我信兮。"],"source":"《诗经》"},{"title":"凯风","author":"佚名","dynasty":"先秦","form":"诗","lines":["凯风自南，吹彼棘心。棘心夭夭，母氏劬劳。","凯风自南，吹彼棘薪。母氏圣善，我无令人。","爰有寒痊？在浚之下。有子七人，母氏劳苦。","睍睆黄鸟，载好其音。有子七人，莫慰母心。"],"source":"《诗经》"},{"title":"雄雉","author":"佚名","dynasty":"先秦","form":"诗","lines":["雄雉于飞，泄泄其羽。我之怀矣，自诒伊阻。","雄雉于飞，下上其音。展矣君子，实劳我心。","瞻彼日月，悠悠我思。道之云远，曷云能来？","百尔君子，不知德行。不忮不求，何用不臧。"],"source":"《诗经》"},{"title":"匏有苦叶","author":"佚名","dynasty":"先秦","form":"诗","lines":["匏有苦叶，济有深涉。深则厉，浅则揭。","有瀰济盈，有鷕雉鸣。济盈不濡轨，雉鸣求其牡。","雍雍鸣雁，旭日始旦。士如归妻，迨冰未泮。","招招舟子，人涉卬否。不涉卬否，卬须我友。"],"source":"《诗经》"},{"title":"谷风","author":"佚名","dynasty":"先秦","form":"诗","lines":["习习谷风，以阴以雨。黾勉同心，不宜有怒。采葑采菲，无以下体？德音莫违，及尔同死。","行道迟迟，中心有违。不远伊迩，薄送我畿。谁谓荼苦，其甘如荠。宴尔新婚，如兄如弟。","泾以渭浊，湜湜其沚。宴尔新婚，不我屑以。毋逝我梁，毋发我笱。我躬不阅，遑恤我后。","就其深矣，方之舟之。就其浅矣，泳之游之。何有何亡，黾勉求之。凡民有丧，匍匐救之。","不我能畜，反以我为仇。既阻我德，贾用不售。昔育恐育鞫，及尔颠覆。既生既育，比予于毒。","我有旨蓄，亦以御冬。宴尔新婚，以我御穷。有洸有溃，既诒我肄。不念昔者，伊余来塈。"],"source":"《诗经》"},{"title":"式微","author":"佚名","dynasty":"先秦","form":"诗","lines":["式微，式微，胡不归？微君之故，胡为乎中露！","式微，式微，胡不归？微君之躬，胡为乎泥中！"],"source":"《诗经》"},{"title":"旄丘","author":"佚名","dynasty":"先秦","form":"诗","lines":["旄丘之葛兮，何诞之节兮。叔兮伯兮，何多日也？","何其处也？必有与也！何其久也？必有以也！","狐裘蒙戎，匪车不东。叔兮伯兮，靡所与同。","琐兮尾兮，流离之子。叔兮伯兮，褎如充耳。"],"source":"《诗经》"},{"title":"简兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["简兮简兮，方将万舞。日之方中，在前上处。","硕人俣俣，公庭万舞。有力如虎，执辔如组。","左手执龠，右手秉翟。赫如渥赭，公言锡爵。","山有榛，隰有苓。云谁之思？西方美人。彼美人兮，西方之人兮。"],"source":"《诗经》"},{"title":"泉水","author":"佚名","dynasty":"先秦","form":"诗","lines":["毖彼泉水，亦流于淇。有怀于卫，靡日不思。娈彼诸姬，聊与之谋。","出宿于泲，饮饯于祢。女子有行，远父母兄弟，问我诸姑，遂及伯姊。","出宿于干，饮饯于言。载脂载辖，还车言迈。遄臻于卫，不瑕有害？","我思肥泉，兹之永叹。思须与漕，我心悠悠。驾言出游，以写我忧。"],"source":"《诗经》"},{"title":"北门","author":"佚名","dynasty":"先秦","form":"诗","lines":["出自北门，忧心殷殷。终窭且贫，莫知我艰。已焉哉！天实为之，谓之何哉！","王事适我，政事一埤益我。我入自外，室人交遍谪我。已焉哉！天实为之，谓之何哉！","王事敦我，政事一埤遗我。我入自外，室人交遍摧我。已焉哉！天实为之，谓之何哉！"],"source":"《诗经》"},{"title":"北风","author":"佚名","dynasty":"先秦","form":"诗","lines":["北风其凉，雨雪其雱。惠而好我，携手同行。其虚其邪？既亟只且！","北风其喈，雨雪其霏。惠而好我，携手同归。其虚其邪？既亟只且！","莫赤匪狐，莫黑匪乌。惠而好我，携手同车。其虚其邪？既亟只且！"],"source":"《诗经》"},{"title":"静女","author":"佚名","dynasty":"先秦","form":"诗","lines":["静女其姝，俟我于城隅。爱而不见，搔首踟蹰。","静女其娈，贻我彤管。彤管有炜，说怿女美。","自牧归荑，洵美且异。匪女之为美，美人之贻。"],"source":"《诗经》"},{"title":"新台","author":"佚名","dynasty":"先秦","form":"诗","lines":["新台有泚，河水瀰瀰。燕婉之求，蘧篨不鲜。","新台有洒，河水浼浼。燕婉之求，蘧篨不殄。","鱼网之设，鸿则离之。燕婉之求，得此戚施。"],"source":"《诗经》"},{"title":"二子乘舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["二子乘舟，泛泛其景。愿言思子，中心养养！","二子乘舟，泛泛其逝。愿言思子，不瑕有害？"],"source":"《诗经》"},{"title":"柏舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["泛彼柏舟，在彼中河。髧彼两髦，实维我仪。之死矢靡它。母也天只，不谅人只！","泛彼柏舟，在彼河侧。髧彼两髦，实维我特。之死矢靡慝。母也天只，不谅人只！"],"source":"《诗经》"},{"title":"墙有茨","author":"佚名","dynasty":"先秦","form":"诗","lines":["墙有茨，不可扫也。中冓之言，不可道也。所可道也，言之丑也。","墙有茨，不可襄也。中冓之言，不可详也。所可详也，言之长也。","墙有茨，不可束也。中冓之言，不可读也。所可读也，言之辱也。"],"source":"《诗经》"},{"title":"君子偕老","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子偕老，副笄六珈。委委佗佗，如山如河，象服是宜。子之不淑，云如之何？","玼兮玼兮，其之翟也。鬒发如云，不屑髢也。玉之瑱也，象之揥也，扬且之晳也。胡然而天也！胡然而帝也。","瑳兮瑳兮，其之展也。蒙彼绉絺，是绁袢也。子之清扬，扬且之颜也。展如之人兮，邦之媛也！"],"source":"《诗经》"},{"title":"桑中","author":"佚名","dynasty":"先秦","form":"诗","lines":["爰采唐矣？沬之乡矣。云谁之思？美孟姜矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。","爰采麦矣？沬之北矣。云谁之思？美孟弋矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。","爰采葑矣？沬之东矣。云谁之思？美孟庸矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。"],"source":"《诗经》"},{"title":"鹑之奔奔","author":"佚名","dynasty":"先秦","form":"诗","lines":["鹑之奔奔，鹊之彊彊。人之无良，我以为兄！","鹊之彊彊，鹑之奔奔。人之无良，我以为君！"],"source":"《诗经》"},{"title":"定之方中","author":"佚名","dynasty":"先秦","form":"诗","lines":["定之方中，作于楚宫。揆之以日，作于楚室。树之榛栗，椅桐梓漆，爰伐琴桑。","升彼虚矣，以望楚矣。望楚与堂，景山与京。降观于桑，卜云其吉，终然允臧。","灵雨既零，命彼倌人，星言夙驾，说于桑田。匪直也人，秉心塞渊，騋牝三千。"],"source":"《诗经》"},{"title":"蝃蝀","author":"佚名","dynasty":"先秦","form":"诗","lines":["蝃蝀在东，莫之敢指。女子有行，远父母兄弟。","朝隮于西，崇朝其雨。女子有行，远兄弟父母。","乃如之人也，怀婚姻也。大无信也，不知命也！"],"source":"《诗经》"},{"title":"相鼠","author":"佚名","dynasty":"先秦","form":"诗","lines":["相鼠有皮，人而无仪！人而无仪，不死何为？","相鼠有齿，人而无止！人而无止，不死何俟？","相鼠有体，人而无礼，人而无礼！胡不遄死？"],"source":"《诗经》"},{"title":"干旄","author":"佚名","dynasty":"先秦","form":"诗","lines":["孑孑干旄，在浚之郊。素丝纰之，良马四之。彼姝者子，何以畀之？","孑孑干旟，在浚之都。素丝组之，良马五之。彼姝者子，何以予之？","孑孑干旌，在浚之城。素丝祝之，良马六之。彼姝者子，何以告之？"],"source":"《诗经》"},{"title":"载驰","author":"佚名","dynasty":"先秦","form":"诗","lines":["载驰载驱，归唁卫侯。驱马悠悠，言至于漕。大夫跋涉，我心则忧。","既不我嘉，不能旋反。视尔不臧，我思不远。","既不我嘉，不能旋济？视尔不臧，我思不閟。","陟彼阿丘，言采其蝱。女子善怀，亦各有行。许人尤之，众稚且狂。","我行其野，芃芃其麦。控于大邦，谁因谁极？大夫君子，无我有尤。百尔所思，不如我所之。"],"source":"《诗经》"},{"title":"淇奥","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼淇奥，绿竹猗猗。有匪君子，如切如磋，如琢如磨，瑟兮僴兮，赫兮咺兮。有匪君子，终不可谖兮。","瞻彼淇奥，绿竹青青。有匪君子，充耳秀莹，会弁如星。瑟兮僴兮。赫兮咺兮，有匪君子，终不可谖兮。","瞻彼淇奥，绿竹如箦。有匪君子，如金如锡，如圭如璧。宽兮绰兮，猗重较兮。善戏谑兮，不为虐兮。"],"source":"《诗经》"},{"title":"考槃","author":"佚名","dynasty":"先秦","form":"诗","lines":["考槃在涧，硕人之宽。独寐寤言，永矢弗谖。","考槃在阿，硕人之薖。独寐寤歌，永矢弗过。","考槃在六，硕人之轴。独寐寤宿，永矢弗告。"],"source":"《诗经》"},{"title":"硕人","author":"佚名","dynasty":"先秦","form":"诗","lines":["硕人其颀，衣锦褧衣。齐侯之子，卫侯之妻。东宫之妹，邢侯之姨，谭公维私。","手如柔荑，肤如凝脂，领如蝤蛴，齿如瓠犀，螓首蛾眉，巧笑倩兮，美目盼兮。","硕人敖敖，说于农郊。四牡有骄，朱幩镳镳。翟茀以朝。大夫夙退，无使君劳。","河水洋洋，北流活活。施罛濊濊，鳣鲔发发。葭菼揭揭，庶姜孽孽，庶士有朅。"],"source":"《诗经》"},{"title":"氓","author":"佚名","dynasty":"先秦","form":"诗","lines":["氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。送子涉淇，至于顿丘。匪我愆期，子无良媒。将子无怒，秋以为期。","乘彼垝垣，以望复关。不见复关，泣涕涟涟。既见复关，载笑载言。尔卜尔筮，体无咎言。以尔车来，以我贿迁。","桑之未落，其叶沃若。于嗟鸠兮！无食桑葚。于嗟女兮！无与士耽。士之耽兮，犹可说也。女之耽兮，不可说也。","桑之落矣，其黄而陨。自我徂尔，三岁食贫。淇水汤汤，渐车帷裳。女也不爽，士二其行。士也罔极，二三其德。","三岁为妇，靡室劳矣。夙兴夜寐，靡有朝矣。言既遂矣，至于暴矣。兄弟不知，咥其笑矣。静言思之，躬自悼矣。","及尔偕老，老使我怨。淇则有岸，隰则有泮。总角之宴，言笑晏晏，信誓旦旦，不思其反。反是不思，亦已焉哉！"],"source":"《诗经》"},{"title":"竹竿","author":"佚名","dynasty":"先秦","form":"诗","lines":["籊籊竹竿，以钓于淇。岂不尔思？远莫致之。","泉源在左，淇水在右。女子有行，远兄弟父母。","淇水在右，泉源在左。巧笑之瑳，佩玉之傩。","淇水滺滺，桧楫松舟。驾言出游，以写我忧。"],"source":"《诗经》"},{"title":"芄兰","author":"佚名","dynasty":"先秦","form":"诗","lines":["芄兰之支，童子佩觿。虽则佩觿，能不我知。容兮遂兮，垂带悸兮。","芄兰之叶，童子佩韘。虽则佩韘，能不我甲。容兮遂兮，垂带悸兮。"],"source":"《诗经》"},{"title":"河广","author":"佚名","dynasty":"先秦","form":"诗","lines":["谁谓河广？一苇杭之。谁谓宋远？跂予望之。","谁谓河广？曾不容刀。谁谓宋远？曾不崇朝。"],"source":"《诗经》"},{"title":"伯兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["伯兮朅兮，邦之桀兮。伯也执殳，为王前驱。","自伯之东，首如飞蓬。岂无膏沐？谁适为容！","其雨其雨，杲杲出日。愿言思伯，甘心首疾。","焉得谖草？言树之背。愿言思伯。使我心痗。"],"source":"《诗经》"},{"title":"有狐","author":"佚名","dynasty":"先秦","form":"诗","lines":["有狐绥绥，在彼淇梁。心之忧矣，之子无裳。","有狐绥绥，在彼淇厉。心之忧矣，之子无带。","有狐绥绥，在彼淇侧。心之忧矣，之子无服。"],"source":"《诗经》"},{"title":"木瓜","author":"佚名","dynasty":"先秦","form":"诗","lines":["投我以木瓜，报之以琼琚。匪报也，永以为好也！","投我以木桃，报之以琼瑶。匪报也，永以为好也！","投我以木李，报之以琼九。匪报也，永以为好也！"],"source":"《诗经》"},{"title":"黍离","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？","彼黍离离，彼稷之穗。行迈靡靡，中心如醉。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？","彼黍离离，彼稷之实。行迈靡靡，中心如噎。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？"],"source":"《诗经》"},{"title":"君子于役","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子于役，不知其期。曷至哉？鸡栖于埘。日之夕矣，羊牛下来。君子于役，如之何勿思！","君子于役，不日不月。曷其有佸？鸡栖于桀。日之夕矣，羊牛下括。君子于役，苟无饥渴？"],"source":"《诗经》"},{"title":"君子阳阳","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子阳阳，左执簧，右招我由房，其乐只且！","君子陶陶，左执翿，右招我由敖，其乐只且！"],"source":"《诗经》"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，不流束薪。彼其之子，不与我戍申。怀哉怀哉，曷月予还归哉？","扬之水，不流束楚。彼其之子，不与我戍甫。怀哉怀哉，曷月予还归哉？","扬之水，不流束蒲。彼其之子，不与我戍许。怀哉怀哉，曷月予还归哉？"],"source":"《诗经》"},{"title":"中谷有蓷","author":"佚名","dynasty":"先秦","form":"诗","lines":["中谷有蓷，暵其干矣。有女仳离，慨其叹矣。慨其叹矣，遇人之艰难矣。","中谷有蓷，暵其修矣。有女仳离，条其歗矣。条其歗矣，遇人之不淑矣。","中谷有蓷，暵其湿矣。有女仳离，啜其泣矣。啜其泣矣，何嗟及矣。"],"source":"《诗经》"},{"title":"兔爰","author":"佚名","dynasty":"先秦","form":"诗","lines":["有兔爰爰，雉离于罗。我生之初，尚无为；我生之后，逢此百罹。尚寐无吪。","有兔爰爰，雉离于罦。我生之初，尚无造；我生之后，逢此百忧。尚寐无觉。","有兔爰爰，雉离于罿。我生之初，尚无庸；我生之后，逢此百凶。尚寐无聪。"],"source":"《诗经》"},{"title":"葛藟","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵绵葛藟，在河之浒。终远兄弟，谓他人父。谓他人父，亦莫我顾！","绵绵葛爰，在河之藟。终远兄弟，谓他人母。谓他人母，亦莫我有！","绵绵葛藟，在河之漘。终远兄弟，谓他人昆。谓他人昆，亦莫我闻！"],"source":"《诗经》"},{"title":"采葛","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼采葛兮，一日不见，如三月兮！","彼采萧兮，一日不见，如三秋兮！","彼采艾兮！一日不见，如三岁兮！"],"source":"《诗经》"},{"title":"大车","author":"佚名","dynasty":"先秦","form":"诗","lines":["大车槛槛，毳衣如菼。岂不尔思？畏子不敢。","大车啍啍，毳衣如璊，岂不尔思？畏子不奔。","谷则异室，死则同穴。谓予不信，有如皎日。"],"source":"《诗经》"},{"title":"丘中有麻","author":"佚名","dynasty":"先秦","form":"诗","lines":["丘中有麻，彼留子嗟。彼留子嗟，将其来施施。","丘中有麦，彼留子国。彼留子国，将其来食。","丘中有李，彼留之子。彼留之子，贻我佩九。"],"source":"《诗经》"},{"title":"缁衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["缁衣之宜兮，敝予又改为兮。适子之馆兮。还予授子之粲兮。","缁衣之好兮，敝予又改造兮。适子之馆兮，还予授子之粲兮。","缁衣之席兮，敝予又改作兮。适子之馆兮，还予授子之粲兮。"],"source":"《诗经》"},{"title":"将仲子","author":"佚名","dynasty":"先秦","form":"诗","lines":["将仲子兮，无逾我里，无折我树杞。岂敢爱之？畏我父母。仲可怀也，父母之言亦可畏也。","将仲子兮，无逾我墙，无折我树桑。岂敢爱之？畏我诸兄。仲可怀也，诸兄之言亦可畏也。","将仲子兮，无逾我园，无折我树檀。岂敢爱之？畏人之多言。仲可怀也，人之多言亦可畏也。"],"source":"《诗经》"},{"title":"叔于田","author":"佚名","dynasty":"先秦","form":"诗","lines":["叔于田，巷无居人。岂无居人？不如叔也。洵美且仁。","叔于狩，巷无饮酒。岂无饮酒？不如叔也。洵美且好。","叔适野，巷无服马。岂无服马？不如叔也。洵美且武。"],"source":"《诗经》"},{"title":"大叔于田","author":"佚名","dynasty":"先秦","form":"诗","lines":["叔于田，乘乘马。执辔如组，两骖如舞。叔在薮，火烈具举。襢裼暴虎，献于公所。将叔勿狃，戒其伤女。","叔于田，乘乘黄。两服上襄，两骖雁行。叔在薮，火烈具扬。叔善射忌，又良御忌。抑罄控忌，抑纵送忌。","叔于田，乘乘鸨。两服齐首，两骖如手。叔在薮，火烈具阜。叔马慢忌，叔发罕忌，抑释掤忌，抑鬯弓忌。"],"source":"《诗经》"},{"title":"清人","author":"佚名","dynasty":"先秦","form":"诗","lines":["清人在彭，驷介旁旁。二矛重英，河上乎翱翔。","清人在消，驷介麃麃。二矛重乔，河上乎逍遥。","清人在轴，驷介陶陶。左旋右抽，中军作好。"],"source":"《诗经》"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘如濡，洵直且侯。彼其之子，舍命不渝。","羔裘豹饰，孔武有力。彼其之子，邦之司直。","羔裘晏兮，三英粲兮。彼其之子，邦之彦兮。"],"source":"《诗经》"},{"title":"遵大路","author":"佚名","dynasty":"先秦","form":"诗","lines":["遵大路兮，掺执子之袪兮。无我恶兮，不蓵故也！","遵大路兮，掺执子之手兮。无我魗兮，不蓵好也！"],"source":"《诗经》"},{"title":"女曰鸡鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["女曰鸡鸣，士曰昧旦。子兴视夜，明星有烂。将翱将翔，弋凫与雁。","弋言加之，与子宜之。宜言饮酒，与子偕老。琴瑟在御，莫不静好。","知子之来之，杂佩以赠之。知子之顺之，杂佩以问之。知子之好之，杂佩以报之。"],"source":"《诗经》"},{"title":"有女同车","author":"佚名","dynasty":"先秦","form":"诗","lines":["有女同车，颜如舜华。将翱将翔，佩玉琼琚。彼美孟姜，洵美且都。","有女同行，颜如舜英。将翱将翔，佩玉将将。彼美孟姜，德音不忘。"],"source":"《诗经》"},{"title":"山有扶苏","author":"佚名","dynasty":"先秦","form":"诗","lines":["山有扶苏，隰有荷华。不见子都，乃见狂且。","山有乔松，隰有游龙，不见子充，乃见狡童。"],"source":"《诗经》"},{"title":"萚兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["萚兮萚兮，风其吹女。叔兮伯兮，倡予和女。","萚兮萚兮，风其漂女。叔兮伯兮，倡予要女。"],"source":"《诗经》"},{"title":"狡童","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼狡童兮，不与我言兮。维子之故，使我不能餐兮。","彼狡童兮，不与我食兮。维子之故，使我不能息兮。"],"source":"《诗经》"},{"title":"褰裳","author":"佚名","dynasty":"先秦","form":"诗","lines":["子惠思我，褰裳涉溱。子不我思，岂无他人？狂童之狂也且！","子惠思我，褰裳涉洧。子不我思，岂无他士？狂童之狂也且！"],"source":"《诗经》"},{"title":"丰","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之丰兮，俟我乎巷兮，悔予不送兮。","子之昌兮，俟我乎堂兮，悔予不将兮。","衣锦褧衣，裳锦褧裳。叔兮伯兮，驾予与行。","裳锦褧裳，衣锦褧衣。叔兮伯兮，驾予与归。"],"source":"《诗经》"},{"title":"东门之墠","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之墠，茹藘在阪。其室则迩，其人甚远。","东门之栗，有践家室。岂不尔思？子不我即！"],"source":"《诗经》"},{"title":"风雨","author":"佚名","dynasty":"先秦","form":"诗","lines":["风雨凄凄，鸡鸣喈喈，既见君子。云胡不夷？","风雨潇潇，鸡鸣胶胶。既见君子，云胡不瘳？","风雨如晦，鸡鸣不已。既见君子，云胡不喜？"],"source":"《诗经》"},{"title":"子衿","author":"佚名","dynasty":"先秦","form":"诗","lines":["青青子衿，悠悠我心。纵我不往，子宁不嗣音？","青青子佩，悠悠我思。纵我不往，子宁不来？","挑兮达兮，在城阙兮。一日不见，如三月兮。"],"source":"《诗经》"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，不流束楚。终鲜兄弟，维予与女。无信人之言，人实诳女。","扬之水，不流束薪。终鲜兄弟，维予二人。无信人之言，人实不信。"],"source":"《诗经》"},{"title":"出其东门","author":"佚名","dynasty":"先秦","form":"诗","lines":["出其东门，有女如云。虽则如云。匪我思存。缟衣綦巾，聊乐我员。","出其闉阇，有女如荼。虽则如荼，匪我思且。缟衣茹藘，聊可与娱。"],"source":"《诗经》"},{"title":"野有蔓草","author":"佚名","dynasty":"先秦","form":"诗","lines":["野有蔓草，零露漙兮。有美一人，清扬婉兮。邂逅相遇，适我愿兮。","野有蔓草，零露瀼瀼。有美一人，婉如清扬。邂逅相遇，与子偕臧。"],"source":"《诗经》"},{"title":"溱洧","author":"佚名","dynasty":"先秦","form":"诗","lines":["溱与洧，方涣涣兮。士与女，方秉蕳兮。女曰观乎？士曰既且。且往观乎？","洧之外，洵訏且乐。维士与女，伊其相谑，赠之以勺药。","溱与洧，浏其清矣。士与女，殷其盈矣。女曰观乎？士曰既且。且往观乎？","洧之外，洵訏且乐。维士与女，伊其将谑，赠之以勺药。"],"source":"《诗经》"},{"title":"鸡鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸡既鸣矣，朝既盈矣。匪鸡则鸣，苍蝇之声。","东方明矣，朝既昌矣。匪东方则明，月出之光。","虫飞薨薨，甘与子同梦。会且归矣，无庶予子憎。"],"source":"《诗经》"},{"title":"还","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之还兮，遭我乎狃之间兮。并驱从两肩兮，揖我谓我儇兮。","子之茂兮，遭我乎狃之道兮。并驱从两牡兮，揖我谓我好兮。","子之昌兮，遭我乎狃之阳兮。并驱从两狼兮，揖我谓我臧兮。"],"source":"《诗经》"},{"title":"着","author":"佚名","dynasty":"先秦","form":"诗","lines":["俟我于着乎而，充耳以素乎而，尚之以琼华乎而。","俟我于庭乎而，充耳以青乎而，尚之以琼莹乎而。","俟我于堂乎而，充耳以黄乎而，尚之以琼英乎而。"],"source":"《诗经》"},{"title":"东方之日","author":"佚名","dynasty":"先秦","form":"诗","lines":["东方之日兮，彼姝者子，在我室兮。在我室兮，履我即兮。","东方之月兮，彼姝者子，在我闼兮。在我闼兮，履我发兮。"],"source":"《诗经》"},{"title":"东方未明","author":"佚名","dynasty":"先秦","form":"诗","lines":["东方未明，颠倒衣裳。颠之倒之，自公召之。","东方未晞，颠倒裳衣。倒之颠之，自公令之。","折柳樊圃，狂夫瞿瞿。不能辰夜，不夙则莫。"],"source":"《诗经》"},{"title":"南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["南山崔崔，雄狐绥绥。鲁道有荡，齐子由归。既曰归止，曷又怀止？","葛屦五两，冠緌双止。鲁道有荡，齐子庸止。既曰庸止，曷又从止？","蓺麻如之何？衡从其亩。取妻如之何？必告父母。既曰告止，曷又鞠止？","析薪如之何？匪斧不克。取妻如之何？匪媒不得。既曰得止，曷又极止？"],"source":"《诗经》"},{"title":"甫田","author":"佚名","dynasty":"先秦","form":"诗","lines":["无田甫田，维莠骄骄。无思远人，劳心忉忉。","无田甫田，维莠桀桀。无思远人，劳心怛怛。","婉兮娈兮。总角丱兮。未几见兮，突而弁兮！"],"source":"《诗经》"},{"title":"卢令","author":"佚名","dynasty":"先秦","form":"诗","lines":["卢令令，其人美且仁。","卢重环，其人美且鬈。","卢重鋂，其人美且偲。"],"source":"《诗经》"},{"title":"敝笱","author":"佚名","dynasty":"先秦","form":"诗","lines":["敝笱在梁，其鱼鲂鳏。齐子归止，其从如云。","敝笱在梁，其鱼鲂鱮。齐子归止，其从如雨。","敝笱在梁，其鱼唯唯。齐子归止，其从如水。"],"source":"《诗经》"},{"title":"载驱","author":"佚名","dynasty":"先秦","form":"诗","lines":["载驱薄薄，簟茀朱鞹。鲁道有荡，齐子发夕。","四骊济济，垂辔沵沵。鲁道有荡，齐子岂弟。","汶水汤汤，行人彭彭。鲁道有荡，齐子翱翔。","汶水滔滔，行人儦儦。鲁道有荡，齐了游敖。"],"source":"《诗经》"},{"title":"猗嗟","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗嗟昌兮，颀而长兮。抑若扬兮，美目扬兮。巧趋跄兮，射则臧兮。","猗嗟名兮，美目清兮。仪既成兮，终日射侯，不出正兮，展我甥兮。","猗嗟娈兮，清扬婉兮。舞则选兮，射则贯兮，四矢反兮，以御乱兮。"],"source":"《诗经》"},{"title":"葛屦","author":"佚名","dynasty":"先秦","form":"诗","lines":["纠纠葛屦，可以履霜？掺掺女手，可以缝裳？要之襋之，好人服之。","好人提提，宛然左辟，佩其象揥。维是褊心，是以为刺。"],"source":"《诗经》"},{"title":"汾沮洳","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼汾沮洳，言采其莫。彼其之子，美无度。美无度，殊异乎公路。","彼汾一方，言采其桑。彼其之子，美如英。美如英，殊异乎公行。","彼汾一曲，言采其藚。彼其之子，美如玉。美如玉，殊异乎公族。"],"source":"《诗经》"},{"title":"园有桃","author":"佚名","dynasty":"先秦","form":"诗","lines":["园有桃，其实之肴。心之忧矣，我歌且谣。不知我者，谓我士也骄。","彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！","园有棘，其实之食。心之忧矣，聊以行国。不知我者，谓我士也罔极。","彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！"],"source":"《诗经》"},{"title":"陟岵","author":"佚名","dynasty":"先秦","form":"诗","lines":["陟彼岵兮，瞻望父兮。父曰：嗟！予子行役，夙夜无已。上慎旃哉，犹来！无止！","陟彼屺兮，瞻望母兮。母曰：嗟！予季行役，夙夜无寐。上慎旃哉，犹来！无弃！","陟彼冈兮，瞻望兄兮。兄曰：嗟！予弟行役，夙夜必偕。上慎旃哉，犹来！无死！"],"source":"《诗经》"},{"title":"十亩之间","author":"佚名","dynasty":"先秦","form":"诗","lines":["十亩之间兮，桑者闲闲兮，行与子还兮。","十亩之外兮，桑者泄泄兮，行与子逝兮。"],"source":"《诗经》"},{"title":"伐檀","author":"佚名","dynasty":"先秦","form":"诗","lines":["坎坎伐檀兮，置之河之干兮。河水清且涟猗。不稼不穑，胡取禾三百廛兮？","不狩不猎，胡瞻尔庭有县貆兮？彼君子兮，不素餐兮！","坎坎伐辐兮，置之河之侧兮。河水清且直猗。不稼不穑，胡取禾三百亿兮？","不狩不猎，胡瞻尔庭有县特兮？彼君子兮，不素食兮！","坎坎伐轮兮，置之河之漘兮。河水清且沦猗。不稼不穑，胡取禾三百囷兮？","不狩不猎，胡瞻尔庭有县鹑兮？彼君子兮，不素飧兮！"],"source":"《诗经》"},{"title":"硕鼠","author":"佚名","dynasty":"先秦","form":"诗","lines":["硕鼠硕鼠，无食我黍！三岁贯女，莫我肯顾。逝将去女，适彼乐土。乐土乐土，爰得我所。","硕鼠硕鼠，无食我麦！三岁贯女，莫我肯德。逝将去女，适彼乐国。乐国乐国，爰得我直。","硕鼠硕鼠，无食我苗！三岁贯女，莫我肯劳。逝将去女，适彼乐郊。乐郊乐郊，谁之永号？"],"source":"《诗经》"},{"title":"蟋蟀","author":"佚名","dynasty":"先秦","form":"诗","lines":["蟋蟀在堂，岁聿其莫。今我不乐，日月其除。无已大康，职思其居。好乐无荒，良士瞿瞿。","蟋蟀在堂，岁聿其逝。今我不乐，日月其迈。无已大康，职思其外。好乐无荒，良士蹶蹶。","蟋蟀在堂，役车其休。今我不乐，日月其慆。无以大康。职思其忧。好乐无荒，良士休休。"],"source":"《诗经》"},{"title":"山有枢","author":"佚名","dynasty":"先秦","form":"诗","lines":["山有枢，隰有榆。子有衣裳，弗曳弗娄。子有车马，弗驰弗驱。宛其死矣，他人是愉。","山有栲，隰有杻。子有廷内，弗洒弗扫。子有钟鼓，弗鼓弗考。宛其死矣，他人是保。","山有漆，隰有栗。子有酒食，何不日鼓瑟？且以喜乐，且以永日。宛其死矣，他人入室。"],"source":"《诗经》"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，白石凿凿。素衣朱襮，从子于沃。既见君子，云何不乐？","扬之水，白石皓皓。素衣朱绣，从子于鹄。既见君子，云何其忧？","扬之水，白石粼粼。我闻有命，不敢以告人。"],"source":"《诗经》"},{"title":"椒聊","author":"佚名","dynasty":"先秦","form":"诗","lines":["椒聊之实，蕃衍盈升。彼其之子，硕大无朋。椒聊且，远条且。","椒聊之实，蕃衍盈匊。彼其之子，硕大且笃。椒聊且，远条且。"],"source":"《诗经》"},{"title":"绸缪","author":"佚名","dynasty":"先秦","form":"诗","lines":["绸缪束薪，三星在天。今夕何夕，见此良人？子兮子兮，如此良人何？","绸缪束刍，三星在隅。今夕何夕，见此邂逅？子兮子兮，如此邂逅何？","绸缪束楚，三星在户。今夕何夕，见此粲者？子兮子兮，如此粲者何？"],"source":"《诗经》"},{"title":"杕杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，其叶湑湑。独行踽踽。岂无他人？不如我同父。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？","有杕之杜，其叶箐箐。独行睘睘。岂无他人？不如我同姓。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？"],"source":"《诗经》"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘豹祛，自我人居居。岂无他人？维子之故。","羔裘豹褎，自我人究究。岂无他人？维子之好。"],"source":"《诗经》"},{"title":"鸨羽","author":"佚名","dynasty":"先秦","form":"诗","lines":["肃肃鸨羽，集于苞栩。王事靡盬，不能蓺稷黍。父母何怙？悠悠苍天，曷其有所？","肃肃鸨翼，集于苞棘。王事靡盬，不能蓺黍稷。父母何食？悠悠苍天，曷其有极？","肃肃鸨行，集于苞桑，王事靡盬，不能蓺稻梁。父母何尝？悠悠苍天，曷其有常？"],"source":"《诗经》"},{"title":"无衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["岂曰无衣七兮？不如子之衣，安且吉兮！","岂曰无衣六兮？不如子之衣，安且燠兮！"],"source":"《诗经》"},{"title":"有杕之杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，生于道左。彼君子兮，噬肯适我？中心好之，曷饮食之？","有杕之杜，生于道周。彼君子兮，噬肯来游？中心好之，曷饮食之？"],"source":"《诗经》"},{"title":"葛生","author":"佚名","dynasty":"先秦","form":"诗","lines":["葛生蒙楚，蔹蔓于野。予美亡此，谁与？独处？","葛生蒙棘，蔹蔓于域。予美亡此，谁与？独息？","角枕粲兮，锦衾烂兮。予美亡此，谁与？独旦？","夏之日，冬之夜。百岁之后，归于其居。","冬之夜，夏之日。百岁之后，归于其室。"],"source":"《诗经》"},{"title":"采苓","author":"佚名","dynasty":"先秦","form":"诗","lines":["采苓采苓，首阳之巅。人之为言，苟亦无信。舍旃舍旃，苟亦无然。人之为言，胡得焉？","采苦采苦，首阳之下。人之为言，苟亦无与。舍旃舍旃，苟亦无然。人之为言，胡得焉？","采葑采葑，首阳之东。人之为言，苟亦无从。舍旃舍旃，苟亦无然。人之为言，胡得焉？"],"source":"《诗经》"},{"title":"车邻","author":"佚名","dynasty":"先秦","form":"诗","lines":["有车邻邻，有马白颠。未见君子，寺人之令。","阪有漆，隰有栗。既见君子，并坐鼓瑟。今者不乐，逝者其耋。","阪有桑，隰有杨。既见君子，并坐鼓簧。今者不乐，逝者其亡。"],"source":"《诗经》"},{"title":"驷驖","author":"佚名","dynasty":"先秦","form":"诗","lines":["驷驖孔阜，六辔在手。公之媚子，从公于狩。","奉时辰牡，辰牡孔硕。公曰左之，舍拔则获。","游于北园，四马既闲。輶车鸾镳，载猃歇骄。"],"source":"《诗经》"},{"title":"小戎","author":"佚名","dynasty":"先秦","form":"诗","lines":["小戎俴收，五楘梁辀。游环胁驱，阴靷鋈续。文茵畅毂，驾我骐馵。","言念君子，温其如玉。在其板屋，乱我心曲。","四牡孔阜，六辔在手。骐骝是中，騧骊是骖。龙盾之合，鋈以觼軜。","言念君子，温其在邑。方何为期？胡然我念之！","俴驷孔群，厹矛鋈錞。蒙伐有苑，虎韔镂膺。交韔二弓，竹闭绲縢。","言念君子，载寝载兴。厌厌良人，秩秩德音。"],"source":"《诗经》"},{"title":"蒹葭","author":"佚名","dynasty":"先秦","form":"诗","lines":["蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。","蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。","蒹葭采采，白露未已。所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在水中沚。"],"source":"《诗经》"},{"title":"终南","author":"佚名","dynasty":"先秦","form":"诗","lines":["终南何有？有条有梅。君子至止，锦衣狐裘。颜如渥丹，其君也哉！","终南何有？有纪有堂。君子至止，黻衣绣裳。佩玉将将，寿考不忘！"],"source":"《诗经》"},{"title":"黄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["交交黄鸟，止于棘。谁从穆公？子车奄息。维此奄息，百夫之特。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！","交交黄鸟，止于桑。谁从穆公？子车仲行。维此仲行，百夫之防。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！","交交黄鸟，止于楚。谁从穆公？子车针虎。维此针虎，百夫之御。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！"],"source":"《诗经》"},{"title":"晨风","author":"佚名","dynasty":"先秦","form":"诗","lines":["鴥彼晨风，郁彼北林。未见君子，忧心钦钦。如何如何，忘我实多！","山有苞栎，隰有六駮。未见君子，忧心靡乐。如何如何，忘我实多！","山有苞棣，隰有树檖。未见君子，忧心如醉。如何如何，忘我实多！"],"source":"《诗经》"},{"title":"无衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇！","岂曰无衣？与子同泽。王于兴师，修我矛戟。与子偕作！","岂曰无衣？与子同裳。王于兴师，修我甲兵。与子偕行！"],"source":"《诗经》"},{"title":"渭阳","author":"佚名","dynasty":"先秦","form":"诗","lines":["我送舅氏，曰至渭阳。何以赠之？路车乘黄。","我送舅氏，悠悠我思。何以赠之？琼瑰玉佩。"],"source":"《诗经》"},{"title":"权舆","author":"佚名","dynasty":"先秦","form":"诗","lines":["于我乎，夏屋渠渠，今也每食无余。于嗟乎，不承权舆！","于我乎，每食四簋，今也每食不饱。于嗟乎，不承权舆！"],"source":"《诗经》"},{"title":"宛丘","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之汤兮，宛丘之上兮。洵有情兮，而无望兮。","坎其击鼓，宛丘之下。无冬无夏，值其鹭羽。","坎其击缶，宛丘之道。无冬无夏，值其鹭翿。"],"source":"《诗经》"},{"title":"东门之枌","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之枌，宛丘之栩。子仲之子，婆娑其下。","穀旦于差，南方之原。不绩其麻，市也婆娑。","穀旦于逝，越以鬷迈。视尔如荍，贻我握椒。"],"source":"《诗经》"},{"title":"衡门","author":"佚名","dynasty":"先秦","form":"诗","lines":["衡门之下，可以栖迟。泌之洋洋，可以乐饥。","岂其食鱼，必河之鲂？岂其取妻，必齐之姜？","岂其食鱼，必河之鲤？岂其取妻，必宋之子？"],"source":"《诗经》"},{"title":"东门之池","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之池，可以沤麻。彼美淑姬，可与晤歌。","东门之池，可以沤纻。彼美淑姬，可与晤语。","东门之池，可以沤菅。彼美淑姬，可与晤言。"],"source":"《诗经》"},{"title":"东门之杨","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之杨，其叶牂牂。昏以为期，明星煌煌。","东门之杨，其叶肺肺。昏以为期，明星晢晢。"],"source":"《诗经》"},{"title":"墓门","author":"佚名","dynasty":"先秦","form":"诗","lines":["墓门有棘，斧以斯之。夫也不良，国人知之。知而不已，谁昔然矣。","墓门有梅，有鸮萃止。夫也不良，歌以讯之。讯予不顾，颠倒思予。"],"source":"《诗经》"},{"title":"防有鹊巢","author":"佚名","dynasty":"先秦","form":"诗","lines":["防有鹊巢，邛有旨苕。谁侜予美？心焉忉忉。","中唐有甓，邛有旨鷊。谁侜予美？心焉惕惕。"],"source":"《诗经》"},{"title":"月出","author":"佚名","dynasty":"先秦","form":"诗","lines":["月出皎兮。佼人僚兮。舒窈纠兮。劳心悄兮。","月出皓兮。佼人懰兮。舒忧受兮。劳心慅兮。","月出照兮。佼人燎兮。舒夭绍兮。劳心惨兮。"],"source":"《诗经》"},{"title":"株林","author":"佚名","dynasty":"先秦","form":"诗","lines":["胡为乎株林？从夏南！匪适株林，从夏南！","驾我乘马，说于株野。乘我乘驹，朝食于株！"],"source":"《诗经》"},{"title":"泽陂","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼泽之陂，有蒲与荷。有美一人，伤如之何？寤寐无为，涕泗滂沱。","彼泽之陂，有蒲与蕳。有美一人，硕大且卷。寤寐无为，中心悁悁。","彼泽之陂，有蒲菡萏。有美一人，硕大且俨。寤寐无为，辗转伏枕。"],"source":"《诗经》"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘逍遥，狐裘以朝。岂不尔思？劳心忉忉。","羔裘翱翔，狐裘在堂。岂不尔思？我心忧伤。","羔裘如膏，日出有曜。岂不尔思？中心是悼。"],"source":"《诗经》"},{"title":"素冠","author":"佚名","dynasty":"先秦","form":"诗","lines":["庶见素冠兮，棘人栾栾兮。劳心慱慱兮。","庶见素衣兮，我心伤悲兮。聊与子同归兮。","庶见素韠兮，我心蕴结兮。聊与子如一兮。"],"source":"《诗经》"},{"title":"隰有苌楚","author":"佚名","dynasty":"先秦","form":"诗","lines":["隰有苌楚，猗傩其枝，夭之沃沃，乐子之无知。","隰有苌楚，猗傩其华，夭之沃沃。乐子之无家。","隰有苌楚，猗傩其实，夭之沃沃。乐子之无室。"],"source":"《诗经》"},{"title":"匪风","author":"佚名","dynasty":"先秦","form":"诗","lines":["匪风发兮，匪车偈兮。顾瞻周道，中心怛兮。","匪风飘兮，匪车嘌兮。顾瞻周道，中心吊兮。","谁能亨鱼？溉之釜鬵。谁将西归？怀之好音。"],"source":"《诗经》"},{"title":"蜉蝣","author":"佚名","dynasty":"先秦","form":"诗","lines":["蜉蝣之羽，衣裳楚楚。心之忧矣，于我归处。","蜉蝣之翼，采采衣服。心之忧矣，于我归息。","蜉蝣掘阅，麻衣如雪。心之忧矣，于我归说。"],"source":"《诗经》"},{"title":"候人","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼候人兮，何戈与祋。彼其之子，三百赤芾。","维鹈在梁，不濡其翼。彼其之子，不称其服。","维鹈在梁，不濡其咮。彼其之子，不遂其媾。","荟兮蔚兮，南山朝隮。婉兮娈兮，季女斯饥。"],"source":"《诗经》"},{"title":"鳲鸠","author":"佚名","dynasty":"先秦","form":"诗","lines":["鳲鸠在桑，其子七兮。淑人君子，其仪一兮。其仪一兮，心如结兮。","鳲鸠在桑，其子在梅。淑人君子，其带伊丝。其带伊丝，其弁伊骐。","鳲鸠在桑，其子在棘。淑人君子，其仪不忒。其仪不忒，正是四国。","鳲鸠在桑，其子在榛。淑人君子，正是国人，正是国人。胡不万年？"],"source":"《诗经》"},{"title":"下泉","author":"佚名","dynasty":"先秦","form":"诗","lines":["冽彼下泉，浸彼苞稂。忾我寤叹，念彼周京。","冽彼下泉，浸彼苞萧。忾我寤叹，念彼京周。","冽彼下泉，浸彼苞蓍。忾我寤叹，念彼京师。","芃芃黍苗，阴雨膏之。四国有王，郇伯劳之。"],"source":"《诗经》"},{"title":"七月","author":"佚名","dynasty":"先秦","form":"诗","lines":["七月流火，九月授衣。一之日觱发，二之日栗烈。无衣无褐，何以卒岁？","三之日于耜，四之日举趾。同我妇子，馌彼南亩。田畯至喜。","七月流火，九月授衣。春日载阳，有鸣仓庚。女执懿筐，遵彼微行，爰求柔桑。","春日迟迟，采蘩祁祁。女心伤悲，殆及公子同归。","七月流火，八月萑苇。蚕月条桑，取彼斧斨。以伐远扬，猗彼女桑。","七月鸣鵙，八月载绩。载玄载黄，我朱孔阳，为公子裳。","四月秀葽，五月鸣蜩。八月其获，十月陨萚。一之日于貉，取彼狐狸，为公子裘。","二之日其同，载缵武功。言私其豵，献豜于公。","五月斯螽动股，六月莎鸡振羽。七月在野，八月在宇，九月在户，十月蟋蟀，入我床下。","穹窒熏鼠，塞向墐户。嗟我妇子，曰为改岁，入此室处。","六月食郁及薁，七月亨葵及菽。八月剥枣，十月获稻。为此春酒，以介眉寿。","七月食瓜，八月断壶，九月叔苴，采荼薪樗。食我农夫。","九月筑场圃，十月纳禾稼。黍稷重穋，禾麻菽麦。嗟我农夫，我稼既同，上入执宫功。","昼尔于茅，宵尔索綯，亟其乘屋，其始播百谷。","二之日凿冰冲冲，三之日纳于凌阴。四之日其蚤，献羔祭韭。九月肃霜，十月涤场。","朋酒斯飨，曰杀羔羊，跻彼公堂。称彼兕觥：万寿无疆！"],"source":"《诗经》"},{"title":"鸱鸮","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸱鸮鸱鸮，既取我子，无毁我室。恩斯勤斯，鬻子之闵斯。","迨天之未阴雨，彻彼桑土，绸缪牖户。今女下民，或敢侮予？","予手拮据，予所捋荼。予所蓄租，予口卒瘏，曰予未有室家。","予羽谯谯，予尾翛翛，予室翘翘。风雨所漂摇，予维音哓哓！"],"source":"《诗经》"},{"title":"东山","author":"佚名","dynasty":"先秦","form":"诗","lines":["我徂东山，慆慆不归。我来自东，零雨其濛。我东曰归，我心西悲。","制彼裳衣，勿士行枚。蜎蜎者蠋，烝在桑野。敦彼独宿，亦在车下。","我徂东山，慆慆不归。我来自东，零雨其濛。果臝之实，亦施于宇。","伊威在室，蠨蛸在户。町畽鹿场，熠耀宵行。不可畏也，伊可怀也。","我徂东山，慆慆不归。我来自东，零雨其濛。鹳鸣于垤，妇叹于室。","洒扫穹窒，我征聿至。有敦瓜苦，烝在栗薪。自我不见，于今三年。","我徂东山，慆慆不归。我来自东，零雨其濛。仓庚于飞，熠耀其羽。","之子于归，皇驳其马。亲结其缡，九十其仪。其新孔嘉，其旧如之何？"],"source":"《诗经》"},{"title":"破斧","author":"佚名","dynasty":"先秦","form":"诗","lines":["既破我斧，又缺我斨。周公东征，四国是皇。哀我人斯，亦孔之将。","既破我斧，又缺我锜。周公东征，四国是遒。哀我人斯，亦孔之嘉。","既破我斧，又缺我銶。周公东征，四国是遒。哀我人斯，亦孔之休。"],"source":"《诗经》"},{"title":"伐柯","author":"佚名","dynasty":"先秦","form":"诗","lines":["伐柯如何？匪斧不克。取妻如何？匪媒不得。","伐柯伐柯，其则不远。我觏之子，笾豆有践。"],"source":"《诗经》"},{"title":"九罭","author":"佚名","dynasty":"先秦","form":"诗","lines":["九罭之鱼，鳟鲂。我觏之子，衮衣绣裳。","鸿飞遵渚，公归无所，于女信处。鸿飞遵六，公归不复，于女信宿。","是以有衮衣兮，无以我公归兮，无使我心悲兮。"],"source":"《诗经》"},{"title":"狼跋","author":"佚名","dynasty":"先秦","form":"诗","lines":["狼跋其胡，载疐其尾。公孙硕肤，赤舄几几。","狼疐其尾，载跋其胡。公孙硕肤，德音不瑕？"],"source":"《诗经》"},{"title":"鹿鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["呦呦鹿鸣，食野之苹。我有嘉宾，鼓瑟吹笙。吹笙鼓簧，承筐是将。人之好我，示我周行。","呦呦鹿鸣，食野之蒿。我有嘉宾，德音孔昭。视民不恌，君子是则是效。我有旨酒，嘉宾式燕以敖。","呦呦鹿鸣，食野之芩。我有嘉宾，鼓瑟鼓琴。鼓瑟鼓琴，和乐且湛。我有旨酒，以燕乐嘉宾之心。"],"source":"《诗经》"},{"title":"四牡","author":"佚名","dynasty":"先秦","form":"诗","lines":["四牡騑騑，周道倭迟。岂不怀归？王事靡盬，我心伤悲。","四牡騑騑，啴啴骆马。岂不怀归？王事靡盬，不遑启处。","翩翩者鵻，载飞载下，集于苞栩。王事靡盬，不遑将父。","翩翩者鵻，载飞载止，集于苞杞。王事靡盬，不遑将母。","驾彼四骆，载骤骎骎。岂不怀归？是用作歌，将母来谂。"],"source":"《诗经》"},{"title":"皇皇者华","author":"佚名","dynasty":"先秦","form":"诗","lines":["皇皇者华，于彼原隰。駪駪征夫，每怀靡及。","我马维驹，六辔如濡。载驰载驱，周爰咨诹。","我马维骐，六辔如丝。载驰载驱，周爰咨谋。","我马维骆，六辔沃若。载驰载驱，周爰咨度。","我马维骃，六辔既均。载驰载驱，周爰咨询。"],"source":"《诗经》"},{"title":"棠棣","author":"佚名","dynasty":"先秦","form":"诗","lines":["棠棣之华，鄂不韡韡。凡今之人，莫如兄弟。","死丧之威，兄弟孔怀。原隰裒矣，兄弟求矣。","脊令在原，兄弟急难。每有良朋，况也永叹。","兄弟阋于墙，外御其务。每有良朋，烝也无戎。","丧乱既平，既安且宁。虽有兄弟，不如友生？","傧尔笾豆，饮酒之饫。兄弟既具，和乐且孺。","妻子好合，如鼓瑟琴。兄弟既翕，和乐且湛。","宜尔室家，乐尔妻帑。是究是图，亶其然乎？"],"source":"《诗经》"},{"title":"伐木","author":"佚名","dynasty":"先秦","form":"诗","lines":["伐木丁丁，鸟鸣嘤嘤。出自幽谷，迁于乔木。嘤其鸣矣，求其友声。","相彼鸟矣，犹求友声。矧伊人矣，不求友生？神之听之，终和且平。","伐木许许，酾酒有藇！既有肥羜，以速诸父。宁适不来，微我弗顾。","于粲洒扫，陈馈八簋。既有肥牡，以速诸舅。宁适不来，微我有咎。","伐木于阪，酾酒有衍。笾豆有践，兄弟无远。民之失德，乾餱以愆。","有酒湑我，无酒酤我。坎坎鼓我，蹲蹲舞我。迨我暇矣，饮此湑矣。"],"source":"《诗经》"},{"title":"天保","author":"佚名","dynasty":"先秦","form":"诗","lines":["天保定尔，亦孔之固。俾尔单厚，何福不除？俾尔多益，以莫不庶。","天保定尔，俾尔戬穀。罄无不宜，受天百禄。降尔遐福，维日不足。","天保定尔，以莫不兴。如山如阜，如冈如陵，如川之方至，以莫不增。","吉蠲为饎，是用孝享。禴祠烝尝，于公先王。君曰：卜尔，万寿无疆。","神之吊矣，诒尔多福。民之质矣，日用饮食。群黎百姓，遍为尔德。","如月之恒，如日之升。如南山之寿，不骞不崩。如松柏之茂，无不尔或承。"],"source":"《诗经》"},{"title":"采薇","author":"佚名","dynasty":"先秦","form":"诗","lines":["采薇采薇，薇亦作止。曰归曰归，岁亦莫止。靡室靡家，玁狁之故。不遑启居，玁狁之故。","采薇采薇，薇亦柔止。曰归曰归，心亦忧止。忧心烈烈，载饥载渴。我戍未定，靡使归聘。","采薇采薇，薇亦刚止。曰归曰归，岁亦阳止。王事靡盬，不遑启处。忧心孔疚，我行不来！","彼尔维何？维常之华。彼路斯何？君子之车。戎车既驾，四牡业业。岂敢定居？一月三捷。","驾彼四牡，四牡骙骙。君子所依，小人所腓。四牡翼翼，象弭鱼服。岂不日戒？玁狁孔棘！","昔我往矣，杨柳依依。今我来思，雨雪霏霏。行道迟迟，载渴载饥。我心伤悲，莫知我哀！"],"source":"《诗经》"},{"title":"出车","author":"佚名","dynasty":"先秦","form":"诗","lines":["我出我车，于彼牧矣。自天子所，谓我来矣。召彼仆夫，谓之载矣。王事多难，维其棘矣。","我出我车，于彼郊矣。设此旐矣，建彼旄矣。彼旟旐斯，胡不旆旆？忧心悄悄，仆夫况瘁。","王命南仲，往城于方。出车彭彭，旂旐央央。天子命我，城彼朔方。赫赫南仲，玁狁于襄。","昔我往矣，黍稷方华。今我来思，雨雪载途。王事多难，不遑启居。岂不怀归？畏此简书。","喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。既见君子，我心则降。赫赫南仲，薄伐西戎。","春日迟迟，卉木萋萋。仓庚喈喈，采蘩祁祁。执讯获丑，薄言还归。赫赫南仲，玁狁于夷。"],"source":"《诗经》"},{"title":"杕杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，有睆其实。王事靡盬，继嗣我日。日月阳止，女心伤止，征夫遑止。","有杕之杜，其叶萋萋。王事靡盬，我心伤悲。卉木萋止，女心悲止，征夫归止！","陟彼北山，言采其杞。王事靡盬，忧我父母。檀车幝幝，四牡痯痯，征夫不远！","匪载匪来，忧心孔疚。斯逝不至，而多为恤。卜筮偕止，会言近止，征夫迩止！"],"source":"《诗经》"},{"title":"鱼丽","author":"佚名","dynasty":"先秦","form":"诗","lines":["鱼丽于罶，鲿鲨。君子有酒，旨且多。","鱼丽于罶，鲂鳢。君子有酒，多且旨。","鱼丽于罶，鰋鲤。君子有酒，旨且有。物其多矣，","维其嘉矣！物其旨矣，维其偕矣！物其有矣，维其时矣！"],"source":"《诗经》"},{"title":"南有嘉鱼","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有嘉鱼，烝然罩罩。君子有酒，嘉宾式燕以乐。","南有嘉鱼，烝然汕汕。君子有酒，嘉宾式燕以衎。","南有樛木，甘瓠累之。君子有酒，嘉宾式燕绥之。","翩翩者鵻，烝然来思。君子有酒，嘉宾式燕又思。"],"source":"《诗经》"},{"title":"南山有台","author":"佚名","dynasty":"先秦","form":"诗","lines":["南山有台，北山有莱。乐只君子，邦家之基。乐只君子，万寿无期。","南山有桑，北山有杨。乐只君子，邦家之光。乐只君子，万寿无疆。","南山有杞，北山有李。乐只君子，民之父母。乐只君子，德音不已。","南山有栲，北山有杻。乐只君子，遐不眉寿。乐只君子，德音是茂。","南山有枸，北山有楰。乐只君子，遐不黄耇。乐只君子，保艾尔后。"],"source":"《诗经》"},{"title":"蓼萧","author":"佚名","dynasty":"先秦","form":"诗","lines":["蓼彼萧斯，零露湑兮。既见君子，我心写兮。燕笑语兮，是以有誉处兮。","蓼彼萧斯，零露瀼瀼。既见君子，为龙为光。其德不爽，寿考不忘。","蓼彼萧斯，零露泥泥。既见君子，孔燕岂弟。宜兄宜弟，令德寿岂。","蓼彼萧斯，零露浓浓。既见君子，鞗革忡忡。和鸾雍雍，万福攸同。"],"source":"《诗经》"},{"title":"湛露","author":"佚名","dynasty":"先秦","form":"诗","lines":["湛湛露斯，匪阳不晞。厌厌夜饮，不醉无归。","湛湛露斯，在彼丰草。厌厌夜饮，在宗载考。","湛湛露斯，在彼杞棘。显允君子，莫不令德。","其桐其椅，其实离离。岂弟君子，莫不令仪。"],"source":"《诗经》"},{"title":"彤弓","author":"佚名","dynasty":"先秦","form":"诗","lines":["彤弓弨兮，受言藏之。我有嘉宾，中心贶之。钟鼓既设，一朝飨之。","彤弓弨兮，受言载之。我有嘉宾，中心喜之。钟鼓既设，一朝右之。","彤弓弨兮，受言櫜之。我有嘉宾，中心好之。钟鼓既设，一朝酬之。"],"source":"《诗经》"},{"title":"菁菁者莪","author":"佚名","dynasty":"先秦","form":"诗","lines":["菁菁者莪，在彼中阿。既见君子，乐且有仪。","菁菁者莪，在彼中沚。既见君子，我心则喜。","菁菁者莪，在彼中陵。既见君子，锡我百朋。","泛泛杨舟，载沉载浮。既见君子，我心则休。"],"source":"《诗经》"},{"title":"六月","author":"佚名","dynasty":"先秦","form":"诗","lines":["六月栖栖，戎车既饬。四牡骙骙，载是常服。玁狁孔炽，我是用急。王于出征，以匡王国。","比物四骊，闲之维则。维此六月，既成我服。我服既成，于三十里。王于出征，以佐天子。","四牡修广，其大有颙。薄伐玁狁，以奏肤公。有严有翼，共武之服。共武之服，以定王国。","玁狁匪茹，整居焦获。侵镐及方，至于泾阳。织文鸟章，白旆央央。元戎十乘，以先启行。","戎车既安，如轾如轩。四牡既佶，既佶且闲。薄伐玁狁，至于大原。文武吉甫，万邦为宪。","吉甫燕喜，既多受祉。来归自镐，我行永久。饮御诸友，炰鳖脍鲤。侯谁在矣？张仲孝友。"],"source":"《诗经》"},{"title":"采芑","author":"佚名","dynasty":"先秦","form":"诗","lines":["薄言采芑，于彼新田，呈此菑亩。方叔涖止，其车三千。师干之试，方叔率止。","乘其四骐，四骐翼翼。路车有奭，簟茀鱼服，钩膺鞗革。","薄言采芑，于彼新田，于此中乡。方叔涖止，其车三千。旂旐央央，方叔率止。","约軧错衡，八鸾玱玱。服其命服，朱芾斯皇，有玱葱珩。","鴥彼飞隼，其飞戾天，亦集爰止。方叔涖止，其车三千。师干之试，方叔率止。","钲人伐鼓，陈师鞠旅。显允方叔，伐鼓渊渊，振旅阗阗。","蠢尔蛮荆，大邦为仇。方叔元老，克壮其犹。方叔率止，执讯获丑。戎车啴啴，","啴啴焞焞，如霆如雷。显允方叔，征伐玁狁，蛮荆来威。"],"source":"《诗经》"},{"title":"车攻","author":"佚名","dynasty":"先秦","form":"诗","lines":["我车既攻，我马既同。四牡庞庞，驾言徂东。","田车既好，田牡孔阜。东有甫草，驾言行狩。","之子于苗，选徒嚣嚣。建旐设旄，搏兽于敖。","驾彼四牡，四牡奕奕。赤芾金舄，会同有绎。","决拾既佽，弓矢既调。射夫既同，助我举柴。","四黄既驾，两骖不猗。不失其驰，舍矢如破。","萧萧马鸣，悠悠旆旌。徒御不惊，大庖不盈。","之子于征，有闻无声。允矣君子，展也大成。"],"source":"《诗经》"},{"title":"吉日","author":"佚名","dynasty":"先秦","form":"诗","lines":["吉日维戊，既伯既祷。田车既好，四牡孔阜。升彼大阜，从其群丑。","吉日庚午，既差我马。兽之所同，麀鹿麌麌。漆沮之从，天子之所。","瞻彼中原，其祁孔有。儦儦俟俟，或群或友。悉率左右，以燕天子。","既张我弓，既挟我矢。发彼小豝，殪此大兕。以御宾客，且以酌醴。"],"source":"《诗经》"},{"title":"鸿雁","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸿雁于飞，肃肃其羽。之子于征，劬劳于野。爰及矜人，哀此鳏寡。","鸿雁于飞，集于中泽。之子于垣，百堵皆作。虽则劬劳，其究安宅？","鸿雁于飞，哀鸣嗷嗷。维此哲人，谓我劬劳。维彼愚人，谓我宣骄。"],"source":"《诗经》"},{"title":"庭燎","author":"佚名","dynasty":"先秦","form":"诗","lines":["夜如何其？夜未央，庭燎之光。君子至止，鸾声将将。","夜如何其？夜未艾，庭燎晣晣。君子至止，鸾声哕哕。","夜如何其？夜乡晨，庭燎有辉。君子至止，言观其旂。"],"source":"《诗经》"},{"title":"沔水","author":"佚名","dynasty":"先秦","form":"诗","lines":["沔彼流水，朝宗于海。鴥彼飞隼，载飞载止。嗟我兄弟，邦人诸友。莫肯念乱，谁无父母？","沔彼流水，其流汤汤。鴥彼飞隼，载飞载扬。念彼不迹，载起载行。心之忧矣，不可弭忘。","鴥彼飞隼，率彼中陵。民之讹言，宁莫之惩？我友敬矣，谗言其兴。"],"source":"《诗经》"},{"title":"鹤鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["鹤鸣于九皋，声闻于野。鱼潜在渊，或在于渚。乐彼之园，爰有树檀，其下维萚。他山之石，可以为错。","鹤鸣于九皋，声闻于天。鱼在于渚，或潜在渊。乐彼之园，爰有树檀，其下维谷。他山之石，可以攻玉。"],"source":"《诗经》"},{"title":"祈父","author":"佚名","dynasty":"先秦","form":"诗","lines":["祈父，予王之爪牙。胡转予于恤，靡所止居？","祈父，予王之爪士。胡转予于恤，靡所厎止？","祈父，亶不聪。胡转予于恤？有母之尸饔。"],"source":"《诗经》"},{"title":"白驹","author":"佚名","dynasty":"先秦","form":"诗","lines":["皎皎白驹，食我场苗。絷之维之，以永今朝。所谓伊人，于焉逍遥？","皎皎白驹，食我场藿。絷之维之，以永今夕。所谓伊人，于焉嘉客？","皎皎白驹，贲然来思。尔公尔侯，逸豫无期？慎尔优游，勉尔遁思。","皎皎白驹，在彼空谷。生刍一束，其人如玉。毋金玉尔音，而有遐心。"],"source":"《诗经》"},{"title":"黄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["黄鸟黄鸟，无集于穀，无啄我粟。此邦之人，不我肯穀。言旋言归，复我邦族。","黄鸟黄鸟，无集于桑，无啄我粱。此邦之人，不可与明。言旋言归，复我诸兄。","黄鸟黄鸟，无集于栩，无啄我黍。此邦之人，不可与处。言旋言归，复我诸父。"],"source":"《诗经》"},{"title":"我行其野","author":"佚名","dynasty":"先秦","form":"诗","lines":["我行其野，蔽芾其樗。婚姻之故，言就尔居。尔不我畜，复我邦家。","我行其野，言采其蓫。婚姻之故，言就尔宿。尔不我畜，言归斯复。","我行其野，言采其葍。不思旧姻，求尔新特。成不以富，亦祗以异。"],"source":"《诗经》"},{"title":"斯干","author":"佚名","dynasty":"先秦","form":"诗","lines":["秩秩斯干，幽幽南山。如竹苞矣，如松茂矣。兄及弟矣，式相好矣，无相犹矣。","似续妣祖，筑室百堵，西南其户。爰居爰处，爰笑爰语。","约之阁阁，椓之橐橐。风雨攸除，鸟鼠攸去，君子攸芋。","如跂斯翼，如矢斯棘，如鸟斯革，如翚斯飞，君子攸跻。","殖殖其庭，有觉其楹。哙哙其正，哕哕其冥。君子攸宁。","下莞上簟，乃安斯寝。乃寝乃兴，乃占我梦。吉梦维何？维熊维罴，维虺维蛇。","大人占之：维熊维罴，男子之祥；维虺维蛇，女子之祥。","乃生男子，载寝之床。载衣之裳，载弄之璋。其泣喤喤，朱芾斯皇，室家君王。","乃生女子，载寝之地。载衣之裼，载弄之瓦。无非无仪，唯酒食是议，无父母诒罹。"],"source":"《诗经》"},{"title":"无羊","author":"佚名","dynasty":"先秦","form":"诗","lines":["谁谓尔无羊？三百维群。谁谓尔无牛？九十其犉。尔羊来思，其角濈濈。尔牛来思，其耳湿湿。","或降于阿，或饮于池，或寝或讹。尔牧来思，何蓑何笠，或负其餱。三十维物，尔牲则具。","尔牧来思，以薪以蒸，以雌以雄。尔羊来思，矜矜兢兢，不骞不崩。麾之以肱，毕来既升。","牧人乃梦，众维鱼矣，旐维旟矣，大人占之；众维鱼矣，实维丰年；旐维旟矣，室家溱溱。"],"source":"《诗经》"},{"title":"节南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["节彼南山，维石岩岩。赫赫师尹，民具尔瞻。忧心如惔，不敢戏谈。国既卒斩，何用不监！","节彼南山，有实其猗。赫赫师尹，不平谓何。天方荐瘥，丧乱弘多。民言无嘉，惨莫惩嗟。","尹氏大师，维周之氐；秉国之钧，四方是维。天子是毗，俾民不迷。不吊昊天，不宜空我师。","弗躬弗亲，庶民弗信。弗问弗仕，勿罔君子。式夷式已，无小人殆。琐琐姻亚，则无膴仕。","昊天不佣，降此鞠訩。昊天不惠，降此大戾。君子如届，俾民心阕。君子如夷，恶怒是违。","不吊昊天，乱靡有定。式月斯生，俾民不宁。忧心如酲，谁秉国成？不自为政，卒劳百姓。","驾彼四牡，四牡项领。我瞻四方，蹙蹙靡所骋。","方茂尔恶，相尔矛矣。既夷既怿，如相酬矣。","昊天不平，我王不宁。不惩其心，覆怨其正。","家父作诵，以究王訩。式讹尔心，以畜万邦。"],"source":"《诗经》"},{"title":"正月","author":"佚名","dynasty":"先秦","form":"诗","lines":["正月繁霜，我心忧伤。民之讹言，亦孔之将。念我独兮，忧心京京。哀我小心，癙忧以痒。","父母生我，胡俾我瘉？不自我先，不自我后。好言自口，莠言自口。忧心愈愈，是以有侮。","忧心惸惸，念我无禄。民之无辜，并其臣仆。哀我人斯，于何从禄？瞻乌爰止？于谁之屋？","瞻彼中林，侯薪侯蒸。民今方殆，视天梦梦。既克有定，靡人弗胜。有皇上帝，伊谁云憎？","谓山盖卑，为冈为陵。民之讹言，宁莫之惩。召彼故老，讯之占梦。具曰予圣，谁知乌之雌雄！","谓天盖高，不敢不局。谓地盖厚，不敢不蹐。维号斯言，有伦有脊。哀今之人，胡为虺蜴？","瞻彼阪田，有菀其特。天之杌我，如不我克。彼求我则，如不我得。执我仇仇，亦不我力。","心之忧矣，如或结之。今兹之正，胡然厉矣？燎之方扬，宁或灭之？赫赫宗周，褒姒灭之！","终其永怀，又窘阴雨。其车既载，乃弃尔辅。载输尔载，将伯助予！","无弃尔辅，员于尔辐。屡顾尔仆，不输尔载。终逾绝险，曾是不意。","鱼在于沼，亦匪克乐。潜虽伏矣，亦孔之炤。忧心惨惨，念国之为虐！","彼有旨酒，又有嘉肴。洽比其邻，婚姻孔云。念我独兮，忧心殷殷。","佌佌彼有屋，蔌蔌方有谷。民今之无禄，天夭是椓。哿矣富人，哀此惸独。"],"source":"《诗经》"},{"title":"十月之交","author":"佚名","dynasty":"先秦","form":"诗","lines":["十月之交，朔月辛卯。日有食之，亦孔之丑。彼月而微，此日而微；今此下民，亦孔之哀。","日月告凶，不用其行。四国无政，不用其良。彼月而食，则维其常；此日而食，于何不臧。","烨烨震电，不宁不令。百川沸腾，山冢崒崩。高岸为谷，深谷为陵。哀今之人，胡惨莫惩？","皇父卿士，番维司徒，家伯维宰，仲允膳夫，棸子内史，蹶维趣马，楀维师氏。醘妻煽方处。","抑此皇父，岂曰不时？胡为我作，不即我谋？彻我墙屋，田卒污莱。曰予不戕，礼则然矣。","皇父孔圣，作都于向。择三有事，亶侯多藏。不慭遗一老，俾守我王。择有车马，以居徂向。","黾勉从事，不敢告劳。无罪无辜，谗口嚣嚣。下民之孽，匪降自天。噂沓背憎，职竞由人。","悠悠我里，亦孔之痗。四方有羡，我独居忧。民莫不逸，我独不敢休。天命不彻，我不敢效我友自逸。"],"source":"《诗经》"},{"title":"雨无正","author":"佚名","dynasty":"先秦","form":"诗","lines":["浩浩昊天，不骏其德。降丧饥馑，斩伐四国。旻天疾威，弗虑弗图。舍彼有罪，既伏其辜。若此无罪，沦胥以铺。","周宗既灭，靡所止戾。正大夫离居，莫知我勚。三事大夫，莫肯夙夜。邦君诸侯，莫肯朝夕。庶曰式臧，覆出为恶。","如何昊天，辟言不信。如彼行迈，则靡所臻。凡百君子，各敬尔身。胡不相畏，不畏于天？","戎成不退，饥成不遂。曾我暬御，惨惨日瘁。凡百君子，莫肯用讯。听言则答，谮言则退。","哀哉不能言，匪舌是出，维躬是瘁。哿矣能言，巧言如流，俾躬处休！","维曰予仕，孔棘且殆。云不何使，得罪于天子；亦云可使，怨及朋友。","谓尔迁于王都。曰予未有室家。鼠思泣血，无言不疾。昔尔出居，谁从作尔室？"],"source":"《诗经》"},{"title":"小旻","author":"佚名","dynasty":"先秦","form":"诗","lines":["旻天疾威，敷于下土。谋犹回遹，何日斯沮？谋臧不从，不臧覆用。我视谋犹，亦孔之邛。","潝潝訿訿，亦孔之哀。谋之其臧，则具是违。谋之不臧，则具是依。我视谋犹，伊于胡厎。","我龟既厌，不我告犹。谋夫孔多，是用不集。发言盈庭，谁敢执其咎？如匪行迈谋，是用不得于道。","哀哉为犹，匪先民是程，匪大犹是经。维迩言是听，维迩言是争。如彼筑室于道谋，是用不溃于成。","国虽靡止，或圣或否。民虽靡膴，或哲或谋，或肃或艾。如彼泉流，无沦胥以败。","不敢暴虎，不敢冯河。人知其一，莫知其他。战战兢兢，如临深渊，如履薄冰。"],"source":"《诗经》"},{"title":"小宛","author":"佚名","dynasty":"先秦","form":"诗","lines":["宛彼鸣鸠，翰飞戾天。我心忧伤，念昔先人。明发不寐，有怀二人。","人之齐圣，饮酒温克。彼昏不知，一醉日富。各敬尔仪，天命不又。","中原有菽，庶民采之。螟蛉有子，蜾蠃负之。教诲尔子，式穀似之。","题彼脊令，载飞载鸣。我日斯迈，而月斯征。夙兴夜寐，毋忝尔所生。","交交桑扈，率场啄粟。哀我填寡，宜岸宜狱。握粟出卜，自何能穀？","温温恭人，如集于木。惴惴小心，如临于谷。战战兢兢，如履薄冰。"],"source":"《诗经》"},{"title":"小弁","author":"佚名","dynasty":"先秦","form":"诗","lines":["弁彼鸴斯，归飞提提。民莫不穀，我独于罹。何辜于天？我罪伊何？心之忧矣，云如之何？","踧踧周道，鞫为茂草。我心忧伤，惄焉如捣。假寐永叹，维忧用老。心之忧矣，疢如疾首。","维桑与梓，必恭敬止。靡瞻匪父，靡依匪母。不属于毛？不罹于里？天之生我，我辰安在？","菀彼柳斯，鸣蜩嘒嘒，有漼者渊，萑苇淠淠。譬彼舟流，不知所届，心之忧矣，不遑假寐。","鹿斯之奔，维足伎伎。雉之朝雊，尚求其雌。譬彼坏木，疾用无枝。心之忧矣，宁莫之知？","相彼投兔，尚或先之。行有死人，尚或墐之。君子秉心，维其忍之。心之忧矣，涕既陨之。","君子信谗，如或酬之。君子不惠，不舒究之。伐木掎矣，析薪扡矣。舍彼有罪，予之佗矣。","莫高匪山，莫浚匪泉。君子无易由言，耳属于垣。无逝我梁，无发我笱。我躬不阅，遑恤我后。"],"source":"《诗经》"},{"title":"巧言","author":"佚名","dynasty":"先秦","form":"诗","lines":["悠悠昊天，曰父母且。无罪无辜，乱如此幠。昊天已威，予慎无罪。昊天大幠，予慎无辜。","乱之初生，僭始既涵。乱之又生，君子信谗。君子如怒，乱庶遄沮。君子如祉，乱庶遄已。","君子屡盟，乱是用长。君子信盗，乱是用暴。盗言孔甘，乱是用餤。匪其止共，维王之邛。","奕奕寝庙，君子作之。秩秩大猷，圣人莫之。他人有心，予忖度之。跃跃毚兔，遇犬获之。","荏染柔木，君子树之。往来行言，心焉数之。蛇蛇硕言，出自口矣。巧言如簧，颜之厚矣。","彼何人斯？居河之麋。无拳无勇，职为乱阶。既微且尰，尔勇伊何？为犹将多，尔居徒几何？"],"source":"《诗经》"},{"title":"何人斯","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼何人斯？其心孔艰。胡逝我梁，不入我门？伊谁云从？维暴之云。","二人从行，谁为此祸？胡逝我梁，不入唁我？始者不如今，云不我可","彼何人斯？胡逝我陈？我闻其声，不见其身。不愧于人？不畏于天？","彼何人斯？其为飘风。胡不自北？胡不自南？胡逝我梁？絺搅我心。","尔之安行，亦不遑舍。尔之亟行，遑脂尔车。一者之来，云何其盱。","尔还而入，我心易也。还而不入，否难知也。一者之来，俾我絺也。","伯氏吹埙，仲氏吹篪。及尔如贯，谅不我郑出此三物，以诅尔斯。","为鬼为蜮，则不可得。有靦面目，视人罔极。作此好歌，以极反侧。"],"source":"《诗经》"},{"title":"巷伯","author":"佚名","dynasty":"先秦","form":"诗","lines":["萋兮斐兮，成是贝锦。彼谮人者，亦已大甚！","哆兮侈兮，成是南箕。彼谮人者，谁适与谋。","缉缉翩翩，谋欲谮人。慎尔言也，谓尔不信。","捷捷幡幡，谋欲谮言。岂不尔受？既其女迁。","骄人好好，劳人草草。苍天苍天，视彼骄人，矜此劳人。","彼谮人者，谁适与谋？取彼谮人，投畀豺虎。豺虎不食，投畀有北。有北不受，投畀有昊！","杨园之道，猗于亩丘。寺人孟子，作为此诗。凡百君子，敬而听之。"],"source":"《诗经》"},{"title":"谷风","author":"佚名","dynasty":"先秦","form":"诗","lines":["习习谷风，维风及雨。将恐将惧，维予与女。将安将乐，女转弃予。","习习谷风，维风及颓。将恐将惧，置予于怀。将安将乐，弃予如遗。","习习谷风，维山崔嵬。无草不死，无木不萎。忘我大德，思我小怨。"],"source":"《诗经》"},{"title":"蓼莪","author":"佚名","dynasty":"先秦","form":"诗","lines":["蓼蓼者莪，匪莪伊蒿。哀哀父母，生我劬劳。","蓼蓼者莪，匪莪伊蔚。哀哀父母，生我劳瘁。","瓶之罄矣，维罍之耻。鲜民之生，不如死之久矣。无父何怙？无母何恃？出则衔恤，入则靡至。","父兮生我，母兮鞠我。抚我畜我，长我育我，顾我复我，出入腹我。欲报之德。昊天罔极！","南山烈烈，飘风发发。民莫不穀，我独何害！南山律律，飘风弗弗。民莫不穀，我独不卒！"],"source":"《诗经》"},{"title":"大东","author":"佚名","dynasty":"先秦","form":"诗","lines":["有饛簋飧，有捄棘匕。周道如砥，其直如矢。君子所履，小人所视。眷言顾之，潸焉出涕。","小东大东，杼柚其空。纠纠葛屦，可以履霜。佻佻公子，行彼周行。既往既来，使我心疚。","有冽氿泉，无浸获薪。契契寤叹，哀我惮人。薪是获薪，尚可载也。哀我惮人，亦可息也。","东人之子，职劳不来。西人之子，粲粲衣服。舟人之子，熊罴是裘。私人之子，百僚是试。","或以其酒，不以其浆。鞙鞙佩璲，不以其长。维天有汉，监亦有光。跂彼织女，终日七襄。","虽则七襄，不成报章。睆彼牵牛，不以服箱。东有启明，西有长庚。有捄天毕，载施之行。","维南有箕，不可以簸扬。维北有斗，不可以挹酒浆。维南有箕，载翕其舌。维北有斗，西柄之揭。"],"source":"《诗经》"},{"title":"四月","author":"佚名","dynasty":"先秦","form":"诗","lines":["四月维夏，六月徂署。先祖匪人，胡宁忍予？","秋日凄凄，百卉具腓。乱离瘼矣，爰其适归？","冬日烈烈，飘风发发。民莫不穀，我独何害？","山有嘉卉，侯栗侯梅。废为残贼，莫知其尤！","相彼泉水，载清载浊。我日构祸，曷云能穀？","滔滔江汉，南国之纪。尽瘁以仕，宁莫我有？","匪鹑匪鸢，翰飞戾天。匪鳣匪鲔，潜逃于渊。","山有蕨薇，隰有杞桋。君子作歌，维以告哀。"],"source":"《诗经》"},{"title":"北山","author":"佚名","dynasty":"先秦","form":"诗","lines":["陟彼北山，言采其杞。偕偕士子，朝夕从事。王事靡盬，忧我父母。","溥天之下，莫非王土；率土之滨，莫非王臣。大夫不均，我从事独贤。","四牡彭彭，王事傍傍。嘉我未老，鲜我方将。旅力方刚，经营四方。","或燕燕居息，或尽瘁事国；或息偃在床，或不已于行。","或不知叫号，或惨惨劬劳；或栖迟偃仰，或王事鞅掌。","或湛乐饮酒，或惨惨畏咎；或出入风议，或靡事不为。"],"source":"《诗经》"},{"title":"无将大车","author":"佚名","dynasty":"先秦","form":"诗","lines":["无将大车，祇自尘兮。无思百忧，祇自疧兮。","无将大车，维尘冥冥。无思百忧，不出于颎。","无将大车，维尘雍兮。无思百忧，祇自重兮。"],"source":"《诗经》"},{"title":"小明","author":"佚名","dynasty":"先秦","form":"诗","lines":["明明上天，照临下土。我征徂西，至于艽野。二月初吉，载离寒暑。","心之忧矣，其毒大苦。念彼共人，涕零如雨。岂不怀归？畏此罪罟！","昔我往矣，日月方除。曷云其还？岁聿云莫。念我独兮，我事孔庶。","心之忧矣，惮我不暇。念彼共人，眷眷怀顾！岂不怀归？畏此谴怒。","昔我往矣，日月方奥。曷云其还？政事愈蹙。岁聿云莫，采萧获菽。","心之忧矣，自诒伊戚。念彼共人，兴言出宿。岂不怀归？畏此反覆。","嗟尔君子，无恒安处。靖共尔位，正直是与。神之听之，式穀以女。","嗟尔君子，无恒安息。靖共尔位，好是正直。神之听之，介尔景福。"],"source":"《诗经》"},{"title":"鼓钟","author":"佚名","dynasty":"先秦","form":"诗","lines":["鼓钟将将，淮水汤汤，忧心且伤。淑人君子，怀允不忘。","鼓钟喈喈，淮水湝湝，忧心且悲。淑人君子，其德不回。","鼓钟伐鼛，淮有三洲，忧心且妯。淑人君子，其德不犹。","鼓钟钦钦，鼓瑟鼓琴，笙磬同音。以雅以南，以龠不僭。"],"source":"《诗经》"},{"title":"楚茨","author":"佚名","dynasty":"先秦","form":"诗","lines":["楚楚者茨，言抽其棘，自昔何为？我蓺黍稷。我黍与与，我稷翼翼。","我仓既盈，我庾维亿。以为酒食，以享以祀，以妥以侑，以介景福。","济济跄跄，絜尔牛羊，以往烝尝。或剥或亨，或四或将。祝祭于祊，","祀事孔明。先祖是皇，神保是飨。孝孙有庆，报以介福，万寿无疆！","执爨踖踖，为俎孔硕，或燔或炙。君妇莫莫，为豆孔庶。为宾为客，","献酬交错。礼仪卒度，笑语卒获。神保是格，报以介福，万寿攸酢！","我孔戁矣，式礼莫愆。工祝致告，徂赉孝孙。苾芬孝祀，神嗜饮食。","卜尔百福，如几如式。既齐既稷，既匡既敕。永锡尔极，时万时亿！","礼仪既备，钟鼓既戒，孝孙徂位，工祝致告，神具醉止，皇尸载起。","鼓钟送尸，神保聿归。诸宰君妇，废彻不迟。诸父兄弟，备言燕私。","乐具入奏，以绥后禄。尔肴既将，莫怨具庆。既醉既饱，小大稽首。","神嗜饮食，使君寿考。孔惠孔时，维其尽之。子子孙孙，勿替引之！"],"source":"《诗经》"},{"title":"信南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["信彼南山，维禹甸之。畇畇原隰，曾孙田之。我疆我理，南东其亩。","上天同云。雨雪雰雰，益之以霡霂。既优既渥，既沾既足。生我百谷。","疆埸翼翼，黍稷彧彧。曾孙之穑，以为酒食。畀我尸宾，寿考万年。","中田有庐，疆埸有瓜。是剥是菹，献之皇祖。曾孙寿考，受天之祜。","祭以清酒，从以骍牡，享于祖考。执其鸾刀，以启其毛，取其血膋。","是烝是享，苾苾芬芬。祀事孔明，先祖是皇。报以介福。万寿无疆。"],"source":"《诗经》"},{"title":"甫田","author":"佚名","dynasty":"先秦","form":"诗","lines":["倬彼甫田，岁取十千。我取其陈，食我农人。自古有年。","今适南亩，或耘或耔。黍稷薿薿，攸介攸止，烝我髦士。","以我齐明，与我牺羊，以社以方。我田既臧，农夫之庆。","琴瑟击鼓，以御田祖。以祈甘雨，以介我稷黍，以穀我士女。","曾孙来止，以其妇子。馌彼南亩，田畯至喜。攘其左右，","尝其旨否。禾易长亩，终善且有。曾孙不怒，农夫克敏。","曾孙之稼，如茨如梁。曾孙之庾，如坻如京。乃求千斯仓，","乃求万斯箱。黍稷稻粱，农夫之庆。报以介福，万寿无疆。"],"source":"《诗经》"},{"title":"大田","author":"佚名","dynasty":"先秦","form":"诗","lines":["大田多稼，既种既戒，既备乃事。以我覃耜，俶载南亩。","播厥百谷，既庭且硕，曾孙是若。","既方既皂，既坚既好，不稂不莠。去其螟螣，及其蟊贼，","无害我田稚。田祖有神，秉畀炎火。","有渰萋萋，兴雨祈祈。雨我公田，遂及我私。彼有不获稚，","此有不敛穧，彼有遗秉，此有滞穗，伊寡妇之利。","曾孙来止，以其妇子。馌彼南亩，田畯至喜。来方禋祀，","以其骍黑，与其黍稷。以享以祀，以介景福。"],"source":"《诗经》"},{"title":"瞻彼洛矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼洛矣，维水泱泱。君子至止，福禄如茨。韎韐有奭，以作六师。","瞻彼洛矣，维水泱泱。君子至止，鞸琫有珌。君子万年，保其家室。","瞻彼洛矣，维水泱泱。君子至止，福禄既同。君子万年，保其家邦。"],"source":"《诗经》"},{"title":"裳裳者华","author":"佚名","dynasty":"先秦","form":"诗","lines":["裳裳者华，其叶湑兮。我觏之子，我心写兮。我心写兮，是以有誉处兮。","裳裳者华，芸其黄矣。我觏之子，维其有章矣。维其有章矣，是以有庆矣。","裳裳者华，或黄或白。我觏之子，乘其四骆。乘其四骆，六辔沃若。","左之左之，君子宜之。右之右之，君子有之。维其有之，是以似之。"],"source":"《诗经》"},{"title":"桑扈","author":"佚名","dynasty":"先秦","form":"诗","lines":["交交桑扈，有莺其羽。君子乐胥，受天之祜。","交交桑扈，有莺其领。君子乐胥，万邦之屏。","之屏之翰，百辟为宪。不戢不难，受福不那。","兕觥其觩，旨酒思柔。彼交匪敖，万福来求。"],"source":"《诗经》"},{"title":"鸳鸯","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸳鸯于飞，毕之罗之。君子万年，福禄宜之。","鸳鸯在梁，戢其左翼。君子万年，","宜其遐福。乘马在厩，摧之秣之。君子万年，福禄艾之。","乘马在厩，秣之摧之。君子万年，福禄绥之。"],"source":"《诗经》"},{"title":"頍弁","author":"佚名","dynasty":"先秦","form":"诗","lines":["有頍者弁，实维伊何？尔酒既旨，尔肴既嘉。岂伊异人？兄弟匪他。","茑与女萝，施于松柏。未见君子，忧心奕奕；既见君子，庶几说怿。","有頍者弁，实维何期？尔酒既旨，尔肴既时。岂伊异人？兄弟具来。","茑与女萝，施于松上。未见君子，忧心怲怲；既见君子，庶几有臧。","有頍者弁，实维在首。尔酒既旨，尔肴既阜。岂伊异人？兄弟甥舅。","如彼雨雪，先集维霰。死丧无日，无几相见。乐酒今夕，君子维宴。"],"source":"《诗经》"},{"title":"车舝","author":"佚名","dynasty":"先秦","form":"诗","lines":["间关车之舝兮，思娈季女逝兮。匪饥匪渴，德音来括。虽无好友？式燕且喜。","依彼平林，有集维鷮。辰彼硕女，令德来教。式燕且誉，好尔无射。","虽无旨酒？式饮庶几。虽无嘉肴？式食庶几。虽无德与女？式歌且舞？","陟彼高冈，析其柞薪。析其柞薪，其叶湑兮。鲜我觏尔，我心写兮。","高山仰止，景行行止。四牡騑騑，六辔如琴。觏尔新婚，以慰我心。"],"source":"《诗经》"},{"title":"青蝇","author":"佚名","dynasty":"先秦","form":"诗","lines":["营营青蝇，止于樊。岂弟君子，无信谗言。","营营青蝇，止于棘。谗人罔极，交乱四国。","营营青蝇，止于榛。谗人罔极，构我二人。"],"source":"《诗经》"},{"title":"宾之初筵","author":"佚名","dynasty":"先秦","form":"诗","lines":["宾之初筵，左右秩秩。笾豆有楚，殽核维旅。酒既和旨，饮酒孔偕。","钟鼓既设，举酬逸逸。大侯既抗，弓矢斯张。射夫既同，献尔发功。","发彼有的，以祈尔爵。","籥舞笙鼓，乐既和奏。烝衎烈祖，以洽百礼。百礼既至，有壬有林。","锡尔纯嘏，子孙其湛。其湛曰乐，各奏尔能。宾载手仇，室人入又。","酌彼康爵，以奏尔时。","宾之初筵，温温其恭。其未醉止，威仪反反。曰既醉止，威仪幡幡。","舍其坐迁，屡舞仙仙。其未醉止，威仪抑抑。曰既醉止，威仪抑抑。","是曰既醉，不知其秩。","宾既醉止，载号载呶。乱我笾豆，屡舞僛僛。是曰既醉，不知其邮。","侧弁之俄，屡舞傞傞。既醉而出，并受其福。醉而不出，是谓伐德。","饮酒孔嘉，维其令仪。","凡此饮酒，或醉或否。既立之监，或佐之史。彼醉不臧，不醉反耻。","式勿从谓，无俾大怠。匪言勿言，匪由勿语。由醉之言，俾出童羖。","三爵不识，矧敢多又。"],"source":"《诗经》"},{"title":"鱼藻","author":"佚名","dynasty":"先秦","form":"诗","lines":["鱼在在藻，有颁其首。王在在镐，岂乐饮酒。","鱼在在藻，有莘其尾。王在在镐，饮酒乐岂。","鱼在在藻，依于其蒲。王在在镐，有那其居。"],"source":"《诗经》"},{"title":"采菽","author":"佚名","dynasty":"先秦","form":"诗","lines":["采菽采菽，筐之莒之。君子来朝，何锡予之？虽无予之？路车乘马。又何予之？玄衮及黼。","觱沸槛泉，言采其芹。君子来朝，言观其旂。其旂淠淠，鸾声嘒嘒。载骖载驷，君子所届。","赤芾在股，邪幅在下。彼交匪纾，天子所予。乐只君子，天子命之。乐只君子，福禄申之。","维柞之枝，其叶蓬蓬。乐只君子，殿天子之邦。乐只君子，万福攸同。平平左右，亦是率从。","汎汎杨舟，绋纚维之。乐只君子，天子葵之。乐只君子，福禄膍之。优哉游哉，亦是戾矣。"],"source":"《诗经》"},{"title":"角弓","author":"佚名","dynasty":"先秦","form":"诗","lines":["骍骍角弓，翩其反矣。兄弟婚姻，无胥远矣。","尔之远矣，民胥然矣。尔之教矣，民胥效矣。","此令兄弟，绰绰有裕。不令兄弟，交相为愈。","民之无良，相怨一方。受爵不让，至于已斯亡。","老马反为驹，不顾其后。如食宜饇，如酌孔取。","毋教猱升木，如涂涂附。君子有徽猷，小人与属。","雨雪瀌瀌，见晛曰消。莫肯下遗，式居娄骄。","雨雪浮浮，见晛曰流。如蛮如髦，我是用忧。"],"source":"《诗经》"},{"title":"菀柳","author":"佚名","dynasty":"先秦","form":"诗","lines":["有菀者柳，不尚息焉。上帝甚蹈，无自暱焉。俾予靖之，后予极焉。","有菀者柳，不尚愒焉。上帝甚蹈，无自瘵焉。俾予靖之，后予迈焉。","有鸟高飞，亦傅于天。彼人之心，于何其臻。曷予靖之，居以凶矜。"],"source":"《诗经》"},{"title":"都人士","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼都人士，狐裘黄黄。其容不改，出言有章。行归于周，万民所望。","彼都人士，台笠缁撮。彼君子女，绸直如发。我不见兮，我心不说。","彼都人士，充耳琇实。彼君子女，谓之尹吉。我不见兮，我心苑结。","彼都人士，垂带而厉。彼君子女，卷发如虿。我不见兮，言从之迈。","匪伊垂之，带则有余。匪伊卷之，发则有旟。我不见兮，云何盱矣。"],"source":"《诗经》"},{"title":"采绿","author":"佚名","dynasty":"先秦","form":"诗","lines":["终朝采绿，不盈一匊。予发曲局，薄言归沐。","终朝采蓝，不盈一襜。五日为期，六日不詹。","之子于狩，言韔其弓。之子于钓，言纶之绳。","其钓维何？维鲂及鱮。维鲂及鱮，薄言观者。"],"source":"《诗经》"},{"title":"黍苗","author":"佚名","dynasty":"先秦","form":"诗","lines":["芃芃黍苗，阴雨膏之。悠悠南行，召伯劳之。","我任我辇，我车我牛。我行既集，盖云归哉。","我徒我御，我师我旅。我行既集，盖云归处。","肃肃谢功，召伯营之。烈烈征师，召伯成之。","原隰既平，泉流既清。召伯有成，王心则宁。"],"source":"《诗经》"},{"title":"隰桑","author":"佚名","dynasty":"先秦","form":"诗","lines":["隰桑有阿，其叶有难。既见君子，其乐如何。","隰桑有阿，其叶有沃。既见君子，云何不乐。","隰桑有阿，其叶有幽。既见君子，德音孔胶。","心乎爱矣，遐不谓矣？中心藏之，何日忘之！"],"source":"《诗经》"},{"title":"白华","author":"佚名","dynasty":"先秦","form":"诗","lines":["白华菅兮，白茅束兮。之子之远，俾我独兮。","英英白云，露彼菅茅。天步艰难，之子不犹。","滮池北流，浸彼稻田。啸歌伤怀，念彼硕人。","樵彼桑薪，卬烘于煁。维彼硕人，实劳我心。","鼓钟于宫，声闻于外。念子懆懆，视我迈迈。","有鹙在梁，有鹤在林。维彼硕人，实劳我心。","鸳鸯在梁，戢其左翼。之子无良，二三其德。","有扁斯石，履之卑兮。之子之远，俾我疧兮。"],"source":"《诗经》"},{"title":"绵蛮","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵蛮黄鸟，止于丘阿。道之云远，我劳如何。饮之食之，教之诲之。命彼后车，谓之载之。","绵蛮黄鸟，止于丘隅。岂敢惮行，畏不能趋。饮之食之。教之诲之。命彼后车，谓之载之。","绵蛮黄鸟，止于丘侧。岂敢惮行，畏不能极。饮之食之，教之诲之。命彼后车，谓之载之。"],"source":"《诗经》"},{"title":"瓠叶","author":"佚名","dynasty":"先秦","form":"诗","lines":["幡幡瓠叶，采之亨之。君子有酒，酌言尝之。","有兔斯首，炮之燔之。君子有酒，酌言献之。","有兔斯首，燔之炙之。君子有酒，酌言酢之。","有兔斯首，燔之炮之。君子有酒，酌言酬之。"],"source":"《诗经》"},{"title":"渐渐之石","author":"佚名","dynasty":"先秦","form":"诗","lines":["渐渐之石，维其高矣。山川悠远，维其劳矣。武人东征，不遑朝矣。","渐渐之石，维其卒矣。山川悠远，曷其没矣？武人东征，不遑出矣。","有豕白蹢，烝涉波矣。月离于毕，俾滂沱矣。武人东征，不皇他矣。"],"source":"《诗经》"},{"title":"苕之华","author":"佚名","dynasty":"先秦","form":"诗","lines":["苕之华，芸其黄矣。心之忧矣，维其伤矣！","苕之华，其叶青青。知我如此，不如无生！","牂羊坟首，三星在罶。人可以食，鲜可以饱！"],"source":"《诗经》"},{"title":"何草不黄","author":"佚名","dynasty":"先秦","form":"诗","lines":["何草不黄？何日不行？何人不将？经营四方。","何草不玄？何人不矜？哀我征夫，独为匪民。","匪兕匪虎，率彼旷野。哀我征夫，朝夕不暇。","有芃者狐，率彼幽草。有栈之车，行彼周道。"],"source":"《诗经》"},{"title":"文王","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王在上，于昭于天。周虽旧邦，其命维新。有周不显，帝命不时。文王陟降，在帝左右。","亹亹文王，令闻不已。陈锡哉周，侯文王孙子。文王孙子，本支百世，凡周之士，不显亦世。","世之不显，厥犹翼翼。思皇多士，生此王国。王国克生，维周之桢；济济多士，文王以宁。","穆穆文王，于缉熙敬止。假哉天命。有商孙子。商之孙子，其丽不亿。上帝既命，侯于周服。","侯服于周，天命靡常。殷士肤敏。裸将于京。厥作裸将，常服黼冔。王之荩臣。无念尔祖。","无念尔祖，聿修厥德。永言配命，自求多福。殷之未丧师，克配上帝。宜鉴于殷，骏命不易！","命之不易，无遏尔躬。宣昭义问，有虞殷自天。上天之载，无声无臭。仪刑文王，万邦作孚。"],"source":"《诗经》"},{"title":"大明","author":"佚名","dynasty":"先秦","form":"诗","lines":["明明在下，赫赫在上。天难忱斯，不易维王。天位殷适，使不挟四方。","挚仲氏任，自彼殷商，来嫁于周，曰嫔于京。乃及王季，维德之行。","大任有身，生此文王。维此文王，小心翼翼。昭事上帝，聿怀多福。厥德不回，以受方国。","天监在下，有命既集。文王初载，天作之合。在洽之阳，在渭之涘。","文王嘉止，大邦有子。大邦有子，伣天之妹。文定厥祥，亲迎于渭。造舟为梁，不显其光。","有命自天，命此文王。于周于京，缵女维莘。长子维行，笃生武王。保右命尔，燮伐大商。","殷商之旅，其会如林。矢于牧野，维予侯兴。上帝临女，无二尔心。","牧野洋洋，檀车煌煌，驷騵彭彭。维师尚父，时维鹰扬。凉彼武王，四伐大商，会朝清明。"],"source":"《诗经》"},{"title":"绵","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵绵瓜瓞。民之初生，自土沮漆。古公亶父，陶复陶冗，未有家室。","古公亶父，来朝走马。率西水浒，至于岐下。爰及姜女，聿来胥宇。","周原膴膴，堇荼如饴。爰始爰谋，爰契我龟，曰止曰时，筑室于兹。","乃慰乃止，乃左乃右，乃疆乃理，乃宣乃亩。自西徂东，周爰执事。","乃召司空，乃召司徒，俾立室家。其绳则直，缩版以载，作庙翼翼。","捄之陾陾，度之薨薨，筑之登登，削屡冯冯。百堵皆兴，鼛鼓弗胜。","乃立皋门，皋门有伉。乃立应门，应门将将。乃立冢土，戎丑攸行。","四不殄厥愠，亦不陨厥问。柞棫拔矣，行道兑矣。混夷駾矣，维其喙矣！","虞芮质厥成，文王蹶厥生。予曰有疏附，予曰有先后。予曰有奔奏，予曰有御侮！"],"source":"《诗经》"},{"title":"棫朴","author":"佚名","dynasty":"先秦","form":"诗","lines":["芃芃棫朴，薪之槱之。济济辟王，左右趣之。","济济辟王，左右奉璋。奉璋峨峨，髦士攸宜。","淠彼泾舟，烝徒楫之。周王于迈，六师及之。","倬彼云汉，为章于天。周王寿考，遐不作人？","追琢其章，金玉其相。勉勉我王，纲纪四方。"],"source":"《诗经》"},{"title":"旱麓","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼旱麓，榛楛济济。岂弟君子，干禄岂弟。","瑟彼玉瓒，黄流在中。岂弟君子，福禄攸降。","鸢飞戾天，鱼跃于渊。岂弟君子，遐不作人？","清酒既载，骍牡既备。以享以祀，以介景福。","瑟彼柞棫，民所燎矣。岂弟君子，神所劳矣。","莫莫葛藟，施于条枚。岂弟君子，求福不回。"],"source":"《诗经》"},{"title":"思齐","author":"佚名","dynasty":"先秦","form":"诗","lines":["思齐大任，文王之母，思媚周姜，京室之妇。大姒嗣徽音，则百斯男。","惠于宗公，神罔时怨，神罔时恫。刑于寡妻，至于兄弟，以御于家邦。","雍雍在宫，肃肃在庙。不显亦临，无射亦保。","四戎疾不殄，烈假不瑕。不闻亦式，不谏亦入。四成人有德，小子有造。古之人无斁，誉髦斯士。"],"source":"《诗经》"},{"title":"皇矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["皇矣上帝，临下有赫。监观四方，求民之莫。维此二国，其政不获。","维彼四国，爰究爰度。上帝耆之，憎其式廓。乃眷西顾，此维与宅。","作之屏之，其菑其翳。修之平之，其灌其栵。启之辟之，其柽其椐。","攘之剔之，其檿其柘。帝迁明德，串夷载路。天立厥配，受命既固。","帝省其山，柞棫斯拔，松柏斯兑。帝作邦作对，自大伯王季。维此王季，","因心则友。则友其兄，则笃其庆，载锡之光。受禄无丧，奄有四方。","维此王季，帝度其心。貊其德音，其德克明。克明克类，克长克君。","王此大邦，克顺克比。比于文王，其德靡悔。既受帝祉，施于孙子。","帝谓文王：无然畔援，无然歆羡，诞先登于岸。密人不恭，敢距大邦，","侵阮徂共。王赫斯怒，爰整其旅，以按徂旅。以笃于周祜，以对于天下。","依其在京，侵自阮疆。陟我高冈，无矢我陵。我陵我阿，无饮我泉，","我泉我池。度其鲜原，居岐之阳，在渭之将。万邦之方，下民之王。","帝谓文王：予怀明德，不大声以色，不长夏以革。不识不知，顺帝之则。","帝谓文王：訽尔仇方，同尔弟兄。以尔钩援，与尔临冲，以伐崇墉。","临冲闲闲，崇墉言言。执讯连连，攸馘安安。是类是禡，是致是附，","四方以无侮。临冲茀茀，崇墉仡仡。是伐是四，是绝是忽。四方以无拂。"],"source":"《诗经》"},{"title":"灵台","author":"佚名","dynasty":"先秦","form":"诗","lines":["经始灵台，经之营之。庶民攻之，不日成之。经始勿亟，庶民子来。","王在灵囿，麀鹿攸伏。麀鹿濯濯，白鸟翯翯。王在灵沼，于牣鱼跃。","虡业维枞，贲鼓维镛。于论鼓钟，于乐辟雍。","于论鼓钟，于乐辟雍。鼍鼓逢逢。矇瞍奏公。"],"source":"《诗经》"},{"title":"下武","author":"佚名","dynasty":"先秦","form":"诗","lines":["下武维周，世有哲王。三后在天，王配于京。","王配于京，世德作求。永言配命，成王之孚。","成王之孚，下土之式。永言孝思，孝思维则。","媚兹一人，应侯顺德。永言孝思，昭哉嗣服。","昭兹来许，绳其祖武。于万斯年，受天之祜。","受天之祜，四方来贺。于万斯年，不遐有佐。"],"source":"《诗经》"},{"title":"文王有声","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王有声，遹骏有声。遹求厥宁，遹观厥成。文王烝哉！","文王受命，有此武功。既伐于崇，作邑于丰。文王烝哉！","筑城伊淢，作丰伊匹。匪棘其欲，遹追来孝。王后烝哉！","王公伊濯，维丰之垣。四方攸同，王后维翰。王后烝哉！","丰水东注，维禹之绩。四方攸同，皇王维辟。皇王烝哉！","镐京辟雍，自西自东，自南自北，无思不服。皇王烝哉！","考卜维王，宅是镐京。维龟正之，武王成之。武王烝哉！","丰水有芑，武王岂不仕？诒厥孙谋，以燕翼子。武王烝哉！"],"source":"《诗经》"},{"title":"生民","author":"佚名","dynasty":"先秦","form":"诗","lines":["厥初生民，时维姜嫄。生民如何？克禋克祀，以弗无子。","履帝武敏歆，攸介攸止，载震载夙。载生载育，时维后稷。","诞弥厥月，先生如达。不拆不副，无菑无害。以赫厥灵。","上帝不宁，不康禋祀，居然生子。","诞寘之隘巷，牛羊腓字之。诞寘之平林，会伐平林。","诞寘之寒冰，鸟覆翼之。鸟乃去矣，后稷呱矣。","实覃实訏，厥声载路。诞实匍匐，克岐克嶷。以就口食。","蓺之荏菽，荏菽旆旆。禾役穟穟，麻麦幪幪，瓜瓞唪唪。","诞后稷之穑，有相之道。茀厥丰草，种之黄茂。实方实苞，实种实褎。","实发实秀，实坚实好。实颖实栗，即有邰家室。","诞降嘉种，维秬维秠，维穈维芑。恒之秬秠，是获是亩。","恒之穈芑，是任是负。以归肇祀。","诞我祀如何？或舂或揄，或簸或蹂。释之叟叟，烝之浮浮。","载谋载惟。取萧祭脂，取羝以軷，载燔载烈，以兴嗣岁。","卬盛于豆，于豆于登。其香始升，上帝居歆。胡臭亶时。","后稷肇祀。庶无罪悔，以迄于今。"],"source":"《诗经》"},{"title":"行苇","author":"佚名","dynasty":"先秦","form":"诗","lines":["敦彼行苇，牛羊勿践履。方苞方体，维叶泥泥。","戚戚兄弟，莫远具尔。或四之筵，或授之几。","四筵设席，授几有缉御。或献或酢，洗爵奠斝。","醓醢以荐，或燔或炙。嘉肴脾臄，或歌或咢。","敦弓既坚，四鍭既均，舍矢既均，序宾以贤。","敦弓既句，既挟四鍭。四鍭如树，序宾以不侮。","曾孙维主，酒醴维醽，酌以大斗，以祈黄耇。","黄耇台背，以引以翼。寿考维祺，以介景福。"],"source":"《诗经》"},{"title":"既醉","author":"佚名","dynasty":"先秦","form":"诗","lines":["既醉以酒，既饱以德。君子万年，介尔景福。","既醉以酒，尔肴既将。君子万年，介尔昭明。","昭明有融，高朗令终，令终有俶。公尸嘉告。","其告维何？笾豆静嘉。朋友攸摄，摄以威仪。","威仪孔时，君子有孝子。孝子不匮，永锡尔类。","其类维何？室家之壶。君子万年，永锡祚胤。","其胤维何？天被尔禄。君子万年，景命有仆。","其仆维何？厘尔女士。厘尔女士，从以孙子。"],"source":"《诗经》"},{"title":"凫鹥","author":"佚名","dynasty":"先秦","form":"诗","lines":["凫鹥在泾，公尸在燕来宁。尔酒既清，尔肴既馨。公尸燕饮，福禄来成。","凫鹥在沙，公尸来燕来宜。尔酒既多，尔肴既嘉。公尸燕饮，福禄来为。","凫鹥在渚，公尸来燕来处。尔酒既湑，尔肴伊脯。公尸燕饮，福禄来下。","凫鹥在潀，公尸来燕来宗，既燕于宗，福禄攸降。公尸燕饮，福禄来崇。","凫鹥在亹，公尸来止熏熏。旨酒欣欣，燔炙芬芬。公尸燕饮，无有后艰。"],"source":"《诗经》"},{"title":"假乐","author":"佚名","dynasty":"先秦","form":"诗","lines":["假乐君子，显显令德，宜民宜人。受禄于天，保右命之，自天申之。","千禄百福，子孙千亿。穆穆皇皇，宜君宜王。不愆不忘，率由旧章。","威仪抑抑，德音秩秩。无怨无恶，率由群匹。受福无疆，四方之纲。","之纲之纪，燕及朋友。百辟卿士，媚于天子。不解于位，民之攸塈。"],"source":"《诗经》"},{"title":"公刘","author":"佚名","dynasty":"先秦","form":"诗","lines":["笃公刘，匪居匪康。乃埸乃疆，乃积乃仓；乃裹餱粮，于橐于囊。","思辑用光，弓矢斯张；干戈戚扬，爰方启行。","笃公刘，于胥斯原。既庶既繁，既顺乃宣，而无永叹。陟则在巘，","复降在原。何以舟之？维玉及瑶，鞞琫容刀。","笃公刘，逝彼百泉。瞻彼溥原，乃陟南冈。乃觏于京，京师之野。","于时处处，于时庐旅，于时言言，于时语语。","笃公刘，于京斯依。跄跄济济，俾筵俾几。既登乃依，乃造其曹。","执豕于牢，酌之用匏。食之饮之，君之宗之。","笃公刘，既溥既长。既景乃冈，相其阴阳，观其流泉。其军三单，","度其隰原。彻田为粮，度其夕阳。豳居允荒。","笃公刘，于豳斯馆。涉渭为乱，取厉取锻，止基乃理。爰众爰有，","夹其皇涧。溯其过涧。止旅乃密，芮鞫之即。"],"source":"《诗经》"},{"title":"泂酌","author":"佚名","dynasty":"先秦","form":"诗","lines":["泂酌彼行潦，挹彼注兹，可以餴饎。岂弟君子，民之父母。","泂酌彼行潦，挹彼注兹，可以濯罍。岂弟君子，民之攸归。","泂酌彼行潦，挹彼注兹，可以濯溉。岂弟君子，民之攸墍。"],"source":"《诗经》"},{"title":"卷阿","author":"佚名","dynasty":"先秦","form":"诗","lines":["有卷者阿，飘风自南。岂弟君子，来游来歌，以矢其音。","伴奂尔游矣，优游尔休矣。岂弟君子，俾尔弥尔性，似先公酋矣。","尔土宇昄章，亦孔之厚矣。岂弟君子，俾尔弥尔性，百神尔主矣。","尔受命长矣，茀禄尔康矣。岂弟君子，俾尔弥尔性，纯嘏尔常矣。","有冯有翼，有孝有德，以引以翼。岂弟君子，四方为则。","颙颙卬卬，如圭如璋，令闻令望。岂弟君子，四方为纲。","凤凰于飞，翙翙其羽，亦集爰止。蔼蔼王多吉士，维君子使，媚于天子。","凤凰于飞，翙翙其羽，亦傅于天。蔼蔼王多吉人，维君子命，媚于庶人。","凤凰鸣矣，于彼高冈。梧桐生矣，于彼朝阳。菶菶萋萋，雍雍喈喈。","君子之车，既庶且多。君子之马，既闲且驰。矢诗不多，维以遂歌。"],"source":"《诗经》"},{"title":"民劳","author":"佚名","dynasty":"先秦","form":"诗","lines":["民亦劳止，汔可小康。惠此中国，以绥四方。无纵诡随，以谨无良。","式遏寇虐，憯不畏明。柔远能迩，以定我王。","民亦劳止，汔可小休。惠此中国，以为民逑。无纵诡随，以谨惛怓。","式遏寇虐，无俾民忧。无弃尔劳，以为王休。","民亦劳止，汔可小息。惠此京师，以绥四国。无纵诡随，以谨罔极。","式遏寇虐，无俾作慝。敬慎威仪，以近有德。","民亦劳止，汔可小愒。惠此中国，俾民忧泄。无纵诡随，以谨丑厉。","式遏寇虐，无俾正败。戎虽小子，而式弘大。","民亦劳止，汔可小安。惠此中国，国无有残。无纵诡随，以谨缱绻。","式遏寇虐，无俾正反。王欲玉女，是用大谏。"],"source":"《诗经》"},{"title":"板","author":"佚名","dynasty":"先秦","form":"诗","lines":["上帝板板，下民卒瘅。出话不然，为犹不远。","靡圣管管。不实于亶。犹之未远，是用大谏。","天之方难，无然宪宪。天之方蹶，无然泄泄。","辞之辑矣，民之洽矣。辞之怿矣，民之莫矣。","我虽异事，及尔同僚。我即尔谋，听我嚣嚣。","我言维服，勿以为笑。先民有言，询于刍荛。","天之方虐，无然谑谑。老夫灌灌，小子蹻蹻。","匪我言耄，尔用忧谑。多将熇熇，不可救药。","天之方懠。无为夸毗。威仪卒迷，善人载尸。","民之方殿屎，则莫我敢葵？丧乱蔑资，曾莫惠我师？","天之牖民，如埙如篪，如璋如圭，如取如携。","携无曰益，牖民孔易。民之多辟，无自立辟。","价人维藩，大师维垣，大邦维屏，大宗维翰，","怀德维宁，宗子维城。无俾城坏，无独斯畏。","敬天之怒，无敢戏豫。敬天之渝，无敢驰驱。","昊天曰明，及尔出王。昊天曰旦，及尔游衍。"],"source":"《诗经》"},{"title":"荡","author":"佚名","dynasty":"先秦","form":"诗","lines":["荡荡上帝，下民之辟。疾威上帝，其命多辟。","天生烝民，其命匪谌。靡不有初，鲜克有终。","文王曰咨，咨汝殷商。曾是彊御？曾是掊克？","曾是在位？曾是在服？天降滔德，女兴是力。","文王曰咨，咨女殷商。而秉义类，彊御多怼。","流言以对。寇攘式内。侯作侯祝，靡届靡究。","文王曰咨，咨女殷商。女炰烋于中国。敛怨以为德。","不明尔德，时无背无侧。尔德不明，以无陪无卿。","文王曰咨，咨女殷商。天不湎尔以酒，不义从式。","既衍尔止。靡明靡晦。式号式呼。俾昼作夜。","文王曰咨，咨女殷商。如蜩如螗，如沸如羹。","小大近丧，人尚乎由行。内奰于中国，覃及鬼方。","文王曰咨，咨女殷商。匪上帝不时，殷不用旧。","虽无老成人，尚有典刑。曾是莫听，大命以倾。","文王曰咨，咨女殷商。人亦有言：颠沛之揭，","枝叶未有害，本实先拨。殷鉴不远，在夏后之世。"],"source":"《诗经》"},{"title":"抑","author":"佚名","dynasty":"先秦","form":"诗","lines":["抑抑威仪，维德之隅。人亦有言：靡哲不愚，庶人之愚，亦职维疾。","哲人之愚，亦维斯戾。无竞维人，四方其训之。有觉德行，四国顺之。","訏谟定命，远犹辰告。敬慎威仪，维民之则。其在于今，兴迷乱于政。","颠覆厥德，荒湛于酒。女虽湛乐从，弗念厥绍。罔敷求先王，克共明刑。","四皇天弗尚，如彼泉流，无沦胥以亡。夙兴夜寐，洒扫庭内，维民之章。","修尔车马，弓矢戎兵，用戒戎作，用逷蛮方。质尔人民，谨尔侯度，用戒不虞。","慎尔出话，敬尔威仪，无不柔嘉。白圭之玷，尚可磨也；斯言之玷，不可为也！","无易由言，无曰苟矣，莫扪朕舌，言不可逝矣。无言不仇，无德不报。","惠于朋友，庶民小子。子孙绳绳，万民靡不承。视尔友君子，辑柔尔颜，不遐有愆。","相在尔室，尚不愧于屋漏。无曰不显，莫予云觏。神之格思，不可度思，矧可射思！","辟尔为德，俾臧俾嘉。淑慎尔止，不愆于仪。不僭不贼，鲜不为则。投我以桃，报之以李。","彼童而角，实虹小子。荏染柔木，言缗之丝。温温恭人，维德之基。","其维哲人，告之话言，顺德之行。其维愚人，覆谓我僭。民各有心。","于乎小子，未知臧否。匪手携之，言示之事。匪面命之，言提其耳。","借曰未知，亦既抱子。民之靡盈，谁夙知而莫成？昊天孔昭，我生靡乐。","视尔梦梦，我心惨惨。诲尔谆谆，听我藐藐。匪用为教，覆用为虐。","借曰未知，亦聿既耄。于乎，小子，告尔旧止。听用我谋，庶无大悔。","天方艰难，曰丧厥国。取譬不远，昊天不忒。回遹其德，俾民大棘。"],"source":"《诗经》"},{"title":"桑柔","author":"佚名","dynasty":"先秦","form":"诗","lines":["菀彼桑柔，其下侯旬，捋采其刘，瘼此下民。不殄心忧，仓兄填兮。倬彼昊天，宁不我矜？","四牡骙骙，旟旐有翩。乱生不夷，靡国不泯。民靡有黎，具祸以烬。于乎有哀，国步斯频。","国步灭资，天不我将。靡所止疑，云徂何往？君子实维，秉心无竞。谁生厉阶，至今为梗？","忧心殷殷，念我土宇。我生不辰，逢天僤怒。自西徂东，靡所定处。多我觏痻，孔棘我圉。","为谋为毖，乱况斯削。告尔忧恤，诲尔序爵。谁能执热，逝不以濯？其何能淑，载胥及溺。","如彼溯风，亦孔之僾。民有肃心，荓云不逮。好是稼穑，力民代食。稼穑维宝，代食维好？","天降丧乱，灭我立王。降此蟊贼，稼穑卒痒。哀恫中国，具赘卒荒。靡有旅力，以念穹苍。","维此惠君，民人所瞻。秉心宣犹，考慎其相。维彼不顺，自独俾臧。自有肺肠，俾民卒狂。","瞻彼中林，甡甡其鹿。朋友已谮，不胥以穀。人亦有言：进退维谷。","维此圣人，瞻言百里。维彼愚人，覆狂以喜。匪言不能，胡斯畏忌？","维此良人，弗求弗迪。维彼忍心，是顾是复。民之贪乱，宁为荼毒。","大风有隧，有空大谷。维此良人，作为式穀。维彼不顺，征以中垢。","大风有隧，贪人败类。听言则对，诵言如醉。匪用其良，复俾我悖。","嗟尔朋友，予岂不知而作。如彼飞虫，时亦弋获。既之阴女，反予来赫。","民之罔极，职凉善背。为民不利，如云不克。民之回遹，职竞用力。","民之未戾，职盗为寇。凉曰不可，覆背善詈。虽曰匪予，既作尔歌！"],"source":"《诗经》"},{"title":"云汉","author":"佚名","dynasty":"先秦","form":"诗","lines":["倬彼云汉，昭回于天。王曰：于乎！何辜今之人？天降丧乱，饥馑荐臻。","靡神不举，靡爱斯牲。圭壁既卒，宁莫我听？","旱既大甚，蕴隆虫虫。不殄禋祀，自郊徂宫。上下奠瘗，靡神不宗。","后稷不克，上帝不临。耗斁下土，宁丁我梗","旱既大甚，则不可推。兢兢业业，如霆如雷。周余黎民，靡有孑遗。","昊天上帝，则不我遗。胡不相畏？先祖于摧。","旱既大甚，则不可沮。赫赫炎炎，云我无所。大命近止，靡瞻靡顾。","群公先正，则不我助。父母先祖，胡宁忍予？","旱既大甚，涤涤山川。旱魃为虐，如惔如焚。我心惮暑，忧心如熏。","群公先正，则不我闻。昊天上帝，宁俾我遁？","旱既大甚，黾勉畏去。胡宁瘨我以旱？憯不知其故。祈年孔夙，方社不莫。","昊天上帝，则不我虞。","敬恭明神，宜无悔怒。旱既大甚，散无友纪。鞫哉庶正，疚哉冢宰。","趣马师氏，膳夫左右。靡人不周。无不能止，瞻卬昊天，云如何里！","瞻卬昊天，有嘒其星。大夫君子，昭假无赢。大命近止，无弃尔成。","何求为我。以戾庶正。瞻卬昊天，曷惠其宁？"],"source":"《诗经》"},{"title":"崧高","author":"佚名","dynasty":"先秦","form":"诗","lines":["崧高维岳，骏极于天。维岳降神，生甫及申。维申及甫，维周之翰。四国于蕃。四方于宣。","亹亹申伯，王缵之事。于邑于谢，南国是式。王命召伯，定申伯之宅。登是南邦，世执其功。","王命申伯，式是南邦。因是谢人，以作尔庸。王命召伯，彻申伯土田。王命傅御，迁其私人。","申伯之功，召伯是营。有俶其城，寝庙既成。既成藐藐，王锡申伯。四牡蹻蹻，钩膺濯濯。","王遣申伯，路车乘马。我图尔居，莫如南土。锡尔介圭，以作尔宝。往近王舅，南土是保。","申伯信迈，王饯于郿。申伯还南，谢于诚归。王命召伯，彻申伯土疆。以峙其粻，式遄其行。","申伯番番，既入于谢。徒御啴啴。周邦咸喜，戎有良翰。不显申伯，王之元舅，文武是宪。","申伯之德，柔惠且直。揉此万邦，闻于四国。吉甫作诵，其诗孔硕。其风四好，以赠申伯。"],"source":"《诗经》"},{"title":"烝民","author":"佚名","dynasty":"先秦","form":"诗","lines":["天生烝民，有物有则。民之秉彝，好是懿德。天监有周，昭假于下。保兹天子，生仲山甫。","仲山甫之德，柔嘉维则。令仪令色。小心翼翼。古训是式。威仪是力。天子是若，明命使赋。","王命仲山甫，式是百辟，缵戎祖考，王躬是保。出纳王命，王之喉舌。赋政于外，四方爰发。","肃肃王命，仲山甫将之。邦国若否，仲山甫明之。既明且哲，以保其身。夙夜匪解，以事一人。","人亦有言，柔则茹之，刚则吐之。维仲山甫，柔亦不茹，刚亦不吐。不侮矜寡，不畏强御。","人亦有言，德輶如毛，民鲜克举之。我仪图之，维仲山甫举之。爱莫助之。衮职有阙，维仲山甫补之。","仲山甫出祖。四牡业业。征夫捷捷，每怀靡及。四牡彭彭，八鸾锵锵。王命仲山甫，城彼东方。","四牡骙骙，八鸾喈喈。仲山甫徂齐，式遄其归。吉甫作诵，穆如清风。仲山甫永怀，以慰其心。"],"source":"《诗经》"},{"title":"韩奕","author":"佚名","dynasty":"先秦","form":"诗","lines":["奕奕梁山，维禹甸之，有倬其道。","韩侯受命，王亲命之：缵戎祖考，无废朕命。","夙夜匪解，虔共尔位，朕命不易。","粲不庭方，以佐戎辟。四牡奕奕，孔修且张。","韩侯入觐，以其介圭，入觐于王。","王锡韩侯，淑旂绥章，簟茀错衡。","玄衮赤舄，钩膺镂锡，鞹鞃浅幭，鞗革金厄。","韩侯出祖，出宿于屠。显父饯之，清酒百壶。","其殽维何？炰鳖鲜鱼。其蔌维何？维笋及蒲。","其赠维何？乘马路车。笾豆有且。侯氏燕胥。","韩侯取妻，汾王之甥，蹶父之子。","韩侯迎止，于蹶之里。","百两彭彭，八鸾锵锵，不显其光。","诸娣从之，祁祁如云。韩侯顾之，烂其盈门。","蹶父孔武，靡国不到。为韩姞相攸，莫如韩乐。","孔乐韩土，川泽訏訏，鲂鱮甫甫，麀鹿噳噳。","有熊有罴，有猫有虎。庆既令居，韩姞燕誉。","溥彼韩城，燕师所完。以先祖受命，因时百蛮。","王锡韩侯，其追其貊。奄受北国，因以其伯。","实墉实壑，实亩实藉。献其貔皮，赤豹黄罴。"],"source":"《诗经》"},{"title":"江汉","author":"佚名","dynasty":"先秦","form":"诗","lines":["江汉浮浮，武夫滔滔。匪安匪游，淮夷来求。既出我车，既设我旟。匪安匪舒，淮夷来铺。","江汉汤汤，武夫洸洸。经营四方，告成于王。四方既平，王国庶定。时靡有争，王心载宁。","江汉之浒，王命召虎：式辟四方，彻我疆土。匪疚匪棘，王国来极。于疆于理，至于南海。","王命召虎：来旬来宣。文武受命，召公维翰。无曰予小子，召公是似。肇敏戎公，用锡尔祉。","厘尔圭瓒，秬鬯一卣。告于文人，锡山土田。于周受命，自召祖命，虎拜稽首：天子万年！","虎拜稽首，对扬王休。作召公考：天子万寿！明明天子，令闻不已，矢其文德，洽此四国。"],"source":"《诗经》"},{"title":"常武","author":"佚名","dynasty":"先秦","form":"诗","lines":["赫赫明明。王命卿士，南仲大祖，大师皇父。整我六师，以修我戎。既敬既戒，惠此南国。","王谓尹氏，命程伯休父，左右陈行。戒我师旅，率彼淮浦，省此徐土。不留不处，三事就绪。","赫赫业业，有严天子。王舒保作，匪绍匪游。徐方绎骚，震惊徐方。如雷如霆，徐方震惊。","王奋厥武，如震如怒。进厥虎臣，阚如虓虎。铺敦淮濆，仍执丑虏。截彼淮浦，王师之所。","王旅啴啴，如飞如翰。如江如汉，如山之苞。如川之流，绵绵翼翼。不测不克，濯征徐国。","王犹允塞，徐方既来。徐方既同，天子之功。四方既平，徐方来庭。徐方不回，王曰还归。"],"source":"《诗经》"},{"title":"瞻卬","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻卬昊天，则不我惠。孔填不宁，降此大厉。邦靡有定，士民其瘵。","蟊贼蟊疾，靡有夷届。罪罟不收，靡有夷瘳。","人有土田，女反有之。人有民人，女覆夺之。此宜无罪，女反收之。","彼宜有罪，女覆说之。","哲夫成城，哲妇倾城。懿厥哲妇，为枭为鸱。妇有长舌，维厉之阶。","乱匪降自天，生自妇人。匪教匪诲，时维妇寺。","鞫人忮忒。谮始竞背。岂曰不极？伊胡为慝？如贾三倍，君子是识。","妇无公事，休其蚕织。","天何以剌？何神不富？舍尔介狄，维予胥忌。不吊不祥，威仪不类。","人之云亡，邦国殄瘁。","天之降罔，维其优矣。人之云亡，心之忧矣。天之降罔，维其几矣。","人之云亡，心之悲矣。","觱沸槛泉，维其深矣。心之忧矣，宁自今矣？不自我先，不自我后。","藐藐昊天，无不克巩。无忝皇祖，式救尔后。"],"source":"《诗经》"},{"title":"召旻","author":"佚名","dynasty":"先秦","form":"诗","lines":["旻天疾威，天笃降丧。瘨我饥馑，民卒流亡。我居圉卒荒。","天降罪罟，蟊贼内讧。昏椓靡共，溃溃回遹，实靖夷我邦。","皋皋訿訿，曾不知其玷。兢兢业业，孔填不宁，我位孔贬。","如彼岁旱，草不溃茂，如彼栖苴。我相此邦，无不溃止。","维昔之富不如时，维今之疚不如兹。彼疏斯粺，胡不自替？职兄斯引。","池之竭矣，不云自频。泉之竭矣，不云自中。溥斯害矣，职兄斯弘，不灾我躬。","昔先王受命，有如召公，日辟国百里，今也日蹙国百里。于乎哀哉！维今之人，不尚有旧！"],"source":"《诗经》"},{"title":"清庙","author":"佚名","dynasty":"先秦","form":"诗","lines":["于穆清庙，肃雍显相。济济多士，秉文之德。对越在天，骏奔走在庙。不显不承，无射于人斯。"],"source":"《诗经》"},{"title":"维天之命","author":"佚名","dynasty":"先秦","form":"诗","lines":["维天之命，于穆不已。于乎不显，文王之德之纯。假以溢我，我其收之。骏惠我文王，曾孙笃之。"],"source":"《诗经》"},{"title":"维清","author":"佚名","dynasty":"先秦","form":"诗","lines":["维清缉熙，文王之典。肇禋，迄用有成，维周之祯。"],"source":"《诗经》"},{"title":"烈文","author":"佚名","dynasty":"先秦","form":"诗","lines":["烈文辟公，锡兹祉福。惠我无疆，子孙保之。无封靡于尔邦，维王其崇之。","念兹戎功，继序其皇之。无竞维人，四方其训之。不显维德，百辟其刑之。于乎，前王不忘！"],"source":"《诗经》"},{"title":"天作","author":"佚名","dynasty":"先秦","form":"诗","lines":["天作高山，大王荒之。彼作矣，文王康之。彼徂矣，岐有夷之行。子孙保之。"],"source":"《诗经》"},{"title":"昊天有成命","author":"佚名","dynasty":"先秦","form":"诗","lines":["昊天有成命，二后受之。成王不敢康，夙夜基命宥密。于缉熙！单厥心，四其靖之。"],"source":"《诗经》"},{"title":"我将","author":"佚名","dynasty":"先秦","form":"诗","lines":["我将我享，维羊维牛，维天其右之。仪式刑文王之典，日靖四方。","伊嘏文王，既右飨之。我其夙夜，畏天之威，于时保之。"],"source":"《诗经》"},{"title":"时迈","author":"佚名","dynasty":"先秦","form":"诗","lines":["时迈其邦，昊天其子之，实右序有周。薄言震之，莫不震叠。怀柔百神，及河乔岳，允王维后。","明昭有周，式序在位。载戢干戈，载橐弓矢。我求懿德，四于时夏，允王保之。"],"source":"《诗经》"},{"title":"执竞","author":"佚名","dynasty":"先秦","form":"诗","lines":["执竞武王，无竞维烈。不显成康，上帝是皇。自彼成康，奄有四方，斤斤其明。","钟鼓喤喤，磬莞将将，降福穰穰。降福简简，威仪反反。既醉既饱，福禄来反。"],"source":"《诗经》"},{"title":"思文","author":"佚名","dynasty":"先秦","form":"诗","lines":["思文后稷，克配彼天。立我烝民，莫菲尔极。贻我来牟，帝命率育，无此疆尔界。陈常于时夏。"],"source":"《诗经》"},{"title":"臣工","author":"佚名","dynasty":"先秦","form":"诗","lines":["嗟嗟臣工，敬尔在公。王厘尔成，来咨来茹。嗟嗟保介，维莫之春，亦又何求？如何新畲？","于皇来牟，将受厥明。明昭上帝，迄用康年。命我众人：庤乃钱镈，奄观铚艾。"],"source":"《诗经》"},{"title":"噫嘻","author":"佚名","dynasty":"先秦","form":"诗","lines":["噫嘻成王，既昭假尔。率时农夫，播厥百谷。骏发尔私，终三十里。亦服尔耕，十千维耦。"],"source":"《诗经》"},{"title":"振鹭","author":"佚名","dynasty":"先秦","form":"诗","lines":["振鹭于飞，于彼西雍。我客戾止，亦有斯容。在彼无恶，在此无斁。庶几夙夜，以永终誉。"],"source":"《诗经》"},{"title":"丰年","author":"佚名","dynasty":"先秦","form":"诗","lines":["丰年多黍多稌，亦有高廪，万亿及秭。为酒为醴，烝畀祖妣。以洽百礼，降福孔皆。"],"source":"《诗经》"},{"title":"有瞽","author":"佚名","dynasty":"先秦","form":"诗","lines":["有瞽有瞽，在周之庭。设业设虡，崇牙树羽。应田县鼓，鞉磬柷圉。既备","乃奏，箫管备举。喤喤厥声，肃雍和鸣，先祖是听。我客戾止，永观厥成。"],"source":"《诗经》"},{"title":"潜","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗与漆沮，潜有多鱼。有鳣有鲔，鲦鲿鰋鲤。以享以祀，以介景福。"],"source":"《诗经》"},{"title":"雝","author":"佚名","dynasty":"先秦","form":"诗","lines":["有来雝雝，至止肃肃。相维辟公，天子穆穆。于荐广牡，相予四祀。假哉皇考！绥予孝子。","宣哲维人，文武维后。燕及皇天，克昌厥后。绥我眉寿，介以繁祉，既右烈考，亦右文母。"],"source":"《诗经》"},{"title":"载见","author":"佚名","dynasty":"先秦","form":"诗","lines":["载见辟王，曰求厥章。龙旂阳阳，和铃央央。鞗革有鸧，休有烈光。率见昭考，以孝以享。","以介眉寿，永言保之，思皇多祜。烈文辟公，绥以多福，俾缉熙于纯嘏。"],"source":"《诗经》"},{"title":"有客","author":"佚名","dynasty":"先秦","form":"诗","lines":["有客有客，亦白其马。有萋有且，敦琢其旅。有客宿宿，有客信信。","言授之絷，以絷其马。薄言追之，左右绥之。既有淫威，降福孔夷。"],"source":"《诗经》"},{"title":"武","author":"佚名","dynasty":"先秦","form":"诗","lines":["于皇武王！无竞维烈。允文文王，克开厥后。嗣武受之，胜殷遏刘，耆定尔功。"],"source":"《诗经》"},{"title":"闵予小子","author":"佚名","dynasty":"先秦","form":"诗","lines":["闵予小子，遭家不造，嬛嬛在疚。于乎皇考，永世克孝。","念兹皇祖，陟降庭止。维予小子，夙夜敬止。于乎皇王，继序思不忘。"],"source":"《诗经》"},{"title":"访落","author":"佚名","dynasty":"先秦","form":"诗","lines":["访予落止，率时昭考。于乎悠哉，朕未有艾。将予就之，继犹判涣。","维予小子，未堪家多难。绍庭上下，陟降厥家。休矣皇考，以保明其身。"],"source":"《诗经》"},{"title":"敬之","author":"佚名","dynasty":"先秦","form":"诗","lines":["敬之敬之，天维显思，命不易哉。无曰高高在上，陟降厥士，日监在兹。","维予小子，不聪敬止。日就月将，学有缉熙于光明。佛时仔肩，示我显德行。"],"source":"《诗经》"},{"title":"小毖","author":"佚名","dynasty":"先秦","form":"诗","lines":["予其惩，而毖后患。莫予荓蜂，自求辛螫。肇允彼桃虫，拚飞维鸟。未堪家多难，予又集于蓼。"],"source":"《诗经》"},{"title":"载芟","author":"佚名","dynasty":"先秦","form":"诗","lines":["载芟载柞，其耕泽泽。千耦其耘，徂隰徂畛。侯主侯伯，侯亚侯旅，侯彊侯以。","有嗿其馌，思媚其妇，有依其士。有略其耜，俶载南亩，播厥百谷。实函斯活，驿驿其达。","有厌其杰，厌厌其苗，绵绵其麃。载获济济，有实其积，万亿及秭。为酒为醴，烝畀祖妣，不洽百礼。","有飶其香。邦家之光。有椒其馨，胡考之宁。匪且有且，匪今斯今，振古如兹。"],"source":"《诗经》"},{"title":"良耜","author":"佚名","dynasty":"先秦","form":"诗","lines":["畟畟良耜，俶载南亩。播厥百谷，实函斯活。或来瞻女，载筐及莒，其饟伊黍。","其笠伊纠，其镈斯赵，以薅荼蓼。荼蓼朽止，黍稷茂止。获之挃挃，积之栗栗。","其崇如墉，其比如栉。以开百室，百室盈止，妇子宁止。杀时犉牡，有捄其角。以似以续，续古之人。"],"source":"《诗经》"},{"title":"丝衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["丝衣其紑，载弁俅俅。自堂徂基，自羊徂牛，鼐鼎及鼒，兕觥其觩。旨酒思柔。不吴不敖，胡考之休。"],"source":"《诗经》"},{"title":"酌","author":"佚名","dynasty":"先秦","form":"诗","lines":["于铄王师，遵养时晦。时纯熙矣，是用大介。我龙受之，蹻蹻王之造。载用有嗣，实维尔公允师。"],"source":"《诗经》"},{"title":"桓","author":"佚名","dynasty":"先秦","form":"诗","lines":["绥万邦，屡丰年。天命匪解，桓桓武王。保有厥士，于以四方，克定厥家。于昭于天，皇以间之。"],"source":"《诗经》"},{"title":"赉","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王既勤止，我应受之。敷时绎思，我徂维求定。时周之命，于绎思。"],"source":"《诗经》"},{"title":"般","author":"佚名","dynasty":"先秦","form":"诗","lines":["于皇时周！陟其高山，嶞山乔岳，允犹翕河。敷天之下，裒时之对。时周之命。"],"source":"《诗经》"},{"title":"駉","author":"佚名","dynasty":"先秦","form":"诗","lines":["駉駉牡马，在坰之野。薄言駉者，有驈有皇，有骊有黄，以车彭彭。思无疆思，马斯臧。","駉駉牡马，在坰之野。薄言駉者，有骓有駓，有骍有骐，以车伾伾。思无期思，马斯才。","駉駉牡马，在坰之野。溥言駉者，有驒有骆，有骝有雒，以车绎绎。思无斁思，马斯作。","駉駉牡马，在坰之野。薄言駉者，有骃有騢，有驔有鱼，以车祛祛。思无邪思，马斯徂。"],"source":"《诗经》"},{"title":"有駜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有駜有駜，駜彼乘黄。夙夜在公，在公明明。振振鹭，鹭于下。鼓咽咽，醉言舞。于胥乐兮！","有駜有駜，駜彼乘牡。夙夜在公，在公饮酒。振振鹭，鹭于飞。鼓咽咽，醉言归。于胥乐兮！","有駜有駜，駜彼乘駽。夙夜在公，在公载燕。自今以始，岁其有。君子有穀，诒孙子。于胥乐兮！"],"source":"《诗经》"},{"title":"泮水","author":"佚名","dynasty":"先秦","form":"诗","lines":["思乐泮水，薄采其芹。鲁侯戾止，言观其旂。其旂茷茷，鸾声哕哕。无小无大，从公于迈。","思乐泮水，薄采其藻。鲁侯戾止，其马蹻蹻。其马蹻蹻，其音昭昭。载色载笑，匪怒伊教。","思乐泮水，薄采其茆。鲁侯戾止，在泮饮酒。既饮旨酒，永锡难老。顺彼长道，屈此群丑。","穆穆鲁侯，敬明其德。敬慎威仪，维民之则。允文允武，昭假烈祖。靡有不孝，自求伊祜。","明明鲁侯，克明其德。既作泮宫，淮夷攸服。矫矫虎臣，在泮献馘。淑问如皋陶，在泮献囚。","济济多士，克广德心。桓桓于征，狄彼东南。烝烝皇皇，不吴不扬。不告于訩，在泮献功。","角弓其觩。束矢其搜。戎车孔博。徒御无斁。既克淮夷，孔淑不逆。式固尔犹，淮夷卒获。","翩彼飞鸮，集于泮林。食我桑黮，怀我好音。憬彼淮夷，来献其琛。元龟象齿，大赂南金。"],"source":"《诗经》"},{"title":"閟宫","author":"佚名","dynasty":"先秦","form":"诗","lines":["閟宫有侐，实实枚枚。赫赫姜嫄，其德不回。上帝是依，无灾无害。","弥月不迟，是生后稷。降之百福。黍稷重穋，稙稚菽麦。奄有下国，俾民稼穑。","有稷有黍，有稻有秬。奄有下土，缵禹之绪。后稷之孙，实维大王。","居岐之阳，实始剪商。至于文武，缵大王之绪，致天之届，于牧之野。","无二无虞，上帝临女。敦商之旅，克咸厥功。王曰叔父，建尔元子，俾侯于鲁。","大启尔宇，为周室辅。乃命鲁公，俾侯于东。锡之山川，土田附庸。","周公之孙，庄公之子。龙旂承祀。六辔耳耳。春秋匪解，享祀不忒。","皇皇后帝！皇祖后稷！享以骍牺，是飨是宜。降福既多，周公皇祖，亦其福女。","秋而载尝，夏而楅衡，白牡骍刚。牺尊将将，毛炰胾羹。笾豆大房，万舞洋洋。","孝孙有庆。俾尔炽而昌，俾尔寿而臧。保彼东方，鲁邦是尝。不亏不崩，不震不腾。","三寿作朋，如冈如陵。公车千乘，朱英绿縢。二矛重弓。公徒三万，贝胄朱綅。","烝徒增增，戎狄是膺，荆舒是惩，则莫我敢承！俾尔昌而炽，俾尔寿而富。","黄发台背，寿胥与试。俾尔昌而大，俾尔耆而艾。万有千岁，眉寿无有害。","泰山岩岩，鲁邦所詹。奄有龟蒙，遂荒大东。至于海邦，淮夷来同。","莫不率从，鲁侯之功。保有凫绎，遂荒徐宅。至于海邦，淮夷蛮貊。","及彼南夷，莫不率从。莫敢不诺，鲁侯是若。天锡公纯嘏，眉寿保鲁。","居常与许，复周公之宇。鲁侯燕喜，令妻寿母。宜大夫庶士，邦国是有。","既多受祉，黄发儿齿。徂徠之松，新甫之柏。是断是度，是寻是尺。","松桷有舄，路寝孔硕，新庙奕奕。奚斯所作，孔曼且硕，万民是若。"],"source":"《诗经》"},{"title":"那","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗与那与！置我鞉鼓。奏鼓简简，衎我烈祖。汤孙奏假，绥我思成。","鞉鼓渊渊，嘒嘒管声。既和且平，依我磬声。于赫汤孙！穆穆厥声。","庸鼓有斁，万舞有奕。我有嘉客，亦不夷怿。自古在昔，先民有作。","温恭朝夕，执事有恪，顾予烝尝，汤孙之将。"],"source":"《诗经》"},{"title":"烈祖","author":"佚名","dynasty":"先秦","form":"诗","lines":["嗟嗟烈祖！有秩斯祜。申锡无疆，及尔斯所。既载清酤，赉我思成。","亦有和羹，既戒既平。鬷假无言，时靡有争。绥我眉寿，黄耇无疆。","约軧错衡，八鸾鸧鸧。以假以享，我受命溥将。自天降康，丰年穰穰。","来假来飨，降福无疆。顾予烝尝，汤孙之将。"],"source":"《诗经》"},{"title":"玄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["天命玄鸟，降而生商，宅殷土芒芒。古帝命武汤，正域彼四方。","方命厥后，奄有九有。商之先后，受命不殆，在武丁孙子。武丁孙子，武王靡不胜。","龙旂十乘，大糦是承。邦畿千里，维民所止，肇域彼四海。","四海来假，来假祁祁。景员维河。殷受命咸宜，百禄是何。"],"source":"《诗经》"},{"title":"长发","author":"佚名","dynasty":"先秦","form":"诗","lines":["浚哲维商，长发其祥。洪水芒芒，禹敷下土方。外大国是疆，幅陨既长。有娀方将，帝立子生商。","玄王桓拨，受小国是达，受大国是达。率履不越，遂视既发。相士烈烈。海外有截。","帝命不违，至于汤齐。汤降不迟，圣敬日跻。昭假迟迟，上帝是祗，帝命式于九围。","受小球大球，为下国缀旒，何天之休。不竞不絿，不刚不柔。敷政优优。百禄是遒。","受小共大共，为下国骏厖。何天之龙，敷奏其勇。不震不动，不戁不竦，百禄是总。","武王载旆，有虔秉钺。如火烈烈，则莫我敢曷。苞有三蘖，莫遂莫达。九有有截，韦顾既伐，昆吾夏桀。","昔在中叶，有震且业。允也天子，降予卿士。实维阿衡，实左右商王。"],"source":"《诗经》"},{"title":"殷武","author":"佚名","dynasty":"先秦","form":"诗","lines":["挞彼殷武，奋伐荆楚。深入其阻，裒荆之旅。有截其所，汤孙之绪。","维女荆楚，居国南乡。昔有成汤，自彼氐羌，莫敢不来享，莫敢不来王。曰商是常。","天命多辟，设都于禹之绩。岁事来辟，勿予祸适，稼穑匪解。","天命降监，下民有严。不僭不滥，不敢怠遑。命于下国，封建厥福。","商邑翼翼，四方之极。赫赫厥声，濯濯厥灵。寿考且宁，以保我后生。","陟彼景山，松伯丸丸。是断是迁，方斫是虔。松桷有梴，旅楹有闲，寝成孔安。"],"source":"《诗经》"},{"title":"离骚","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["帝高阳之苗裔兮，朕皇考曰伯庸。","摄提贞于孟陬兮，惟庚寅吾以降。","皇览揆余初度兮，肇锡余以嘉名：","名余曰正则兮，字余曰灵均。","纷吾既有此内美兮，又重之以修能。","扈江离与辟芷兮，纫秋兰以为佩。","汨余若将不及兮，恐年岁之不吾与。","朝搴阰之木兰兮，夕揽洲之宿莽。","日月忽其不淹兮，春与秋其代序。","惟草木之零落兮，恐美人之迟暮。","不抚壮而弃秽兮，何不改乎此度?","乘骐骥以驰骋兮，来吾道夫先路！","昔三后之纯粹兮，固众芳之所在。","杂申椒与菌桂兮，岂惟纫夫蕙茝！","彼尧、舜之耿介兮，既遵道而得路。","何桀纣之猖披兮，夫惟捷径以窘步。","惟夫党人之偷乐兮，路幽昧以险隘。","岂余身之殚殃兮，恐皇舆之败绩！","忽奔走以先后兮，及前王之踵武。","荃不查余之中情兮，反信谗而齌怒。","余固知謇謇之为患兮，忍而不能舍也。","指九天以为正兮，夫惟灵修之故也。","曰黄昏以为期兮，羌中道而改路！","初既与余成言兮，后悔遁而有他。","余既不难夫离别兮，伤灵修之数化。","余既滋兰之九畹兮，又树蕙之百亩。","畦留夷与揭车兮，杂杜衡与芳芷。","冀枝叶之峻茂兮，愿俟时乎吾将刈。","虽萎绝其亦何伤兮，哀众芳之芜秽。","众皆竞进以贪婪兮，凭不厌乎求索。","羌内恕己以量人兮，各兴心而嫉妒。","忽驰骛以追逐兮，非余心之所急。","老冉冉其将至兮，恐修名之不立。","朝饮木兰之坠露兮，夕餐秋菊之落英。","苟余情其信姱以练要兮，长顑颔亦何伤。","掔木根以结茞兮，贯薜荔之落蕊。","矫菌桂以纫蕙兮，索胡绳之纚纚。","謇吾法夫前修兮，非世俗之所服。","虽不周于今之人兮，愿依彭咸之遗则。","长太息以掩涕兮，哀民生之多艰。","余虽好修姱以鞿羁兮，謇朝谇而夕替。","既替余以蕙纕兮，又申之以揽茝。","亦余心之所善兮，虽九死其犹未悔。","怨灵修之浩荡兮，终不察夫民心。","众女嫉余之蛾眉兮，谣诼谓余以善淫。","固时俗之工巧兮，偭规矩而改错。","背绳墨以追曲兮，竞周容以为度。","忳郁邑余侘傺兮，吾独穷困乎此时也。","宁溘死以流亡兮，余不忍为此态也。","鸷鸟之不群兮，自前世而固然。","何方圜之能周兮，夫孰异道而相安？","屈心而抑志兮，忍尤而攘诟。","伏清白以死直兮，固前圣之所厚。","悔相道之不察兮，延伫乎吾将反。","回朕车以复路兮，及行迷之未远。","步余马于兰皋兮，驰椒丘且焉止息。","进不入以离尤兮，退将复修吾初服。","制芰荷以为衣兮，集芙蓉以为裳。","不吾知其亦已兮，苟余情其信芳。","高余冠之岌岌兮，长余佩之陆离。","芳与泽其杂糅兮，唯昭质其犹未亏。","忽反顾以游目兮，将往观乎四荒。","佩缤纷其繁饰兮，芳菲菲其弥章。","民生各有所乐兮，余独好修以为常。","虽体解吾犹未变兮，岂余心之可惩。","女嬃之婵媛兮，申申其詈予，曰：","鲧婞直以亡身兮，终然夭乎羽之野。","汝何博謇而好修兮，纷独有此姱节？","薋菉葹以盈室兮，判独离而不服。","众不可户说兮，孰云察余之中情？","世并举而好朋兮，夫何茕独而不予听？","依前圣以节中兮，喟凭心而历兹。","济沅、湘以南征兮，就重华而敶词：","启《九辩》与《九歌》兮，夏康娱以自纵。","不顾难以图后兮，五子用失乎家衖。","羿淫游以佚畋兮，又好射夫封狐。","固乱流其鲜终兮，浞又贪夫厥家。","浇身被服强圉兮，纵欲而不忍。","日康娱而自忘兮，厥首用夫颠陨。","夏桀之常违兮，乃遂焉而逢殃。","后辛之菹醢兮，殷宗用而不长。","汤、禹俨而祗敬兮，周论道而莫差。","举贤才而授能兮，循绳墨而不颇。","皇天无私阿兮，览民德焉错辅。","夫维圣哲以茂行兮，苟得用此下土。","瞻前而顾后兮，相观民之计极。","夫孰非义而可用兮？","孰非善而可服？","阽余身而危死兮，览余初其犹未悔。","不量凿而正枘兮，固前修以菹醢。","曾歔欷余郁邑兮，哀朕时之不当。","揽茹蕙以掩涕兮，沾余襟之浪浪。","跪敷衽以陈辞兮，耿吾既得此中正。","驷玉虬以桀鹥兮，溘埃风余上征。","朝发轫于苍梧兮，夕余至乎县圃。","欲少留此灵琐兮，日忽忽其将暮。","吾令羲和弭节兮，望崦嵫而勿迫。","路漫漫其修远兮，吾将上下而求索。","饮余马于咸池兮，总余辔乎扶桑。","折若木以拂日兮，聊逍遥以相羊。","前望舒使先驱兮，后飞廉使奔属。","鸾皇为余先戒兮，雷师告余以未具。","吾令凤鸟飞腾兮，继之以日夜。","飘风屯其相离兮，帅云霓而来御。","纷总总其离合兮，斑陆离其上下。","吾令帝阍开关兮，倚阊阖而望予。","时暧暧其将罢兮，结幽兰而延伫。","世溷浊而不分兮，好蔽美而嫉妒。","朝吾将济于白水兮，登阆风而绁马。","忽反顾以流涕兮，哀高丘之无女。","溘吾游此春宫兮，折琼枝以继佩。","及荣华之未落兮，相下女之可诒。","吾令丰隆乘云兮，求宓妃之所在。","解佩纕以结言兮，吾令謇修以为理。","纷总总其离合兮，忽纬繣其难迁。","夕归次于穷石兮，朝濯发乎洧盘。","保厥美以骄傲兮，日康娱以淫游。","虽信美而无礼兮，来违弃而改求。","览相观于四极兮，周流乎天余乃下。","望瑶台之偃蹇兮，见有娀之佚女。","吾令鸩为媒兮，鸩告余以不好。","雄鸠之鸣逝兮，余犹恶其佻巧。","心犹豫而狐疑兮，欲自适而不可。","凤皇既受诒兮，恐高辛之先我。","欲远集而无所止兮，聊浮游以逍遥。","及少康之未家兮，留有虞之二姚。","理弱而媒拙兮，恐导言之不固。","世溷浊而嫉贤兮，好蔽美而称恶。","闺中既以邃远兮，哲王又不寤。","怀朕情而不发兮，余焉能忍而与此终古？","索琼茅以筳篿兮，命灵氛为余占之。","曰：两美其必合兮，孰信修而慕之？","思九州之博大兮，岂惟是其有女？」","曰：勉远逝而无狐疑兮，孰求美而释女？","何所独无芳草兮，尔何怀乎故宇？」","世幽昧以昡曜兮，孰云察余之善恶？","民好恶其不同兮，惟此党人其独异！","户服艾以盈要兮，谓幽兰其不可佩。","览察草木其犹未得兮，岂珵美之能当？","苏粪壤以充祎兮，谓申椒其不芳。","欲从灵氛之吉占兮，心犹豫而狐疑。","巫咸将夕降兮，怀椒糈而要之。","百神翳其备降兮，九疑缤其并迎。","皇剡剡其扬灵兮，告余以吉故。","曰：勉升降以上下兮，求矩矱之所同。","汤、禹俨而求合兮，挚、咎繇而能调。","苟中情其好修兮，又何必用夫行媒？","说操筑于傅岩兮，武丁用而不疑。","吕望之鼓刀兮，遭周文而得举。","宁戚之讴歌兮，齐桓闻以该辅。","及年岁之未晏兮，时亦犹其未央。","恐鹈鴃之先鸣兮，使夫百草为之不芳。","何琼佩之偃蹇兮，众薆然而蔽之。","惟此党人之不谅兮，恐嫉妒而折之。","时缤纷其变易兮，又何可以淹留？","兰芷变而不芳兮，荃蕙化而为茅。","何昔日之芳草兮，今直为此萧艾也？","岂其有他故兮，莫好修之害也！","余以兰为可恃兮，羌无实而容长。","委厥美以从俗兮，苟得列乎众芳。","椒专佞以慢慆兮，樧又欲充夫佩帏。","既干进而务入兮，又何芳之能祗？","固时俗之流从兮，又孰能无变化？","览椒兰其若兹兮，又况揭车与江离？","惟兹佩之可贵兮，委厥美而历兹。","芳菲菲而难亏兮，芬至今犹未沬。","和调度以自娱兮，聊浮游而求女。","及余饰之方壮兮，周流观乎上下。","灵氛既告余以吉占兮，历吉日乎吾将行。","折琼枝以为羞兮，精琼爢以为粻。","为余驾飞龙兮，杂瑶象以为车。","何离心之可同兮？","吾将远逝以自疏。","邅吾道夫昆仑兮，路修远以周流。","扬云霓之晻蔼兮，鸣玉鸾之啾啾。","朝发轫于天津兮，夕余至乎西极。","凤皇翼其承旗兮，高翱翔之翼翼。","忽吾行此流沙兮，遵赤水而容与。","麾蛟龙使梁津兮，诏西皇使涉予。","路修远以多艰兮，腾众车使径待。","路不周以左转兮，指西海以为期。","屯余车其千乘兮，齐玉轪而并驰。","驾八龙之婉婉兮，载云旗之委蛇。","抑志而弭节兮，神高驰之邈邈。","奏《九歌》而舞《韶》兮，聊假日以偷乐。","陟升皇之赫戏兮，忽临睨夫旧乡。","仆夫悲余马怀兮，蜷局顾而不行。","乱曰：已矣哉！国无人莫我知兮，又何怀乎故都！","既莫足与为美政兮，吾将从彭咸之所居！"],"source":"《楚辞》"},{"title":"东皇太一","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["吉日兮辰良，穆将愉兮上皇","抚长剑兮玉珥，璆锵鸣兮琳琅","瑶席兮玉瑱，盍将把兮琼芳","蕙肴蒸兮兰藉，奠桂酒兮椒浆","扬枹兮拊鼓，疏缓节兮安歌","陈竽瑟兮浩倡","灵偃蹇兮姣服，芳菲菲兮满堂","五音纷兮繁会，君欣欣兮乐康。"],"source":"《楚辞》"},{"title":"云中君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["浴兰汤兮沐芳，华采衣兮若英","灵连蜷兮既留，烂昭昭兮未央","謇将憺兮寿宫，与日月兮齐光","龙驾兮帝服，聊翱游兮周章","灵皇皇兮既降，猋远举兮云中","览冀洲兮有余，横四海兮焉穷","思夫君兮太息，极劳心兮忡忡"],"source":"《楚辞》"},{"title":"湘君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["君不行兮夷犹，蹇谁留兮中洲","美要眇兮宜修，沛吾乘兮桂舟","令沅湘兮无波，使江水兮安流","望夫君兮未来，吹参差兮谁思","驾飞龙兮北征，邅吾道兮洞庭","薜荔柏兮蕙绸，荪桡兮兰旌","望涔阳兮极浦，横大江兮扬灵","扬灵兮未极，女婵媛兮为余太息","横流涕兮潺湲，隐思君兮陫侧","桂棹兮兰枻，斵冰兮积雪","采薜荔兮水中，搴芙蓉兮木末","心不同兮媒劳，恩不甚兮轻绝","石濑兮浅浅，飞龙兮翩翩","交不忠兮怨长，期不信兮告余以不闲","朝骋骛兮江皋，夕弭节兮北渚","鸟次兮屋上，水周兮堂下","捐余玦兮江中，遗余佩兮醴浦","采芳洲兮杜若，将以遗兮下女","时不可兮再得，聊逍遥兮容与。"],"source":"《楚辞》"},{"title":"湘夫人","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["帝子降兮北渚，目眇眇兮愁予","袅袅兮秋风，洞庭波兮木叶下","登白薠兮骋望，与佳期兮夕张","鸟何萃兮苹中，罾何为兮木上？","沅有茝兮醴有兰，思公子兮未敢言","荒忽兮远望，观流水兮潺湲","麋何食兮庭中，蛟何为兮水裔","朝驰余马兮江皋，夕济兮西澨","闻佳人兮召余，将腾驾兮偕逝","筑室兮水中，葺之兮荷盖","荪壁兮紫坛，播芳椒兮成堂","桂栋兮兰橑，辛夷楣兮药房","罔薜荔兮为帷，擗蕙櫋兮既张","白玉兮为镇，疏石兰兮为芳","芷葺兮荷屋，缭之兮杜衡","合百草兮实庭，建芳馨兮庑门","九嶷缤兮并迎，灵之来兮如云","捐余袂兮江中，遗余褋兮醴浦","搴汀洲兮杜若，将以遗兮远者","时不可兮骤得，聊逍遥兮容与！"],"source":"《楚辞》"},{"title":"大司命","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["广开兮天门，纷吾乘兮玄云","令飘风兮先驱，使涷雨兮洒尘","君回翔兮以下，逾空桑兮从女","纷总总兮九州，何寿夭兮在予","高飞兮安翔，乘清气兮御阴阳","吾与君兮齐速，导帝之兮九坑","灵衣兮被被，玉佩兮陆离","一阴兮一阳，众莫知兮余所为","折疏麻兮瑶华，将以遗兮离居","老冉冉兮既极，不寖近兮愈疏","乘龙兮辚辚，高驰兮冲天","结桂枝兮延伫，羌愈思兮愁人","愁人兮奈何，愿若今兮无亏","固人命兮有当，孰离合兮何为？"],"source":"《楚辞》"},{"title":"少司命","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["秋兰兮麋芜，罗生兮堂下","绿叶兮素华，芳菲菲兮袭予","夫人兮自有美子，荪何以兮愁苦","秋兰兮青青，绿叶兮紫茎","满堂兮美人，忽独与余兮目成","入不言兮出不辞，乘回风兮载云旗","悲莫悲兮生别离，乐莫乐兮新相知","荷衣兮蕙带，儵而来兮忽而逝","夕宿兮帝郊，君谁须兮云之际","与女沐兮咸池，曦女发兮阳之阿","望美人兮未来，临风怳兮浩歌","孔盖兮翠旌，登九天兮抚彗星","竦长剑兮拥幼艾，荪独宜兮为民正。"],"source":"《楚辞》"},{"title":"东君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["暾将出兮东方，照吾槛兮扶桑","抚余马兮安驱，夜皎皎兮既明","驾龙輈兮乘雷，载云旗兮委蛇","长太息兮将上，心低徊兮顾怀","羌声色兮娱人，观者儋兮忘归","縆瑟兮交鼓，萧钟兮瑶簴","鸣篪兮吹竽，思灵保兮贤姱","翾飞兮翠曾，展诗兮会舞","应律兮合节，灵之来兮敝日","青云衣兮白霓裳，举长矢兮射天狼","操余弧兮反沦降，援北斗兮酌桂浆","撰余辔兮高驰翔，杳冥冥兮以东行。"],"source":"《楚辞》"},{"title":"河伯","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["与女游兮九河，冲风起兮水扬波","乘水车兮荷盖，驾两龙兮骖螭","登昆仑兮四望，心飞扬兮浩荡","日将暮兮怅忘归，惟极浦兮寤怀","鱼鳞屋兮龙堂，紫贝阙兮珠宫","灵何惟兮水中","乘白鼋兮逐文鱼，与女游兮河之渚","流澌纷兮将来下","子交手兮东行，送美人兮南浦","波滔滔兮来迎，鱼鳞鳞兮媵予。"],"source":"《楚辞》"},{"title":"山鬼","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["若有人兮山之阿，被薜荔兮带女萝","既含睇兮又宜笑，子慕予兮善窈窕","乘赤豹兮从文狸，辛夷车兮结桂旗","被石兰兮带杜衡，折芬馨兮遗所思","余处幽篁兮终不见天，路险难兮独后来","表独立兮山之上，云容容兮而在下","杳冥冥兮羌昼晦，东风飘兮神灵雨","留灵修兮憺忘归，岁既晏兮孰华予","采三秀兮于山间，石磊磊兮葛蔓蔓","怨公子兮怅忘归，君思我兮不得闲","山中人兮芳杜若，饮石泉兮荫松柏","君思我兮然疑作","雷填填兮雨冥冥，猿啾啾兮狖夜鸣","风飒飒兮木萧萧，思公子兮徒离忧。"],"source":"《楚辞》"},{"title":"国殇","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["操吴戈兮被犀甲，车错毂兮短兵接","旌蔽日兮敌若云，矢交坠兮士争先","凌余阵兮躐余行，左骖殪兮右刃伤","霾两轮兮絷四马，援玉枹兮击鸣鼓","天时怼兮威灵怒，严杀尽兮弃原野","出不入兮往不反，平原忽兮路超远","带长剑兮挟秦弓，首身离兮心不惩","诚既勇兮又以武，终刚强兮不可凌","身既死兮神以灵，魂魄毅兮为鬼雄。"],"source":"《楚辞》"},{"title":"礼魂","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["成礼兮会鼓，","传芭兮代舞","姱女倡兮容与","春兰兮秋菊，","长无绝兮终古。"],"source":"《楚辞》"},{"title":"天问","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["曰：","遂古之初，谁传道之？","上下未形，何由考之？","冥昭瞢暗，谁能极之？","冯翼惟象，何以识之？","明明暗暗，惟时何为？","阴阳三合，何本何化？","圜则九重，孰营度之？","惟兹何功，孰初作之？","斡维焉系，天极焉加？","八柱何当，东南何亏？","九天之际，安放安属？","隅隈多有，谁知其数？","天何所沓？","十二焉分？","日月安属？","列星安陈？","出自汤谷，次于蒙汜。","自明及晦，所行几里？","夜光何德，死则又育？","厥利维何，而顾菟在腹？","女岐无合，夫焉取九子？","伯强何处？","惠气安在？","何阖而晦？","何开而明？","角宿未旦，曜灵安藏？","不任汩鸿，师何以尚之？","佥曰","“何忧，何不课而行之？”","鸱龟曳衔，鲧何听焉？","顺欲成功，帝何刑焉？","永遏在羽山，夫何三年不施？","伯禹愎鲧，夫何以变化？","纂就前绪，遂成考功。","何续初继业，而厥谋不同？","洪泉极深，何以窴之？","地方九则，何以坟之？","河海应龙？","何尽何历？","鲧何所营？","禹何所成？","康回冯怒，墬何故以东南倾？","九州安错？","川谷何洿？","东流不溢，孰知其故？","东西南北，其修孰多？","南北顺椭，其衍几何？","昆仑悬圃，其尻安在？","增城九重，其高几里？","四方之门，其谁从焉？","西北辟启，何气通焉？","日安不到？","烛龙何照？","羲和之未扬，若华何光？","何所冬暖？","何所夏寒？","焉有石林？","何兽能言？","焉有虬龙，负熊以游？","雄虺九首，鯈忽焉在？","何所不死？","长人何守？","靡蓱九衢，枲华安居？","灵蛇吞象，厥大何如？","黑水玄趾，三危安在？","延年不死，寿何所止？","鲮鱼何所？","鬿堆焉处？","羿焉彃日？","乌焉解羽？","禹之力献功，降省下土四方。","焉得彼嵞山女，而通之於台桑？","闵妃匹合，厥身是继。","胡维嗜不同味，而快鼌饱？","启代益作后，卒然离蠥。","何启惟忧，而能拘是达？","皆归射鞫，而无害厥躬。","何后益作革，而禹播降？","启棘宾商，《九辨》《九歌》。","何勤子屠母，而死分竟地？","帝降夷羿，革孽夏民。","胡射夫河伯，而妻彼雒嫔？","冯珧利决，封豨是射。","何献蒸肉之膏，而后帝不若？","浞娶纯狐，眩妻爰谋。","何羿之射革，而交吞揆之？","阻穷西征，岩何越焉？","化而为黄熊，巫何活焉？","咸播秬黍，莆雚是营。","何由并投，而鲧疾修盈？","白蜺婴茀，胡为此堂？","安得夫良药，不能固臧？","天式从横，阳离爰死。","大鸟何鸣，夫焉丧厥体？","蓱号起雨，何以兴之？","撰体协胁，鹿何膺之？","鳌戴山抃，何以安之？","释舟陵行，何之迁之？","惟浇在户，何求于嫂？","何少康逐犬，而颠陨厥首？","女歧缝裳，而馆同爰止。","何颠易厥首，而亲以逢殆？","汤谋易旅，何以厚之？","覆舟斟寻，何道取之？","桀伐蒙山，何所得焉？","妺嬉何肆，汤何殛焉？","舜闵在家，父何以鳏？","尧不姚告，二女何亲？","厥萌在初，何所亿焉？","璜台十成，谁所极焉？","登立为帝，孰道尚之？","女娲有体，孰制匠之？","舜服厥弟，终然为害。","何肆犬豕，而厥身不危败？","吴获迄古，南岳是止。","孰期去斯，得两男子？","缘鹄饰玉，后帝是飨。","何承谋夏桀，终以灭丧？","帝乃降观，下逢伊挚。","何条放致罚，而黎服大说？","简狄在台，喾何宜？","玄鸟致贻，女何喜？","该秉季德，厥父是臧。","胡终弊于有扈，牧夫牛羊？","干协时舞，何以怀之？","平胁曼肤，何以肥之？","有扈牧竖，云何而逢？","击床先出，其命何从？","恒秉季德，焉得夫朴牛？","何往营班禄，不但还来？","昏微循迹，有狄不宁。","何繁鸟萃棘，负子肆情？","眩弟并淫，危害厥兄。","何变化以作诈，而后嗣逢长？","成汤东巡，有莘爰极。","何乞彼小臣，而吉妃是得？","水滨之木，得彼小子。","夫何恶之，媵有莘之妇？","汤出重泉，夫何辠尤？","不胜心伐帝，夫谁使挑之？","会朝争盟，何践吾期？","苍鸟群飞，孰使萃之？","列击纣躬，叔旦不嘉。","何亲揆发足，周之命以咨嗟？","授殷天下，其位安施？","反成乃亡，其罪伊何？","争遣伐器，何以行之？","并驱击翼，何以将之？","昭后成游，南土爰底。","厥利惟何，逢彼白雉？","穆王巧梅，夫何为周流？","环理天下，夫何索求？","妖夫曳炫，何号于市？","周幽谁诛？","焉得夫褒姒？","天命反侧，何罚何佑？","齐桓九会，卒然身杀。","彼王纣之躬，孰使乱惑？","何恶辅弼，谗谄是服？","比干何逆，而抑沈之？","雷开阿顺，而赐封之？","何圣人之一德，卒其异方？","梅伯受醢，箕子详狂？","稷维元子，帝何竺之？","投之于冰上，鸟何燠之？","何冯弓挟矢，殊能将之？","既惊帝切激，何逢长之？","伯昌号衰，秉鞭作牧。","何令彻彼岐社，命有殷国？","迁藏就岐，何能依？","殷有惑妇，何所讥？","受赐兹醢，西伯上告。","何亲就上帝罚，殷之命以不救？","师望在肆，昌何识？","鼓刀扬声，后何喜？","武发杀殷，何所悒？","载尸集战，何所急？","伯林雉经，维其何故？","何感天抑墬，夫谁畏惧？","皇天集命，惟何戒之？","受礼天下，又使至代之？","初汤臣挚，后兹承辅。","何卒官汤，尊食宗绪？","勋阖梦生，少离散亡。","何壮武历，能流厥严？","彭铿斟雉，帝何飨？","受寿永多，夫何久长？","中央共牧，后何怒？","蜂蛾微命，力何固？","惊女采薇，鹿何佑？","北至回水，萃何喜？","兄有噬犬，弟何欲？","易之以百两，卒无禄？","薄暮雷电，归何忧？","厥严不奉，帝何求？","伏匿穴处，爰何云？","荆勋作师，夫何长？","悟过改更，我又何言？","吴光争国，久余是胜。","何环穿自闾社丘陵，爰出子文？","吾告堵敖以不长。","何试上自予，忠名弥彰？"],"source":"《楚辞》"},{"title":"惜诵","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["惜诵以致愍兮，发愤以抒情。","所作忠而言之兮，指苍天以为正。","令五帝使折中兮，戒六神与向服。","俾山川以备御兮，命咎繇使听直。","竭忠诚而事君兮，反离群而赘肬。","忘儇媚以背众兮，待明君其知之。","言与行其可迹兮，情与貌其不变。","故相臣莫若君兮，所以证之不远。","吾谊先君而后身兮，羌众人之所仇也。","专惟君而无他兮，又众兆之所雠也。","壹心而不豫兮，羌无可保也。","疾亲君而无他兮，有招祸之道也。","思君其莫我忠兮，忽忘身之贱贫。","事君而不贰兮，迷不知宠之门。","患何罪以遇罚兮，亦非余之所志也。","行不群以巅越兮，又众兆之所咍也。","纷逢尤以离谤兮，謇不可释也。","情沉抑而不达兮，又蔽而莫之白也。","心郁邑余侘傺兮，又莫察余之中情。","固烦言不可结而诒兮，愿陈志而无路。","退静默而莫余知兮，进号呼又莫吾闻。","申侘傺之烦惑兮，中闷瞀之忳忳。","昔余梦登天兮，魂中道而无杭。","吾使厉神占之兮，曰有志极而无旁。","终危独以离异兮，曰君可思而不可恃。","故众口其铄金兮，初若是而逢殆。","惩于羹者而吹齑兮，何不变此志也？","欲释阶而登天兮，犹有曩之态也。","众骇遽以离心兮，又何以为此伴也？","同极而异路兮，又何以为此援也？","晋申生之孝子兮，父信谗而不好。","行婞直而不豫兮，鲧功用而不就。","吾闻作忠以造怨兮，忽谓之过言。","九折臂而成医兮，吾至今而知其信然。","矰弋机而在上兮，罻罗张而在下。","设张辟以娱君兮，愿侧身而无所。","欲儃徊以干傺兮，恐重患而离尤。","欲高飞而远集兮，君罔谓汝何之？","欲横奔而失路兮，盖志坚而不忍。","背膺牉以交痛兮，心郁结而纡轸。","擣木兰以矫蕙兮，糳申椒以为粮。","播江离与滋菊兮，愿春日以为糗芳。","恐情质之不信兮，故重著以自明。","矫兹媚以私处兮，愿曾思而远身。"],"source":"《楚辞》"},{"title":"涉江","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["余幼好此奇服兮，年既老而不衰。","带长铗之陆离兮，冠切云之崔嵬，被明月兮佩宝璐。","世混浊而莫余知兮，吾方高驰而不顾。","驾青虬兮骖白螭，吾与重华游兮瑶之圃。","登昆仑兮食玉英，与天地兮同寿，与日月兮同光。","哀南夷之莫吾知兮，旦余济乎江湘。","乘鄂渚而反顾兮，欸秋冬之绪风。","步余马兮山皋，邸余车兮方林。","乘舲船余上沅兮，齐吴榜以击汰。","船容与而不进兮，淹回水而疑滞。","朝发枉渚兮，夕宿辰阳。","苟余心其端直兮，虽僻远之何伤。","入溆浦余儃徊兮，迷不知吾所如。","深林杳以冥冥兮，猿狖之所居。","山峻高以蔽日兮，下幽晦以多雨。","霰雪纷其无垠兮，云霏霏而承宇。","哀吾生之无乐兮，幽独处乎山中。","吾不能变心而从俗兮，固将愁苦而终穷。","接舆髡首兮，桑扈臝行。","忠不必用兮，贤不必以。","伍子逢殃兮，比干菹醢。","与前世而皆然兮，吾又何怨乎今之人！","余将董道而不豫兮，固将重昏而终身！","乱曰：","鸾鸟凤皇，日以远兮。","燕雀乌鹊，巢堂坛兮。","露申辛夷，死林薄兮。","腥臊并御，芳不得薄兮。","阴阳易位，时不当兮。","怀信佗傺，忽乎吾将行兮！"],"source":"《楚辞》"},{"title":"哀郢","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["皇天之不纯命兮，何百姓之震愆？","民离散而相失兮，方仲春而东迁。","去故乡而就远兮，遵江夏以流亡。","出国门而轸怀兮，甲之鼂吾以行。","发郢都而去闾兮，怊荒忽其焉极？","楫齐扬以容与兮，哀见君而不再得。","望长楸而太息兮，涕淫淫其若霰。","过夏首而西浮兮，顾龙门而不见。","心婵媛而伤怀兮，眇不知其所蹠。","顺风波以从流兮，焉洋洋而为客。","凌阳侯之汜滥兮，忽翱翔之焉薄。","心絓结而不解兮，思蹇产而不释。","将运舟而下浮兮，上洞庭而下江。","去终古之所居兮，今逍遥而来东。","羌灵魂之欲归兮，何须臾而忘反。","背夏浦而西思兮，哀故都之日远。","登大坟以远望兮，聊以舒吾忧心。","哀州土之平乐兮，悲江介之遗风。","当陵阳之焉至兮，淼南渡之焉如？","曾不知夏之为丘兮，孰两东门之可芜？","心不怡之长久兮，忧与愁其相接。","惟郢路之辽远兮，江与夏之不可涉。","忽若不信兮，至今九年而不复。","惨郁郁而不通兮，蹇侘傺而含慼。","外承欢之汋约兮，谌荏弱而难持。","忠湛湛而愿进兮，妒被离而鄣之。","尧舜之抗行兮，瞭杳杳而薄天。","众谗人之嫉妒兮，被以不慈之伪名。","憎愠惀之修美兮，好夫人之慷慨。","众踥蹀而日进兮，美超远而逾迈。","乱曰：","曼余目以流观兮，冀一反之何时？","鸟飞反故乡兮，狐死必首丘。","信非吾罪而弃逐兮，何日夜而忘之？"],"source":"《楚辞》"},{"title":"抽思","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["心郁郁之忧思兮，独永叹乎增伤。","思蹇产之不释兮，曼遭夜之方长。","悲秋风之动容兮，何回极之浮浮。","数惟荪之多怒兮，伤余心之忧忧。","愿摇起而横奔兮，览民尤以自镇。","结微情以陈词兮，矫以遗夫美人。","昔君与我诚言兮，曰黄昏以为期。","羌中道而回畔兮，反既有此他志。","憍吾以其美好兮，览余以其修姱。","与余言而不信兮，盖为余而造怒。","愿承閒而自察兮，心震悼而不敢。","悲夷犹而冀进兮，心怛伤之憺憺。","兹历情以陈辞兮，荪详聋而不闻。","固切人之不媚兮，众果以我为患。","初吾所陈之耿著兮，岂至今其庸亡？","何独乐斯之謇謇兮？","愿荪美之可光。","望三王以为像兮，指彭咸以为仪。","夫何极而不至兮，故远闻而难亏。","善不由外来兮，名不可以虚作。","孰无施而有报兮，孰不实而有获？","少歌曰：与美人抽思兮，并日夜而无正。","憍吾以其美好兮，敖朕辞而不听。","倡曰：","有鸟自南兮，来集汉北。","好姱佳丽兮，牉独处此异域。","惸茕独而不群兮，又无良媒在其侧。","道卓远而日忘兮，愿自申而不得。","望北山而流涕兮，临流水而太息。","望孟夏之短夜兮，何晦明之若岁？","惟郢路之辽远兮，魂一夕而九逝。","曾不知路之曲直兮，南指月与列星。","愿径逝而未得兮，魂识路之营营。","何灵魂之信直兮，人之心不与吾心同！","理弱而媒不通兮，尚不知余之从容。","乱曰：","长濑湍流，溯江潭兮。","狂顾南行，聊以娱心兮。","轸石崴嵬，蹇吾愿兮。","超回志度，行隐进兮。","低徊夷犹，宿北姑兮。","烦冤瞀容，实沛徂兮。","愁叹苦神，灵遥思兮。","路远处幽，又无行媒兮。","道思作颂，聊以自救兮。","忧心不遂，斯言谁告兮。"],"source":"《楚辞》"},{"title":"怀沙","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["滔滔孟夏兮，草木莽莽。","伤怀永哀兮，汩徂南土。","眴兮杳杳，孔静幽默。","郁结纡轸兮，离慜而长鞠。","抚情效志兮，冤屈而自抑。","刓方以为圜兮，常度未替。","易初本迪兮，君子所鄙。","章画志墨兮，前图未改。","内厚质正兮，大人所盛。","巧倕不斲兮，孰察其拨正。","玄文处幽兮，矇瞍谓之不章","离娄微睇兮，瞽以为无明。","变白以为黑兮，倒上以为下。","凤皇在笯兮，鸡鹜翔舞。","同糅玉石兮，一概而相量。","夫惟党人之鄙固兮，羌不知余之所臧。","任重载盛兮，陷滞而不济。","怀瑾握瑜兮，穷不知所示。","邑犬之群吠兮，吠所怪也。","非俊疑杰兮，固庸态也。","文质疏内兮，众不知余之异采。","材朴委积兮，莫知余之所有。","重仁袭义兮，谨厚以为丰。","重华不可遌兮，孰知余之从容！","古固有不并兮，岂知其何故也？","汤禹久远兮，邈而不可慕也？","惩违改忿兮，抑心而自强。","离慜而不迁兮，愿志之有像。","进路北次兮，日昧昧其将暮。","舒忧娱哀兮，限之以大故。","乱曰：","浩浩沅湘，分流汩兮。","修路幽蔽，道远忽兮。","怀质抱情，独无匹兮。","伯乐既没，骥焉程兮。","民生禀命，各有所错兮。","定心广志，余何所畏惧兮？","曾伤爰哀，永叹喟兮。","世浑浊莫吾知，人心不可谓兮。","知死不可让，愿勿爱兮。","明告君子，吾将以为类兮。"],"source":"《楚辞》"},{"title":"思美人","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["思美人兮，揽涕而竚眙。","媒绝路阻兮，言不可结而诒。","蹇蹇之烦冤兮，陷滞而不发。","申旦以舒中情兮，志沉菀而莫达。","愿寄言于浮云兮，遇丰隆而不将。","因归鸟而致辞兮，羌迅高而难当。","高辛之灵盛兮，遭玄鸟而致诒。","欲变节以从俗兮，媿易初而屈志。","独历年而离愍兮，羌凭心犹未化。","宁隐闵而寿考兮，何变易之可为！","知前辙之不遂兮，未改此度。","车既覆而马颠兮，蹇独怀此异路。","勒骐骥而更驾兮，造父为我操之，","迁逡次而勿驱兮，聊假日以须是时。","指嶓冢之西隈兮，与纁黄以为期。","开春发岁兮，白日出之悠悠。","吾将荡志而愉乐兮，遵江夏以娱忧。","揽大薄之芳茝兮，搴长洲之宿莽。","惜吾不及古人兮，吾谁与玩此芳草？","解萹薄与杂菜兮，备以为交佩。","佩缤纷以缭转兮，遂萎绝而离异。","吾且儃徊以娱忧兮，观南人之变态。","窃快在中心兮，扬厥凭而不竢。","芳与泽其杂糅兮，羌芳华自中出。","纷郁郁其远蒸兮，满内而外扬。","情与质信可保兮，羌居蔽而闻章。","令薜荔以为理兮，惮举趾而缘木。","因芙蓉而为媒兮，惮褰裳而濡足。","登高吾不说兮，入下吾不能。","固朕形之不服兮，然容与而狐疑。","广遂前画兮，未改此度也。","命则处幽吾将罢兮，愿及白日之未暮也。","独茕茕而南行兮，思彭咸之故也。"],"source":"《楚辞》"},{"title":"惜往日","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["惜往日之曾信兮，受命诏以昭时。","奉先功以照下兮，明法度之嫌疑。","国富强而法立兮，属贞臣而日竢。","秘密事之载心兮，虽过失犹弗治。","心纯庞而不泄兮，遭谗人而嫉之。","君含怒而待臣兮，不清澈其然否。","蔽晦君之聪明兮，虚惑误又以欺。","弗参验以考实兮，远迁臣而弗思。","信谗谀之浑浊兮，盛气志而过之。","何贞臣之无罪兮，被离谤而见尤。","惭光景之诚信兮，身幽隐而备之。","临沅湘之玄渊兮，遂自忍而沉流。","卒没身而绝名兮，惜壅君之不昭。","君无度而弗察兮，使芳草为薮幽。","焉舒情而抽信兮，恬死亡而不聊。","独障壅而弊隐兮，使贞臣为无由。","闻百里之为虏兮，伊尹烹于庖厨。","吕望屠于朝歌兮，宁戚歌而饭牛。","不逢汤武与桓缪兮，世孰云而知之。","吴信谗而弗味兮，子胥死而后忧。","介子忠而立枯兮，文君寤而追求。","封介山而为之禁兮，报大德之优游。","思久故之亲身兮，因缟素而哭之。","或忠信而死节兮，或訑谩而不疑。","弗省察而按实兮，听谗人之虚辞。","芳与泽其杂糅兮，孰申旦而别之？","何芳草之早殀兮，微霜降而下戒。","谅聪不明而蔽壅兮，使谗谀而日得。","自前世之嫉贤兮，谓蕙若其不可佩。","妒佳冶之芬芳兮，嫫母姣而自好。","虽有西施之美容兮，谗妒入以自代。","愿陈情以白行兮，得罪过之不意。","情冤见之日明兮，如列宿之错置。","乘骐骥而驰骋兮，无辔衔而自载","乘泛泭以下流兮，无舟楫而自备。","背法度而心治兮，辟与此其无异。","宁溘死而流亡兮，恐祸殃之有再。","不毕辞而赴渊兮，惜壅君之不识。"],"source":"《楚辞》"},{"title":"橘颂","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["后皇嘉树，橘徕服兮。","受命不迁，生南国兮。","深固难徙，更壹志兮。","绿叶素荣，纷其可喜兮。","曾枝剡棘，圆果抟兮。","青黄杂糅，文章烂兮。","精色内白，类任道兮。","纷緼宜修，姱而不丑兮。","嗟尔幼志，有以异兮。","独立不迁，岂不可喜兮？","深固难徙，廓其无求兮。","苏世独立，横而不流兮。","闭心自慎，终不失过兮。","秉德无私，参天地兮。","愿岁并谢，与长友兮。","淑离不淫，梗其有理兮。","年岁虽少，可师长兮。","行比伯夷，置以为像兮。"],"source":"《楚辞》"},{"title":"悲回风","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["悲回风之摇蕙兮，心冤结而内伤。","物有微而陨性兮，声有隐而先倡。","夫何彭咸之造思兮，暨志介而不忘！","万变其情岂可盖兮，孰虚伪之可长？","鸟兽鸣以号群兮，草苴比而不芳。","鱼葺鳞以自别兮，蛟龙隐其文章。","故荼荠不同亩兮，兰茝幽而独芳。","惟佳人之永都兮，更统世以自贶。","眇远志之所及兮，怜浮云之相羊。","介眇志之所惑兮，窃赋诗之所明。","惟佳人之独怀兮，折若椒以自处。","曾歔欷之嗟嗟兮，独隐伏而思虑。","涕泣交而凄凄兮，思不眠以至曙。","终长夜之曼曼兮，掩此哀而不去。","寤从容以周流兮，聊逍遥以自恃。","伤太息之愍怜兮，气于邑而不可止。","糺思心以为纕兮，编愁苦以为膺。","折若木以弊光兮，随飘风之所仍。","存彷佛而不见兮，心踊跃其若汤。","抚珮衽以案志兮，超惘惘而遂行。","岁曶曶其若颓兮，时亦冉冉而将至。","薠蘅槁而节离兮，芳以歇而不比。","怜思心之不可惩兮，证此言之不可聊。","宁溘死而流亡兮，不忍此心之常愁。","孤子吟而抆泪兮，放子出而不还。","孰能思而不隐兮，照彭咸之所闻。","登石峦以远望兮，路眇眇之默默。","入景响之无应兮，闻省想而不可得。","愁郁郁之无快兮，居戚戚而不可解。","心鞿羁而不开兮，气缭转而自缔。","穆眇眇之无垠兮，莽芒芒之无仪。","声有隐而相感兮，物有纯而不可为。","邈漫漫之不可量兮，缥绵绵之不可纡。","愁悄悄之常悲兮，翩冥冥之不可娱。","凌大波而流风兮，讬彭咸之所居。","上高岩之峭岸兮，处雌蜺之标颠。","据青冥而摅虹兮，遂儵忽而扪天。","吸湛露之浮源兮，漱凝霜之雰雰。","依风穴以自息兮，忽倾寤以婵媛。","冯昆仑以澂雾兮，隐渂山以清江。","惮涌湍之礚礚兮，听波声之汹汹。","纷容容之无经兮，罔芒芒之无纪。","轧洋洋之无从兮，驰委移之焉止？","漂翻翻其上下兮，翼遥遥其左右。","氾潏潏其前后兮，伴张驰之信期。","观炎气之相仍兮，窥烟液之所积。","悲霜雪之俱下兮，听潮水之相击。","借光景以往来兮，施黄棘之枉策。","求介子之所存兮，见伯夷之放迹。","心调度而弗去兮，刻著志之无适。","曰吾怨往昔之所冀兮，悼来者之悐悐。","浮江淮而入海兮，从子胥而自适。","望大河之洲渚兮，悲申徒之抗迹。","骤谏君而不听兮，重任石之何益？","心絓结而不解兮，思蹇产而不释。"],"source":"《楚辞》"},{"title":"远游","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["悲时俗之迫阨兮，愿轻举而远游。","质菲薄而无因兮，焉讬乘而上浮？","遭沈浊而污秽兮，独郁结其谁语！","夜耿耿而不寐兮，魂营营而至曙。","惟天地之无穷兮，哀人生之长勤。","往者余弗及兮，来者吾不闻。","步徙倚而遥思兮，怊惝怳而乖怀。","意荒忽而流荡兮，心愁悽而增悲。","神倏忽而不反兮，形枯槁而独留。","内惟省以操端兮，求正气之所由。","漠虚静以恬愉兮，澹无为而自得。","闻赤松之清尘兮，愿承风乎遗则。","贵真人之休德兮，美往世之登仙","与化去而不见兮，名声著而日延。","奇傅说之讬辰星兮，羡韩众之得一。","形穆穆以浸远兮，离人群而遁逸。","因气变而遂曾举兮，忽神奔而鬼怪。","时仿佛以遥见兮，精晈晈以往来。","超氛埃而淑邮兮，终不反其故都。","免众患而不惧兮，世莫知其所如。","恐天时之代序兮，耀灵晔而西征。","微霜降而下沦兮，悼芳草之先蘦。","聊仿佯而逍遥兮，永历年而无成。","谁可与玩斯遗芳兮？","长向风而舒情。","高阳邈以远兮，余将焉所程？","重曰：","春秋忽其不淹兮，奚久留此故居。","轩辕不可攀援兮，吾将从王乔而娱戏。","餐六气而饮沆瀣兮，漱正阳而含朝霞。","保神明之清澄兮，精气入而麤秽除。","顺凯风以从游兮，至南巢而壹息。","见王子而宿之兮，审壹气之和德。","曰“道可受兮，不可传","其小无内兮，其大无垠。","毋滑而魂兮，彼将自然","壹气孔神兮，于中夜存。","虚以待之存，无为之先","庶类以成兮，此德之门。”","闻至贵而遂徂兮，忽乎吾将行。","仍羽人于丹丘，留不死之旧乡。","朝濯发于汤谷兮，夕晞余身兮九阳。","吸飞泉之微液兮，怀琬琰之华英。","玉色頩以脕颜兮，精醇粹而始壮。","质销铄以汋约兮，神要眇以淫放。","嘉南州之炎德兮，丽桂树之冬荣","山萧条而无兽兮，野寂漠其无人。","载营魄而登霞兮，掩浮云而上征。","命天阍其开关兮，排阊阖而望予。","召丰隆使先导兮，问太微之所居。","集重阳入帝宫兮，造旬始而观清都。","朝发轫于太仪兮，夕始临乎于微闾。","屯余车之万乘兮，纷容与而并驰。","驾八龙之婉婉兮，载云旗之逶蛇。","建雄虹之采旄兮，五色杂而炫耀。","服偃蹇以低昂兮，骖连蜷以骄骜。","骑胶葛以杂乱兮，斑漫衍而方行。","撰余辔而正策兮，吾将过乎句芒。","历太皓以右转兮，前飞廉以启路。","阳杲杲其未光兮，凌天地以径度。","风伯为余先驱兮，氛埃辟而清凉。","凤凰翼其承旂兮，遇蓐收乎西皇。","揽慧星以为旍兮，举斗柄以为麾。","叛陆离其上下兮，游惊雾之流波。","时暧曃其曭莽兮，召玄武而奔属。","后文昌使掌行兮，选署众神以并轂。","路漫漫其修远兮，徐弭节而高厉。","左雨师使径侍兮，右雷公以为卫。","欲度世以忘归兮，意姿睢以抯挢。","内欣欣而自美兮，聊媮娱以淫乐。","涉青云以汎滥游兮，忽临睨夫旧乡。","仆夫怀余心悲兮，边马顾而不行。","思旧故以想象兮，长太息而掩涕。","汜容与而遐举兮，聊抑志而自弭。","指炎神而直驰兮，吾将往乎南疑。","览方外之荒忽兮，沛罔瀁而自浮。","祝融戒而跸御兮，腾告鸾鸟迎宓妃。","张咸池奏承云兮，二女御九韶歌。","使湘灵鼓瑟兮，令海若舞冯夷。","玄螭虫象并出进兮，形蟉虯而逶蛇。","雌蜺便娟以增挠兮，鸾鸟轩翥而翔飞。","音乐博衍无终极兮，焉乃逝以徘徊。","舒并节以驰骛兮，逴绝垠乎寒门。","轶迅风于清源兮，从颛顼乎增冰。","历玄冥以邪径兮，乘间维以反顾。","召黔赢而见之兮，为余先乎平路。","经营四方兮，周流六漠。","上至列缺兮，降望大壑。","下峥嵘而无地兮，上寥廓而无天。","视倏忽而无见兮，听惝恍而无闻。","超无为以至清兮，与泰初而为邻。"],"source":"《楚辞》"},{"title":"卜居","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["屈原既放，三年不得复见。竭知尽忠而蔽障于谗。心烦虑乱，不知所从。乃往见太卜郑詹尹曰：“余有所疑，愿因先生决之。”詹尹乃端策拂龟，曰：“君将何以教之？”","屈原曰：“吾宁悃悃款款，朴以忠乎，将送往劳来，斯无穷乎？宁诛锄草茅以力耕乎，将游大人以成名乎？宁正言不讳以危身乎，将从俗富贵以偷生乎？宁超然高举以保真乎，将哫訾栗斯，喔咿儒儿，以事妇人乎？宁廉洁正直以自清乎，将突梯滑稽，如脂如韦，以洁楹乎？宁昂昂若千里之驹乎，将泛泛若水中之凫，与波上下，偷以全吾躯乎？宁与骐骥亢轭乎，将随驽马之迹乎？宁与黄鹄比翼乎，将与鸡鹜争食乎？此孰吉孰凶？何去何从？世溷浊而不清：蝉翼为重，千钧为轻黄钟毁弃，瓦釜雷鸣谗人高张，贤士无名。吁嗟默默兮，谁知吾之廉贞！”","詹尹乃释策而谢曰：“夫尺有所短，寸有所长物有所不足，智有所不明数有所不逮，神有所不通。用君之心，行君之意。龟策诚不能知此事。”"],"source":"《楚辞》"},{"title":"渔父","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["屈原既放，游于江潭，行吟泽畔，颜色憔悴，形容枯槁。渔父见而问之曰：“子非三闾大夫与？何故至于斯？”屈原曰：“举世皆浊我独清，众人皆醉我独醒，是以见放。”","渔父曰：“圣人不凝滞于物，而能与世推移。世人皆浊，何不淈其泥而扬其波？众人皆醉，何不餔其糟而歠其醨？何故深思高举，自令放为？”","屈原曰：“吾闻之，新沐者必弹冠，新浴者必振衣安能以身之察察，受物之汶汶者乎？宁赴湘流，葬于江鱼之腹中。安能以皓皓之白，而蒙世俗之尘埃乎?”","渔父莞尔而笑，鼓枻而去。","乃歌曰：“沧浪之水清兮，可以濯吾缨。沧浪之水浊兮，可以濯吾足。”遂去，不复与言。"],"source":"《楚辞》"},{"title":"九辩","author":"宋玉","dynasty":"先秦","form":"辞赋","lines":["悲哉，秋之为气也！萧瑟兮草木摇落而变衰。","憭栗兮若在远行，登山临水兮送将归。","泬漻兮天高而气清，寂寥兮收潦而水清。","憯悽增欷兮，薄寒之中人，怆怳懭悢兮，去故而就新。","坎廪兮贫士失职而志不平，廓落兮羁旅而无友生，惆怅兮而私自怜！","燕翩翩其辞归兮，蝉寂漠而无声。","雁廱廱而南游兮，鹍鸡啁哳而悲鸣。","独申旦而不寐兮，哀蟋蟀之宵征。","时亹亹而过中兮，蹇淹留而无成。","悲忧穷戚兮独处廓，有美一人兮心不绎。","去乡离家兮来远客，超逍遥兮今焉薄！","专思君兮不可化，君不知兮可奈何！","蓄怨兮积思，心烦憺兮忘食事。","原一见兮道余意，君之心兮与余异。","车既驾兮朅而归，不得见兮心伤悲。","倚结軨兮长太息，涕潺湲兮下霑轼。","忼慨绝兮不得，中瞀乱兮迷惑。","私自怜兮何极？","心怦怦兮谅直。","皇天平分四时兮，窃独悲此凛秋。","白露既下百草兮，奄离披此梧楸。","去白日之昭昭兮，袭长夜之悠悠。","离芳蔼之方壮兮，余萎约而悲愁。","秋既先戒以白露兮，冬又申之以严霜。","收恢台之孟夏兮，然欿傺而沉藏。","叶菸邑而无色兮，枝烦挐而交横。","颜淫溢而将罢兮，柯仿佛而萎黄。","萷櫹椮之可哀兮，形销铄而瘀伤。","惟其纷糅而将落兮，恨其失时而无当。","揽騑辔而下节兮，聊逍遥以相佯。","岁忽忽而遒尽兮，恐余寿之弗将。","悼余生之不时兮，逢此世之俇攘。","澹容与而独倚兮，蟋蟀鸣此西堂。","心怵惕而震荡兮，何所忧之多方。","卬明月而太息兮，步列星而极明。","窃悲夫蕙华之曾敷兮，纷旖旎乎都房。","何曾华之无实兮，从风雨而飞飏！","以为君独服此蕙兮，羌无以异于众芳。","闵奇思之不通兮，将去君而高翔。","心闵怜之惨悽兮，愿一见而有明。","重无怨而生离兮，中结轸而增伤。","岂不郁陶而思君兮？","君之门以九重！猛犬狺狺而迎吠兮，关梁闭而不通。","皇天淫溢而秋霖兮，后土何时而得漧？","塊独守此无泽兮，仰浮云而永叹！何时俗之工巧兮？","背绳墨而改错！郤骐骥而不乘兮，策驽骀而取路。","当世岂无骐骥兮，诚莫之能善御。","见执辔者非其人兮，故駶跳而远去。","凫雁皆唼夫梁藻兮，凤愈飘翔而高举。","圜凿而方枘兮，吾固知其鉏铻而难入。","众鸟皆有所登棲兮，凤独遑遑而无所集。","原衔枚而无言兮，尝被君之渥洽。","太公九十乃显荣兮，诚未遇其匹合。","谓骐骥兮安归？","谓凤皇兮安棲？","变古易俗兮世衰，今之相者兮举肥。","骐骥伏匿而不见兮，凤皇高飞而不下。","鸟兽犹知怀德兮，何云贤士之不处？","骥不骤进而求服兮，凤亦不贪餧而妄食。","君弃远而不察兮，虽原忠其焉得？","欲寂漠而绝端兮，窃不敢忘初之厚德。","独悲愁其伤人兮，冯郁郁其何极？","霜露惨悽而交下兮，心尚幸其弗济。","霰雪雰糅其增加兮，乃知遭命之将至。","原徼幸而有待兮，泊莽莽与野草同死。","原自往而径游兮，路壅绝而不通。","欲循道而平驱兮，又未知其所从。","然中路而迷惑兮，自压桉而学诵。","性愚陋以褊浅兮，信未达乎从容。","窃美申包胥之气盛兮，恐时世之不固。","何时俗之工巧兮？","灭规矩而改凿！独耿介而不随兮，原慕先圣之遗教。","处浊世而显荣兮，非余心之所乐。","与其无义而有名兮，宁穷处而守高。","食不媮而为饱兮，衣不苟而为温。","窃慕诗人之遗风兮，原讬志乎素餐。","蹇充倔而无端兮，泊莽莽而无垠。","无衣裘以御冬兮，恐溘死不得见乎阳春。","靓杪秋之遥夜兮，心缭悷而有哀。","春秋逴逴而日高兮，然惆怅而自悲。","四时递来而卒岁兮，阴阳不可与俪偕。","白日晼晚其将入兮，明月销铄而减毁。","岁忽忽而遒尽兮，老冉冉而愈弛。","心摇悦而日幸兮，然怊怅而无冀。","中憯恻之悽怆兮，长太息而增欷。","年洋洋以日往兮，老嵺廓而无处。","事亹亹而觊进兮，蹇淹留而踌躇。","何氾滥之浮云兮？","猋壅蔽此明月。","忠昭昭而原见兮，然霠曀而莫达。","原皓日之显行兮，云蒙蒙而蔽之。","窃不自聊而原忠兮，或黕点而汙之。","尧舜之抗行兮，瞭冥冥而薄天。","何险巇之嫉妒兮？","被以不慈之伪名。","彼日月之照明兮，尚黯黮而有瑕。","何况一国之事兮，亦多端而胶加。","被荷裯之晏晏兮，然潢洋而不可带。","既骄美而伐武兮，负左右之耿介。","憎愠惀之修美兮，好夫人之慷慨。","众踥蹀而日进兮，美超远而逾迈。","农夫辍耕而容与兮，恐田野之芜秽。","事緜緜而多私兮，窃悼後之危败。","世雷同而炫曜兮，何毁誉之昧昧！","今修饰而窥镜兮，後尚可以竄藏。","愿寄言夫流星兮，羌倏忽而难当。","卒壅蔽此浮云，下暗漠而无光。","尧舜皆有所举任兮，故高枕而自适。","谅无怨于天下兮，心焉取此怵惕？","乘骐骥之浏浏兮，驭安用夫强策？","谅城郭之不足恃兮，虽重介之何益？","邅翼翼而无终兮，忳惛惛而愁约。","生天地之若过兮，功不成而无嶜。","原沉滞而不见兮，尚欲布名乎天下。","然潢洋而不遇兮，直怐愗而自苦。","莽洋洋而无极兮，忽翱翔之焉薄？","国有骥而不知乘兮，焉皇皇而更索？","宁戚讴于车下兮，桓公闻而知之。","无伯乐之相善兮，今谁使乎誉之？","罔流涕以聊虑兮，惟著意而得之。","纷纯纯之愿忠兮，妒被离而鄣之。","原赐不肖之躯而别离兮，放游志乎云中。","乘精气之抟抟兮，骛诸神之湛湛。","骖白霓之習習兮，历群灵之丰丰。","左硃雀之茇茇兮，右苍龙之躣躣。","属雷师之阗阗兮，通飞廉之衙衙。","前轻辌之锵锵兮，后辎乘之从从。","载云旗之委蛇兮，扈屯骑之容容。","计专专之不可化兮，原遂推而为臧。","赖皇天之厚德兮，还及君之无恙！"],"source":"《楚辞》"},{"title":"招魂","author":"宋玉","dynasty":"先秦","form":"辞赋","lines":["朕幼清以廉洁兮，身服义而未沫。","主此盛德兮，牵于俗而芜秽。","上无所考此盛德兮，长离殃而愁苦。","帝告巫阳曰：“有人在下，我欲辅之。魂魄离散，汝筮予之。”","巫阳对曰：“掌梦！上帝其难从。若必筮予之，恐后之谢，不能复用。”","巫阳焉乃下招曰：魂兮归来！去君之恒干，何为四方些？","舍君之乐处，而离彼不祥些！魂兮归来！东方不可以讬些。","长人千仞，惟魂是索些。","十日代出，流金铄石些。","彼皆习之，魂往必释些。","归来兮！不可以讬些。","魂兮归来！南方不可以止些。","雕题黑齿，得人肉以祀，以其骨为醢些。","蝮蛇蓁蓁，封狐千里些。","雄虺九首，往来倏忽，吞人以益其心些。","归来兮！不可久淫些。","魂兮归来！西方之害，流沙千里些。","旋入雷渊，爢散而不可止些。","幸而得脱，其外旷宇些。","赤蚁若象，玄蜂若壶些。","五谷不生，丛菅是食些。","其土烂人，求水无所得些。","彷徉无所倚，广大无所极些。","归来兮！恐自遗贼些。","魂兮归来！北方不可以止些。","增冰峨峨，飞雪千里些。","归来兮！不可以久些。","魂兮归来！君无上天些。","虎豹九关，啄害下人些。","一夫九首，拔木九千些。","豺狼从目，往来侁侁些。","悬人以嬉，投之深渊些。","致命于帝，然后得瞑些。","归来！往恐危身些。","魂兮归来！君无下此幽都些。","土伯九约，其角觺觺些。","敦脄血拇，逐人伂駓駓些。","参目虎首，其身若牛些。","此皆甘人，归来！恐自遗灾些。","魂兮归来！入修门些。","工祝招君，背行先些。","秦篝齐缕，郑绵络些。","招具该备，永啸呼些。","魂兮归来！反故居些。","天地四方，多贼奸些。","像设君室，静闲安些。","高堂邃宇，槛层轩些。","层台累榭，临高山些。","网户朱缀，刻方连些。","冬有穾厦，夏室寒些。","川谷径复，流潺湲些。","光风转蕙，氾崇兰些。","经堂入奥，朱尘筵些。","砥室翠翘，挂曲琼些。","翡翠珠被，烂齐光些。","蒻阿拂壁，罗帱张些。","纂组绮缟，结琦璜些。","室中之观，多珍怪些。","兰膏明烛，华容备些。","二八侍宿，射递代些。","九侯淑女，多迅众些。","盛鬋不同制，实满宫些。","容态好比，顺弥代些。","弱颜固植，謇其有意些。","姱容修态，絚洞房些。","蛾眉曼睩，目腾光些。","靡颜腻理，遗视矊些。","离榭修幕，侍君之闲些。","悲帷翠帐，饰高堂些。","红壁沙版，玄玉梁些。","仰观刻桷，画龙蛇些。","坐堂伏槛，临曲池些。","芙蓉始发，杂芰荷些。","紫茎屏风，文缘波些。","文异豹饰，侍陂陁些。","轩辌既低，步骑罗些。","兰薄户树，琼木篱些。","魂兮归来！何远为些？","室家遂宗，食多方些。","稻粢穱麦，挐黄梁些。","大苦醎酸，辛甘行些。","肥牛之腱，臑若芳些。","和酸若苦，陈吴羹些。","胹鳖炮羔，有柘浆些。","鹄酸臇凫，煎鸿鸧些。","露鸡臛蠵，厉而不爽些。","粔籹蜜饵，有餦餭些。","瑶浆蜜勺，实羽觞些。","挫糟冻饮，酎清凉些。","华酌既陈，有琼浆些。","归来反故室，敬而无妨些。","肴羞未通，女乐罗些。","敶钟按鼓，造新歌些。","《涉江》《采菱》，发《扬荷》些。","美人既醉，朱颜酡些。","嬉光眇视，目曾波些。","被文服纤，丽而不奇些。","长发曼鬋，艳陆离些。","二八齐容，起郑舞些。","衽若交竿，抚案下些。","竽瑟狂会，搷鸣鼓些。","宫庭震惊，发<激楚>些。","吴歈蔡讴，奏大吕些。","士女杂坐，乱而不分些。","放敶组缨，班其相纷些。","郑卫妖玩，来杂陈些。","《激楚》之结，独秀先些。","菎蔽象棋，有六簙些。","分曹并进，遒相迫些。","成枭而牟，呼五白些。","晋制犀比，费白日些。","铿钟摇簴，揳梓瑟些。","娱酒不废，沈日夜些。","兰膏明烛，华灯错些。","结撰至思，兰芳假些。","人有所极，同心赋些。","酎饮尽欢，乐先故些。","魂兮归来！反故居些。","乱曰：献岁发春兮，汨吾南征。","菉蘋齐叶兮，白芷生。","路贯庐江兮，左长薄。","倚沼畦瀛兮，遥望博。","青骊结驷兮，齐千乘。","悬火延起兮，玄颜烝。","步及骤处兮，诱骋先。","抑骛若通兮，引车右还。","与王趋梦兮，课后先。","君王亲发兮，惮青兕。","朱明承夜兮，时不可以淹。","皋兰被径兮，斯路渐。","湛湛江水兮，上有枫。","目极千里兮，伤春心。","魂兮归来，哀江南！"],"source":"《楚辞》"},{"title":"大招","author":"景差","dynasty":"先秦","form":"辞赋","lines":["青春受谢，白日昭只。","春气奋发，万物遽只。","冥凌浃行，魂无逃只。","魂魄归来！无远遥只。","魂乎归来！无东无西，无南无北只。","东有大海，溺水浟浟只。","螭龙并流，上下悠悠只。","雾雨淫淫，白皓胶只。","魂乎无东！汤谷寂寥只。","魂乎无南！南有炎火千里，蝮蛇蜒只。","山林险隘，虎豹蜿只。","鰅鳙短狐，王虺骞只。","魂乎无南！蜮伤躬只","魂乎无西！西方流沙，漭洋洋只。","豕首纵目，被发鬤只。","长爪踞牙，诶笑狂只。","魂乎无西！多害伤只。","魂乎无北！北有寒山，趠龙赩只。","代水不可涉，深不可测只。","天白颢颢，寒凝凝只。","魂乎无往！盈北极只。","魂魄归来！闲以静只。","自恣荆楚，安以定只。","逞志究欲，心意安只。","穷身永乐，年寿延只。","魂乎归来！乐不可言只。","五谷六仞，设菰梁只。","鼎臑盈望，和致芳只。","内鸧鸽鹄，味豺羹只。","魂乎归来！恣所尝只。","鲜蠵甘鸡，和楚酪只。","醢豚苦狗，脍苴蒪只。","吴酸蒿蒌，不沾薄只。","魂兮归来！恣所择只。","炙鸹烝凫，煔鹑敶只。","煎鰿膗雀，遽爽存只。","魂乎归来！丽以先只。","四酎并孰，不涩嗌只。","清馨冻饮，不歠役只。","吴醴白蘖，和楚沥只。","魂乎归来！不遽惕只。","代秦郑卫，鸣竽张只。","伏戏《驾辩》，楚《劳商》只。","讴和《扬阿》，赵萧倡只。","魂乎归来！定空桑只。","二八接舞，投诗赋只。","叩钟调磬，娱人乱只。","四上竞气，极声变只。","魂乎归来！听歌譔只。","朱唇皓齿，嫭以姱只。","比德好闲，习以都只。","丰肉微骨，调以娱只。","魂乎归来！安以舒只。","嫮目宜笑，娥眉曼只。","容则秀雅，稚朱颜只。","魂乎归来！静以安只。","姱修滂浩，丽以佳只。","曾颊倚耳，曲眉规只。","滂心绰态，姣丽施只。","小腰秀颈，若鲜卑只。","魂乎归来！思怨移只。","易中利心，以动作只。","粉白黛黑，施芳泽只。","长袂拂面，善留客只。","魂乎归来！以娱昔只。","青色直眉，美目媔只。","靥辅奇牙，宜笑嘕只。","丰肉微骨，体便娟只。","魂乎归来！恣所便只。","夏屋广大，沙堂秀只。","南房小坛，观绝霤只。","曲屋步壛，宜扰畜只。","腾驾步游，猎春囿只。","琼轂错衡，英华假只。","茝兰桂树，郁弥路只。","魂乎归来！恣志虑只。","孔雀盈园，畜鸾皇只！","鵾鸿群晨，杂鶖鸧只。","鸿鹄代游，曼骕驦只。","魂乎归来！凤凰翔只。","曼泽怡面，血气盛只。","永宜厥身，保寿命只。","室家盈廷，爵禄盛只。","魂乎归来！居室定只。","接径千里，出若云只。","三圭重侯，听类神只。","察笃夭隐，孤寡存只。","魂兮归来！正始昆只。","田邑千畛，人阜昌只。","美冒众流，德泽章只。","先威后文，善美明只。","魂乎归来！赏罚当只。","名声若日，照四海只。","德誉配天，万民理只。","北至幽陵，南交阯只。","西薄羊肠，东穷海只。","魂乎归来！尚贤士只。","发政献行，禁苛暴只。","举杰压陛，诛讥罢只。","直赢在位，近禹麾只。","豪杰执政，流泽施只。","魂乎来归！国家为只。","雄雄赫赫，天德明只。","三公穆穆，登降堂只。","诸侯毕极，立九卿只。","昭质既设，大侯张只。","执弓挟矢，揖辞让只。","魂乎来归！尚三王只。"],"source":"《楚辞》"},{"title":"惜誓","author":"贾谊","dynasty":"先秦","form":"辞赋","lines":["惜余年老而日衰兮，岁忽忽而不反。","登苍天而高举兮，历众山而日远。","观江河之纡曲兮，离四海之霑濡。","攀北极而一息兮，吸沆瀣以充虚。","飞朱鸟使先驱兮，驾太一之象舆。","苍龙蚴虯于左骖兮，白虎骋而为右騑。","建日月以为盖兮，载玉女于後车。","驰骛于杳冥之中兮，休息虖昆仑之墟。","乐穷极而不厌兮，愿从容虖神明。","涉丹水而驰骋兮，右大夏之遗风。","黄鹄之一举兮，知山川之纡曲。","再举兮，睹天地之圜方。","临中国之众人兮，讬回飙乎尚羊。","乃至少原之野兮，赤松、王乔皆在旁。","二子拥瑟而调均兮，余因称乎清商。","澹然而自乐兮，吸众气而翱翔。","念我长生而久仙兮，不如反余之故乡。","黄鹄後时而寄处兮，鸱枭群而制之。","神龙失水而陆居兮，为蝼蚁之所裁。","夫黄鹄神龙犹如此兮，况贤者之逢乱世哉。","寿冉冉而日衰兮，固儃回而不息。","俗流从而不止兮，众枉聚而矫直。","或偷合而苟进兮，或隐居而深藏。","苦称量之不审兮，同权概而就衡。","或推迻而苟容兮，或直言之谔謣。","伤诚是之不察兮，并纫茅丝以为索。","方世俗之幽昏兮，眩白黑之美恶。","放山渊之龟玉兮，相与贵夫砾石。","梅伯数谏而至醢兮，来革顺志而用国。","悲仁人之尽节兮，反为小人之所贼。","比干忠谏而剖心兮，箕子被发而佯狂。","水背流而源竭兮，木去根而不长。","非重躯以虑难兮，惜伤身之无功。","已矣哉！独不见夫鸾凤之高翔兮，乃集大皇之野。","循四极而回周兮，见盛德而後下。","彼圣人之神德兮，远浊世而自藏。","使麒麟可得羁而係兮，又何以异虖犬羊？"],"source":"《楚辞》"},{"title":"招隐士","author":"淮南小山","dynasty":"先秦","form":"辞赋","lines":["桂树丛生兮山之幽，偃蹇连蜷兮枝相缭。","山气巄嵷兮石嵯峨，溪谷崭岩兮水曾波。","猿狖群啸兮虎豹嗥，攀援桂枝兮聊淹留。","王孙游兮不归，春草生兮萋萋。","岁暮兮不自聊，蟪蛄鸣兮啾啾。","坱兮轧，山曲岪，心淹留兮恫慌忽。","罔兮沕，憭兮栗，虎豹穴。","丛薄深林兮，人上栗。","嵚岑碕礒兮，碅磳磈硊","树轮相纠兮，林木茷骫。","青莎杂树兮，薠草靃靡","白鹿麏麚兮，或腾或倚。","状貌崟崟兮峨峨，凄凄兮漇漇。","猕猴兮熊罴，慕类兮以悲","攀援桂枝兮聊淹留。","虎豹斗兮熊罴咆，禽兽骇兮亡其曹。","王孙兮归来，山中兮不可以久留。"],"source":"《楚辞》"},{"title":"初放","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["平生于国兮，长于原野。","言语讷譅兮，又无彊辅。","浅智褊能兮，闻见又寡。","数言便事兮，见怨门下。","王不察其长利兮，卒见弃乎原野。","伏念思过兮，无可改者。","群众成朋兮，上浸以惑。","巧佞在前兮，贤者灭息。","尧、舜圣已没兮，孰为忠直？","高山崔巍兮，水流汤汤。","死日将至兮，与麋鹿同坑。","塊兮鞠，当道宿，举世皆然兮，余将谁告？","斥逐鸿鹄兮，近习鸱枭，斩伐橘柚兮，列树苦桃。","便娟之修竹兮，寄生乎江潭。","上葳蕤而防露兮，下泠泠而来风。","孰知其不合兮，若竹柏之异心。","往者不可及兮，来者不可待。","悠悠苍天兮，莫我振理。","窃怨君之不寤兮，吾独死而後已。"],"source":"《楚辞》"},{"title":"沉江","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["惟往古之得失兮，览私微之所伤。","尧舜圣而慈仁兮，後世称而弗忘。","齐桓失于专任兮，夷吾忠而名彰。","晋献惑于孋姬兮，申生孝而被殃。","偃王行其仁义兮，荆文寤而徐亡。","纣暴虐以失位兮，周得佐乎吕望。","修往古以行恩兮，封比干之丘垄。","贤俊慕而自附兮，日浸淫而合同。","明法令而修理兮，兰芷幽而有芳。","苦众人之妒予兮，箕子寤而佯狂。","不顾地以贪名兮，心怫郁而内伤。","联蕙芷以为佩兮，过鲍肆而失香。","正臣端其操行兮，反离谤而见攘。","世俗更而变化兮，伯夷饿于首阳。","独廉洁而不容兮，叔齐久而逾明。","浮云陈而蔽晦兮，使日月乎无光。","忠臣贞而欲谏兮，谗谀毁而在旁。","秋草荣其将实兮，微霜下而夜降。","商风肃而害生兮，百草育而不长。","众并谐以妒贤兮，孤圣特而易伤。","怀计谋而不见用兮，岩穴处而隐藏。","成功隳而不卒兮，子胥死而不葬。","世从俗而变化兮，随风靡而成行。","信直退而毁败兮，虚伪进而得当。","追悔过之无及兮，岂尽忠而有功。","废制度而不用兮，务行私而去公。","终不变而死节兮，惜年齿之未央。","将方舟而下流兮，冀幸君之发矇。","痛忠言之逆耳兮，恨申子之沉江。","愿悉心之所闻兮，遭值君之不聪。","不开寤而难道兮，不别横之与纵。","听奸臣之浮说兮，绝国家之久长。","灭规矩而不用兮，背绳墨之正方。","离忧患而乃寤兮，若纵火于秋蓬。","业失之而不救兮，尚何论乎祸凶。","彼离畔而朋党兮，独行之士其何望？","日渐染而不自知兮，秋毫微哉而变容。","众轻积而折轴兮，原咎杂而累重。","赴湘沅之流澌兮，恐逐波而复东。","怀沙砾而自沉兮，不忍见君之蔽壅。"],"source":"《楚辞》"},{"title":"怨世","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["世沉淖而难论兮，俗岒峨而嵾嵯。","清泠泠而歼灭兮，溷湛湛而日多。","枭鸮既以成群兮，玄鹤弭翼而屏移。","蓬艾亲入御于床笫兮，马兰踸踔而日加。","弃捐药芷与杜衡兮，余柰世之不知芳何？","何周道之平易兮，然芜秽而险戏。","高阳无故而委尘兮，唐虞点灼而毁议。","谁使正其真是兮，虽有八师而不可为。","皇天保其高兮，后土持其久。","服清白以逍遥兮，偏与乎玄英异色。","西施媞媞而不得见兮，嫫母勃屑而日侍。","桂蠹不知所淹留兮，蓼虫不知徙乎葵菜。","处湣湣之浊世兮，今安所达乎吾志。","意有所载而远逝兮，固非众人之所识。","骥踌躇于弊輂兮，遇孙阳而得代。","吕望穷困而不聊生兮，遭周文而舒志。","宁戚饭牛而商歌兮，桓公闻而弗置。","路室女之方桑兮，孔子过之以自侍。","吾独乖剌而无当兮，心悼怵而耄思。","思比干之恲恲兮，哀子胥之慎事。","悲楚人之和氏兮，献宝玉以为石。","遇厉武之不察兮，羌两足以毕斮。","小人之居势兮，视忠正之何若？","改前圣之法度兮，喜嗫嚅而妄作。","亲谗谀而疏贤圣兮，讼谓闾娵为丑恶。","愉近习而蔽远兮，孰知察其黑白？","卒不得效其心容兮，安眇眇而无所归薄。","专精爽以自明兮，晦冥冥而壅蔽。","年既已过太半兮，然埳轲而留滞。","欲高飞而远集兮，恐离罔而灭败。","独冤抑而无极兮，伤精神而寿夭。","皇天既不纯命兮，余生终无所依。","愿自沉于江流兮，绝横流而径逝。","宁为江海之泥涂兮，安能久见此浊世？"],"source":"《楚辞》"},{"title":"怨思","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["贤士穷而隐处兮，廉方正而不容。","子胥谏而靡躯兮，比干忠而剖心。","子推自割而飤君兮，德日忘而怨深。","行明白而曰黑兮，荆棘聚而成林。","江离弃于穷巷兮，蒺藜蔓乎东厢。","贤者蔽而不见兮，谗谀进而相朋。","枭鸮并进而俱鸣兮，凤皇飞而高翔。","原壹往而径逝兮，道壅绝而不通。"],"source":"《楚辞》"},{"title":"自悲","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["居愁懃其谁告兮，独永思而忧悲。","内自省而不惭兮，操愈坚而不衰。","隐三年而无决兮，岁忽忽其若颓。","怜余身不足以卒意兮，冀一见而复归。","哀人事之不幸兮，属天命而委之咸池。","身被疾而不闲兮，心沸热其若汤。","冰炭不可以相并兮，吾固知乎命之不长。","哀独苦死之无乐兮，惜予年之未央。","悲不反余之所居兮，恨离予之故乡。","鸟兽惊而失群兮，犹高飞而哀鸣。","狐死必首丘兮，夫人孰能不反其真情？","故人疏而日忘兮，新人近而俞好。","莫能行于杳冥兮，孰能施于无报？","苦众人之皆然兮，乘回风而远游。","凌恆山其若陋兮，聊愉娱以忘忧。","悲虚言之无实兮，苦众口之铄金。","过故乡而一顾兮，泣歔欷而霑衿。","厌白玉以为面兮，怀琬琰以为心。","邪气入而感内兮，施玉色而外淫。","何青云之流澜兮，微霜降之蒙蒙。","徐风至而徘徊兮，疾风过之汤汤。","闻南籓乐而欲往兮，至会稽而且止。","见韩众而宿之兮，问天道之所在？","借浮云以送予兮，载雌霓而为旌。","驾青龙以驰骛兮，班衍衍之冥冥。","忽容容其安之兮，超慌忽其焉如？","苦众人之难信兮，愿离群而远举。","登峦山而远望兮，好桂树之冬荣。","观天火之炎炀兮，听大壑之波声。","引八维以自道兮，含沆瀣以长生。","居不乐以时思兮，食草木之秋实。","饮菌若之朝露兮，构桂木而为室。","杂橘柚以为囿兮，列新夷与椒桢。","鹍鹤孤而夜号兮，哀居者之诚贞。"],"source":"《楚辞》"},{"title":"哀命","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["哀时命之不合兮，伤楚国之多忧。","内怀情之洁白兮，遭乱世而离尤。","恶耿介之直行兮，世溷浊而不知。","何君臣之相失兮，上沅湘而分离。","测汨罗之湘水兮，知时固而不反。","伤离散之交乱兮，遂侧身而既远。","处玄舍之幽门兮，穴岩石而窟伏。","从水蛟而为徙兮，与神龙乎休息。","何山石之崭岩兮，灵魂屈而偃蹇。","含素水而蒙深兮，日眇眇而既远。","哀形体之离解兮，神罔两而无舍。","惟椒兰之不反兮，魂迷惑而不知路。","愿无过之设行兮，虽灭没之自乐。","痛楚国之流亡兮，哀灵修之过到。","固时俗之溷浊兮，志瞀迷而不知路。","念私门之正匠兮，遥涉江而远去。","念女嬃之婵媛兮，涕泣流乎于悒。","我决死而不生兮，虽重追吾何及。","戏疾濑之素水兮，望高山之蹇产。","哀高丘之赤岸兮，遂没身而不反。"],"source":"《楚辞》"},{"title":"谬谏","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["怨灵修之浩荡兮，夫何执操之不固？","悲太山之为隍兮，孰江河之可涸？","愿承闲而效志兮，恐犯忌而干讳。","卒抚情以寂寞兮，然怊怅而自悲。","玉与石其同匮兮，贯鱼眼与珠玑。","驽骏杂而不分兮，服罢牛而骖骥。","年滔滔而自远兮，寿冉冉而愈衰。","心悇憛而烦冤兮，蹇超摇而无冀。","固时俗之工巧兮，灭规矩而改错。","郤骐骥而不乘兮，策驽骀而取路。","当世岂无骐骥兮，诚无王良之善驭。","见执辔者非其人兮，故驹跳而远去。","不量凿而正枘兮，恐矩矱之不同。","不论世而高举兮，恐操行之不调。","弧弓弛而不张兮，孰云知其所至？","无倾危之患难兮，焉知贤士之所死？","俗推佞而进富兮，节行张而不著。","贤良蔽而不群兮，朋曹比而党誉。","邪说饰而多曲兮，正法弧而不公。","直士隐而避匿兮，谗谀登乎明堂。","弃彭咸之娱乐兮，灭巧倕之绳墨。","菎蕗杂于黀蒸兮，机蓬矢以射革。","驾蹇驴而无策兮，又何路之能极？","以直鍼而为钓兮，又何鱼之能得？","伯牙之绝弦兮，无锺子期而听之。","和抱璞而泣血兮，安得良工而剖之？","同音者相和兮，同类者相似。","飞鸟号其群兮，鹿鸣求其友。","故叩宫而宫应兮，弹角而角动。","虎啸而谷风至兮，龙举而景云往。","音声之相和兮，言物类之相感也。","夫方圜之异形兮，势不可以相错。","列子隐身而穷处兮，世莫可以寄讬。","众鸟皆有行列兮，凤独翔翔而无所薄。","经浊世而不得志兮，愿侧身岩穴而自讬。","欲阖口而无言兮，尝被君之厚德。","独便悁而怀毒兮，愁郁郁之焉极？","念三年之积思兮，愿壹见而陈辞。","不及君而骋说兮，世孰可为明之？","身寝疾而日愁兮，情沉抑而不扬。","众人莫可与论道兮，悲精神之不通。","乱曰：鸾皇孔凤日以远兮，畜凫驾鹅。","鸡鹜满堂坛兮，鼉黽游乎华池。","要褭奔亡兮，腾驾橐驼。","铅刀进御兮，遥弃太阿。","拔搴玄芝兮，列树芋荷。","橘柚萎枯兮，苦李旖旎。","甂瓯登于明堂兮，周鼎潜潜乎深渊。","自古而固然兮，吾又何怨乎今之人。"],"source":"《楚辞》"},{"title":"哀时命","author":"庄忌","dynasty":"先秦","form":"辞赋","lines":["哀时命之不及古人兮，夫何予生之不遘时！","往者不可扳援兮，徠者不可与期。","志憾恨而不逞兮，杼中情而属诗。","夜炯炯而不寐兮，怀隐忧而历兹。","心郁郁而无告兮，众孰可与深谋！","欿愁悴而委惰兮，老冉冉而逮之。","居处愁以隐约兮，志沉抑而不扬。","道壅塞而不通兮，江河广而无梁。","愿至昆仑之悬圃兮，采锺山之玉英。","揽瑶木之橝枝兮，望阆风之板桐。","弱水汩其为难兮，路中断而不通。","势不能凌波以径度兮，又无羽翼而高翔。","然隐悯而不达兮，独徙倚而彷徉。","怅惝罔以永思兮，心纡轸而增伤。","倚踌躇以淹留兮，日饥馑而绝粮。","廓抱景而独倚兮，超永思乎故乡。","廓落寂而无友兮，谁可与玩此遗芳？","白日晼晼其將入兮，哀余寿之弗将。","车既弊而马罢兮，蹇邅徊而不能行。","身既不容于浊世兮，不知进退之宜当。","冠崔嵬而切云兮，剑淋离而从横。","衣摄叶以储与兮，左袪挂于榑桑","右衽拂于不周兮，六合不足以肆行。","上同凿枘于伏戏兮，下合矩矱于虞唐。","原尊节而式高兮，志犹卑夫禹汤。","虽知困其不改操兮，终不以邪枉害方。","世并举而好朋兮，壹斗斛而相量。","众比周以肩迫兮，贤者远而隐藏。","为凤皇作鹑笼兮，虽翕翅其不容。","灵皇其不寤知兮，焉陈词而效忠。","俗嫉妒而蔽贤兮，孰知余之从容？","愿舒志而抽冯兮，庸讵知其吉凶？","璋珪杂于甑窐兮，陇廉与孟娵同宫。","举世以为恆俗兮，固将愁苦而终穷。","幽独转而不寐兮，惟烦懑而盈匈。","魂眇眇而驰骋兮，心烦冤之忡忡。","志欿憾而不憺兮，路幽昧而甚难。","塊独守此曲隅兮，然欿切而永叹。","愁修夜而宛转兮，气涫沸其若波。","握剞劂而不用兮，操规矩而无所施。","骋骐骥于中庭兮，焉能极夫远道？","置援狖于棂槛兮，夫何以责其捷巧？","驷跛鳖而上山兮，吾固知其不能陞。","释管晏而任臧获兮，何权衡之能称？","箟簬杂于黀蒸兮，机蓬矢以射革。","负檐荷以丈尺兮，欲伸要而不可得。","外迫胁于机臂兮，上牵联于矰隿。","肩倾侧而不容兮，固陿腹而不得息。","务光自投于深渊兮，不获世之尘垢。","孰魁摧之可久兮，愿退身而穷处。","凿山楹而为室兮，下被衣于水渚。","雾露濛濛其晨降兮，云依斐而承宇。","虹霓纷其朝霞兮，夕淫淫而淋雨。","怊茫茫而无归兮，怅远望此旷野。","下垂钓于溪谷兮，上要求于仙者。","与赤松而结友兮，比王侨而为耦。","使枭杨先导兮，白虎为之前後。","浮云雾而入冥兮，骑白鹿而容与。","魂眐眐以寄独兮，汨徂往而不归。","处卓卓而日远兮，志浩荡而伤怀。","鸾凤翔于苍云兮，故矰缴而不能加。","蛟龙潜于旋渊兮，身不挂于罔罗。","知贪饵而近死兮，不如下游乎清波。","宁幽隐以远祸兮，孰侵辱之可为。","子胥死而成义兮，屈原沉于汨罗。","虽体解其不变兮，岂忠信之可化。","志怦怦而内直兮，履绳墨而不颇。","执权衡而无私兮，称轻重而不差。","摡尘垢之枉攘兮，除秽累而反真。","形体白而质素兮，中皎洁而淑清。","时猒饫而不用兮，且隐伏而远身。","聊窜端而匿迹兮，嗼寂默而无声。","独便悁而烦毒兮，焉发愤而筊抒。","时暧暧其将罢兮，遂闷叹而无名。","伯夷死于首阳兮，卒夭隐而不荣。","太公不遇文王兮，身至死而不得逞。","怀瑶象而佩琼兮，愿陈列而无正。","生天坠之若过兮，忽烂漫而无成。","邪气袭余之形体兮，疾憯怛而萌生。","原壹见阳春之白日兮，恐不终乎永年。"],"source":"《楚辞》"},{"title":"匡机","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["极运兮不中，来将屈兮困穷。","余深愍兮惨怛，愿一列兮无从。","乘日月兮上征，顾游心兮鄗酆。","弥览兮九隅，彷徨兮兰宫。","芷闾兮药房，奋摇兮众芳。","菌阁兮蕙楼，观道兮从横。","宝金兮委积，美玉兮盈堂。","桂水兮潺湲，扬流兮洋洋。","蓍蔡兮踊跃，孔鹤兮回翔。","抚槛兮远望，念君兮不忘。","怫郁兮莫陈，永怀兮内伤。"],"source":"《楚辞》"},{"title":"通路","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["天门兮墬户，孰由兮贤者？","无正兮溷厕，怀德兮何睹？","假寐兮愍斯，谁可与兮寤语？","痛凤兮远逝，畜鴳兮近处。","鲸鱏兮幽潜，从虾兮游陼。","乘虬兮登阳，载象兮上行。","朝发兮葱岭，夕至兮明光。","北饮兮飞泉，南采兮芝英。","宣游兮列宿，顺极兮彷徉。","红采兮骍衣，翠缥兮为裳。","舒佩兮綝纚，竦余剑兮干将。","腾蛇兮后从，飞駏兮步旁。","微观兮玄圃，览察兮瑶光。","启匮兮探筴，悲命兮相当。","纫蕙兮永辞，将离兮所思。","浮云兮容与，道余兮何之？","远望兮仟眠，闻雷兮阗阗。","阴忧兮感余，惆怅兮自怜。"],"source":"《楚辞》"},{"title":"危俊","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["林不容兮鸣蜩，余何留兮中州？","陶嘉月兮总驾，搴玉英兮自修。","结荣茝兮逶逝，将去烝兮远游。","径岱土兮魏阙，历九曲兮牵牛。","聊假日兮相佯，遗光燿兮周流。","望太一兮淹息，纡余辔兮自休。","晞白日兮皎皎，弥远路兮悠悠。","顾列孛兮缥缥，观幽云兮陈浮。","钜宝迁兮砏磤，雉咸雊兮相求。","泱莽莽兮究志，惧吾心兮懤懤。","步余马兮飞柱，览可与兮匹俦。","卒莫有兮纤介，永余思兮怞怞。"],"source":"《楚辞》"},{"title":"昭世","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["世溷兮冥昏，违君兮归真。","乘龙兮偃蹇，高回翔兮上臻。","袭英衣兮缇[糹習]，披华裳兮芳芬。","登羊角兮扶舆，浮云漠兮自娱。","握神精兮雍容，与神人兮相胥。","流星坠兮成雨，进瞵盼兮上丘墟。","览旧邦兮滃郁，余安能兮久居。","志怀逝兮心懰栗，纡余辔兮踌躇。","闻素女兮微歌，听王后兮吹竽。","魂悽怆兮感哀，肠回回兮盘纡。","抚余佩兮缤纷，高太息兮自怜。","使祝融兮先行，令昭明兮开门。","驰六蛟兮上征，竦余驾兮入冥。","历九州兮索合，谁可与兮终生。","忽反顾兮西囿，睹轸丘兮崎倾。","横垂涕兮泫流，悲余后兮失灵。"],"source":"《楚辞》"},{"title":"尊嘉","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["季春兮阳阳，列草兮成行。","余悲兮兰生，委积兮从横。","江离兮遗捐，辛夷兮挤臧。","伊思兮往古，亦多兮遭殃。","伍胥兮浮江，屈子兮沉湘。","运余兮念兹，心内兮怀伤。","望淮兮沛沛，滨流兮则逝。","榜舫兮下流，东注兮磕磕。","蛟龙兮导引，文鱼兮上濑。","抽蒲兮陈坐，援芙蕖兮为盖。","水跃兮余旌，继以兮微蔡。","云旗兮电骛，倏忽兮容裔。","河伯兮开门，迎余兮欢欣。","顾念兮旧都，怀恨兮艰难。","窃哀兮浮萍，汎淫兮无根。"],"source":"《楚辞》"},{"title":"蓄英","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["秋风兮萧萧，舒芳兮振条。","微霜兮眇眇，病殀兮鸣蜩。","玄鸟兮辞归，飞翔兮灵丘。","望谿谷兮滃郁，熊罴兮呴嗥。","唐虞兮不存，何故兮久留？","临渊兮汪洋，顾林兮忽荒。","修余兮袿衣，骑霓兮南上。","乘云兮回回，亹亹兮自强。","将息兮兰皋，失志兮悠悠。","蒶蕴兮霉黧，思君兮无聊。","身去兮意存，怆恨兮怀愁。"],"source":"《楚辞》"},{"title":"思忠","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["登九灵兮游神，静女歌兮微晨。","悲皇丘兮积葛，众体错兮交纷。","贞枝抑兮枯槁，枉车登兮庆云。","感余志兮惨栗，心怆怆兮自怜。","驾玄螭兮北征，曏吾路兮葱岭。","连五宿兮建旄，扬氛气兮为旌。","历广漠兮驰骛，览中国兮冥冥。","玄武步兮水母，与吾期兮南荣。","登华盖兮乘阳，聊逍遥兮播光。","抽库娄兮酌醴，援瓟瓜兮接粮。","毕休息兮远逝，发玉軔兮西行。","惟时俗兮疾正，弗可久兮此方。","寤辟摽兮永思，心怫郁兮内伤。"],"source":"《楚辞》"},{"title":"陶壅","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["览杳杳兮世惟，余惆怅兮何归。","伤时俗兮溷乱，将奋翼兮高飞。","驾八龙兮连蜷，建虹旌兮威夷。","观中宇兮浩浩，纷翼翼兮上跻。","浮溺水兮舒光，淹低佪兮京沶。","屯余车兮索友，睹皇公兮问师。","道莫贵兮归真，羡余术兮可夷。","吾乃逝兮南娭，道幽路兮九疑。","越炎火兮万里，过万首兮嶷嶷。","济江海兮蝉蜕，绝北梁兮永辞。","浮云郁兮昼昏，霾土忽兮塺々。","息阳城兮广夏，衰色罔兮中怠。","意晓阳兮燎寤，乃自诊兮在兹。","思尧舜兮袭兴，幸咎繇兮获谋。","悲九州兮靡君，抚轼叹兮作诗。"],"source":"《楚辞》"},{"title":"株昭","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["悲哉于嗟兮，心内切磋。","款冬而生兮，凋彼叶柯。","瓦砾进宝兮，捐弃随和。","铅刀厉御兮，顿弃太阿。","骥垂两耳兮，中坂蹉跎。","蹇驴服驾兮，无用日多。","修洁处幽兮，贵宠沙劘。","凤皇不翔兮，鹑鴳飞扬。","乘虹骖蜺兮，载云变化。","焦明开路兮，后属青蛇。","步骤桂林兮，超骧卷阿。","丘陵翔儛兮，谿谷悲歌。","神章灵篇兮，赴曲相和。","余私娱兹兮，孰哉复加。","还顾世俗兮，坏败罔罗。","卷佩将逝兮，涕流滂沲。","乱曰：皇门开兮照下土，株秽除兮兰芷睹。","四佞放兮後得禹，圣舜摄兮昭尧绪，孰能若兮原为辅。"],"source":"《楚辞》"},{"title":"逢纷","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["伊伯庸之末胄兮，谅皇直之屈原。","云余肇祖于高阳兮，惟楚怀之婵连。","原生受命于贞节兮，鸿永路有嘉名。","齐名字于天地兮，并光明于列星。","吸精粹而吐氛浊兮，横邪世而不取容。","行叩诚而不阿兮，遂见排而逢谗。","后听虚而黜实兮，不吾理而顺情。","肠愤悁而含怒兮，志迁蹇而左倾。","心戃慌其不我与兮，躬速速其不吾亲。","辞灵修而陨志兮，吟泽畔之江滨。","椒桂罗以颠覆兮，有竭信而归诚。","谗夫蔼蔼而漫著兮，曷其不舒予情？","始结言于庙堂兮，信中涂而叛之。","怀兰蕙与衡芷兮，行中野而散之。","声哀哀而怀高丘兮，心愁愁而思旧邦。","愿承闲而自恃兮，径淫曀而道壅。","颜霉黧以沮败兮，精越裂而衰耄。","裳襜襜而含风兮，衣纳纳而掩露。","赴江湘之湍流兮，顺波凑而下降。","徐徘徊于山阿兮，飘风来之洶洶。","驰余车兮玄石，步余马兮洞庭。","平明发兮苍梧，夕投宿兮石城。","芙蓉盖而菱华车兮，紫贝阙而玉堂。","薜荔饰而陆离荐兮，鱼鳞衣而白蜺裳。","登逢龙而下陨兮，违故都之漫漫。","思南郢之旧俗兮，肠一夕而九运。","扬流波之潢潢兮，体溶溶而东回。","心怊怅以永思兮，意晻晻而日颓。","白露纷以涂涂兮，秋风浏以萧萧。","身永流而不还兮，魂长逝而常愁。","叹曰：","譬彼流水纷扬磕兮，波逢汹涌濆壅滂兮。","揄扬涤荡飘流陨往触崟石兮，龙卬脟圈缭戾宛转阻相薄兮，","遭纷逢凶蹇离尤兮，垂文扬采遗将来兮。"],"source":"《楚辞》"},{"title":"离世","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["灵怀其不吾知兮，灵怀其不吾闻。","就灵怀之皇祖兮，愬灵怀之鬼神。","灵怀曾不吾与兮，即听夫人之谀辞。","余辞上参于天坠兮，旁引之于四时。","指日月使延照兮，抚招摇以质正。","立师旷俾端辞兮，命咎繇使并听。","兆出名曰正则兮，卦发字曰灵均。","余幼既有此鸿节兮，长愈固而弥纯。","不从俗而诐行兮，直躬指而信志。","不枉绳以追曲兮，屈情素以从事。","端余行其如玉兮，述皇舆之踵迹。","群阿容以晦光兮，皇舆覆以幽辟。","舆中涂以回畔兮，驷马惊而横奔。","执组者不能制兮，必折轭而摧辕。","断镳衔以驰骛兮，暮去次而敢止。","路荡荡其无人兮，遂不禦乎千里。","身衡陷而下沉兮，不可获而复登。","不顾身之卑贱兮，惜皇舆之不兴。","出国门而端指兮，冀壹寤而锡还。","哀仆夫之坎毒兮，屡离忧而逢患。","九年之中不吾反兮，思彭咸之水游。","惜师延之浮渚兮，赴汨罗之长流。","遵江曲之逶移兮，触石碕而衡游。","波澧澧而扬浇兮，顺长濑之浊流。","凌黄沱而下低兮，思还流而复反。","玄舆驰而并集兮，身容与而日远。","棹舟杭以横濿兮，济湘流而南极。","立江界而长吟兮，愁哀哀而累息。","情慌忽以忘归兮，神浮游以高历。","心蛩蛩而怀顾兮，魂眷眷而独逝。","叹曰：","余思旧邦心依违兮，日暮黄昏羌幽悲兮，","去郢东迁余谁慕兮，谗夫党旅其以兹故兮，","河水淫淫情所愿兮，顾瞻郢路终不返兮。"],"source":"《楚辞》"},{"title":"怨思","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["惟郁郁之忧毒兮，志坎壈而不违。","身憔悴而考旦兮，日黄昏而长悲。","闵空宇之孤子兮，哀枯杨之冤雏。","孤雌吟于高墉兮，鸣鸠栖于桑榆。","玄蝯失于潜林兮，独偏弃而远放。","征夫劳于周行兮，处妇愤而长望。","申诚信而罔违兮，情素洁于纽帛。","光明齐于日月兮，文采耀燿于玉石。","伤压次而不发兮，思沉抑而不扬。","芳懿懿而终败兮，名靡散而不彰。","背玉门以奔骛兮，蹇离尤而干诟。","若龙逢之沉首兮，王子比干之逢醢。","念社稷之几危兮，反为雠而见怨。","思国家之离沮兮，躬获愆而结难。","若青蝇之伪质兮，晋骊姬之反情。","恐登阶之逢殆兮，故退伏于末庭。","孽臣之号咷兮，本朝芜而不治。","犯颜色而触谏兮，反蒙辜而被疑。","菀蘼芜与菌若兮，渐藁本于洿渎。","淹芳芷于腐井兮，弃鸡骇于筐簏。","执棠谿以刜蓬兮，秉干将以割肉。","筐泽泻以豹鞟兮，破荆和以继筑。","时溷浊犹未清兮，世殽乱犹未察。","欲容与以俟时兮，惧年岁之既晏。","顾屈节以从流兮，心巩巩而不夷。","宁浮沅而驰骋兮，下江湘以邅回。","叹曰：","山中槛槛余伤怀兮，征夫皇皇其孰依兮，","经营原野杳冥冥兮，乘骐骋骥舒吾情兮，","归骸旧邦莫谁语兮，长辞远逝乘湘去兮。"],"source":"《楚辞》"},{"title":"远逝","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["志隐隐而郁怫兮，愁独哀而冤结。","肠纷纭以缭转兮，涕渐渐其若屑。","情慨慨而长怀兮，信上皇而质正。","合五岳与八灵兮，讯九鬿与六神。","指列宿以白情兮，诉五帝以置辞。","北斗为我折中兮，太一为余听之。","云服阴阳之正道兮，御后土之中和。","佩苍龙之蚴虬兮，带隐虹之逶蛇。","曳彗星之皓旰兮，抚朱爵与鵔鸃。","游清灵之飒戾兮，服云衣之披披。","杖玉策与朱旗兮，垂明月之玄珠。","举霓旌之墆翳兮，建黄纁之总旄。","躬纯粹而罔愆兮，承皇考之妙仪。","惜往事之不合兮，横汨罗而下沥。","乘隆波而南渡兮，逐江湘之顺流。","赴阳侯之潢洋兮，下石濑而登洲。","陆魁堆以蔽视兮，云冥冥而闇前。","山峻高以无垠兮，遂曾闳而迫身。","雪雰雰而薄木兮，云霏霏而陨集。","阜隘狭而幽险兮，石嵾嵯以翳日。","悲故乡而发忿兮，去余邦之弥久。","背龙门而入河兮，登大坟而望夏首。","横舟航而济湘兮，耳聊啾而戃慌。","波淫淫而周流兮，鸿溶溢而滔荡。","路曼曼其无端兮，周容容而无识。","引日月以指极兮，少须臾而释思。","水波远以冥冥兮，眇不睹其东西。","顺风波以南北兮，雾宵晦以纷纷。","日杳杳以西颓兮，路长远而窘迫。","欲酌醴以娱忧兮，蹇骚骚而不释。","叹曰：","飘风蓬龙埃坲々兮，草木摇落时槁悴兮，","遭倾遇祸不可救兮，长吟永欷涕究究兮，","舒情陈诗冀以自免兮，颓流下陨身日远兮。"],"source":"《楚辞》"},{"title":"惜贤","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["览屈氏之离骚兮，心哀哀而怫郁。","声嗷嗷以寂寥兮，顾仆夫之憔悴。","拨谄谀而匡邪兮，切淟涊之流俗。","荡渨涹之奸咎兮，夷蠢蠢之溷浊。","怀芬香而挟蕙兮，佩江蓠之婓婓。","握申椒与杜若兮，冠浮云之峨峨。","登长陵而四望兮，览芷圃之蠡蠡。","游兰皋与蕙林兮，睨玉石之嵾嵯。","扬精华以炫燿兮，芳郁渥而纯美。","结桂树之旖旎兮，纫荃蕙与辛夷。","芳若兹而不御兮，捐林薄而菀死。","驱子侨之奔走兮，申徒狄之赴渊。","若由夷之纯美兮，介子推之隐山。","晋申生之离殃兮，荆和氏之泣血。","吴申胥之抉眼兮，王子比干之横废。","欲卑身而下体兮，心隐恻而不置。","方圜殊而不合兮，钩绳用而异态。","欲俟时于须臾兮，日阴曀其将暮。","时迟迟其日进兮，年忽忽而日度。","妄周容而入世兮，内距闭而不开。","俟时风之清激兮，愈氛雾其如塺。","进雄鸠之耿耿兮，谗介介而蔽之。","默顺风以偃仰兮，尚由由而进之。","心懭悢以冤结兮，情舛错以曼忧。","搴薜荔于山野兮，采撚支于中洲。","望高丘而叹涕兮，悲吸吸而长怀。","孰契契而委栋兮，日晻晻而下颓。","叹曰：","江湘油油长流汩兮，挑揄扬汰荡迅疾兮。","忧心展转愁怫郁兮，冤结未舒长隐忿兮，","丁时逢殃可奈何兮，劳心悁悁涕滂沱兮。"],"source":"《楚辞》"},{"title":"忧苦","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["悲余心之悁悁兮，哀故邦之逢殃。","辞九年而不复兮，独茕茕而南行。","思余俗之流风兮，心纷错而不受。","遵野莽以呼风兮，步从容于山廋。","巡陆夷之曲衍兮，幽空虚以寂寞。","倚石岩以流涕兮，忧憔悴而无乐。","登巑岏以长企兮，望南郢而闚之。","山修远其辽辽兮，涂漫漫其无时。","听玄鹤之晨鸣兮，于高冈之峨峨。","独愤积而哀娱兮，翔江洲而安歌。","三鸟飞以自南兮，览其志而欲北。","原寄言于三鸟兮，去飘疾而不可得。","欲迁志而改操兮，心纷结其未离。","外彷徨而游览兮，内恻隐而含哀。","聊须臾以时忘兮，心渐渐其烦错。","原假簧以舒忧兮，志纡郁其难释。","叹《离骚》以扬意兮，犹未殫于《九章》。","长嘘吸以于悒兮，涕横集而成行。","伤明珠之赴泥兮，鱼眼玑之坚藏。","同驽骡与乘駔兮，杂斑駮与阘茸。","葛藟虆于桂树兮，鸱鸮集于木兰。","偓促谈于廊庙兮，律魁放乎山间。","恶虞氏之箫《韶》兮，好遗风之《激楚》。","潜周鼎于江淮兮，爨土鬵于中宇。","且人心之持旧兮，而不可保长。","邅彼南道兮，征夫宵行。","思念郢路兮，还顾睠睠。","涕流交集兮，泣下涟涟。","叹曰：","登山长望中心悲兮，菀彼青青泣如颓兮，","留思北顾涕渐渐兮，折锐摧矜凝氾滥兮，","念我茕茕魂谁求兮，仆夫慌悴散若流兮。"],"source":"《楚辞》"},{"title":"愍命","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["昔皇考之嘉志兮，喜登能而亮贤。","情纯洁而罔薉兮，姿盛质而无愆。","放佞人与谄谀兮，斥谗夫与便嬖。","亲忠正之悃诚兮，招贞良与明智。","心溶溶其不可量兮，情澹澹其若渊。","回邪辟而不能入兮，诚原藏而不可迁。","逐下袟于後堂兮，迎虙妃于伊雒。","刜谗贼于中廇兮，选吕管于榛薄。","丛林之下无怨士兮，江河之畔无隐夫。","三苗之徒以放逐兮，伊皋之伦以充庐。","今反表以为里兮，颠裳以为衣。","戚宋万于两楹兮，废周邵于遐夷。","却骐骥以转运兮，腾驴骡以驰逐。","蔡女黜而出帷兮，戎妇入而綵绣服。","庆忌囚于阱室兮，陈不占战而赴围。","破伯牙之号钟兮，挟人筝而弹纬。","藏瑉石于金匮兮，捐赤瑾于中庭。","韩信蒙于介胄兮，行夫将而攻城。","莞芎弃于泽洲兮，瓟瓥蠹于筐簏。","麒麟奔于九皋兮，熊罴群而逸囿。","折芳枝与琼华兮，树枳棘与薪柴。","掘荃蕙与射干兮，耘藜藿与蘘荷。","惜今世其何殊兮，远近思而不同。","或沉沦其无所达兮，或清激其无所通。","哀余生之不当兮，独蒙毒而逢尤。","虽謇謇以申志兮，君乖差而屏之。","诚惜芳之菲菲兮，反以兹为腐也。","怀椒聊之蔎蔎兮，乃逢纷以罹诟也。","叹曰：","嘉皇既殁终不返兮，山中幽险郢路远兮。","谗人諓諓孰可愬兮，征夫罔极谁可语兮。","行吟累欷声喟喟兮，怀忧含戚何侘傺兮。"],"source":"《楚辞》"},{"title":"思古","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["冥冥深林兮，树木郁郁。","山参差以崭岩兮，阜杳杳以蔽日。","悲余心之悁悁兮，目眇眇而遗泣。","风骚屑以摇木兮，云吸吸以湫戾。","悲余生之无欢兮，愁倥傯于山陆。","旦徘徊于长阪兮，夕彷徨而独宿。","发披披以鬤鬤兮，躬劬劳而瘏悴。","魂俇俇而南行兮，泣霑襟而濡袂。","心婵媛而无告兮，口噤闭而不言。","违郢都之旧闾兮，回湘、沅而远迁。","念余邦之横陷兮，宗鬼神之无次。","闵先嗣之中绝兮，心惶惑而自悲。","聊浮游于山陿兮，步周流于江畔。","临深水而长啸兮，且倘佯而氾观。","兴离骚之微文兮，冀灵修之壹悟。","还余车于南郢兮，复往轨于初古。","道修远其难迁兮，伤余心之不能已。","背三五之典刑兮，绝洪范之辟纪。","播规矩以背度兮，错权衡而任意。","操绳墨而放弃兮，倾容幸而侍侧。","甘棠枯于丰草兮，藜棘树于中庭。","西施斥于北宫兮，仳倠倚于弥楹。","乌获戚而骖乘兮，燕公操于马圉。","蒯聩登于清府兮，咎繇弃而在野。","盖见兹以永叹兮，欲登阶而狐疑。","乘白水而高骛兮，因徙弛而长词。","叹曰：","倘佯垆阪沼水深兮，容与汉渚涕淫淫兮，锺牙已死谁为声兮？","纤阿不御焉舒情兮，曾哀悽欷心离离兮，还顾高丘泣如洒兮。"],"source":"《楚辞》"},{"title":"远游","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["悲余性之不可改兮，屡惩艾而不迻。","服觉皓以殊俗兮，貌揭揭以巍巍。","譬若王侨之乘云兮，载赤霄而凌太清。","欲与天地参寿兮，与日月而比荣。","登昆仑而北首兮，悉灵圉而来谒。","选鬼神于太阴兮，登阊阖于玄阙。","回朕车俾西引兮，褰虹旗于玉门。","驰六龙于三危兮，朝西灵于九滨。","结余轸于西山兮，横飞谷以南征。","绝都广以直指兮，历祝融于硃冥。","枉玉衡于炎火兮，委两馆于咸唐。","贯澒濛以东朅兮，维六龙于扶桑。","周流览于四海兮，志升降以高驰。","徵九神于回极兮，建虹采以招指。","驾鸾凤以上游兮，从玄鹤与鹪明。","孔鸟飞而送迎兮，腾群鹤于瑶光。","排帝宫与罗囿兮，升县圃以眩灭。","结琼枝以杂佩兮，立长庚以继日。","凌惊雷以轶骇电兮，缀鬼谷于北辰。","鞭风伯使先驱兮，囚灵玄于虞渊。","遡高风以低佪兮，览周流于朔方。","就颛顼而敶辞兮，考玄冥于空桑。","旋车逝于崇山兮，奏虞舜于苍梧。","济杨舟于会稽兮，就申胥于五湖。","见南郢之流风兮，殒余躬于沅湘。","望旧邦之黯黮兮，时溷浊其犹未央。","怀兰茝之芬芳兮，妒被离而折之。","张绛帷以襜襜兮，风邑邑而蔽之。","日暾暾其西舍兮，阳焱焱而复顾。","聊假日以须臾兮，何骚骚而自故。","叹曰：","譬彼蛟龙乘云浮兮，汎淫澒溶纷若雾兮。","潺湲轇轕雷动电发馺高举兮。","升虚凌冥沛浊浮清入帝宫兮，摇翘奋羽驰风骋雨游无穷兮。"],"source":"《楚辞》"},{"title":"逢尤","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["悲兮愁，哀兮忧！","天生我兮当闇时，被诼谮兮虚获尤。","心烦憒兮意无聊，严载驾兮出戏游。","周八极兮历九州，求轩辕兮索重华。","世既卓兮远眇眇，握佩玖兮中路躇。","羡咎繇兮建典谟，懿风后兮受瑞图。","愍余命兮遭六极，委玉质兮於泥涂。","遽傽遑兮驱林泽，步屏营兮行丘阿。","车軏折兮马虺颓，惷怅立兮涕滂沱。","思丁文兮圣明哲，哀平差兮迷谬愚。","吕傅举兮殷周兴，忌嚭专兮郢吴虚。","仰长叹兮气噎结，悒殟绝兮咶复苏。","虎兕争兮於廷中，豺狼斗兮我之隅。","云雾会兮日冥晦，飘风起兮扬尘埃。","走鬯罔兮乍东西，欲窜伏兮其焉如？","念灵闺兮隩重深，原竭节兮隔无由。","望旧邦兮路逶随，忧心悄兮志勤劬。","魂茕茕兮不遑寐，目眽眽兮寤终朝。"],"source":"《楚辞》"},{"title":"怨上","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["令尹兮謷謷，群司兮譨譨。","哀哉兮淈淈，上下兮同流。","菽藟兮蔓衍，芳虈兮挫枯。","硃紫兮杂乱，曾莫兮别诸。","倚此兮岩穴，永思兮窈悠。","嗟怀兮眩惑，用志兮不昭。","将丧兮玉斗，遗失兮钮枢。","我心兮煎熬，惟是兮用忧。","进恶兮九旬，复顾兮彭务。","拟斯兮二踪，未知兮所投。","谣吟兮中野，上察兮璇玑。","大火兮西睨，摄提兮运低。","雷霆兮硠磕，雹霰兮霏霏。","奔电兮光晃，凉风兮怆悽。","鸟兽兮惊骇，相从兮宿栖。","鸳鸯兮噰噰，狐狸兮徾徾。","哀吾兮介特，独处兮罔依。","蝼蛄兮鸣东，蟊蠽兮号西。","蛓缘兮我裳，蠋入兮我怀。","虫豸兮夹余，惆怅兮自悲。","伫立兮忉怛，心结縎兮折摧。"],"source":"《楚辞》"},{"title":"疾世","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["周徘徊兮汉渚，求水神兮灵女。","嗟此国兮无良，媒女诎兮謰謱。","鴳雀列兮譁讙，鸲鹆鸣兮聒余。","抱昭华兮宝璋，欲衒鬻兮莫取。","言旋迈兮北徂，叫我友兮配耦。","日阴曀兮未光，阒睄窕兮靡睹。","纷载驱兮高驰，将谘询兮皇羲。","遵河皋兮周流，路变易兮时乖。","濿沧海兮东游，沐盥浴兮天池。","访太昊兮道要，云靡贵兮仁义。","志欣乐兮反征，就周文兮邠歧。","秉玉英兮结誓，日欲暮兮心悲。","惟天禄兮不再，背我信兮自违。","逾陇堆兮渡漠，过桂车兮合黎。","赴昆山兮馽騄，从邛遨兮栖迟。","吮玉液兮止渴，齧芝华兮疗饥。","居嵺廓兮尠畴，远梁昌兮几迷。","望江汉兮濩渃，心紧絭兮伤怀。","时昢昢兮且旦，尘莫莫兮未晞。","忧不暇兮寝食，吒增叹兮如雷。"],"source":"《楚辞》"},{"title":"悯上","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["哀世兮睩睩，諓諓兮嗌喔。","众多兮阿媚，骪靡兮成俗。","贪枉兮党比，贞良兮茕独。","鹄窜兮枳棘，鹈集兮帷幄。","罽蕠兮青葱，槁本兮萎落。","睹斯兮伪惑，心为兮隔错。","逡巡兮圃薮，率彼兮畛陌。","川谷兮渊渊，山阜兮峉峉。","丛林兮崟崟，株榛兮岳岳。","霜雪兮漼溰，冰冻兮洛泽。","东西兮南北，罔所兮归薄。","庇廕兮枯树，匍匐兮岩石。","蜷跼兮寒局数，独处兮志不申。","年齿尽兮命迫促，魁垒挤摧兮常困辱。","含忧强老兮愁无乐，须发苎悴兮顠鬓白。","思灵泽兮一膏沐，怀兰英兮把琼若，待天明兮立踯躅。","云蒙蒙兮电鯈烁，孤雌惊兮鸣呴呴。","思怫郁兮肝切剥，忿悁悒兮孰诉告。"],"source":"《楚辞》"},{"title":"遭厄","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["悼屈子兮遭厄，沉王躬兮湘汨。","何楚国兮难化，迄于今兮不易。","士莫志兮羔裘，竞佞谀兮谗阋。","指正义兮为曲，訿玉璧兮为石。","殦雕游兮华屋，鵔鸃栖兮柴蔟。","起奋迅兮奔走，违群小兮謑訽。","载青云兮上昇，適昭明兮所处。","蹑天衢兮长驱，踵九阳兮戏荡。","越云汉兮南济，秣余马兮河鼓。","云霓纷兮晻翳，参辰回兮颠倒。","逢流星兮问路，顾我指兮从左。","俓娵觜兮直驰，御者迷兮失轨。","遂踢达兮邪造，与日月兮殊道。","志阏绝兮安如，哀所求兮不耦。","攀天阶兮下视，见鄢郢兮旧宇。","意逍遥兮欲归，众秽盛兮沓沓。","思哽饐兮诘诎，涕流澜兮如雨。"],"source":"《楚辞》"},{"title":"悼乱","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["嗟嗟兮悲夫，殽乱兮纷挐。","茅丝兮同综，冠屦兮共絇。","督万兮侍宴，周邵兮负刍。","白龙兮见射，灵龟兮执拘。","仲尼兮困厄，邹衍兮幽囚。","伊余兮念兹，奔遁兮隐居。","将升兮高山，上有兮猴猿。","欲入兮深谷，下有兮虺蛇。","左见兮鸣鵙，右睹兮呼枭。","惶悸兮失气，踊跃兮距跳。","便旋兮中原，仰天兮增叹。","菅蒯兮楙莽，雚苇兮仟眠。","鹿蹊兮躖躖，貒貉兮蟫蟫。","鹯鹞兮轩轩，鹑鹌兮甄甄。","哀我兮寡独，靡有兮齐伦。","意欲兮沉吟，迫日兮黄昏。","玄鹤兮高飞，曾逝兮青冥。","鶬鶊兮喈喈，山鹊兮嚶嚶。","鸿鸬兮振翅，归雁兮于征。","吾志兮觉悟，怀我兮圣京。","垂屣兮将起，跓俟兮硕明。"],"source":"《楚辞》"},{"title":"伤时","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["惟昊天兮昭灵，阳气发兮清明。","风習習兮和暖，百草萌兮华荣。","堇荼茂兮扶疏，蘅芷彫兮莹嫇。","愍贞良兮遇害，将夭折兮碎糜。","时混混兮浇饡，哀当世兮莫知。","览往昔兮俊彦，亦诎辱兮系纍。","管束缚兮桎梏，百贸易兮传卖。","遭桓缪兮识举，才德用兮列施。","且从容兮自慰，玩琴书兮游戏。","迫中国兮迮陿，吾欲之兮九夷。","超五岭兮嵯峨，观浮石兮崔嵬。","陟丹山兮炎野，屯余车兮黄支。","就祝融兮稽疑，嘉己行兮无为。","乃回朅兮北逝，遇神孈兮宴娭。","欲静居兮自娱，心愁慼兮不能。","放余辔兮策驷，忽飙腾兮浮云。","蹠飞杭兮越海，从安期兮蓬莱。","缘天梯兮北上，登太一兮玉台。","使素女兮鼓簧，乘戈和兮讴谣。","声噭誂兮清和，音晏衍兮要婬。","咸欣欣兮酣乐，余眷眷兮独悲。","顾章华兮太息，志恋恋兮依依。"],"source":"《楚辞》"},{"title":"哀岁","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["旻天兮清凉，玄气兮高朗。","北风兮潦洌，草木兮苍唐。","蛜蚗兮噍噍，蝍蛆兮穰穰。","岁忽忽兮惟暮，余感时兮悽怆。","伤俗兮泥浊，矇蔽兮不章。","宝彼兮沙砾，捐此兮夜光。","椒瑛兮湟汙，葈耳兮充房。","摄衣兮缓带，操我兮墨阳。","昇车兮命仆，将驰兮四荒。","下堂兮见虿，出门兮触螽。","巷有兮蚰蜓，邑多兮螳螂。","睹斯兮嫉贼，心为兮切伤。","俛念兮子胥，仰怜兮比干。","投剑兮脱冕，龙屈兮蜿蟤。","潜藏兮山泽，匍匐兮丛攒。","窥见兮溪涧，流水兮沄沄。","鼋鼍兮欣欣，鱣鲇兮延延。","群行兮上下，骈罗兮列陈。","自恨兮无友，特处兮茕茕。","冬夜兮陶陶，雨雪兮冥冥。","神光兮颎颎，鬼火兮荧荧。","修德兮困控，愁不聊兮遑生。","忧纡兮郁郁，恶所兮写情。"],"source":"《楚辞》"},{"title":"守志","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["陟玉峦兮逍遥，览高冈兮峣峣。","桂树列兮纷敷，吐紫华兮布条。","实孔鸾兮所居，今其集兮惟鸮。","乌鹊惊兮哑哑，余顾盼兮怊怊。","彼日月兮闇昧，障覆天兮祲氛。","伊我后兮不聪，焉陈诚兮效忠。","摅羽翮兮超俗，游陶遨兮养神。","乘六蛟兮蜿蝉，遂驰骋兮升云。","扬彗光兮为旗，秉电策兮为鞭。","朝晨发兮鄢郢，食时至兮增泉。","绕曲阿兮北次，造我车兮南端。","谒玄黄兮纳贽，崇忠贞兮弥坚。","历九宫兮遍观，睹秘藏兮宝珍。","就传说兮骑龙，与织女兮合婚。","举天罼兮掩邪，彀天弧兮射奸。","随真人兮翱翔，食元气兮长存。","望太微兮穆穆，睨三阶兮炳分。","相辅政兮成化，建烈业兮垂勋。","目瞥瞥兮西没，道遐回兮阻叹。","志稸积兮未通，怅敞罔兮自怜。","乱曰：","天庭明兮云霓藏，三光朗兮镜万方。","斥蜥蜴兮进龟龙，策谋从兮翼机衡。","配稷契兮恢唐功，嗟英俊兮未为双。"],"source":"《楚辞》"}];
